  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."AANWVIEW" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ANW_REF_NR", "EXTERNE_NR", "ABOSTATUS") AS
  select a.e_mandant,a.adr_gr,a.adr_nr,a.person_nr,
       s.obj_nr, s.ausg, a.anw_ref_nr,a.externe_nr,'xxxxxxxxx'
  from versges s, anwref a
where s.adr_gr    = a.adr_gr
   and s.adr_nr    = a.adr_nr
   and s.person_nr = a.person_nr
   and s.e_mandant = a.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ABOAVIEW" ("ADR_GR", "ADR_NR", "HAUPT_NAME", "ADR_NR_BV", "LAND_CODE", "INAUS", "HAUPT_PLZ", "HAUPT_ORT", "STRASSE", "HAUSNR", "HAUSNR_ZUS", "POSTFACH", "VERSAND_ADR", "DATUM_NEU", "DATUM_AEND", "PERSON_NR", "A_TYP", "E_MANDANT", "OBJ_NR", "AUSG", "ABO_NR", "BER_MENGE", "VBEG_DAT", "VBEG_JAHR", "VBEG_HEFT", "VEND_DAT", "VEND_JAHR", "VEND_HEFT", "PREIS_KAT", "WAEHRUNG", "R_ART", "R_BEG_DAT", "R_BEG_JAHR", "R_BEG_HNR", "R_ENDE_DAT", "R_ENDE_JAHR", "R_ENDE_HNR", "ABOSTATUS", "ZEILE1", "ZEILE2", "ZEILE3", "VORNAME", "NACHNAME", "K_GRUND", "STATUS", "FAKT_ZR", "R_GRUND", "F_ENDE_DAT_E", "KZ_MAHNUNG", "RECHKOPIEN", "PLZ_WOHN", "WOHNORT", "PLZ_POST", "POSTORT", "PLZ_GK", "GKORT", "B_ID_AEND", "PERSON_NR_BV", "ABTEILUNG", "KZ_STORNO", "AUFTRAGS_NR", "SPREIS", "RA_FAKT", "HEFT_ANZ", "W_AKT_ID", "W_UAKT_ID", "PREIS_KAT_NO", "NO_ENDE_DAT", "NO_ENDE_JAHR", "NO_ENDE_HNR", "STDB_BIS", "VERLBER_ID", "EXTERNE_NR", "DATUM_NEU_P", "DATUM_AEND_P", "NAME1", "NAME2", "ANREDE_CODE", "VERANLASSER", "BESTELLG", "EINDRUCK_NR", "KZ_EINDRUCK", "ASPERR_CODE", "ABOSPERR_VON", "ABOSPERR_BIS") AS
  select a.adr_gr, a.adr_nr, a.haupt_name, b.adr_nr_bv, a.land_code,
       b.inaus,  a.haupt_plz, a.haupt_ort, a.strasse,
       a.hausnr, a.hausnr_zus, a.postfach, a.versand_adr,
       b.datum_neu, b.datum_aend, b.person_nr, p.a_typ, b.e_mandant,
       b.obj_nr, b.ausg, b.abo_nr,
       b.ber_menge,
       b.vbeg_dat, b.vbeg_jahr,
       b.vbeg_heft, b.vend_dat, b.vend_jahr, b.vend_heft,
       b.preis_kat,
       b.waehrung, b.r_art,
       b.r_beg_dat, b.r_beg_jahr, b.r_beg_hnr, b.r_ende_dat,
       b.r_ende_jahr, b.r_ende_hnr,
       b.abostatus, a.name1, a.name2, a.name3,
       p.vorname, p.nachname, b.k_grund, b.status,
       b.fakt_zr,b.r_grund,b.dat_fakt_von,
       b.kz_mahnung,b.rechkopien,
       a.plz_wohn,a.wohnort,
       a.plz_post,a.postort,
       a.plz_gk,a.gkort,
       b.b_id_aend, b.person_nr_bv, p.abteilung, b.kz_storno,
       b.auftrags_nr,b.spreis,b.ra_fakt,b.heft_anz,b.w_akt_id,b.w_uakt_id,
       b.preis_kat_no,b.no_ende_dat,b.no_ende_jahr,b.no_ende_hnr,
       p.stdb_bis,a.verlber_id, w.externe_nr, p.datum_neu,p.datum_aend,a.name1,a.name2,p.ANREDE_CODE,
       b.veranlasser,b.bestellg, b.EINDRUCK_NR, b.KZ_EINDRUCK, i.ASPERR_CODE,i.ABOSPERR_VON,i.ABOSPERR_BIS
from abostamm b, person p, anschr a, anwref w, ainfo i
where b.adr_gr    = a.adr_gr
   and b.adr_nr    = a.adr_nr
   and b.adr_gr    = p.adr_gr
   and b.adr_nr    = p.adr_nr
   and b.person_nr = p.person_nr
   and b.e_mandant = w.e_mandant(+)
   and b.adr_gr    = w.adr_gr(+)
   and b.adr_nr    = w.adr_nr(+)
   and b.person_nr = w.person_nr(+)
   and w.anw_ref_nr(+) = 'VS'
   and b.adr_nr = i.adr_nr(+)
   and b.adr_gr = i.adr_gr(+);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ABOKVIEW" ("ADR_GR", "ADR_NR", "ADR_NR_BV", "INAUS", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "ABO_NR", "BER_MENGE", "VBEG_DAT", "VBEG_JAHR", "VBEG_HEFT", "VEND_DAT", "VEND_JAHR", "VEND_HEFT", "PREIS_KAT", "WAEHRUNG", "R_ART", "R_BEG_DAT", "R_BEG_JAHR", "R_BEG_HNR", "R_ENDE_DAT", "R_ENDE_JAHR", "R_ENDE_HNR", "ABOSTATUS", "K_GRUND", "STATUS", "FAKT_ZR", "PERSON_NR_BV", "KZ_STORNO", "AUFTRAGS_NR", "SPREIS", "RA_FAKT", "W_AKT_ID", "W_UAKT_ID", "PREIS_KAT_NO", "NO_ENDE_DAT", "NO_ENDE_JAHR", "NO_ENDE_HNR", "BEST_DATUM", "K_DATUM", "VERSAND_SOLL_VBEG", "VERSAND_SOLL_VEND", "VERSAND_SOLL_NO", "VERSAND_SOLL_RBEG", "VERSAND_SOLL_REND", "LFD_NR", "IVW_GRUPPE", "LAND_CODE_LE", "LFD_NR_AKTVORB") AS
  select                a.adr_gr, a.adr_nr, a.adr_nr_bv, a.inaus,
                      a.person_nr, a.e_mandant,
                      a.obj_nr, a.ausg, a.abo_nr,
                      a.ber_menge,
                      a.vbeg_dat, a.vbeg_jahr, a.vbeg_heft,
                      a.vend_dat, a.vend_jahr, a.vend_heft,
                      a.preis_kat, a.waehrung, a.r_art,
                      a.r_beg_dat, a.r_beg_jahr, a.r_beg_hnr,
                      a.r_ende_dat, a.r_ende_jahr, a.r_ende_hnr,
                      a.abostatus, a.k_grund, a.status,
                      a.fakt_zr, a.person_nr_bv,a.kz_storno,a.auftrags_nr,
                      a.spreis,a.ra_fakt,a.w_akt_id,a.w_uakt_id,
                      a.preis_kat_no,a.no_ende_dat,a.no_ende_jahr,a.no_ende_hnr,
                      a.best_datum, a.k_datum,
                      k.versand_soll, kk.versand_soll,to_date(null),
                      kkk.versand_soll, kkkk.versand_soll, a.LFD_NR, a.IVW_GRUPPE, s.land_code, a.lfd_nr_aktvorb
