  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ABOVERSH" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "JAHR", "HNR", "ADR_NR_BV", "PERSON_NR_BV", "PREIS_KAT", "L_MENGE") AS
  select
      v.e_mandant,v.adr_gr,v.adr_nr,v.person_nr,v.u_obj_nr,v.u_ausg,v.abo_nr,v.jahr,v.hnr,a.adr_nr_bv,a.person_nr_bv,a.preis_kat,v.l_menge
from vershist v, abostamm a
where v.adr_gr=a.adr_gr and v.adr_nr=a.adr_nr and v.person_nr=a.person_nr
and   v.obj_nr=a.obj_nr and v.ausg=a.ausg
and   v.e_mandant=a.e_mandant and v.abo_nr=a.abo_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ABOVERSHDBV" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "JAHR", "HNR", "ADR_NR_BV", "PERSON_NR_BV", "PREIS_KAT", "L_MENGE", "IVW_LIST", "ZUS_KAT", "RAB_KAT", "WAEHRUNG", "FAKT_ZR", "INAUS") AS
  select
      v.e_mandant,v.adr_gr,v.adr_nr,v.person_nr,v.u_obj_nr,v.u_ausg,v.abo_nr,v.jahr,v.hnr,a.adr_nr_bv,a.person_nr_bv,
      a.preis_kat,v.l_menge,v.ivw_list,az.rz_kat,ar.rz_kat,a.waehrung,a.fakt_zr,a.inaus
from vershist v, abostamm a, abofakt af
	left outer join aborab ar on
	ar.adr_gr=af.adr_gr
and	ar.adr_nr=af.adr_nr
and   	ar.person_nr=af.person_nr
and   	ar.obj_nr=af.obj_nr
and   	ar.ausg=af.ausg
and   	ar.e_mandant=af.e_mandant
and   	ar.abo_nr=af.abo_nr
	left outer join abozus az on
	az.adr_gr=af.adr_gr
and	az.adr_nr=af.adr_nr
and   	az.person_nr=af.person_nr
and   	az.obj_nr=af.obj_nr
and   	az.ausg=af.ausg
and   	az.e_mandant=af.e_mandant
and   	az.abo_nr=af.abo_nr

where	v.adr_gr=a.adr_gr
and	v.adr_nr=a.adr_nr
and   	v.person_nr=a.person_nr
and   	v.obj_nr=a.obj_nr
and   	v.ausg=a.ausg
and   	v.e_mandant=a.e_mandant
and   	v.abo_nr=a.abo_nr
and	af.adr_gr=a.adr_gr
and	af.adr_nr=a.adr_nr
and   	af.person_nr=a.person_nr
and   	af.obj_nr=a.obj_nr
and   	af.ausg=a.ausg
and   	af.e_mandant=a.e_mandant
and   	af.abo_nr=a.abo_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ABOZVIEW" ("VORNAME", "NACHNAME", "STRASSE", "HAUSNR", "HAUPT_PLZ", "HAUPT_ORT", "OBJ_NR", "BER_MENGE", "VBEG_JAHR", "VBEG_HEFT", "VEND_JAHR", "VEND_HEFT", "ADR_GR", "ADR_NR", "EMAIL", "NUMMER") AS
  select p.vorname, p.nachname, a.strasse,
                      a.hausnr, a.haupt_plz, a.haupt_ort,
                      b.obj_nr, b.ber_menge,
                      b.vbeg_jahr, b.vbeg_heft,
                      b.vend_jahr, b.vend_heft,
                      a.adr_gr, a.adr_nr,
                      (select nummer from telecom t,teleart l where t.adr_gr (+)   = p.adr_gr
                                 and t.adr_nr (+)   = p.adr_nr
                                 and t.person_nr (+) = p.person_nr
                                 and l.tel_art (+) = t.tel_art
                                 and l.verw_id='E' ),
                      (select nummer from telecom t,teleart l where t.adr_gr (+)   = p.adr_gr
                                 and t.adr_nr (+)   = p.adr_nr
                                 and t.person_nr (+) = p.person_nr
                                 and l.tel_art (+) = t.tel_art
                                 and l.verw_id='T' )

  from abostamm b, person p, anschr a

 where b.adr_gr    = a.adr_gr
   and b.adr_nr    = a.adr_nr
   and b.adr_gr    = p.adr_gr
   and b.adr_nr    = p.adr_nr
   and b.person_nr = p.person_nr
   and p.a_typ='P' ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ABSATZVIEW" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "N_ARTIKEL_NR", "RECH_TYP", "RECH_DAT", "SUM_BER_MENGE", "SUM_FREI_BER", "SUM_GUT_MENGE", "SUM_FREI_GUT") AS
  select u.e_mandant, t.l_ausg_nr, t.l_aufl_nr, t.artikel_nr, to_number(regexp_replace(t.artikel_nr,'[^[:digit:]]')), s.rech_typ, u.rech_dat,
         nvl(sum(t.ber_menge),0), nvl(sum(t.frei_menge),0), 0, 0
  from bufakst s, bufakupo u, bufakset t,
       bufakpos f LEFT OUTER JOIN bustaord o on
          f.staord_nr = o.staord_nr and
          o.l_ausg_nr_k != 1
  where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and u.rech_nr      = t.rech_nr
  and u.rech_dat     = t.rech_dat
  and u.f_mandant    = t.f_mandant
  and u.pos_nr       = t.pos_nr
  and u.upos_nr      = t.upos_nr
  and s.rech_typ     like 'R%'
  and (s.rech_typ != 'RS' or s.r_art != 'P' or u.p_status_lief != 'F')
  and (s.rech_typ != 'RO' or s.r_art != 'P')
  and t.e_mandant    = u.e_mandant
  and u.bundle!='F' and u.bundle != 'E'
  group by u.e_mandant, t.l_ausg_nr, t.l_aufl_nr, t.artikel_nr, to_number(regexp_replace(t.artikel_nr,'[^[:digit:]]')), s.rech_typ, u.rech_dat
union
  select u.e_mandant, u.l_ausg_nr, u.l_aufl_nr, u.artikel_nr, to_number(regexp_replace(u.artikel_nr,'[^[:digit:]]')), s.rech_typ, u.rech_dat,
         nvl(sum(u.ber_menge),0), nvl(sum(u.frei_menge),0), 0, 0
  from bufakst s, bufakupo u,
       bufakpos f LEFT OUTER JOIN bustaord o on
          f.staord_nr = o.staord_nr and
          o.l_ausg_nr_k != 1
  where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and s.rech_typ     like 'R%'
  and (s.rech_typ != 'RS' or s.r_art != 'P' or u.p_status_lief != 'F')
  and (s.rech_typ != 'RO' or s.r_art != 'P')
  and u.e_mandant    = u.e_mandant
  and (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
       and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr)
      or exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
         and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr and (u.bundle = 'F' or u.bundle = 'E')))
