select k.adr_pool_nr, k.adr_gr, k.e_mandant, k.benutzer_id,
	k.pool_typ, k.status, k.kurz_bez, k.bez, k.gueltig_ab, k.gueltig_bis,
	b.teil_pool_nr, rtrim(b.benutzer_id), '', ''
from ADRPBEN b, ADRPKOPF k
where b.teil_pool_nr = -1
and   b.adr_pool_nr  = k.adr_pool_nr
union
select k.adr_pool_nr, k.adr_gr, k.e_mandant, k.benutzer_id,
	k.pool_typ, k.status, k.kurz_bez, k.bez, k.gueltig_ab, k.gueltig_bis,
	b.teil_pool_nr, rtrim(b.benutzer_id), rtrim(p.kurz_bez), rtrim(p.beschreibung)
from ADRPBEN b, ADRPTP p, ADRPKOPF k
where b.adr_pool_nr  = p.adr_pool_nr
and	b.teil_pool_nr = p.teil_pool_nr
and	b.adr_pool_nr  = k.adr_pool_nr
and     b.bengrp_id  = '000'
union
select k.adr_pool_nr, k.adr_gr, k.e_mandant, k.benutzer_id,
	k.pool_typ, k.status, k.kurz_bez, k.bez, k.gueltig_ab, k.gueltig_bis,
	b.teil_pool_nr, rtrim(g.benutzer_id), rtrim(p.kurz_bez), rtrim(p.beschreibung)
from ADRPBEN b, ADRPTP p, ADRPKOPF k, BENGRPZU g
where b.adr_pool_nr  = p.adr_pool_nr
and	b.teil_pool_nr = p.teil_pool_nr
and	b.adr_pool_nr  = k.adr_pool_nr
and     b.bengrp_id    = g.bengrp_id
and     b.benutzer_id  = '000000';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ADRPVIEW" ("ADR_POOL_NR", "BENUTZER_ID", "POOL_TYP", "E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "A_TYP", "QUELLE_NR", "STATUS", "TEIL_POOL_NR", "HAUPT_NAME", "LAND_CODE", "HAUPT_ORT", "HAUPT_PLZ", "MEDIUM", "NAME1", "NAME2", "STRASSE", "KZ_LOESCHEN", "NACHNAME", "VORNAME", "TITEL_CODE", "ANREDE_CODE", "ERFASSER_ID", "DATUM_AKT", "LFD_NR_BERICHT", "BEZIRK_ID") AS
  select
	a.adr_pool_nr, a.benutzer_id, a.pool_typ,
	k.e_mandant,
	a.adr_gr, a.adr_nr, a.person_nr, a.a_typ,
	a.quelle_nr, a.status, a.teil_pool_nr,
	b.haupt_name, b.land_code, b.haupt_ort, b.haupt_plz, c.medium,
	b.name1, b.name2, b.strasse,
	p.kz_loeschen, p.nachname, p.vorname, p.titel_code, p.anrede_code,
	a.erfasser_id, a.datum_akt, a.lfd_nr_bericht, b.bezirk_id
from    adrpool a LEFT OUTER JOIN adrptp c  ON
        a.adr_pool_nr = c.adr_pool_nr and a.teil_pool_nr = c.teil_pool_nr
                  LEFT OUTER JOIN adrpkopf k ON
        a.adr_pool_nr = k.adr_pool_nr,
        anschr b, person p
        where a.adr_gr = b.adr_gr
	and a.adr_nr = b.adr_nr
	and p.adr_gr = a.adr_gr
	and p.adr_nr = a.adr_nr
	and p.person_nr = a.person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."AELVIEW" ("JOBNR", "ADR_GR", "ADR_NR", "AUFT_NR", "AUFT_HIST_NR", "DISPO_NR", "DISPO_HIST_NR", "VORGANG_TYP", "KZ_VERARB", "OBJ_NR", "AUSG", "HNR_NUM", "ANZART_ID", "GRUPPEN_NR", "ANZ_SI", "ANZ_SCHALTUNG", "DRUCK_ID", "FARB_ID", "FORMAT_ID", "E_MANDANT", "ADR_NR_WA", "HAUPT_NAME", "F_TYP_NR", "KZ_BEST", "AKTION", "VERTRETER_ID", "ANZ_SEITEN", "ANZ_GRAMM") AS
  select r.jobnr, r.adr_gr, r.adr_nr, r.auft_nr, r.auft_hist_nr, r.dispo_nr, r.dispo_hist_nr,
       r.vorgang_typ, r.kz_verarb, d.obj_nr, d.ausg, r.hnr_num, d.anzart_id,
       r.gruppen_nr, d.anz_si, d.anz_schaltung, d.druck_id, d.farb_id, d.format_id,
       d.e_mandant, a.adr_nr_wa, h.haupt_name, v.f_typ_nr, d.kz_best, d.aktion,
       v.vertreter_id, d.anz_seiten, d.anz_gramm
from   rechbuch r, dispo d, auftrag a, anschr h, advert v
where  r.adr_gr = d.adr_gr and r.adr_nr = d.adr_nr and r.auft_nr = d.auft_nr and
       r.auft_hist_nr = d.auft_hist_nr and r.dispo_nr = d.dispo_nr and
       r.dispo_hist_nr = d.dispo_hist_nr and
       r.adr_gr = a.adr_gr and r.adr_nr = a.adr_nr and r.auft_nr = a.auft_nr and
       r.auft_hist_nr = a.auft_hist_nr and
       r.adr_gr = h.adr_gr and r.adr_nr = h.adr_nr and
       r.adr_gr = v.adr_gr and r.adr_nr = v.adr_nr and r.auft_nr = v.auft_nr and
       r.auft_hist_nr = v.auft_hist_nr and (v.f_typ_nr='WT1' or v.f_typ_nr='WT2');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."AENDVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "DATUM") AS
  select p1.adr_gr, p1.adr_nr, p1.person_nr ,
max(GREATEST(nvl(p1.modified_on, '01.01.1900'),
nvl(p2.modified_on, '01.01.1900'),
nvl(a.modified_on, '01.01.1900'),
nvl(abo.modified_on, '01.01.1900'),
nvl(b.rech_dat, '01.01.1900'),
nvl(w1.datum_von, '01.01.1900'),
nvl(w2.datum_bis, '01.01.1900'),
nvl(i1.abosperr_von, '01.01.1900'),
nvl(i2.abosperr_bis, '01.01.1900')))
from person p1, person p2, anschr a, abostamm abo, bufakst b,
personws w1, personws w2, ainfo i1, ainfo i2
where p1.adr_gr = p2.adr_gr
and p1.adr_nr = p2.adr_nr
and p2.person_nr = 0
and a.adr_gr(+) = p1.adr_gr
and a.adr_nr(+) = p1.adr_nr
and abo.adr_gr(+) = p1.adr_gr
and abo.adr_nr(+) = p1.adr_nr
and abo.person_nr(+) = p1.person_nr
and b.adr_gr(+) = p1.adr_gr
and b.adr_nr_e(+) = p1.adr_nr
and b.person_nr_e(+) = p1.person_nr
and w1.adr_gr(+) = p1.adr_gr
and w1.adr_nr(+) = p1.adr_nr
and w1.person_nr(+) = p1.person_nr
and w1.datum_von(+) <= sysdate
and w2.adr_gr(+) = p1.adr_gr
and w2.adr_nr(+) = p1.adr_nr
and w2.person_nr(+) = p1.person_nr
and w2.datum_bis(+) < sysdate
and i1.adr_gr(+) = p1.adr_gr
and i1.adr_nr(+) = p1.adr_nr
and i1.abosperr_von(+) <= sysdate
and i2.adr_gr(+) = p1.adr_gr
and i2.adr_nr(+) = p1.adr_nr
and i2.abosperr_bis(+) < sysdate
group by p1.adr_gr, p1.adr_nr, p1.person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."AFILLVIEW" ("RESSOURCE", "FILTER_1", "FILTER_2", "FILTER_3", "FILTER_4", "FILTER_5", "FILTER_6", "WERT_1", "WERT_2", "WERT_3", "WERT_4", "PRIO", "PRIO_DATUM", "PRIO_FLAG") AS
  select
        'DUMMY                         ',
        'DUMMY                                             ',
        'DUMMY                                             ',
        'DUMMY                                             ',
        'DUMMY                                             ',
        'DUMMY                                             ',
        'DUMMY                         DUMMY                         DUMMY                                   ',
        '                                                                                                                                                                                                                                                                                                                                                                                                                ',
        '                                                                                                                                                                                                                                                                                                                                                                                                                ',
        '                                                                                                                                                                                                                                                                                                                                                                                                                ',
        '                                                                                                                                                                                                                                                                                                                                                                                                                ',
        999999999, null,
        'DUMMY                         '
from    SYKUNDE                ------ Dummy-Eintrag fur varchar2
        where kunde='NoRow'
union                          ------ STRASSE nur Land='D','A','CH' und STRASSEPLZ mit Land und und PLZ (s.u.)
select  distinct
	'STRASSE', 'DE', ' ', upper(STRADA.str_name46), ' ', ' ', ' ',
         STRADA.str_name46, null, null, '  ',
        C4LISTPRIO.ANZAHL, STRADA.datum_man, '  '
from    STRADA,C4LISTPRIO   where
        upper(substr(STRADA.str_name46,1,40)) = C4LISTPRIO.val_1 and  C4LISTPRIO.tabelle='STRADA' and  C4LISTPRIO.key_1='STRASSE'
union
select  distinct
	'STRASSE', 'DE', ' ', upper(STRADA.str_name46), ' ', ' ', ' ',
        STRADA.str_name46, null, null, '  ',
        1,  --!!!
	STRADA.datum_man, '  '
from    STRADA
where   not exists (select tabelle from C4LISTPRIO
                    where upper(substr(STRADA.str_name46,1,40))  =  C4LISTPRIO.val_1 and  C4LISTPRIO.tabelle='STRADA' and C4LISTPRIO.key_1='STRASSE')
union                          ----------------------------- ...... und STRASSEPLZ mit Land und und PLZ
select  distinct
	'STRASSEPLZ', 'DE', STRADA.str_plz, upper(STRADA.str_name46), ' ', upper(plz_oname), STRADA.str_alort,
        STRADA.str_name46, rtrim(STRADA.str_name46), STRADA.str_plz, ' ',
        C4LISTPRIO.ANZAHL, STRADA.datum_man, '  '
from    STRADA, PLZDA, C4LISTPRIO
where   STRADA.str_alort=PLZDA.plz_alort  and PLZ_ART_AW = 'W' and str_plz = plz_plz
        and upper(substr(STRADA.str_name46,1,40)) = C4LISTPRIO.val_1 and  C4LISTPRIO.tabelle='STRADA' and  C4LISTPRIO.key_1='STRASSE'
union
select  distinct
	'STRASSEPLZ', 'DE', STRADA.str_plz, upper(STRADA.str_name46), ' ', upper(plz_oname), STRADA.str_alort,
        STRADA.str_name46, rtrim(STRADA.str_name46), STRADA.str_plz, ' ',
        1,  --!!!
	STRADA.datum_man, '  '
from    STRADA, PLZDA
where   STRADA.str_alort=PLZDA.plz_alort  and PLZ_ART_AW = 'W' and str_plz = plz_plz
        and not exists (select tabelle from C4LISTPRIO where
                        upper(substr(STRADA.str_name46,1,40))  =  C4LISTPRIO.val_1 and  C4LISTPRIO.tabelle='STRADA' and C4LISTPRIO.key_1='STRASSE')
union
select  distinct           ----------------------------------------------------------------  PLZ mit ORT
	'PLZORT', 'DE', PLZDA.plz_plz,   upper(plz_oname), PLZ_ART_AW, PLZ_ART_AP, ' ',  -->ART_AW='W'ohnort  + ART_AP='P'ostfach sowie'G'Kunde
        rtrim(PLZDA.plz_plz), rtrim(PLZDA.plz_oname), rtrim(PLZDA.plz_ozusatz), ' ',
        (select count(*) from PLZDA p where substr(p.plz_plz,1,2)=substr(PLZDA.plz_plz,1,2) and p.plz_oname=PLZDA.plz_oname group by plz_oname),
        null, null
from    PLZDA
where   PLZ_ART_AW <> 'A'   	-- alte, ausgemusterte PLZ
union
select  distinct
	'PLZORT', 'CH', STRACH.plz,    upper(ort), 'W', 'OFF!', ' ',  -->ART_AW='W'ohnort + ART_AP='P'ostfach sowie'G'Kunde
        rtrim(STRACH.plz), rtrim(STRACH.ort), ' ', ' ',
        (select count(*) from STRACH p where substr(p.plz,1,2)=substr(STRACH.plz,1,2) and p.ort=STRACH.ort group by ort),
        null, null
from    STRACH
union
select  distinct
	'PLZORT', 'AT', STRAAT.plz,    upper(ort), 'W', 'OFF!', ' ',  -->ART_AW='W'ohnort + ART_AP='P'ostfach sowie'G'Kunde
        rtrim(STRAAT.plz), rtrim(STRAAT.ort), rtrim(STRAAT.ortsteil), ' ',
        (select count(*) from STRAAT p where substr(p.plz,1,2)=substr(STRAAT.plz,1,2) and p.ort=STRAAT.ort group by ort),
        null, null
from    STRAAT;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ANCUVIEW" ("ANC_NR", "VERSION_ID", "ADR_GR", "ADR_NR", "PERSON_NR", "LFD_NR", "E_MANDANT", "ANGEBOT_ID", "BEZEICHNUNG", "GUELTIG_AB", "GUELTIG_BIS", "JAHR", "VERFASSER_ID", "ERFASSER_ID", "PRUEFER_ID", "DAT_P_NEU", "DAT_P_AEND", "STATUS", "KONZERN_ID", "KONZERN_ID_WA", "KZ_VORLAGE", "F_TYP", "BER_ERFASSER_ID", "BER_DATUM_AKT", "BER_LFD_NR", "MODUS", "ADR_NR_STAMM", "PERSON_NR_STAMM", "OBJ_NR_PAKET", "GRP_ID", "B_ID_GRP", "DATUM_AEND", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "BEZIRK_ID", "OBJ_NR", "AUSG", "ANZART_ID", "ANC_TYP", "RABATT_TYP") AS
  SELECT s.anc_nr, s.version_id, s.adr_gr, w.adr_nr, w.person_nr, o.lfd_nr,
       s.e_mandant, s.angebot_id, s.bezeichnung, s.gueltig_ab, s.gueltig_bis,
       s.jahr, s.verfasser_id, s.erfasser_id, s.pruefer_id, s.dat_p_neu, s.dat_p_aend,
       s.status, s.konzern_id, s.konzern_id_wa, s.kz_vorlage, w.f_typ,
       s.ber_erfasser_id, s.ber_datum_akt, s.ber_lfd_nr, s.modus,
       s.adr_nr, s.person_nr, s.obj_nr, s.grp_id, s.b_id_grp, s.datum_aend,
       a.haupt_name, a.haupt_plz, a.haupt_ort, a.bezirk_id,
       o.obj_nr, o.ausg, o.anzart_id, o.anc_typ, o.rabatt_typ
FROM   ancstamm s, ancobj o, ancwtwa w, anschr a
WHERE  s.anc_nr = o.anc_nr
AND    s.version_id = o.version_id
AND    s.adr_gr = o.adr_gr
AND    s.anc_nr = w.anc_nr
AND    s.version_id = w.version_id
AND    s.adr_gr = w.adr_gr
AND    w.adr_gr = a.adr_gr
AND    w.adr_nr = a.adr_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ANCVIEW" ("ANC_NR", "VERSION_ID", "ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "ANGEBOT_ID", "BEZEICHNUNG", "GUELTIG_AB", "GUELTIG_BIS", "JAHR", "VERFASSER_ID", "ERFASSER_ID", "PRUEFER_ID", "DAT_P_NEU", "DAT_P_AEND", "STATUS", "KONZERN_ID", "KONZERN_ID_WA", "KZ_VORLAGE", "F_TYP", "BER_ERFASSER_ID", "BER_DATUM_AKT", "BER_LFD_NR", "MODUS") AS
  SELECT s.anc_nr, s.version_id, s.adr_gr, w.adr_nr, w.person_nr,
       s.e_mandant, s.angebot_id, s.bezeichnung, s.gueltig_ab, s.gueltig_bis,
       s.jahr, s.verfasser_id, s.erfasser_id, s.pruefer_id, s.dat_p_neu, s.dat_p_aend,
       s.status, s.konzern_id, s.konzern_id_wa, s.kz_vorlage, w.f_typ,
       s.ber_erfasser_id, s.ber_datum_akt, s.ber_lfd_nr, s.modus
FROM   ancstamm s, ancwtwa w
WHERE s.anc_nr = w.anc_nr
AND      s.version_id = w.version_id
AND      s.adr_gr = w.adr_gr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ANPRVIEW" ("ANZART_ID", "BESCHREIBUNG", "VERW_ID", "E_MANDANT", "OBJ_NR", "AUSG", "JAHR", "HNR", "WAEHRUNG") AS
  select distinct a.anzart_id, a.beschreibung, a.verw_id,
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preisefa p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id,
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preisemm p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id,
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preiseonl p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id,
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preisesi p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id,
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preisete p where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.beschreibung, a.verw_id,
        p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr, p.waehrung
        from anzart a, preisezl p where a.anzart_id=p.anzart_id;


