select distinct a.anzart_id, a.anzgrp_id, a.beschreibung, a.verw_id, a.kz_rabatt,
        p.e_mandant, p.obj_nr, p.ausg, a.kz_pr_staff, a.verwend_ga, p.plazierungs_id, p.waehrung from anzart a, preiseonl p
       where a.anzart_id=p.anzart_id
