select distinct a.anzart_id, a.anzgrp_id, a.beschreibung, a.verw_id, a.kz_rabatt,
        p.e_mandant, p.obj_nr, p.ausg, a.kz_pr_staff, a.verwend_ga, '        ', '   ' from anzart a, preisesi p
       where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.anzgrp_id, a.beschreibung, a.verw_id, a.kz_rabatt,
        p.e_mandant, p.obj_nr, p.ausg, a.kz_pr_staff, a.verwend_ga, '        ', '   ' from anzart a, preisete p
       where a.anzart_id=p.anzart_id
union
select distinct a.anzart_id, a.anzgrp_id, a.beschreibung, a.verw_id, a.kz_rabatt,
        p.e_mandant, p.obj_nr, p.ausg, a.kz_pr_staff, a.verwend_ga, '        ', '   ' from anzart a, preisezl p
       where a.anzart_id=p.anzart_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ARTIKELNRVIEW" ("E_MANDANT", "L_AUSG_NR", "ARTIKEL_NR", "N_ARTIKEL_NR") AS
  select
e_mandant, l_ausg_nr, artikel_nr,
nvl(to_number(translate(artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),0)
from bumanaus;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ATRVIEW" ("ADR_GR", "ADR_NR", "KONZERN_ID", "KONZERN_NAME", "HAUPT_NAME", "NAME1", "NAME2", "NAME3", "LAND_CODE", "PLZ", "ORT", "NACHNAME", "VORNAME", "PERSON_NR", "ATR_AUFT_NR", "STATUS", "ATR_JAHR", "ADR_NR_KONZERN") AS
  SELECT
      a.adr_gr, a.adr_nr, a.konzern_id, k.syn, a.haupt_name,
      a.name1, a.name2, a.name3,
      a.land_code, a.haupt_plz, a.haupt_ort,
      p.nachname, p.vorname, p.person_nr,
      atr.atr_auftr_nr, atr.status, atr_jahr, k.adr_nr
FROM
      anschr a
        LEFT OUTER JOIN atrauft atr ON
                           atr.adr_gr        = a.adr_gr      and
                           atr.adr_nr        = a.adr_nr
        LEFT OUTER JOIN person p ON
                           atr.adr_gr        = p.adr_gr      and
                           atr.adr_nr        = p.adr_nr      and
                           atr.person_nr     = p.person_nr
        LEFT OUTER JOIN konzern k ON
                           a.konzern_id      = k.konzern_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."AUFTVIEW" ("ADR_GR", "ADR_NR", "AUFT_NR", "VOLUMEN_FA", "VOLUMEN_MM", "ANZ_SI", "ANZ_DISPOS", "STATUS", "ANZ_SEITEN", "ANZ_GRAMM", "NETTO_BETRAG") AS
  select adr_gr, adr_nr, auft_nr,
          sum(volumen_fa), sum(volumen_mm), sum(anz_si), sum(anz_anzeigen), min(status),
          sum(anz_seiten),sum(anz_gramm),sum(netto_betrag)
from   dispo
where  auft_hist_nr = 0 and dispo_hist_nr = 0 and
           (status<>'L' and status<>'S' and status<>'O')
group by adr_gr, adr_nr,auft_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."AWAAVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "ABO_NR", "AKT_ID", "UAKT_ID", "PREIS_KAT", "BER_MENGE", "ADR_NR_RE", "PERSON_NR_RE", "VBEG_DAT", "VEND_DAT", "VBEG_HEFT", "VEND_HEFT", "VBEG_JAHR", "VEND_JAHR", "LANDART", "PREIS_KAT_NO", "K_GRUND", "BEST_DAT_ABO", "BESTELLG_ABO", "VERTRETER_ID", "ABO_KOND", "PROV_STATUS", "KZ_PROV_SCHNORRER", "PROV_MENGE", "KGS", "LAND_CODE", "HAUPT_PLZ", "PLZ_WOHN", "PLZ_POST", "PLZ_GK", "PROV_KOND", "PROV_STD_AKTION", "KZ_ABW_PROV", "KZ_PROV_GENEHM", "DATUM_NEU_ABO", "DATUM_AEND_ABO", "NO_ENDE_DAT", "NO_ENDE_JAHR", "NO_ENDE_HNR", "K_DATUM", "KZ_INAKTIV_PROV") AS
  SELECT 	a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr,
        a.w_akt_id, a.w_uakt_id, a.preis_kat, a.ber_menge, a.adr_nr_bv, a.person_nr_bv,
		a.vbeg_dat, a.vend_dat, a.vbeg_heft, a.vend_heft, a.vbeg_jahr, a.vend_jahr,
		a.inaus, a.preis_kat_no, a.k_grund, a.best_datum, a.bestellg,
		w.vertreter_id, w.abo_kond, w.prov_status, w.kz_prov_schnorrer, prov_menge,
		i.kgs,
		r.land_code, r.haupt_plz, r.plz_wohn, r.plz_post, r.plz_gk,
		m.prov_kond, m.prov_std_aktion, m.kz_abw_prov, m.kz_prov_genehm,
		a.datum_neu, a.datum_aend, a.no_ende_dat, a.no_ende_jahr, a.no_ende_hnr, a.k_datum,
		w.kz_inaktiv_prov
FROM   	anschr r,
        abostamm a LEFT OUTER JOIN ainfo i ON
		           a.adr_gr=i.adr_gr and
		           a.adr_nr=i.adr_nr
		           LEFT OUTER JOIN werbepr w ON
		           a.adr_gr=w.adr_gr and
		           a.adr_nr=w.adr_nr and
		           a.person_nr=w.person_nr and
		           a.e_mandant=w.e_mandant and
		           a.obj_nr=w.obj_nr and
		           a.ausg=w.ausg and
	               a.abo_nr=w.abo_nr
				   LEFT OUTER JOIN mhaktion m ON
		           a.e_mandant = m.e_mandant and
		           a.w_akt_id  = m.akt_id
WHERE	a.adr_gr=r.adr_gr and
		a.adr_nr=r.adr_nr and
		a.datum_neu >= '01.04.2011' and
		w.vertreter_id is null and
		((w.prov_status='P') OR (w.prov_status='K') OR (w.prov_status='Z') OR (w.prov_status is NULL));


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BBERVIEW" ("ERFASSER_ID", "DATUM_AKT", "ZEIT_AKT", "ADR_GR", "ADR_NR", "PERSON_NR", "VERFASSER_ID", "ADR_NR_WA", "PERSON_NR_WA", "LFD_NR", "PRODUKT_ID", "PRODUKT", "BETREFF", "DATUM_BES", "G_ART", "DATUM_LOE", "KZ_SPERR", "N_ART", "VORNAME", "NACHNAME") AS
