;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BENMANVI" ("E_MANDANT", "E_ANW", "ADR_GR", "BKLASSE", "BENUTZER_ID", "ALIAS_NAME", "BEREICH") AS
  select
ma.e_mandant, ma.e_anw, ab.adr_gr, ab.bklasse, be.benutzer_id, be.alias_name, an.bereich
from manan ma, adrber ab, benutzer be, anwend an
where
ma.adr_gr = ab.adr_gr and
ab.bklasse = be.bklasse and
an.e_anw = ma.e_anw and
(not exists (select * from manben mb where mb.benutzer_id = be.benutzer_id) or
exists (select * from manben mb where mb.benutzer_id = be.benutzer_id and mb.e_mandant = ma.e_mandant));


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BERITBVI" ("BENUTZER_ID", "TBAU_ID", "VERWEND_TYP", "BEZ", "TEXT_NR", "KONTO_ID", "TEXT") AS
  select
a.benutzer_id, a.tbau_id, a.verwend_typ, a.bez, a.text_nr, a.konto_id, to_char(substr(b.text,1,400))
