where a.text_nr=b.text_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BLMAVIEW" ("ADR_GR", "ADR_NR", "HAUPT_NAME", "ADR_NR_BV", "LAND_CODE", "INAUS", "HAUPT_PLZ", "HAUPT_ORT", "STRASSE", "HAUSNR", "HAUSNR_ZUS", "POSTFACH", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "ABO_NR", "BER_MENGE", "VBEG_DAT", "VBEG_JAHR", "VBEG_HEFT", "VEND_DAT", "VEND_JAHR", "VEND_HEFT", "PREIS_KAT", "WAEHRUNG", "R_ART", "R_BEG_DAT", "R_BEG_JAHR", "R_BEG_HNR", "R_ENDE_DAT", "R_ENDE_JAHR", "R_ENDE_HNR", "ABOSTATUS", "PERSON_NR_BV", "EXTERNE_NR", "EINDRUCK_NR", "KZ_EINDRUCK", "L_MENGE", "JAHR", "HNR", "DATUM", "RZ_KAT_WMITTEL", "RZ_KAT_PORTO", "RZ_KAT_EINDRUCK", "RZ_KAT_EMAIL", "ZU_BETRAG_P", "ZU_BETRAG_W", "ZU_BETRAG_E", "ZU_BETRAG_M", "A_TYP", "FAKT_ZR", "EINDRUCK_ART", "KZ_AKTIV", "AEND_ART", "B_ID_AEND", "DATUM_AEND", "KZ_GEDRUCKT", "DATUM_GEDRUCKT", "KZ_STORNO", "RZ_KAT_GEBN", "RZ_KAT_GEBUE", "ZU_BETRAG_GEBN", "ZU_BETRAG_GEBUE") AS
  select a.adr_gr, a.adr_nr, a.haupt_name, b.adr_nr_bv, a.land_code,
       b.inaus,  a.haupt_plz, a.haupt_ort, a.strasse,
       a.hausnr, a.hausnr_zus, a.postfach,
       b.person_nr, b.e_mandant,
       b.obj_nr, b.ausg, b.abo_nr,
       h.ber_menge,
       b.vbeg_dat, b.vbeg_jahr,
       b.vbeg_heft, b.vend_dat, b.vend_jahr, b.vend_heft,
       h.preis_kat,
       b.waehrung, b.r_art,
       b.r_beg_dat, b.r_beg_jahr, b.r_beg_hnr, b.r_ende_dat,
       b.r_ende_jahr, b.r_ende_hnr,
       b.abostatus,
       b.person_nr_bv,
       r.externe_nr,
       h.EINDRUCK_NR, h.EINDRUCK_art,
       h.L_MENGE,h.jahr,h.hnr,h.datum,
       h.RZ_KAT_WMITTEL,h.RZ_KAT_PORTO,h.RZ_KAT_EINDRUCK,h.RZ_KAT_EMAIL,
       h.ZU_BETRAG_P,h.ZU_BETRAG_W,h.ZU_BETRAG_E,h.ZU_BETRAG_M, p.A_TYP, b.FAKT_ZR,h.EINDRUCK_ART,h.KZ_AKTIV,h.AEND_ART,
       h.B_ID_AEND,h.DATUM_AEND,h.KZ_GEDRUCKT,h.DATUM_GEDRUCKT,b.KZ_STORNO,
       h.RZ_KAT_GEBN,h.RZ_KAT_GEBUE,h.ZU_BETRAG_GEBN,h.ZU_BETRAG_GEBUE
from abostamm b, person p, anschr a, aboref r, blmabohi h
where b.adr_gr     = a.adr_gr
   and b.adr_nr    = a.adr_nr
   and b.adr_gr    = p.adr_gr
   and b.adr_nr    = p.adr_nr
   and b.person_nr = p.person_nr
   and b.adr_gr    = h.adr_gr
   and b.adr_nr    = h.adr_nr
   and b.e_mandant = h.e_mandant
   and b.person_nr = h.person_nr
   and b.obj_nr    = h.obj_nr
   and b.ausg      = h.ausg
   and b.abo_nr    = h.abo_nr
   and b.e_mandant = r.e_mandant(+)
   and b.adr_gr    = r.adr_gr(+)
   and b.adr_nr    = r.adr_nr(+)
   and b.person_nr = r.person_nr(+)
   and b.obj_nr    = r.obj_nr(+)
   and b.ausg      = r.ausg(+)
   and b.abo_nr    = r.abo_nr(+)
   and r.anw_ref_nr(+) = 'EX';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BONVIEW" ("BON_AUFTR_NR", "BESCHREIBUNG", "BDATUM", "STATUS", "PERSON_NR", "ADR_GR", "ADR_NR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "NACHNAME", "VORNAME", "E_MANDANT") AS
