  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BQNVIEW" ("ADR_GR", "ADR_NR", "AUFT_NR", "ANZ_ZEILEN", "ANZ_MM", "ANZ_TEXT", "ANZ_STICHWORT") AS
  select adr_gr, adr_nr, auft_nr,
