  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BROBVIEW" ("ERFASSER_ID", "DATUM_AKT", "LFD_NR", "E_MANDANT", "OBJ_NR", "ZEIT_AKT", "ADR_GR", "ADR_NR", "PERSON_NR", "VERFASSER_ID", "ADR_NR_WA", "PERSON_NR_WA", "PRODUKT_ID", "BETREFF", "DATUM_BES", "G_ART", "DATUM_LOE", "KZ_SPERR", "N_ART", "VERTEILER", "VORNAME", "NACHNAME", "TEXT_NR", "DATUM_WV_VERF", "BEBEW_ID", "LFD_NR_ANSCHR", "VERWEND_TYP", "BEWERT_ID", "TEXT_NR_HIST", "TEXT_NR_KURZ") AS
