  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BSUMVIEW" ("AUFT_NR", "ANZ_POS", "BER_MENGE", "FREI_MENGE", "PREISKAT", "VERS_IST_DAT", "L_AUSG_NR") AS
  select  s.auft_nr, count(*), sum(s.ber_menge), sum(s.frei_menge),
	min(s.preiskat), min(s.vers_ist_dat), min(s.l_ausg_nr)
from    buaufpos s, buausgab b
where s.l_ausg_nr > 0 and
      s.l_ausg_nr = b.l_ausg_nr and
      (b.prod_typ != 'EIND' and b.prod_typ != 'KART' and b.prod_typ != 'MOPL' and b.prod_typ != 'PLAK' and
       b.prod_typ != 'ZT' and b.prod_typ != 'MIK' and b.prod_typ != 'WERB')
group by auft_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUAAVIEW" ("E_MANDANT", "AUFT_NR", "AUF_POS", "BEST_DATUM", "L_VERS_DAT", "FAKT_SOLL_DAT", "AKT_ID", "UAKT_ID", "STAORD_NR", "L_AUSG_NR", "ARTIKEL_NR", "ISBN", "SO_POS_ID", "STATUS", "AUFTRAG_TYP", "RECH_NR", "RECH_DAT", "AUFTRAG_VERW", "POS_STATUS", "BER_MENGE", "FREI_MENGE", "RETOUR_MENGE", "L_AUFL_NR", "HERKUNFT", "POS_BETRAG", "P_STATUS_LIEF", "F_MANDANT", "RECH_TYP", "R_ART", "RECH_REF", "VERS_SOLL_DAT", "RE_BRUTTO", "RE_MWST", "RE_NETTO") AS
  select s.e_mandant, s.auft_nr, s.auf_pos,
       a.best_datum, a.l_vers_dat, a.fakt_soll_dat, a.akt_id, a.uakt_id,
       a.staord_nr, s.l_ausg_nr, m.artikel_nr, b.isbn, o.so_pos_id, a.status, a.auftrag_typ,
       f.rech_nr, f.rech_dat, a.auftrag_verw, s.status, s.ber_menge, s.frei_menge, s.retour_menge,
       s.l_aufl_nr, a.herkunft, s.pos_betrag, f.p_status_lief,
       t.f_mandant, t.rech_typ, t.r_art, t.rech_ref, a.vers_soll_dat,
       t.re_brutto, t.re_mwst, t.re_netto
  from buaufpos s, buauftra a, bumanaus m, buausgab b, busopos o, bufakupo f, bufakst t
 where a.auft_nr = s.auft_nr and
            b.l_ausg_nr(+)  = s.l_ausg_nr and
            m.e_mandant(+) = s.e_mandant and
            m.l_ausg_nr(+)  = s.l_ausg_nr and
            o.so_pos_id(+)  = s.so_pos_id and
            f.auft_nr (+) = s.auft_nr and
            f.auf_pos (+) = s.auf_pos and
            t.rech_nr (+) = f.rech_nr and
            t.rech_dat (+) = f.rech_dat and
            t.f_mandant (+) = f.f_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUABOVIE" ("ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "ABO_NR", "ADR_NR_BV", "PERSON_NR_BV", "ABOSTATUS", "VBEG_DAT", "LIST_NR", "BU_RA") AS
  select a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, a.adr_nr_bv, a.person_nr_bv,
       a.abostatus, k.versand_soll, NULL, p.bu_ra
from abostamm a, mobjtyp m, burabobj b, kalender k, burabatt p, preiskat v
where a.e_mandant  = m.e_mandant and
      a.obj_nr     = m.obj_nr and
      m.kz_abrech  = 'H' and
      a.preis_kat  = v.preis_kat and
      v.berechnen != 'N' and
      a.e_mandant  = k.e_mandant and
      a.obj_nr     = k.obj_nr and
      a.ausg       = k.ausg and
      a.vbeg_heft  = k.hnr and
      a.vbeg_jahr  = k.jahr and
      b.bu_ra      = p.bu_ra and
      a.e_mandant  = b.e_mandant and
      ((a.obj_nr   = b.obj_nr) or
      (b.obj_nr    = '0'))
union
select a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, a.adr_nr_bv, a.person_nr_bv,
       a.abostatus, a.vbeg_dat, NULL, p.bu_ra
from abostamm a, mobjtyp m, burabobj b, burabatt p, preiskat v
where a.e_mandant  = m.e_mandant and
      a.obj_nr     = m.obj_nr and
      m.kz_abrech  = 'Z' and
      a.preis_kat  = v.preis_kat and
      v.berechnen != 'N' and
      b.bu_ra      = p.bu_ra and
      a.e_mandant  = b.e_mandant and
      ((a.obj_nr   = b.obj_nr) or
      (b.obj_nr    = '0'))
union
select a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, a.adr_nr_bv, a.person_nr_bv,
       a.abostatus, a.vbeg_dat, p.list_nr, '      '
from abostamm a, mobjtyp m, bupreobj b, buplist p, preiskat v
where a.e_mandant  = m.e_mandant and
      a.obj_nr     = m.obj_nr and
      m.kz_abrech  = 'Z' and
      a.preis_kat  = v.preis_kat and
      v.berechnen != 'N' and
      b.list_nr    = p.list_nr and
      a.e_mandant  = b.e_mandant and
      ((a.obj_nr   = b.obj_nr) or
      (b.obj_nr    = '0'))
union
select a.adr_gr, a.adr_nr, a.person_nr, a.e_mandant, a.obj_nr, a.ausg, a.abo_nr, a.adr_nr_bv, a.person_nr_bv,
       a.abostatus, k.versand_soll, p.list_nr, '      '
from abostamm a, mobjtyp m, bupreobj b, kalender k, buplist p, preiskat v
where a.e_mandant  = m.e_mandant and
      a.obj_nr     = m.obj_nr and
      m.kz_abrech  = 'H' and
      a.preis_kat  = v.preis_kat and
      v.berechnen != 'N' and
      a.e_mandant  = k.e_mandant and
      a.obj_nr     = k.obj_nr and
      a.ausg       = k.ausg and
      a.vbeg_heft  = k.hnr and
      a.vbeg_jahr  = k.jahr and
      b.list_nr    = p.list_nr and
