  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUABSVI1" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "N_ARTIKEL_NR", "PROD_TYP", "KZ_BOD", "FORMAT", "SUM_MENGE") AS
  select a.e_mandant, a.l_ausg_nr, a.l_aufl_nr, a.artikel_nr, a.n_artikel_nr, b.prod_typ, b.kz_bod, h.format, sum(sum_ber_menge+sum_frei_ber- sum_gut_menge-
sum_frei_gut)
from absatzview a,
     buausgab b LEFT OUTER JOIN buherste h on
          b.l_ausg_nr = h.l_ausg_nr
where a.l_ausg_nr=b.l_ausg_nr and
      a.rech_dat>=add_months(sysdate,-36)
group by a.e_mandant, a.l_ausg_nr, a.l_aufl_nr, a.artikel_nr, a.n_artikel_nr, b.prod_typ, b.kz_bod, h.format;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUAKVIEW" ("LIST_NR", "E_MANDANT", "L_AUSG_NR", "BEST_ART", "M_PREIS_GRP", "WAEHRUNG", "GUELTIG_AB", "AKT_ID", "SUBS_DAT1", "PREISKAT", "KZ_UEBER", "L_AUFL_NR", "BERECHNEN", "KZ_KUGRU", "PRIORITAET") AS
  select l.list_nr, m.e_mandant, m.l_ausg_nr, m.best_art, m.m_preis_grp, l.waehrung,
               l.gueltig_ab, l.akt_id, l.subs_dat1, l.preiskat, p.kz_ueber, m.l_aufl_nr, k.berechnen, k.kz_kugru, k.prioritaet
from  buplist l, bumprzu m, bumprgrp p, buprkat k
where m.m_preis_grp  = l.m_preis_grp and
          m.e_mandant  = l.e_mandant and
          m.best_art = l.best_art and
          m.m_preis_grp  = p.m_preis_grp and
          m.e_mandant  = p.e_mandant and
          l.l_ausg_nr is null and
          l.l_aufl_nr is null and
          k.preiskat  = l.preiskat
union
select l.list_nr, l.e_mandant, l.l_ausg_nr, l.best_art, l.m_preis_grp, l.waehrung,
               l.gueltig_ab, l.akt_id, l.subs_dat1, l.preiskat, 'F', l.l_aufl_nr, k.berechnen, k.kz_kugru, k.prioritaet
from  buplist l, buprkat k
where l.m_preis_grp is null and
      l.l_ausg_nr is not null and
      l.l_aufl_nr is not null and
      k.preiskat  = l.preiskat;


