  select a.l_titel_nr, b.l_ausg_nr,  t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id,
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, a.nachname, a.vorname, a.haupt_name,
           b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id
  from  buautor a, butitel t, buausgab b, bumanaus m
 where t.l_titel_nr = a.l_titel_nr and
            b.l_titel_nr (+) = a.l_titel_nr and
            m.l_ausg_nr (+) = b.l_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUARTAUFLVIEW" ("L_AUSG_NR_NEU", "L_AUFL_NR_NEU", "SUM_AUFL_HOEHE") AS
  select
  a.l_ausg_nr_neu, a.l_aufl_nr_neu, sum(l.aufl_hoehe)
from buaufl l, buartikel a where
   (l.l_ausg_nr = a.l_ausg_nr_alt and l.l_aufl_nr = a.l_aufl_nr_alt) and
   exists (select * from buartikel a2 where (l.l_ausg_nr=a2.l_ausg_nr_alt and l.l_aufl_nr=a2.l_aufl_nr_alt)
   or  (l.l_ausg_nr=a2.l_ausg_nr_neu and l.l_aufl_nr=a2.l_aufl_nr_neu))
   group by a.l_ausg_nr_neu, a.l_aufl_nr_neu
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUARTBESVIEW" ("E_MANDANT", "LAGER_CODE", "BEST_ART", "L_AUSG_NR_NEU", "L_AUFL_NR_NEU", "REGAL_ID", "EBENE_ID", "PLATZ_ID", "SUM_MENGE") AS
