  l.e_mandant, l. lager_code, l.best_art, a.l_ausg_nr_neu, a.l_aufl_nr_neu, l.regal_id, l.ebene_id, l.platz_id, sum(l.menge)
from bulagbes l, buartikel a where
   (l.l_ausg_nr = a.l_ausg_nr_alt and l.l_aufl_nr = a.l_aufl_nr_alt) and
   exists (select * from buartikel a2 where (l.l_ausg_nr=a2.l_ausg_nr_alt and l.l_aufl_nr=a2.l_aufl_nr_alt)
   or  (l.l_ausg_nr=a2.l_ausg_nr_neu and l.l_aufl_nr=a2.l_aufl_nr_neu))
   group by l.e_mandant, l. lager_code, l.best_art, a.l_ausg_nr_neu, a.l_aufl_nr_neu, l.regal_id, l.ebene_id, l.platz_id
;


