B.BREITE      ,B.DICKE,B.HOEHE ,B.ANZAHL ,B.REIHEN_CODE,B.BAND_NR  ,B.LAND_CODE ,B.BU_LA_ID    ,B.KOMBITYP     ,
B.E_MANDANT ,B.B_ID_AEND  ,B.AEND_DATUM  ,B.KZ_AUFL_PREIS,B.KZ_EIGEN   ,B.KZ_BESTAND  ,B.EINZEL_FAKT  ,
B.SPERR_GRUND   ,B.KZ_LOESCHEN    ,B.WARN_ID         ,B.BENUTZER_EK      ,B.EK_RAB_GR         ,B.KZ_OFFEN ,
