  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUAUSLAG" ("LAGER_CODE", "KZ_AUSSEN", "L_AUSG_NR", "L_AUFL_NR", "AUFLAGE_NR", "E_MANDANT", "BEST_ART", "ARTIKEL_NR", "LAGER_MANDANT", "L_TITEL_NR", "TITEL_SUCH", "TITEL1", "ISBN", "KZ_BESTAND", "KOMBITYP", "MELD_NR", "SUM_MENGE") AS
