group by jahr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUCRMV_AUFTRAG" ("MODIFIED_ON", "BESTELL_NR_EXTERN", "MANDANT", "AUFTRAG_ID", "AUFTRAG_ID2", "LEISTUNGSEMPFAENGER_ID", "LEISTUNGSEMPFAENGER_NAME", "LEISTUNGSEMPFAENGER_ZH", "LEISTUNGSEMPFAENGER", "LEISTUNGSEMPFAENGER_PNR", "RECHNUNGSEMPFAENGER_ID", "RECHNUNGSEMPFAENGER_NAME", "RECHNUNGSEMPFAENGER_ZH", "RECHNUNGSEMPFAENGER", "RECHNUNGSEMPFAENGER_PNR", "BESTELLER_ID", "BESTELLER_NAME", "BESTELLER_ZH", "BESTELLER", "BESTELLER_PNR", "AUFTRAGSSTATUS", "POSITIONSSTATUS", "BESTELL_DATUM", "ARTIKEL_NR", "ARTIKEL_NAME", "ANZAHL_ARTIKEL_BERECHNET", "ANZAHL_ARTIKEL_FREI", "ANZAHL_ARTIKEL_RETOUR", "AKTIONS_ID", "AKTIONS_BEZEICHNUNG", "WAEHRUNG", "PREIS_LISTE", "PREIS_POSITION_GESAMT", "POSITIONSRABATTCODE", "POSITIONSRABATT", "PREIS_POSITION_ABZGL_RABATT", "AUFTRAGSRABATTCODE", "AUFTRAGSRABATT", "PREIS_NETTO", "PREIS_MWST", "PREIS_BRUTTO", "BRUTTO_NETTO", "ABRECHNUNGSART", "ZAHLUNGSCODE", "ZAHLUNGSART", "FAKTURA_NR", "NOTIZ", "CREATED_DATE", "CREATED_USER", "UPDATE_DATE", "UPDATE_USER") AS
  SELECT BAT.modified_on,	TREF.key_ext_char_3, BAV.E_MANDANT, BAV.AUFT_NR,  ('bu-' || BAV.AUFT_NR || '-' || BAV.AUF_POS),
	(
		CASE
		WHEN (PLE.a_typ = 'F') THEN
			('c-unt-' || PLE.adr_nr)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'M') THEN
			(
				'c-mit-' || PLE.adr_nr || '-' || PLE.person_nr
			)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'P') THEN
			('c-per-' || PLE.adr_nr)
		ELSE
			('c-err-' || PLE.adr_nr)
		END
		END
		END
	),
	TRIM (ALE.name1),
	(
		TRIM (PLE.nachname) || CASE
		WHEN (PLE.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (PLE.vorname)
	),
PLE.adr_nr,
PLE.person_nr,
CASE
WHEN (PRE.adr_nr IS NULL) THEN
	(
		CASE
		WHEN (PLE.a_typ = 'F') THEN
			('c-unt-' || PLE.adr_nr)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'M') THEN
			(
				'c-mit-' || ple.adr_nr || '-' || ple.person_nr
			)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'P') THEN
			('c-per-' || ple.adr_nr)
		ELSE
			('c-err-' || PLE.adr_nr)
		END
		END
		END
	)
ELSE
	(
		CASE
		WHEN (pre.a_typ = 'F') THEN
			('c-unt-' || pre.adr_nr)
		ELSE
			CASE
		WHEN (pre.a_typ = 'M') THEN
			(
				'c-mit-' || pre.adr_nr || '-' || pre.person_nr
			)
		ELSE
			CASE
		WHEN (pre.a_typ = 'P') THEN
			('c-per-' || pre.adr_nr)
		ELSE
			('c-err-' || pre.adr_nr)
		END
		END
		END
	)
END,
 CASE
WHEN (pre.adr_nr IS NULL) THEN
	TRIM (Ale.name1)
ELSE
	TRIM (are.name1)
END,
 CASE
WHEN (pre.adr_nr IS NULL) THEN
	(
		TRIM (Ple.nachname) || CASE
		WHEN (Ple.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (Ple.vorname)
	)
ELSE
	(
		TRIM (pre.nachname) || CASE
		WHEN (Pre.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (pre.vorname)
	)
END,
CASE
WHEN (PRE.adr_nr IS NULL) THEN
  PLE.adr_nr
ELSE
  PRE.adr_nr
END,
CASE
WHEN (PRE.adr_nr IS NULL) THEN
  PLE.person_nr
ELSE
  PRE.person_nr
END,
CASE
WHEN (PBE.adr_nr IS NULL) THEN
	(
		CASE
		WHEN (PLE.a_typ = 'F') THEN
			('c-unt-' || PLE.adr_nr)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'M') THEN
			(
				'c-mit-' || ple.adr_nr || '-' || ple.person_nr
			)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'P') THEN
			('c-per-' || ple.adr_nr)
		ELSE
			('c-err-' || PLE.adr_nr)
		END
		END
		END
	)
ELSE
	(
		CASE
		WHEN (pbe.a_typ = 'F') THEN
			('c-unt-' || pbe.adr_nr)
		ELSE
			CASE
		WHEN (pbe.a_typ = 'M') THEN
			(
				'c-mit-' || pbe.adr_nr || '-' || pbe.person_nr
			)
		ELSE
			CASE
		WHEN (pbe.a_typ = 'P') THEN
			('c-per-' || pbe.adr_nr)
		ELSE
			('c-err-' || pbe.adr_nr)
		END
		END
		END
	)
END,
CASE
WHEN (pbe.adr_nr IS NULL) THEN
	TRIM (Ale.name1)
ELSE
	TRIM (abe.name1)
END,
 CASE
WHEN (pbe.adr_nr IS NULL) THEN
	(
		TRIM (Ple.nachname) || CASE
		WHEN (Ple.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (Ple.vorname)
	)
ELSE
	(
		TRIM (pbe.nachname) || CASE
		WHEN (Pbe.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (pbe.vorname)
	)
END,
CASE
WHEN (PBE.adr_nr IS NULL) THEN
  PLE.adr_nr
ELSE
  PBE.adr_nr
END,
CASE
WHEN (PBE.adr_nr IS NULL) THEN
  PLE.person_nr
ELSE
  PBE.person_nr
END,
BAV.STATUS,
BAV.POS_STATUS,
BAV.BEST_DATUM,
BAV.artikel_nr,
CASE WHEN (bga.l_titel_nr = 0) THEN COALESCE(bus.artikel_bez,bga.ausg_text) ELSE but.titel1 END,
BAV.BER_MENGE,
BAV.FREI_MENGE,
BAV.RETOUR_MENGE,
BAV.AKT_ID,
WA.b_aktid,
BAT.WAEHRUNG,
BAP.EINZEL_PREIS,
BAP.GES_PREIS,
BAP.BU_RA,
BAP.RAB_PROZ,
BAP.POS_BETRAG,
BAT.BU_RA,
BAT.RAB_PROZ,
BAV.RE_NETTO,
BAV.RE_MWST,
BAV.RE_BRUTTO,
BAP.brut_net,
BAT.R_ART,
ZB.Z_BED,
ZB.BESCHREIBUNG,
BAV.RECH_NR,
BAT.AUFTRAG_TEXT,
BAT.DATUM_NEU,
BAT.B_ID_NEU,
BAT.DATUM_AEND,
BAT.B_ID_AEND
FROM
	BUAAVIEW BAV
JOIN BUAUFTRA bat ON (BAT.AUFT_NR = BAV.AUFT_NR AND (BAT.HERKUNFT != 'VA' or BAT.HERKUNFT is null))
JOIN BUAUFPOS bap ON (BAV.AUFT_NR = BAP.AUFT_NR AND BAV.AUF_POS=BAP.AUF_POS)
JOIN ZAHLBED zb ON (
	BAT.Z_BED = ZB.Z_BED
	AND BAT.E_MANDANT = ZB.E_MANDANT
)
JOIN BUAUSGAB bga ON (bga.L_AUSG_NR = bav.L_AUSG_NR)
LEFT JOIN BUTITEL but ON (but.L_TITEL_NR = bga.l_titel_nr)
LEFT JOIN BUAUSSPR bus ON (bus.L_AUSG_NR = bav.L_AUSG_NR and bus.SPRACH_CODE = 'D')
LEFT JOIN mhaktion wa ON (wa.e_mandant = BAV.e_mandant and wa.akt_id = BAV.akt_id)
LEFT JOIN person PLE ON (
	PLE.adr_gr = BAT.adr_gr
	AND PLE.adr_nr = BAT.ADR_NR_le
	AND PLE.person_nr = BAT.person_nr_le
)
LEFT JOIN person PRE ON (
	PRE.adr_gr = BAT.adr_gr
	AND PRE.adr_nr = BAT.ADR_NR_re
	AND PRE.person_nr = BAT.person_nr_re
)
LEFT JOIN person PBE ON (
	PBE.adr_gr = BAT.adr_gr
	AND PBE.adr_nr = BAT.ADR_NR_best
	AND PBE.person_nr = BAT.person_nr_best
)
LEFT JOIN anschr ALE ON (
	ALE.adr_gr = BAT.adr_gr
	AND ALE.adr_nr = BAT.adr_nr_le
)
LEFT JOIN anschr ARE ON (
	ARE.adr_gr = BAT.adr_gr
	AND ARE.adr_nr = BAT.adr_nr_re
)
LEFT JOIN anschr ABE ON (
	ABE.adr_gr = BAT.adr_gr
	AND ABE.adr_nr = BAT.adr_nr_best
)
LEFT JOIN transref TREF ON (
  TREF.transfer_id = 'COVCRM_' || BAT.e_mandant
  AND TREF.kunde = 'FAL'
  AND TREF.bereich = 'BUABO'
  AND TREF.verwend_typ = 'WSVIMP'
  AND TREF.referenz_typ = 'EXT_NR_AUFT_NR'
  AND TREF.key_cov_char_1 is null
	AND TREF.key_cov_char_4 = BAT.auft_nr
)
WHERE (bav.rech_typ like 'R%' and (bav.rech_typ != 'RS' or bav.r_art != 'P' or bav.p_status_lief != 'F') and (bav.rech_typ != 'RO' or bav.r_art != 'P')
    OR bav.rech_typ like 'G%'
    OR (bav.rech_typ like 'L%' and bav.rech_ref is null)
    OR bav.rech_nr is null
    );


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUCRMV_TITEL" ("MODIFIED_ON", "TITEL_ID", "E_MANDANT", "ARTIKEL_NR", "ISBN", "EAN", "ARTIKEL_BEZ", "AUFLAGEN_NR", "AUFLAGEN_BEZ", "MENGE") AS
  select b.modified_on, 'B-' || m.e_mandant || '-' || b.l_ausg_nr || '-' || l.l_aufl_nr, m.e_mandant, m.artikel_nr, b.isbn, b.ean, case when (b.l_titel_nr = 0) then coalesce(s.artikel_bez,b.ausg_text) else t.titel1 end, 0, l.aufl_text,
(select sum(g.ges_menge) - sum(g.anz_reserv) from bulagges g where g.e_mandant = m.e_mandant and g.l_ausg_nr = l.l_ausg_nr and g.l_aufl_nr = l.l_aufl_nr) -
coalesce((select sum(i.min_best) from bulagmin i where i.e_mandant = m.e_mandant and i.l_ausg_nr = l.l_ausg_nr and i.l_aufl_nr = l.l_aufl_nr),0)
from	BUAUSGAB b
	left join BUAUSSPR s on	(s.l_ausg_nr = b.l_ausg_nr and s.sprach_code = 'D')
	left join BUTITEL t on (t.l_titel_nr = b.l_titel_nr)
	join BUMANAUS m on (m.l_ausg_nr = b.l_ausg_nr)
	join BUAUFL l on (l.l_ausg_nr = b.l_ausg_nr and l.l_aufl_nr = 0)
where	(b.herkunft != 'VA' or b.herkunft is null) and b.kz_aufl_best = 'F'
union
select b.modified_on, 'B-' || m.e_mandant || '-' || b.l_ausg_nr || '-' || l.l_aufl_nr, m.e_mandant, m.artikel_nr, b.isbn, b.ean, case when (b.l_titel_nr = 0) then coalesce(s.artikel_bez,b.ausg_text) else t.titel1 end, l.auflage_nr, l.aufl_text,
(select sum(g.ges_menge) - sum(g.anz_reserv) from bulagges g where g.e_mandant = m.e_mandant and g.l_ausg_nr = l.l_ausg_nr and g.l_aufl_nr = l.l_aufl_nr) -
coalesce((select sum(i.min_best) from bulagmin i where i.e_mandant = m.e_mandant and i.l_ausg_nr = l.l_ausg_nr and i.l_aufl_nr = l.l_aufl_nr),0)
from	BUAUSGAB b
	left join BUAUSSPR s on	(s.l_ausg_nr = b.l_ausg_nr and s.sprach_code = 'D')
	left join BUTITEL t on (t.l_titel_nr = b.l_titel_nr)
	join BUMANAUS m on (m.l_ausg_nr = b.l_ausg_nr)
	join BUAUFL l on (l.l_ausg_nr = b.l_ausg_nr and l.l_aufl_nr > 0)
where	(b.herkunft != 'VA' or b.herkunft is null) and b.kz_aufl_best = 'T';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUDRUVIE" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "AUFLAGE_NR", "STATUS", "SUM_HOEHE_IST") AS
  select m.e_mandant, m.l_ausg_nr, a.l_aufl_nr, m.artikel_nr, a.auflage_nr, a.status, sum(d.aufl_hoehe_ist)
from  buaufdru d, bumanaus m, buaufl a
where m.l_ausg_nr=d.l_ausg_nr and
      d.l_ausg_nr=a.l_ausg_nr and
      d.l_aufl_nr=a.l_aufl_nr
group by m.e_mandant, m.l_ausg_nr, a.l_aufl_nr, m.artikel_nr, a.auflage_nr, a.status;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUEINKVI" ("LFD_NR", "E_MANDANT", "ARTIKEL_NR", "L_AUSG_NR", "AUFLAGE_NR", "L_AUFL_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "WAEHRUNG", "KOSTENART", "KOSTENART_BEZ", "POS_BETRAG", "BRUT_NET", "POS_TEXT", "RECH_NR", "RECH_DAT") AS
  select  b.lfd_nr, b.e_mandant, m.artikel_nr, b.l_ausg_nr, a.auflage_nr, b.l_aufl_nr, b.adr_gr, b.adr_nr, b.person_nr,
        b.waehrung, b.kostenart, k.bez, b.pos_betrag, b.brut_net, b.pos_text, b.rech_nr, b.rech_dat
from bueinkos b, bumanaus m, bukalkos k, buaufl a
where b.l_ausg_nr = m.l_ausg_nr and
      b.e_mandant  = m.e_mandant and
      b.kostenart = k.kostenart and
      b.l_ausg_nr = a.l_ausg_nr and
      b.l_aufl_nr = a.l_aufl_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUEKVIEW" ("E_MANDANT", "EK_NR", "POS_NR", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "ISBN", "AUFLAGE_NR", "TITEL_SUCH", "AUSG_TEXT", "BEST_ART", "LIEF_DAT_SOLL", "LIEF_DAT_IST", "K_WOCHE", "ZUSTAND_ID", "ADR_GR", "ADR_NR_LI", "HAUPT_NAME", "EK_BEST_NR", "BEST_DAT", "VERLAGS_ID", "BEST_MENGE", "EK_PREIS", "LIEFER_MENGE", "GES_PREIS", "POS_BETRAG", "BER_MENGE", "FREI_MENGE", "ADR_NR_RE", "PERSON_NR_RE", "KZ_STORNO_EK", "KZ_STORNO_POS", "STATUS_AUF", "STATUS_POS", "WAEHRUNG", "KZ_BESTAETIGT", "RAB_PROZ", "N_ARTIKEL_NR", "MAHN_DAT", "MELD_NR", "MAHN_TAGE", "ERSTMAHN_TAGE", "KZ_STORNO_INTERN", "FAX_NR", "EMAIL", "RECH_NR", "RECH_DAT", "MAHN_MENGE", "REM_MENGE") AS
  select p.e_mandant, p.ek_nr, p.pos_nr, p.l_ausg_nr, p.l_aufl_nr,
                    m.artikel_nr, b.isbn, l.auflage_nr, t.titel_such, b.ausg_text, p.best_art, p.lief_dat_soll,
                    p.lief_dat_ist, p.k_woche, p.zustand_id, s.adr_gr_li, s.adr_nr_li, a.haupt_name, s.ek_best_nr,
                    s.best_dat, s.verlags_id, p.best_menge, p.ek_preis, p.liefer_menge, p.ges_preis, p.pos_betrag,
                    p.ber_menge, p.frei_menge, s.adr_nr_re, s.person_nr_re, s.kz_storno, p.kz_storno,
                    s.status, p.status, s.waehrung, p.kz_bestaetigt, p.rab_proz,
    to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ABCDEFGHIJKLMNOPQRSTUVWXYZAOU ','0123456789')),
                    p.mahn_dat, l.meld_nr, e.mahn_tage, d.erstmahn_tage, p.kz_storno_intern,
                    (select nummer from telecom t, teleart r where
                    r.verw_id='X' and r.tel_art=t.tel_art and t.adr_gr = s.adr_gr_li and t.adr_nr = s.adr_nr_li and t.person_nr = 0 and rownum = 1),
                    (select nummer from telecom t, teleart r where
                    r.verw_id='E' and r.tel_art=t.tel_art and t.adr_gr = s.adr_gr_li and t.adr_nr = s.adr_nr_li and t.person_nr = 0 and rownum = 1), p.rech_nr, p.rech_dat, p.mahn_menge, p.rem_menge
  from buekpos p, buekstam s, anschr a, buausgab b, bumanaus m, buaufl l, butitel t, bumeldnr e, land d
 where s.e_mandant = p.e_mandant and
            s.ek_nr = p.ek_nr and
            m.e_mandant = p.e_mandant and
            m.l_ausg_nr  = p.l_ausg_nr and
            a.adr_gr (+) = s.adr_gr_li and
            a.adr_nr (+) = s.adr_nr_li and
            b.l_ausg_nr  = p.l_ausg_nr and
            l.l_ausg_nr  = p.l_ausg_nr and
            l.l_aufl_nr  = p.l_aufl_nr and
            t.l_titel_nr = b.l_titel_nr and
            e.meld_nr = l.meld_nr and
            d.land_code (+) = a.land_code;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUFAKLSV" ("ABRUF_NR", "RECH_NR", "RECH_DAT", "E_MANDANT", "RECH_TYP", "AUFT_NR", "REF_NR") AS
  select  p.abruf_nr, p.rech_nr, p.rech_dat, p.e_mandant, s.rech_typ, p.auft_nr, p.lief_ref
from bufakpos p, bufakst s
where p.rech_nr    = s.rech_nr   and
      p.rech_dat   = s.rech_dat  and
      p.f_mandant  = s.f_mandant and
      p.rech_nr > 0  and
      p.lief_ref  is null and
      (s.rech_typ = 'LS' or s.rech_typ = 'L');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUFAKPOSVIEW" ("RECH_NR", "RECH_DAT", "POS_NR", "F_MANDANT", "POS_NETTO", "POS_BRUTTO", "POS_MWST", "SUM_GELIEF", "GEWICHT") AS
  select p.rech_nr, p.rech_dat, p.pos_nr, p.f_mandant,
p.pos_netto, p.pos_brutto, p.pos_mwst, sum(u.gelief_men), sum(u.gelief_men * (case when a.gewicht > 0 then a.gewicht else b.gewicht end))
from bufakpos p, bufakupo u, buausgab b, buaufl a
where
u.rech_nr = p.rech_nr and
u.rech_dat = p.rech_dat and
u.pos_nr = p.pos_nr and
u.f_mandant = p.f_mandant and
kz_geliefert = 'F' and
u.l_ausg_nr = b.l_ausg_nr (+) and
u.l_ausg_nr = a.l_ausg_nr (+) and
u.l_aufl_nr = a.l_aufl_nr (+)
group by
p.rech_nr, p.rech_dat, p.pos_nr, p.f_mandant,
p.pos_netto, p.pos_brutto, p.pos_mwst
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUFAKSEV" ("RECH_NR", "RECH_DAT", "F_MANDANT", "ADR_GR", "ADR_NR_E", "PERSON_NR_E", "POS_NR", "UPOS_NR", "E_MANDANT", "RECH_TYP", "R_ART", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "ARTIKEL_NR", "GEWICHT", "BER_MENGE", "KOMBITYP", "GELIEF_MEN", "P_STATUS_LIEF", "SO_POS_ID", "WAEHRUNG", "AUF_POS", "AUFTRAG_VERW", "LAND_E", "PREISKAT", "RAPROZ", "STAORD_NR", "FREI_MENGE", "ABRUF_NR", "R_FORMULAR", "FD_ID", "OBJ_NR", "KZ_PROBEHEFT", "KZ_STRECKE", "TITEL1", "AKT_ID", "UAKT_ID", "VERTRET_AUFT_TYP", "AUFT_NR", "PROV_GRP", "UPOS_SUM_BR", "UPOS_SUM_NE", "KZ_PROV_ERL", "VERTRETER_ID", "ADR_NR_RE", "SORTIERUNG", "UPOS_BRUTTO", "PERSON_NR_RE", "LAGER_CODE", "UPOS_NETTO", "NACH_NR_LE", "RECH_REF", "SHOP_ID", "HERKUNFT", "KZ_KOMMISSION", "AUFTRAG_TYP", "KZ_PARTIE", "KZ_MANUELL", "STEUER_CODE", "UPOS_NE_LIEF", "KZ_AGENTUR", "POS_GEWICHT", "VERS_WEG", "VERSART", "LAND_GR_E", "ZAHLBED", "MWST_FREI", "EG_ID", "E_PREIS_BR", "UPOS_SUM_MW", "MW_PROZ", "VERTRETER_ID_UPOS", "VG_MENGE", "PROD_TYP", "BEST_WEG", "BEST_DATUM", "ARTIKEL_NR_SET", "BUNDLE", "SET_NR") AS
  select  u.rech_nr, u.rech_dat, u.f_mandant, s.adr_gr, s.adr_nr_e, s.person_nr_e,
        u.pos_nr, u.upos_nr, u.e_mandant, s.rech_typ, s.r_art, t.l_ausg_nr, t.l_aufl_nr, t.best_art, t.artikel_nr,
	p.gewicht, t.ber_menge, u.kombityp, t.gelief_men, u.p_status_lief, u.so_pos_id,
	s.waehrung, u.auf_pos, a.auftrag_verw, s.land_e, u.preiskat, u.raproz, p.staord_nr,
	t.frei_menge, s.abruf_nr, s.r_formular, s.fd_id, u.obj_nr, u.kz_probeheft, u.kz_strecke, t.titel1,
        p.akt_id, p.uakt_id, p.vertret_auft_typ, u.auft_nr, u.prov_grp, t.upos_sum_br, t.upos_sum_ne, u.kz_prov_erl,
	s.vertreter_id, a.adr_nr_re, s.sortierung, t.upos_brutto, a.person_nr_re, u.LAGER_CODE, t.upos_netto, f.NACH_NR_LE,
        s.rech_ref, u.shop_id, s.herkunft, a.kz_kommission, p.auftrag_typ, u.kz_partie, s.kz_manuell, t.steuer_code,
