  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUFREXVI" ("L_AUSG_NR", "L_AUFL_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "NACHNAME", "FREI_MENGE", "AUFT_NR", "DATUM", "KZ_ABGELEHNT", "KZ_LIZENZ", "KOMMENTAR", "VERLAGS_ID") AS
  select b.l_ausg_nr, b.l_aufl_nr, b.adr_gr, b.adr_nr, b.person_nr,
       a1.haupt_name, p1.nachname, b.FREI_MENGE, b.AUFT_NR,  b.DATUM, b.KZ_ABGELEHNT, b.KZ_LIZENZ, b.KOMMENTAR, b.VERLAGS_ID
