                        b.l_titel_nr    = g.l_titel_nr
		    LEFT OUTER JOIN busegagr seg ON
			b.grup_id = seg.grup_id,
          bufakupo u LEFT OUTER JOIN (select r1.auft_nr_gut, r1.auf_pos, r1.l_ausg_nr, r1.l_aufl_nr, r1.best_art, r1.ret_gr_id from buretour r1
                                         group by r1.auft_nr_gut, r1.auf_pos, r1.l_ausg_nr, r1.l_aufl_nr, r1.best_art, r1.ret_gr_id) r ON
                         u.auft_nr     = r.auft_nr_gut
                      and u.auf_pos      = r.auf_pos
                      and u.l_ausg_nr    = r.l_ausg_nr
                      and u.l_aufl_nr    = r.l_aufl_nr
                      and u.best_art     = r.best_art
                    LEFT OUTER JOIN eindrart e ON
                        e.eindr_art = u.eindr_art
                    LEFT OUTER JOIN bufastat st ON
			      st.rech_nr = u.rech_nr
			   and st.rech_dat = u.rech_dat
                           and st.pos_nr = u.pos_nr
			   and st.upos_nr = u.upos_nr
                           and st.set_nr = 0
                           and st.f_mandant = u.f_mandant
where s.rech_nr      = u.rech_nr
