         l.aufl_dat_ist, sum(u.gelief_men), u.kz_partie, s.herkunft, u.liz_typ, b.grup_id, s.rech_nr, u.preiskat, u.kz_strecke, u.obj_nr,
	 b.prod_typ, b.verlags_id, s.land_gr_e, s.rech_ref, u.steuer_code, u.kz_geliefert, f.auftrag_typ, s.eg_id, s.mwst_frei, b.l_titel_nr, r.ret_gr_id,
