  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUGSIVIE" ("DATUM_INV", "L_AUSG_NR", "E_MANDANT", "BEST_ART", "L_AUFL_NR", "L_AUFL_NR_WERT", "GES_MENGE", "ARTIKEL_NR", "LAGER_MANDANT", "L_TITEL_NR", "TITEL1", "ISBN", "N_ARTIKEL_NR", "GRUP_ID", "KZ_BESTAND", "HERKUNFT", "PROD_TYP", "KZ_LOESCHEN", "KZ_AUFL_BEST", "KZ_KEINE_INVENTU", "KZ_INV_BEWERT", "AUFL_STATUS", "GEWICHT", "AUFLAGE_NR", "AUFL_DAT_IST", "STEUER_CODE", "L_EK_PREIS", "DS_PREIS") AS
  select  l.datum_inv, l.l_ausg_nr, l.e_mandant, l.best_art, l.l_aufl_nr, w.l_aufl_nr, sum(l.ges_menge), m.artikel_nr, m.lager_mandant,
        t.l_titel_nr, t.titel1, b.isbn, to_number(regexp_replace(m.artikel_nr,'[^[:digit:]]')), b.grup_id, b.kz_bestand, b.herkunft, b.prod_typ, m.kz_loeschen, b.kz_aufl_best,
        b.kz_keine_inventu, w.kz_inv_bewert, a.status, b.gewicht, a.auflage_nr, a.aufl_dat_ist, m.steuer_code, w.l_ek_preis, w.ds_preis
  from bulagsi l, bulawert w, bumanaus m, buaufl a, buausgab b, butitel t
  where w.l_ausg_nr = l.l_ausg_nr and
        w.best_art = l.best_art and
        w.e_mandant = l.e_mandant and
        m.l_ausg_nr = w.l_ausg_nr and
        m.e_mandant = w.e_mandant and
        a.l_ausg_nr = w.l_ausg_nr and
        a.l_aufl_nr = w.l_aufl_nr and
        b.l_ausg_nr = w.l_ausg_nr and
        t.l_titel_nr = b.l_titel_nr
  group by l.datum_inv, l.l_ausg_nr, l.e_mandant, l.best_art, l.l_aufl_nr, w.l_aufl_nr, m.artikel_nr, m.lager_mandant,
        t.l_titel_nr, t.titel1, b.isbn, to_number(regexp_replace(m.artikel_nr,'[^[:digit:]]')), b.grup_id, b.kz_bestand, b.herkunft, b.prod_typ, m.kz_loeschen, b.kz_aufl_best,
        b.kz_keine_inventu, w.kz_inv_bewert, a.status, b.gewicht, a.auflage_nr, a.aufl_dat_ist, m.steuer_code, w.l_ek_preis, w.ds_preis;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUGWVIEW" ("AUFT_NR", "GES_GEWICHT") AS
  select s.auft_nr, sum((case when l.gewicht>0 then l.gewicht else a.gewicht end) * (s.ber_menge + coalesce(s.frei_menge,0)))
from buaufpos s, buausgab a, buaufl l
where a.l_ausg_nr  = s.l_ausg_nr and
      l.l_ausg_nr  = s.l_ausg_nr and
      l.l_aufl_nr  = s.l_aufl_nr
group by auft_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUINVIEW" ("LAGER_CODE", "REGAL_ID", "EBENE_ID", "PLATZ_ID", "L_AUSG_NR", "E_MANDANT", "BEST_ART", "L_AUFL_NR", "ZAEHL_MENGE", "MENGE_ALT", "INVENTUR_MENGE", "INVENTUR_NR", "DATUM_INV", "KZ_UEBERNAHME", "KZ_PRUEFEN", "ARTIKEL_NR", "LAGER_MANDANT", "L_TITEL_NR", "TITEL_SUCH", "ISBN", "BENUTZER_ID", "MENGE_ABW", "PROZ_ABW", "N_ARTIKEL_NR", "GRUP_ID", "HERKUNFT", "PROD_TYP", "KZ_KEINE_INVENTU", "KZ_INV_BEWERT", "GRUNDPREIS", "PREIS", "DATUM_ZAEHL") AS
  select l.lager_code, l.regal_id, l.ebene_id, l.platz_id, l.l_ausg_nr, l.e_mandant,
       l.best_art, l.l_aufl_nr, l.zaehl_menge, l.menge_alt, l.inventur_menge, l.inventur_nr, l.datum_inv,
       l.kz_uebernahme, l.kz_pruefen, m.artikel_nr, m.lager_mandant, t.l_titel_nr, t.titel_such, b.isbn,
       l.benutzer_id, (l.zaehl_menge-l.menge_alt),
       ((l.zaehl_menge-l.menge_alt)) * 100 /  (case when l.menge_alt=0 then 1 else l.menge_alt end),
       to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
       l.grup_id, b.herkunft, l.prod_typ, b.kz_keine_inventu, w.kz_inv_bewert, l.grundpreis, l.preis, l.datum_zaehl
from  buinvpla l, bulagbes g , bumanaus m, buausgab b, butitel t, bulawert w
  where l.lager_code  = g.lager_code (+) and
        l.e_mandant   = g.e_mandant  (+) and
        l.l_ausg_nr   = g.l_ausg_nr  (+) and
        l.l_aufl_nr   = g.l_aufl_nr  (+) and
        l.best_art    = g.best_art   (+) and
        l.regal_id    = g.regal_id   (+) and
        l.ebene_id    = g.ebene_id   (+) and
        l.platz_id    = g.platz_id   (+) and
        l.l_ausg_nr   = m.l_ausg_nr  (+) and
        l.e_mandant   = m.e_mandant  (+) and
        l.l_ausg_nr   = b.l_ausg_nr  (+) and
        b.l_titel_nr  = t.l_titel_nr (+) and
        w.l_ausg_nr (+) = l.l_ausg_nr and
        w.l_aufl_nr (+) = l.l_aufl_nr and
        w.best_art (+) = l.best_art and
        w.e_mandant (+) = l.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUISTATV" ("E_MANDANT", "JAHR_MONAT", "BU_LA_ID", "LAND_CODE", "ISTATWCODE", "WAEHRUNG", "SUM_GELIEFERT", "SUM_RECH_BETR", "GES_GEWICHT", "BUCH_ART") AS
  select i.e_mandant, to_number(to_char(i.datum,'YYYYMM')),
        '08', i.land_code, o.istatwcode, f.waehrung,
        sum(i.anzahl),
        sum(f.sum_betr),
        sum(i.gewicht / 1000), f.buch_art
 from   intrasta i, mobjtyp o, fakustat f
  where i.e_mandant = o.e_mandant
    and i.obj_nr    = o.obj_nr
    and o.istatwcode is not null
    and i.e_mandant = f.e_mandant
    and i.obj_nr    = f.obj_nr
    and i.ausg      = f.ausg
    and i.jahr      = f.jahr
    and i.hnr       = f.hnr
    and i.land_code = f.land_code_re
 group by i.e_mandant, to_number(to_char(i.datum,'YYYYMM')), '08',
          i.land_code, o.istatwcode, f.waehrung,f.buch_art
union
 select f.e_mandant, f.jahr_monat, b.bu_la_id,
        f.land_code, (case when substr(a.qaus,1,8) is Null then p.istatwcode else substr(a.qaus,1,8) end), f.waehrung,
        sum(f.sum_berechnet + f.sum_frei), sum(f.sum_netto_betr),
        sum((b.gewicht * (f.sum_berechnet + f.sum_frei)) / 1000), f.auftrag_typ
 from   bufaksum f, buprotyp p,
        buausgab b LEFT OUTER JOIN buartqa a ON
                           b.l_ausg_nr     = a.l_ausg_nr
                           and b.prod_typ  = a.prod_typ
                           and a.qm_id = 'WARENCODE'
 where f.l_ausg_nr     = b.l_ausg_nr
   and b.prod_typ      = p.prod_typ
   and p.istatwcode is not null
   and f.auftrag_typ   in ('B','L','E')
 group by f.e_mandant, f.jahr_monat, b.bu_la_id,
          f.land_code, (case when substr(a.qaus,1,8) is Null then p.istatwcode else substr(a.qaus,1,8) end), f.waehrung,f.auftrag_typ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUKAVIEW" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "L_AUSG_NR_2", "L_AUFL_NR_2", "BEST_ART_2", "ANZAHL", "ARTIKEL_NR_2", "AUFLAGE_NR_2", "LAGER_MANDANT", "LAGER_CODE", "GES_MENGE", "KZ_VORM_BAR", "L_TITEL_NR", "AUSG_TEXT", "AUFL_TEXT") AS
  select k.e_mandant, k.l_ausg_nr, k.l_aufl_nr, k.best_art,
       k.l_ausg_nr_2, k.l_aufl_nr_2, k.best_art_2, k.anzahl, m.artikel_nr,
       a.auflage_nr, m.lager_mandant, l.lager_code, l.ges_menge, e.kz_vorm_bar,
       b.l_titel_nr, b.ausg_text, a.aufl_text
from bukauf k, buausgab b, bumanaus m, bulagges l, buaufl a, bumeldnr e
where  b.l_ausg_nr = k.l_ausg_nr_2 and
       m.e_mandant = k.e_mandant and
       m.l_ausg_nr = k.l_ausg_nr_2 and
       l.e_mandant = m.lager_mandant and
       l.l_ausg_nr = k.l_ausg_nr_2 and
       l.l_aufl_nr = k.l_aufl_nr_2 and
       l.best_art  = k.best_art_2 and
       a.l_ausg_nr = k.l_ausg_nr_2 and
       a.l_aufl_nr = k.l_aufl_nr_2 and
       e.meld_nr = a.meld_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUKOSVIE" ("E_MANDANT", "JAHR_MONAT", "SUM_KOSTEN") AS
  select k.e_mandant, k. jahr_monat, sum(k.sum_kosten)
from bukosten k
group by k.e_mandant, k. jahr_monat;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUKOVIEW" ("L_AUSG_NR", "U_AUSG_NR", "L_AUFL_NR", "E_MANDANT", "ARTIKEL_NR", "STO_DATUM", "NOV_DAT", "ISBN", "TITEL_SUCH", "KZ_FORTSETZ", "TITEL1", "KOMBITYP", "L_TITEL_NR", "ARTIKEL_NR_K", "L_TITEL_NR_K") AS
  select k.l_ausg_nr, k.u_ausg_nr, k.l_aufl_nr, b.e_mandant,
           b.artikel_nr, b.sto_datum, b.nov_dat, a.isbn, t.titel_such, k.kz_fortsetz, t.titel1, a2.kombityp, t.l_titel_nr, m.artikel_nr, a2.l_titel_nr
  from bukombi k, bumanaus b, buausgab a, butitel t, buausgab a2, bumanaus m
 where k.u_ausg_nr  = b.l_ausg_nr and
       a.l_ausg_nr = b.l_ausg_nr and
       t.l_titel_nr = a.l_titel_nr and
       k.l_ausg_nr  = a2.l_ausg_nr and
       m.l_ausg_nr  = a2.l_ausg_nr and
       m.e_mandant  = b.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUKTRVIE" ("E_MANDANT", "KST_TRAEGER", "L_TITEL_NR", "OBJ_NR", "L_AUSG_NR") AS
  select distinct man.e_mandant, rtrim(man.artikel_nr), aus.l_titel_nr, '    ', man.l_ausg_nr
from bumanaus man, buausgab aus
   where man.artikel_nr is not null
     and man.l_ausg_nr = aus.l_ausg_nr
	 and man.l_ausg_nr not in(select ivw.l_ausg_nr from buivwauf ivw, bumanaus man where man.e_mandant=ivw.e_mandant and man.l_ausg_nr=ivw.l_ausg_nr)
	 and aus.l_titel_nr > 0
union
    select distinct erl.e_mandant, rtrim(erl.kst_traeger), aus.l_titel_nr, erl.obj_nr, man.l_ausg_nr
	from erlkonto erl, bumanaus man, buivwauf ivw, buausgab aus
      where erl.kst_traeger is not null
        and erl.e_mandant = man.e_mandant
        and erl.kst_traeger <> man.artikel_nr
		and erl.obj_nr = ivw.obj_nr
		and man.e_mandant = ivw.e_mandant
		and man.l_ausg_nr = ivw.l_ausg_nr
        and man.l_ausg_nr = aus.l_ausg_nr
	    and aus.l_titel_nr > 0
        and erl.ref_nr = 'BUCH'
union
    select distinct man.e_mandant, rtrim(art.qaus), aus.l_titel_nr, '    ', aus.l_ausg_nr
	from bumanaus man, buausgab aus, buartqa art
      where aus.prod_typ = art.prod_typ
        and man.l_ausg_nr = aus.l_ausg_nr
		and aus.l_ausg_nr = art.l_ausg_nr
		and art.qm_id = 'KSTTRAEGER'
		and aus.l_titel_nr = 0
union
    select distinct erl.e_mandant, rtrim(erl.kst_traeger), aus.l_titel_nr, erl.obj_nr, man.l_ausg_nr
	from erlkonto erl, bumanaus man, buausgab aus
      where erl.kst_traeger is not null
        and erl.e_mandant = man.e_mandant
        and erl.kst_traeger <> man.artikel_nr
	and erl.obj_nr = aus.prod_typ
        and man.l_ausg_nr = aus.l_ausg_nr
        and erl.ref_nr = 'BUCH'
		and aus.l_titel_nr = 0;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULAAUFL" ("E_MANDANT", "LAGER_CODE", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "KOMBI_AUSG_NR", "GES_MENGE", "ANZ_RESERV", "ANZ_VORMERK", "AUFLAGE_NR", "FAKTOR") AS
  select
  l.e_mandant, l. lager_code, l.l_ausg_nr, l.l_aufl_nr, l.best_art, 0,
  l.ges_menge, l.anz_reserv, l.anz_vormerk, a.auflage_nr, 1
from bulagges l, buaufl a
where
  l.l_ausg_nr = a.l_ausg_nr and
  l.l_aufl_nr = a.l_aufl_nr
union
select l.e_mandant, l. lager_code, k.u_ausg_nr, l.l_aufl_nr, l.best_art,
  k.l_ausg_nr, l.ges_menge*k.menge, l.anz_reserv, l.anz_vormerk, a.auflage_nr, k.menge
from bulagges l, bukombi k, buausgab b, buaufl a
where
  l.l_ausg_nr = a.l_ausg_nr and
  l.l_aufl_nr = a.l_aufl_nr and
  l.l_ausg_nr = k.l_ausg_nr and
  l.l_aufl_nr = k.l_aufl_nr and
  l.l_ausg_nr = b.l_ausg_nr and
  (kombityp='V' or kombityp='Z')
union
select l.e_mandant, l. lager_code, k.u_ausg_nr, l.l_aufl_nr, l.best_art,
  k1.l_ausg_nr, l.ges_menge*k.menge*k1.menge, l.anz_reserv, l.anz_vormerk, a.auflage_nr, k.menge*k1.menge
from bulagges l, bukombi k, buausgab b, buaufl a, bukombi k1, buausgab b1
where
  l.l_ausg_nr = a.l_ausg_nr and
  l.l_aufl_nr = a.l_aufl_nr and
  l.l_ausg_nr = k1.l_ausg_nr and
  l.l_aufl_nr = k1.l_aufl_nr and
  k.l_ausg_nr = b.l_ausg_nr and
  b.kombityp='Z' and
  k1.l_ausg_nr = b1.l_ausg_nr and
  (b1.kombityp='Z' or b1.kombityp='V') and
  k.l_ausg_nr=k1.u_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULAGAUF" ("LAGER_CODE", "E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "GES_MENGE", "ARTIKEL_NR", "L_TITEL_NR", "TITEL_SUCH", "ISBN", "AUFLAGE_NR", "MELD_NR", "KZ_VORM_BAR", "ANZ_RESERV") AS
  select  g.lager_code, m.lager_mandant, m.l_ausg_nr, a.l_aufl_nr,
           g.best_art, g.ges_menge, m.artikel_nr, t.l_titel_nr, t.titel_such, b.isbn, a.auflage_nr,
           a.meld_nr, e.kz_vorm_bar, g.anz_reserv
  from  bumanaus m, buausgab b, butitel t, buaufl a, bumeldnr e, bulagges g
 where  b.l_ausg_nr  = m.l_ausg_nr and
            t.l_titel_nr = b.l_titel_nr and
            a.l_ausg_nr = m.l_ausg_nr and
            e.meld_nr = a.meld_nr and
            g.l_ausg_nr (+) = a.l_ausg_nr and
            g.l_aufl_nr (+) = a.l_aufl_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULAVIEW" ("LAGER_CODE", "REGAL_ID", "EBENE_ID", "PLATZ_ID", "L_AUSG_NR", "E_MANDANT", "BEST_ART", "L_AUFL_NR", "MENGE", "GES_MENGE", "ARTIKEL_NR", "LAGER_MANDANT", "L_TITEL_NR", "TITEL_SUCH", "ISBN", "N_ARTIKEL_NR", "GRUP_ID", "KZ_BESTAND", "HERKUNFT", "PROD_TYP", "KZ_LOESCHEN", "KZ_AUFL_BEST", "PLATZART", "KZ_KEINE_INVENTU", "KZ_INV_BEWERT", "AUFL_STATUS", "GEWICHT") AS
  select  p.lager_code, p.regal_id, p.ebene_id, p.platz_id, l.l_ausg_nr, l.e_mandant,
           l.best_art, l.l_aufl_nr, l.menge, g.ges_menge, m.artikel_nr, m.lager_mandant,
           t.l_titel_nr, t.titel_such, b.isbn,
           to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
           b.grup_id, b.kz_bestand, b.herkunft, b.prod_typ, m.kz_loeschen, b.kz_aufl_best, p.platzart, b.kz_keine_inventu, w.kz_inv_bewert,
           a.status, b.gewicht
  from bulagpla p, bulagbes l, bulagges g, bumanaus m, buausgab b, butitel t, bulawert w, buaufl a
 where  l.lager_code (+) = p.lager_code and
            l.regal_id (+) = p.regal_id and
            l.ebene_id (+) = p.ebene_id and
            l.platz_id (+) = p.platz_id and
            g.lager_code (+) = l.lager_code and
            g.l_ausg_nr (+) = l.l_ausg_nr and
            g.l_aufl_nr (+) = l.l_aufl_nr and
            g.best_art (+) = l.best_art and
            g.e_mandant (+) = l.e_mandant and
            m.l_ausg_nr (+) = l.l_ausg_nr and
            m.e_mandant (+) = l.e_mandant and
            b.l_ausg_nr (+) = l.l_ausg_nr and
            t.l_titel_nr (+) = b.l_titel_nr and
            w.l_ausg_nr (+) = l.l_ausg_nr and
            w.l_aufl_nr (+) = l.l_aufl_nr and
            w.best_art (+) = l.best_art and
            w.e_mandant (+) = l.e_mandant and
            a.l_ausg_nr (+) = l.l_ausg_nr and
            a.l_aufl_nr (+) = l.l_aufl_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULFVIEW" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "HAUPT_ORT", "NACHNAME", "VORNAME", "ADR_NR_RE", "PERSON_NR_RE", "HAUPT_NAME_RE", "NACHNAME_RE", "VORNAME_RE", "L_AUSG_NR", "ARTIKEL_NR", "ISBN", "L_AUFL_NR", "ARTIKEL_NR_LI", "AUFLAGE_NR_LI", "BEZEICHNUNG_LI") AS
  select b.e_mandant, b.adr_gr, b.adr_nr, b.person_nr, a1.haupt_name, a1.haupt_ort,
       p1.nachname, p1.vorname, b.adr_nr_re, b.person_nr_re, a2.haupt_name, p2.nachname,
       p2.vorname, s.l_ausg_nr, m.artikel_nr, a.isbn, s.l_aufl_nr, s.artikel_nr_li, s.auflage_nr_li, s.bezeichnung_li
from  bulieart s, buliesta b, bumanaus m, buausgab a, person p1, anschr a1,
         person p2, anschr a2
where s.adr_gr (+) = b.adr_gr and
           s.adr_nr  (+)    = b.adr_nr and
           s.e_mandant (+)    = b.e_mandant and
           a1.adr_gr (+)   = b.adr_gr and
           a1.adr_nr  (+)    = b.adr_nr and
           p1.adr_gr  (+)    = b.adr_gr and
           p1.adr_nr  (+)    = b.adr_nr and
           p1.person_nr  (+) = b.person_nr and
           a2.adr_gr  (+)    = b.adr_gr and
           a2.adr_nr   (+)   = b.adr_nr_re and
           p2.adr_gr   (+)   = b.adr_gr and
           p2.adr_nr   (+)   = b.adr_nr_re and
           p2.person_nr  (+) = b.person_nr_re and
            a.l_ausg_nr  (+) = s.l_ausg_nr and
            m.e_mandant (+) = s.e_mandant and
            m.l_ausg_nr  (+) = s.l_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULIEFERSUMVIEW" ("E_MANDANT", "JAHR", "LAND_E", "ARTIKEL_NR", "STEUERSATZ", "GELIEF_MENGE", "GEWICHT") AS
  select  t.e_mandant, to_char(s.rech_dat,'YYYY'), s.land_e, t.artikel_nr, t.mw_proz, sum(t.gelief_men), sum(b.gewicht * t.gelief_men)
   from bufakst s, bufakpos p, bufakupo u, bufakset t, buausgab b, buprotyp o
   where u.rech_nr    = s.rech_nr   and
      u.rech_dat   = s.rech_dat  and
	u.f_mandant  = s.f_mandant and
	u.rech_nr    = p.rech_nr   and
	u.rech_dat   = p.rech_dat  and
	u.f_mandant  = p.f_mandant and
	u.pos_nr     = p.pos_nr and
        u.rech_nr    = t.rech_nr  and
        u.rech_dat     = t.rech_dat and
        u.f_mandant    = t.f_mandant and
        u.pos_nr       = t.pos_nr and
        u.upos_nr      = t.upos_nr and
        s.rech_typ     like '%L%' and
        t.l_ausg_nr = b.l_ausg_nr and
        b.prod_typ = o.prod_typ and
        o.kz_elektron = 'F'
   group by t.e_mandant, to_char(s.rech_dat,'YYYY'), t.artikel_nr, s.land_e, t.mw_proz
union
   select  u.e_mandant, to_char(s.rech_dat,'YYYY'), s.land_e, u.artikel_nr, u.mw_proz, sum(u.gelief_men), sum(b.gewicht * u.gelief_men)
   from bufakst s, bufakpos p, bufakupo u, buausgab b, buprotyp o
   where u.rech_nr    = s.rech_nr   and
      u.rech_dat   = s.rech_dat  and
	u.f_mandant  = s.f_mandant and
	u.rech_nr    = p.rech_nr   and
	u.rech_dat   = p.rech_dat  and
	u.f_mandant  = p.f_mandant and
	u.pos_nr     = p.pos_nr and
        s.rech_typ     like '%L%' and
        u.l_ausg_nr = b.l_ausg_nr and
        b.prod_typ = o.prod_typ and
        o.kz_elektron = 'F'  and
        (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
        and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr))
   group by u.e_mandant, to_char(s.rech_dat,'YYYY'), u.artikel_nr, s.land_e, u.mw_proz;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULIVEVW" ("LAND_CODE", "REG_ID", "REG_CODE", "VERS_WEG", "VERSART", "LIMIT", "WAEHRUNG", "BETRAG", "EXT_CODE") AS
  select a.land_code, a.reg_id, a.reg_code, b.vers_weg, b.versart, c.limit, c.waehrung, c.betrag, c.ext_code
  from regland a, buverart b, buvakost c
 where a.reg_id = b.reg_id and
       a.reg_code = b.reg_code and
       b.vers_weg = c.vers_weg and
       b.versart = c.versart;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULIVIEW" ("E_MANDANT", "AUFT_NR", "AUF_POS", "BEST_DATUM", "L_VERS_DAT", "FAKT_SOLL_DAT", "AKT_ID", "UAKT_ID", "STAORD_NR", "L_AUSG_NR", "STATUS", "AUFTRAG_TYP", "AUFTRAG_VERW", "POS_STATUS", "BER_MENGE", "FREI_MENGE", "RETOUR_MENGE", "KZ_IMPORT_FILE") AS
  select s.e_mandant, s.auft_nr, s.auf_pos,
       a.best_datum, a.l_vers_dat, a.fakt_soll_dat, a.akt_id, a.uakt_id,
       a.staord_nr, s.l_ausg_nr, a.status, a.auftrag_typ,
       a.auftrag_verw, s.status, s.ber_menge, s.frei_menge, s.retour_menge, a.kz_gs_druck
  from buaufpos s, buauftra a
 where a.auft_nr = s.auft_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULIZVIE" ("LIZENZ_NR", "E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "NACHNAME", "LIZ_TYP", "RHYTHMUS", "DATUM_AB", "DATUM_BIS", "DATUM_VERTRAG", "WAEHRUNG", "PREIS", "STATUS", "ABTEILUNG", "VERLAGS_ID", "ISBN_LIZ", "KZ_ERSCH", "KZ_KOPROD", "KZ_EEU", "KZ_ANG_GEDRUCKT", "KZ_RECHTE_ZURUECK", "TITEL_SUCH", "TITEL1", "L_TITEL_NR") AS
  select b.lizenz_nr, b.e_mandant, b.l_ausg_nr, b.l_aufl_nr, b.adr_gr, b.adr_nr, b.person_nr,
       a1.haupt_name, p1.nachname, b.liz_typ, b.rhythmus, b.datum_ab, b.datum_bis, b.datum_vertrag,
       b.waehrung, b.preis, b.status, b.abteilung, b.verlags_id, b.isbn_liz, b.kz_ersch, b.kz_koprod, b.kz_eeu, b.kz_ang_gedruckt,
       b.kz_rechte_zurueck, t.titel_such, t.titel1, t.l_titel_nr
from butitel t, buausgab u, bulizenz b LEFT OUTER JOIN person p1 ON
                  p1.adr_gr    = b.adr_gr and
                  p1.adr_nr    = b.adr_nr and
                  p1.person_nr = b.person_nr
                LEFT OUTER JOIN anschr a1 ON
                  a1.adr_gr    = b.adr_gr and
                  a1.adr_nr    = b.adr_nr
where b.l_ausg_nr  = u.l_ausg_nr and
      t.l_titel_nr = u.l_titel_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BULRVIEW" ("E_MANDANT", "AUFT_NR", "AUF_POS", "ADR_GR", "ADR_NR_BEST", "PERSON_NR_BEST", "ADR_NR_RE", "PERSON_NR_RE", "ADR_NR_LE", "PERSON_NR_LE", "AKT_ID", "UAKT_ID", "STAORD_NR", "L_AUSG_NR", "ARTIKEL_NR", "ISBN", "SO_POS_ID", "AUFLAGE_NR", "BER_MENGE", "FREI_MENGE", "VORMERK_MENGE", "RAB_PROZ", "EINZEL_PREIS", "GES_PREIS", "POS_BETRAG", "VERS_WEG", "MELD_NR", "MELD_TEXT", "STATUS", "BRUT_NET", "AUFTRAG_TYP", "HERKUNFT", "RESERVIERT_MENGE", "L_TITEL_NR", "LAGER_MANDANT", "L_AUFL_NR", "LAGER_CODE", "N_ARTIKEL_NR", "BEST_DATUM", "BEST_TEXT", "BERECHNEN", "GRUP_ID", "VERTRETER_ID", "KOMBI_ARTIKEL_NR", "KOMBITYP", "KZ_KOMMISSION", "POS_TYP", "L_EK_PREIS", "ABWEICH_PROZ", "STORNO", "WB_ID", "HGRP_ID", "UGRP_ID", "PRODUKT", "PROD_TYP", "DATUM_NEU", "Z_BED", "R_ART", "BEST_WEG") AS
  select s.e_mandant, s.auft_nr, s.auf_pos, b.adr_gr, b.adr_nr_best,
       b.person_nr_best, b.adr_nr_re, b.person_nr_re, b.adr_nr_le, b.person_nr_le,
       b.akt_id, b.uakt_id, b.staord_nr, s.l_ausg_nr, m.artikel_nr, a.isbn, o.so_pos_id,
       l.auflage_nr, s.ber_menge, s.frei_menge, s.vormerk_menge, s.rab_proz,
       s.einzel_preis, s.ges_preis, s.pos_betrag, b.vers_weg, l.meld_nr, e.meld_text,
       b.status, s.brut_net, b.auftrag_typ, b.herkunft, s.reserviert_menge, a.l_titel_nr,
       s.lager_mandant, s.l_aufl_nr, s.lager_code,
       to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
       b.best_datum, b.best_text, p.berechnen, a.grup_id, b.vertreter_id, '                    ', a.kombityp, b.kz_kommission, s.pos_typ,
       w.l_ek_preis, ((s.einzel_preis-w.l_ek_preis)) * 100 /  (case when w.l_ek_preis=0 then 1 else w.l_ek_preis end), s.storno,
       r.wb_id, r.hgrp_id, r.ugrp_id, r.produkt, a.prod_typ, b.datum_neu, b.z_bed, b.r_art, b.best_weg
from  buaufpos s, buauftra b, bumanaus m, buausgab a, busopos o, buaufl l, bumeldnr e, buprkat p, bulawert w, buartpro r
where b.auft_nr = s.auft_nr and
            a.l_ausg_nr(+)  = s.l_ausg_nr and
            m.e_mandant(+) = s.e_mandant and
            m.l_ausg_nr(+)  = s.l_ausg_nr and
            o.so_pos_id(+)  = s.so_pos_id and
            l.l_ausg_nr(+)  = s.l_ausg_nr and
            l.l_aufl_nr(+)  = s.l_aufl_nr and
            p.preiskat(+)  = s.preiskat and
            e.meld_nr(+)  = l.meld_nr and
            w.e_mandant(+)  = s.lager_mandant and
            w.l_aufl_nr(+)  = s.l_aufl_nr and
            w.l_ausg_nr(+)  = s.l_ausg_nr and
            w.best_art(+)  = s.best_art and
            r.l_ausg_nr(+) = s.l_ausg_nr
union
select s.e_mandant, s.auft_nr, s.auf_pos, b.adr_gr, b.adr_nr_best,
       b.person_nr_best, b.adr_nr_re, b.person_nr_re, b.adr_nr_le, b.person_nr_le,
       b.akt_id, b.uakt_id, b.staord_nr, a.l_ausg_nr, m2.artikel_nr, a.isbn, Null,
       l.auflage_nr, s.ber_menge, s.frei_menge, (s.vormerk_menge*k.menge), s.rab_proz,
       s.einzel_preis, s.ges_preis, s.pos_betrag, b.vers_weg, l.meld_nr, e.meld_text,
       b.status, s.brut_net, b.auftrag_typ, b.herkunft, s.reserviert_menge, a.l_titel_nr,
       s.lager_mandant, k.l_aufl_nr, s.lager_code,
       to_number(translate(m2.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
       b.best_datum, b.best_text, p.berechnen, a.grup_id, b.vertreter_id, m.artikel_nr, a.kombityp, b.kz_kommission, s.pos_typ, NULL, NULL,
       s.storno, r.wb_id, r.hgrp_id, r.ugrp_id, r.produkt, a.prod_typ, b.datum_neu, b.z_bed, b.r_art, b.best_weg
from  buaufpos s, buauftra b, bumanaus m, buausgab a, buaufl l, bumeldnr e, buprkat p, bukombi k, bumanaus m2, buartpro r
where b.auft_nr = s.auft_nr and
            k.l_ausg_nr     = s.l_ausg_nr and
            m2.e_mandant  = s.e_mandant and
            m2.l_ausg_nr  = k.u_ausg_nr and
            a.l_ausg_nr  = k.u_ausg_nr and
            m.e_mandant  = s.e_mandant and
            m.l_ausg_nr  = s.l_ausg_nr and
            l.l_ausg_nr  = k.u_ausg_nr and
            l.l_aufl_nr  = k.l_aufl_nr and
            p.preiskat(+)  = s.preiskat and
            e.meld_nr (+)  = l.meld_nr and
            r.l_ausg_nr (+) = k.u_ausg_nr
union
select w.e_mandant, 0, 0, w.adr_gr, w.adr_nr,
       w.person_nr, w.adr_nr, w.person_nr, w.adr_nr, w.person_nr,
       Null, Null, 0, r.l_ausg_nr, m.artikel_nr, a.isbn, Null,
       l.auflage_nr, 0, 0, 1, 0, 0, 0, 0, NULL, l.meld_nr, NULL,
       'X', NULL, NULL, NULL, 0, a.l_titel_nr,
       m.lager_mandant, r.l_aufl_nr, 'X?}',
       to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
       NULL, NULL, NULL, a.grup_id, NULL, '                    ', a.kombityp, 'F', NULL, NULL, NULL, 'F',
       p.wb_id, p.hgrp_id, p.ugrp_id, p.produkt, a.prod_typ, NULL, NULL, NULL, NULL
from werbepra r, werbepr w, bumanaus m, buausgab a, buaufl l, buartpro p
where       r.adr_gr    = w.adr_gr    and
            r.adr_nr    = w.adr_nr    and
            r.person_nr = w.person_nr and
            r.e_mandant = w.e_mandant and
            r.obj_nr    = w.obj_nr    and
            r.ausg      = w.ausg      and
            r.abo_nr    = w.abo_nr    and
