            a.l_ausg_nr  = r.l_ausg_nr and
            o.l_ausg_nr(+) = r.l_ausg_nr and
            m.e_mandant = r.e_mandant and
            m.l_ausg_nr = r.l_ausg_nr and
            l.l_ausg_nr = r.l_ausg_nr and
            l.l_aufl_nr = r.l_aufl_nr and
            r.adr_nr    = p.adr_nr_abo and
