  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUMANAUS_BUTMP" ("E_MANDANT", "L_AUSG_NR", "ARTIKEL_NR", "L_AUSG_NR_NEU", "L_AUSG_NR_ERSATZ", "BRUT_NET", "RABATT_TYP", "PROV_GRP", "EK_RAB_PROZ", "KZ_BEOBACHT", "KZ_FORTSETZ", "R_SUBS_DAT1", "R_SUBS_DAT2", "R_SUBS_PROZ", "R_FAKT_DAT", "RAB_GRP", "NOV_DAT", "STEUER_CODE", "STO_DATUM", "LAGER_MANDANT", "KZ_LOESCHEN", "KST_REMM", "KST_VERK") AS
