a.E_MANDANT ,b.L_AUSG_NR  ,b.ARTIKEL_NR  ,a.L_AUSG_NR_NEU,a.L_AUSG_NR_ERSATZ,a.BRUT_NET ,a.RABATT_TYP,
a.PROV_GRP ,a.EK_RAB_PROZ,a.KZ_BEOBACHT ,a.KZ_FORTSETZ,a.R_SUBS_DAT1,a.R_SUBS_DAT2 ,a.R_SUBS_PROZ,
a.R_FAKT_DAT,a.RAB_GRP,a.NOV_DAT ,a.STEUER_CODE,a.STO_DATUM,a.LAGER_MANDANT,a.KZ_LOESCHEN,a.KST_REMM,a.KST_VERK
from bumanaus a, butmp b
where a.l_ausg_nr = 24415

;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUMRAVIE" ("BU_RA", "BEZ", "BERECHNUNG", "KZ_FUER", "RAB_PROZ", "AKT_ID", "M_PREIS_GRP", "E_MANDANT", "L_AUSG_NR", "BEST_ART") AS
