  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUOPTVIE" ("VERS_WEG", "VERSART", "LAND_CODE", "REG_ID", "REG_CODE", "TARA", "LAND_CODE_MAN", "KZ_AUTO_AUS", "KZ_AUTO_IN", "MAX_GEW_AUS", "MAX_GEW_IN", "PRIO_AUS", "PRIO_IN", "KZ_VERW_AUS", "KZ_VERW_IN", "STEUER_CODE", "LAND_CODE_REG", "PLZ_VON", "PLZ_BIS", "WOHNORT", "LIMIT", "TARA_BUVAKOST", "BU_SEND_TYP", "BREITE", "HOEHE", "DICKE") AS
