       b.vers_weg = v.vers_weg (+) and
       b.versart = v.versart (+);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUORVIEW" ("L_AUSG_NR", "U_AUSG_NR", "L_AUFL_NR", "MENGE", "E_MANDANT", "STO_DATUM", "NOV_DAT", "KZ_LOESCHEN", "KZ_LOESCHEN_AUSGAB", "SPERR_GRUND", "KZ_ZUS_BAND", "KZ_FORTSETZ", "KZ_BASIS_BAND") AS
