  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUPKVIEW" ("LIST_NR", "E_MANDANT", "L_AUSG_NR", "BEST_ART", "PREISKAT", "WAEHRUNG", "GUELTIG_AB", "L_AUFL_NR", "AKT_ID", "SUBS_DAT1", "BERECHNEN", "KZ_KUGRU", "PRIORITAET") AS
