from buplist l, buprkat k
where k.preiskat  = l.preiskat;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUPOVIEW" ("E_MANDANT", "AUFT_NR", "AUF_POS", "ADR_GR", "ADR_NR_BEST", "PERSON_NR_BEST", "HAUPT_NAME_BEST", "NACHNAME_BEST", "VORNAME_BEST", "ADR_NR_RE", "PERSON_NR_RE", "HAUPT_NAME_RE", "NACHNAME_RE", "VORNAME_RE", "ADR_NR_LE", "PERSON_NR_LE", "HAUPT_NAME_LE", "NACHNAME_LE", "VORNAME_LE", "BEST_DATUM", "L_VERS_DAT", "FAKT_SOLL_DAT", "AKT_ID", "UAKT_ID", "STAORD_NR", "L_AUSG_NR", "ARTIKEL_NR", "ISBN", "SO_POS_ID", "STATUS", "STATUS_POS", "STORNO_POS", "AUFTRAG_TYP", "RECH_NR", "RECH_DAT", "L_AUFL_NR", "HERKUNFT", "PRIO", "BER_MENGE", "FREI_MENGE", "GELIEF_MEN", "VERTRETER_ID", "OBJ_NR", "PREISKAT_ABO", "GRUP_ID", "BEW_ART", "AUSG", "ABO_NR", "ADR_NR_ABO", "PERSON_NR_ABO", "LIEFER_MENGE_ABO", "EINDR_ART", "BEST_TEXT", "REF_AUFT_NR", "R_ART", "KZ_KOMMISSION", "B_ID_NEU", "DATUM_NEU", "R_FORMULAR") AS
  select s.e_mandant, s.auft_nr, s.auf_pos, b.adr_gr, b.adr_nr_best,
       b.person_nr_best, a1.haupt_name, p1.nachname, p1.vorname,
       b.adr_nr_re, b.person_nr_re, a2.haupt_name, p2.nachname, p2.vorname,
       b.adr_nr_le, b.person_nr_le, a3.haupt_name, p3.nachname, p3.vorname,
       b.best_datum, b.l_vers_dat, b.fakt_soll_dat, b.akt_id, b.uakt_id, b.staord_nr,
       s.l_ausg_nr, m.artikel_nr, a.isbn, o.so_pos_id, b.status, s.status, s.storno,
       b.auftrag_typ, f.rech_nr, f.rech_dat, s.l_aufl_nr, b.herkunft, b.prioritaet,
       s.ber_menge, s.frei_menge, s.gelief_menge, b.vertreter_id, s.obj_nr, s.preiskat_abo, a.grup_id, w.bew_art,
       s.ausg, s.abo_nr, s.adr_nr_abo, s.person_nr_abo, s.liefer_menge_abo, s.eindr_art, b.best_text, r.ref_auft_nr,
       b.r_art, b.kz_kommission, b.b_id_neu, b.datum_neu, b.r_formular
from  buaufpos s, buauftra b, bumanaus m, buausgab a, busopos o, person p1, anschr a1,
         person p2, anschr a2, person p3, anschr a3, bufakupo f, bulagbew w, buaufref r
where b.auft_nr = s.auft_nr and
