  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUPRHIVI" ("KEY_NUM_1", "KEY_NUM_2", "KEY_CHAR_1", "DATIM", "ENTITAET", "LFD_NR_HIST", "L_AUSG_NR", "E_MANDANT", "ISBN", "EAN", "PREISBIND", "REIHEN_CODE", "ARTIKEL_NR", "FELDNAME", "PREISKAT", "GUELTIG_AB", "WAEHRUNG", "LIST_NR", "MENGE", "PREIS", "KZ_BESTAND") AS
  select distinct h.key_num_1, h.key_num_2, h.key_char_1, h.datim, h.entitaet, h.lfd_nr_hist,
          p.l_ausg_nr, p.e_mandant, b.isbn, b.ean, b.preisbind, b.reihen_code, m.artikel_nr, h.feldname,
          p.preiskat, p.gueltig_ab, p.waehrung, p.list_nr, s.menge, s.preis, b.kz_bestand
  from historie h, buausgab b, bumanaus m, buplist p, bumpreis s
 where p.l_ausg_nr  = h.key_num_1 and
            p.e_mandant = h.key_char_1 and
            p.list_nr = h.key_num_2 and
            p.l_aufl_nr = 0 and
            b.l_ausg_nr = p.l_ausg_nr and
            m.l_ausg_nr = p.l_ausg_nr and
            m.e_mandant = p.e_mandant and
            s.list_nr = p.list_nr  and
            h.feldname != 'PREISELOE';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUPROVIE" ("RECH_NR", "RECH_DAT", "POS_NR", "UPOS_NR", "E_MANDANT", "F_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "ARTIKEL_NR", "PROV_BET_NET", "BER_MENGE", "KOMBITYP", "GELIEF_MEN", "P_STATUS_LIEF", "SO_POS_ID", "WAEHRUNG") AS
  select s.rech_nr, s.rech_dat, s.rech_pos_nr, s.rech_upos_nr, s.e_mandant, u.f_mandant,
           u.l_ausg_nr, u.l_aufl_nr, u.best_art, u.artikel_nr, s.prov_bet_net,
           u.ber_menge, u.kombityp, u.gelief_men, u.p_status_lief, u.so_pos_id, s.waehrung
from bufakupo u, buveprov s
where u.rech_nr = s.rech_nr and
      u.rech_dat = s.rech_dat and
      u.e_mandant = s.e_mandant and
      u.pos_nr = s.rech_pos_nr and
      u.upos_nr = s.rech_upos_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUQAGVIE" ("ADR_GR", "ADR_NR", "PERSON_NR", "A_TYP", "Q_CODE", "Q_AUSP_CODE", "GRUP_ID", "E_MANDANT") AS
  SELECT w.adr_gr, w.adr_nr, w.person_nr, w.a_typ, w.q_code, w.q_ausp_code, a.grup_id, a.e_mandant
FROM qwerte w, buqstagr a
WHERE w.adr_gr = a.adr_gr and
              w.a_typ = a.a_typ and
              w.q_code = a.q_code and
              w.q_ausp_code = a.q_ausp_code;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUQMVIEW" ("L_AUSG_NR", "PROD_TYP", "QM_ID", "QAUS_ID", "L_TITEL_NR", "TITEL_SUCH", "TITEL1", "SPRACH_CODE", "ORIG_TITEL", "ORG_SPR_CODE", "VERLAGS_ID", "ISBN", "EAN", "REIHEN_CODE", "KOMBITYP", "ISSN", "AUSG_TEXT", "E_MANDANT", "ARTIKEL_NR", "NACHNAME", "VORNAME", "HAUPT_NAME", "SPERR_GRUND", "KZ_LOESCHEN", "HERKUNFT", "GRUP_ID", "KZ_AUFL_BEST", "B_ID_AEND") AS
