  from butitqa q, buausgab b, butitel t, buautor a, bumanaus m
  where t.l_titel_nr = q.l_titel_nr and
            t.l_titel_nr  = b.l_titel_nr and
            m.l_ausg_nr (+) = b.l_ausg_nr and
            a.l_titel_nr (+)= b.l_titel_nr and
