  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUQPVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "A_TYP", "Q_CODE", "Q_AUSP_CODE", "PREISKAT", "E_MANDANT") AS
