  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUREMVIE" ("EK_NR", "POS_NR", "BEW_NR", "VERLAGS_ID", "ARTIKEL_NR", "AUFLAGE_NR", "TITEL1", "ARTIKEL_BEZ", "AUFL_TEXT", "GES_MENGE", "LIEFERTERMIN", "REM_ENDE_DAT", "TAGE_REM_ENDE", "E_MANDANT", "ADR_GR", "ADR_NR_LI", "L_AUSG_NR", "L_AUFL_NR", "ISBN", "STATUS_POS", "REM_MENGE", "REM_DAT", "LIEFER_MENGE", "LAGER_CODE") AS
  select p.ek_nr, p.pos_nr, w.bew_nr, s.verlags_id,
       to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
       l.auflage_nr, t.titel1, a.artikel_bez, l.aufl_text, g.ges_menge, w.bew_dat, (w.bew_dat+p.rr_frist),
       round(to_number((w.bew_dat+p.rr_frist)-sysdate+1)), s.e_mandant, s.adr_gr_li, s.adr_nr_li, p.l_ausg_nr, p.l_aufl_nr, b.isbn,
       p.status, p.rem_menge, p.rem_dat, w.bew_menge, g.lager_code
 from buekpos p, buekstam s, bumanaus m, buaufl l, buausspr a, bulagbew w, butitel t, buausgab b, bulagges g
 where s.e_mandant = p.e_mandant and
            s.ek_nr = p.ek_nr and
            m.e_mandant = p.e_mandant and
            m.l_ausg_nr  = p.l_ausg_nr and
            l.l_ausg_nr  = p.l_ausg_nr and
            l.l_aufl_nr  = p.l_aufl_nr and
            a.l_ausg_nr (+) = p.l_ausg_nr and
            b.l_ausg_nr  = p.l_ausg_nr and
            t.l_titel_nr = b.l_titel_nr and
            g.e_mandant  = p.e_mandant and
            g.l_ausg_nr  = p.l_ausg_nr and
            g.l_aufl_nr  = p.l_aufl_nr and
            g.lager_code = 'HLA' and
            g.best_art   = '1' and
            w.e_mandant  = p.e_mandant and
            w.l_ausg_nr  = p.l_ausg_nr and
            w.l_aufl_nr  = p.l_aufl_nr and
            w.ek_nr      = p.ek_nr and
            w.ek_pos_nr     = p.pos_nr and
            p.kz_storno = 'F' and
