      (u.kombityp != 'X' or u.kombityp is null)
union
   select u.rech_nr, u.rech_dat, u.f_mandant, u.pos_nr, u.upos_nr, u.e_mandant,
   s.rech_typ, s.r_art, s.adr_gr, r.adr_nr, r.person_nr, a.haupt_name,
