  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUSWVIEW" ("L_TITEL_NR", "L_AUSG_NR", "TITEL_SUCH", "TITEL1", "SPRACH_CODE", "ORIG_TITEL", "ORG_SPR_CODE", "VERLAGS_ID", "ISBN", "EAN", "PROD_TYP", "REIHEN_CODE", "KOMBITYP", "ISSN", "AUSG_TEXT", "E_MANDANT", "ARTIKEL_NR", "STICHWORT", "SPERR_GRUND", "KZ_LOESCHEN", "HERKUNFT", "GRUP_ID") AS
  select s.l_titel_nr, b.l_ausg_nr,  t.titel_such,
           t.titel1, t.sprach_code, t.orig_titel, t.org_spr_code, b.verlags_id,
           b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp, b.issn, b.ausg_text,
           m.e_mandant, m.artikel_nr, s.stichwort, b.sperr_grund, m.kz_loeschen, b.herkunft, b.grup_id
  from  bustichw s, butitel t, buausgab b, bumanaus m
 where t.l_titel_nr = s.l_titel_nr and
            b.l_titel_nr (+) = s.l_titel_nr and
            m.l_ausg_nr (+) = b.l_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUTERVIE" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "N_ARTIKEL_NR", "KURZTITEL", "AUFLAGE_NR", "HERKUNFT", "AUSG_TEXT", "AUFL_TEXT", "AUFG_ID", "ABTEILUNG", "PRIORITAET", "BEN_ZUST", "TERMIN_SOLL", "TERMIN_IST", "STATUS") AS
  select m.e_mandant, t.l_ausg_nr, t.l_aufl_nr, m.artikel_nr,
      to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
        i.titel_such, l.auflage_nr, b.herkunft, b.ausg_text, l.aufl_text, t.aufg_id, t.abteilung,
        t.prioritaet, t.ben_zust, t.termin_soll, t.termin_ist, t.status
from   buaufter t, bumanaus m, butitel i, buaufl l, buausgab b
where t.l_ausg_nr     = m.l_ausg_nr
  and t.l_ausg_nr     = l.l_ausg_nr
  and t.l_aufl_nr     = l.l_aufl_nr
  and t.l_ausg_nr     = b.l_ausg_nr
  and b.l_titel_nr    = i.l_titel_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUTEXVIE" ("L_AUSG_NR", "L_AUFL_NR", "E_MANDANT", "VERW_TYP", "AUFLAGE_NR", "AUFL_TEXT", "SPRACH_CODE", "TYP") AS
  select  a.l_ausg_nr, a.l_aufl_nr, t.e_mandant, t.verw_typ, a.auflage_nr, a.aufl_text, t.sprach_code, t.typ
  from  buaufl a, buauftxt t
where  t.l_ausg_nr (+) = a.l_ausg_nr and
       t.l_aufl_nr (+) = a.l_aufl_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUTIHIVI" ("KEY_NUM_1", "KEY_NUM_2", "KEY_CHAR_1", "DATIM", "ENTITAET", "LFD_NR_HIST", "L_AUSG_NR", "E_MANDANT", "L_TITEL_NR", "TITEL_SUCH", "TITEL1", "ISBN", "EAN", "VERLAGS_ID", "KZ_EIGEN", "AEND_DATUM", "ARTIKEL_NR", "STEUER_CODE", "SPERR_GRUND", "FELDNAME", "MELD_NR", "AUSG_TEXT", "KZ_BESTAND", "BU_SEND", "PROD_TYP", "GRUP_ID", "BAND_NR", "AUFL_DAT_IST", "AUFL_TEXT", "TITEL_UNTER") AS
  select distinct h.key_num_1, h.key_num_2, h.key_char_1,  h.datim, h.entitaet, h.lfd_nr_hist,
          m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such, t.titel1,  b.isbn,  b.ean, b.verlags_id, b.kz_eigen,
          b.aend_datum, m.artikel_nr, m.steuer_code, b.sperr_grund, h.feldname, a.meld_nr, b.ausg_text, b.kz_bestand,
          b.bu_send, b.prod_typ, b.grup_id, b.band_nr, a.aufl_dat_ist, a.aufl_text, t.titel_unter
  from historie h, buausgab b, bumanaus m, butitel t, buaufl a
 where b.l_ausg_nr  = h.key_num_1 and
            m.l_ausg_nr = b.l_ausg_nr and
            a.l_ausg_nr = b.l_ausg_nr and
            a.l_aufl_nr = 0 and
            t.l_titel_nr = b.l_titel_nr and
            entitaet = 'BUAUSGAB'
union
select distinct h.key_num_1, h.key_num_2, h.key_char_1,  h.datim, h.entitaet, h.lfd_nr_hist,
          m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such, t.titel1,  b.isbn,  b.ean, b.verlags_id, b.kz_eigen,
          b.aend_datum, m.artikel_nr, m.steuer_code, b.sperr_grund, h.feldname, a.meld_nr, b.ausg_text, b.kz_bestand,
          b.bu_send, b.prod_typ, b.grup_id, b.band_nr, a.aufl_dat_ist, a.aufl_text, t.titel_unter
  from historie h, butitel t, buausgab b, bumanaus m, buaufl a
 where  t.l_titel_nr  = h.key_num_1 and
            m.l_ausg_nr = b.l_ausg_nr and
            a.l_ausg_nr = b.l_ausg_nr and
            a.l_aufl_nr = 0 and
            b.l_titel_nr = t.l_titel_nr and
            entitaet = 'BUTITEL'  and
            (feldname = 'TITEL_SUCH' or feldname = 'TITEL1' or feldname = 'TITEL_UNTER' or  feldname = 'NEUANLAGE')
union
select distinct h.key_num_1, h.key_num_2, h.key_char_1,  h.datim, h.entitaet, h.lfd_nr_hist,
          m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such, t.titel1,  b.isbn,  b.ean, b.verlags_id, b.kz_eigen,
          b.aend_datum, m.artikel_nr, m.steuer_code, b.sperr_grund, h.feldname, a.meld_nr, b.ausg_text, b.kz_bestand,
          b.bu_send, b.prod_typ, b.grup_id, b.band_nr, a.aufl_dat_ist, a.aufl_text, t.titel_unter
  from historie h, buausgab b, bumanaus m, butitel t, buaufl a
 where m.l_ausg_nr  = h.key_num_1 and
            m.e_mandant = h.key_char_1 and
            b.l_ausg_nr = m.l_ausg_nr and
            a.l_ausg_nr = b.l_ausg_nr and
            a.l_aufl_nr = 0 and
            t.l_titel_nr = b.l_titel_nr and
            entitaet = 'BUMANAUS' and
            (feldname = 'STEUER_CODE' or feldname = 'ARTIKEL_NR')
union
select distinct h.key_num_1, h.key_num_2, h.key_char_1,  h.datim, h.entitaet, h.lfd_nr_hist,
          m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such, t.titel1,  b.isbn,  b.ean, b.verlags_id, b.kz_eigen,
          b.aend_datum, m.artikel_nr, m.steuer_code, b.sperr_grund, h.feldname, a.meld_nr, b.ausg_text, b.kz_bestand,
          b.bu_send, b.prod_typ, b.grup_id, b.band_nr, a.aufl_dat_ist, a.aufl_text, t.titel_unter
  from historie h, butitel t, buausgab b, bumanaus m, buaufl a
 where  a.l_ausg_nr  = h.key_num_1 and
            a.l_aufl_nr = h.key_num_2 and
            h.key_num_2 = 0 and
            m.l_ausg_nr = a.l_ausg_nr and
            b.l_ausg_nr = a.l_ausg_nr and
            a.l_aufl_nr = 0 and
            t.l_titel_nr = b.l_titel_nr and
            entitaet = 'BUAUFL'   and
            (feldname = 'MELD_NR' or feldname = 'AUFL_DAT_IST' or feldname = 'AUFL_TEXT');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUTIVIEW" ("L_TITEL_NR", "L_AUSG_NR", "TITEL_SUCH", "TITEL1", "SPRACH_CODE", "ORIG_TITEL", "ORG_SPR_CODE", "VERLAGS_ID", "ISBN", "EAN", "PROD_TYP", "REIHEN_CODE", "KOMBITYP", "ISSN", "AUSG_TEXT", "E_MANDANT", "ARTIKEL_NR", "SPERR_GRUND", "KZ_LOESCHEN", "L_AUFL_NR", "AUFLAGE_NR", "MELD_NR", "HERKUNFT", "KZ_AUFL_BEST", "N_ARTIKEL_NR", "AUFL_DAT_IST", "AUFL_DAT_SOLL", "AUFL_HOEHE", "BREITE", "HOEHE", "GRUP_ID", "TITEL_UNTER", "WAEHRUNG", "LAGER_MANDANT", "BU_LA_ID", "BU_SEND", "KZ_BASIS_BAND", "ANZ_BEITRAG", "AUFL_STATUS", "BESTUHLUNG", "B_ID_AEND") AS
  select t.l_titel_nr, b.l_ausg_nr,  t.titel_such, t.titel1, t.sprach_code, t.orig_titel,
       t.org_spr_code, b.verlags_id, b.isbn, b.ean, b.prod_typ,  b.reihen_code, b.kombityp,
       b.issn, b.ausg_text, m.e_mandant, m.artikel_nr, b.sperr_grund, m.kz_loeschen,
       l.l_aufl_nr, l.auflage_nr, l.meld_nr, b.herkunft, b.kz_aufl_best,
       nvl(to_number(regexp_replace(m.artikel_nr,'[^[:digit:]]')),0),
       l.aufl_dat_ist, l.aufl_dat_soll, l.aufl_hoehe, b.breite, b.hoehe, b.grup_id, t.titel_unter, l.waehrung, m.lager_mandant,
