  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUUMSAKT" ("E_MANDANT", "RECH_TYP", "DATUM", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "N_ARTIKEL_NR", "SUCH_TITEL", "KURZTITEL", "AUFLAGE_NR", "WAEHRUNG", "SUM_BERECHNET", "SUM_NETTO_BETR", "SUM_BRUTTO_BETR", "SUM_FREI_EXPL", "AKT_ID", "UAKT_ID", "HERKUNFT", "KZ_PROBEHEFT", "OBJ_NR", "AUFT_NR", "AUF_POS", "AUF_POS_ZU", "KZ_PRAEMIE", "KZ_LOESCHEN") AS
  select t.e_mandant, s.rech_typ, t.rech_dat, t.l_ausg_nr,
         t.l_aufl_nr, t.artikel_nr,
      to_number(translate(t.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
         t.titel_kurz, t.titel1,l.auflage_nr, s.waehrung, sum(t.ber_menge), sum(t.upos_sum_ne),
         sum(t.upos_sum_br), sum(t.frei_menge), o.akt_id, o.uakt_id, s.herkunft, u.kz_probeheft, u.obj_nr,
	 u.auft_nr, u.auf_pos, u.auf_pos_zu, u.kz_praemie, m.kz_loeschen
from  bufakst s, bufakpos o, bufakupo u,  buaufl l, bufakset t, bumanaus m
where (s.rech_typ     like 'R%'
  or     s.rech_typ like 'G%' or (s.rech_typ like 'L%' and s.rech_ref is null))
  and (s.rech_typ != 'RO' or s.r_art != 'P')
  and (s.rech_typ != 'RS' or s.r_art != 'P' or u.p_status_lief != 'F')
