  and s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and o.pos_nr       = u.pos_nr
  and u.rech_nr      = t.rech_nr
  and u.rech_dat     = t.rech_dat
  and u.f_mandant    = t.f_mandant
  and u.pos_nr       = t.pos_nr
  and u.upos_nr      = t.upos_nr
  and o.akt_id       is not null
  and t.l_ausg_nr    = l.l_ausg_nr
  and t.l_aufl_nr    = l.l_aufl_nr
  and t.l_ausg_nr    = m.l_ausg_nr
  and t.e_mandant    = m.e_mandant
  and ((u.bundle!='F' and u.bundle != 'E') or u.bundle is null)
  and ((u.preiskat != '$NU%' and u.preiskat != '$NU&') or u.preiskat is null)
