         t.titel_kurz, t.titel1,l.auflage_nr, s.waehrung, o.akt_id, o.uakt_id, s.herkunft, u.kz_probeheft, u.obj_nr,
	 u.auft_nr, u.auf_pos, u.auf_pos_zu, u.kz_praemie, m.kz_loeschen
union
  select u.e_mandant, s.rech_typ, u.rech_dat, u.l_ausg_nr,
