  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUUMSAKTHILF" ("RECH_NR", "RECH_DAT", "F_MANDANT", "POS_NR", "UPOS_NR", "AKT_ID", "UAKT_ID") AS
