     where p.akt_id = x.akt_id))
union
select
u.rech_nr, u.rech_dat, u.f_mandant, u.pos_nr, u.upos_nr, a.akt_id, nvl(a.uakt_id,0)
from
bufakupo u, bufakpos p, buaufpos a
where
u.rech_nr = p.rech_nr and
u.rech_dat = p.rech_dat and
u.f_mandant = p.f_mandant and
u.pos_nr = p.pos_nr and
u.auft_nr = a.auft_nr and
u.auf_pos = a.auf_pos and
p.akt_id is null and
  (a.uakt_id is not null or
