  and s.rech_ref is null
  and not exists (select * from bufakst s2 where s2.rech_ref = s.rech_nr and s.rech_dat = s2.rech_dat and s.f_mandant = s2.f_mandant and s2.kz_re_in_li = 'T' and s2.rech_typ = 'R'
                       and s2.r_formular = 'PDF' and s2.email is not null)
  and not exists (select * from buauftra a1 where a1.auft_nr = f.auft_nr and a1.auftrag_typ = 'B' and a1.fakt_soll_dat > a1.vers_soll_dat)
  and u.l_ausg_nr    = l.l_ausg_nr
  and u.l_aufl_nr    = l.l_aufl_nr
  and u.l_ausg_nr    = b.l_ausg_nr
  and u.auft_nr      = a.auft_nr
  and a.kz_kommission = 'F'
  and (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
       and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr)
      or exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
         and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr and (u.bundle = 'F' or u.bundle = 'E')))
  and u.l_ausg_nr    = m.l_ausg_nr
  and u.e_mandant    = m.e_mandant
  group by s.f_mandant, s.rech_typ, s.rech_dat, u.l_ausg_nr, u.l_aufl_nr,
         s.adr_nr_e, s.person_nr_e, u.artikel_nr,
      to_number(translate(u.artikel_nr, '0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
         u.titel1, l.auflage_nr, s.waehrung, p.a_typ, s.adr_gr, (case when o.benutzer_id is Null then '&$?&$?' else o.benutzer_id end),
         (case when o.sel_id is Null then 999999 else o.sel_id end), (case when g.sach_grp is Null then '&$?&$??&$?' else g.sach_grp end),
         l.aufl_dat_ist, u.kz_partie,
         s.herkunft, u.liz_typ, b.grup_id,s.rech_nr, u.preiskat, u.kz_strecke, u.obj_nr,
	 b.prod_typ, s.land_gr_e, s.rech_ref, u.steuer_code, u.kz_geliefert, f.auftrag_typ, s.eg_id, s.mwst_frei, b.l_titel_nr, r.ret_gr_id,
         seg.seggrup_id, u.eindr_art, u.eindr_art_abo, e.typ, u.bu_ra, b.bu_la_id, f.staord_nr, f.auft_nr, m.kz_loeschen, s.vertreter_id,
         u.raproz, s.e_mandant, f.vertret_auft_typ, s.kz_manuell, u.e_mandant, s.land_e, u.lager_code
union
  select s.f_mandant, s.rech_typ, s.rech_dat, u.l_ausg_nr, u.l_aufl_nr,
         s.adr_nr_e, s.person_nr_e, u.artikel_nr,
      to_number(translate(u.artikel_nr, '0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
         u.titel1, l.auflage_nr, s.waehrung, 0, 0, 0, 0, p.a_typ,
         s.adr_gr, (case when o.benutzer_id is Null then '&$?&$?' else o.benutzer_id end),
         (case when o.sel_id is Null then 999999 else o.sel_id end), (case when g.sach_grp is Null then '&$?&$??&$?' else g.sach_grp end),
         l.aufl_dat_ist, sum(u.gelief_men), u.kz_partie, s.herkunft, u.liz_typ, b.grup_id, s.rech_nr, u.preiskat, u.kz_strecke, u.obj_nr,
	 b.prod_typ, s.land_gr_e, s.rech_ref, u.steuer_code, u.kz_geliefert, f.auftrag_typ, s.eg_id, s.mwst_frei, b.l_titel_nr, r.ret_gr_id,
         seg.seggrup_id, u.eindr_art, u.eindr_art_abo, e.typ, u.bu_ra, b.bu_la_id, f.staord_nr, f.auft_nr, '                    ',
         m.kz_loeschen, s.vertreter_id, u.raproz, s.e_mandant, f.vertret_auft_typ, s.kz_manuell, u.e_mandant, s.land_e, u.lager_code
  from  bufakpos f, buaufl l, bumanaus m,
          bufakst s LEFT OUTER JOIN (select o1.benutzer_id, o1.sel_id, o1.adr_gr, o1.adr_nr, o1.person_nr, o1.a_typ from selpool o1
		                             group by o1.benutzer_id, o1.sel_id, o1.adr_gr, o1.adr_nr, o1.person_nr, o1.a_typ) o ON
				     s.adr_gr = o.adr_gr
                 and s.adr_nr_e = o.adr_nr
                 and s.person_nr_e = o.person_nr
             LEFT OUTER JOIN person p ON
                     s.adr_gr       = p.adr_gr
                 and s.adr_nr_e     = p.adr_nr
                 and s.person_nr_e  = p.person_nr,
          buausgab b LEFT OUTER JOIN bugruppe g ON
                        b.l_titel_nr    = g.l_titel_nr
		    LEFT OUTER JOIN busegagr seg ON
			b.grup_id = seg.grup_id,
          bufakupo u LEFT OUTER JOIN buretour r ON
                            u.auft_nr     = r.auft_nr_ersatz
                        and u.auf_pos      = r.auf_pos
                        and u.l_ausg_nr    = r.l_ausg_nr
                        and u.l_aufl_nr    = r.l_aufl_nr
                        and u.best_art     = r.best_art
                    LEFT OUTER JOIN eindrart e ON
                        e.eindr_art = u.eindr_art
where s.rech_nr      = u.rech_nr
  and s.rech_dat     = u.rech_dat
  and s.f_mandant    = u.f_mandant
  and s.rech_nr      = f.rech_nr
  and s.rech_dat     = f.rech_dat
  and s.f_mandant    = f.f_mandant
  and f.rech_nr      = u.rech_nr
  and f.rech_dat     = u.rech_dat
  and f.f_mandant    = u.f_mandant
  and f.pos_nr       = u.pos_nr
  and s.rech_typ     like 'L%'
  and s.rech_ref is null
  and not exists (select * from bufakst s2 where s2.rech_ref = s.rech_nr and s.rech_dat = s2.rech_dat and s.f_mandant = s2.f_mandant and s2.kz_re_in_li = 'T' and s2.rech_typ = 'R'
                       and s2.r_formular = 'PDF' and s2.email is not null)
  and not exists (select * from buauftra a1 where a1.auft_nr = f.auft_nr and a1.auftrag_typ = 'B' and a1.fakt_soll_dat > a1.vers_soll_dat)
  and u.l_ausg_nr    = l.l_ausg_nr
  and u.l_aufl_nr    = l.l_aufl_nr
  and u.l_ausg_nr    = b.l_ausg_nr
  and not exists (select * from buauftra a where
      u.auft_nr      = a.auft_nr)
  and (not exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
       and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr)
      or exists (select * from bufakset t where u.rech_nr = t.rech_nr and u.rech_dat = t.rech_dat and u.f_mandant = t.f_mandant
         and u.pos_nr = t.pos_nr and u.upos_nr = t.upos_nr and (u.bundle = 'F' or u.bundle = 'E')))
  and u.l_ausg_nr    = m.l_ausg_nr
  and u.e_mandant    = m.e_mandant
  group by s.f_mandant, s.rech_typ, s.rech_dat, u.l_ausg_nr, u.l_aufl_nr,
         s.adr_nr_e, s.person_nr_e, u.artikel_nr,
      to_number(translate(u.artikel_nr, '0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
         u.titel1, l.auflage_nr, s.waehrung, p.a_typ, s.adr_gr, (case when o.benutzer_id is Null then '&$?&$?' else o.benutzer_id end),
         (case when o.sel_id is Null then 999999 else o.sel_id end), (case when g.sach_grp is Null then '&$?&$??&$?' else g.sach_grp end),
         l.aufl_dat_ist, u.kz_partie,
         s.herkunft, u.liz_typ, b.grup_id,s.rech_nr, u.preiskat, u.kz_strecke, u.obj_nr,
	 b.prod_typ, s.land_gr_e, s.rech_ref, u.steuer_code, u.kz_geliefert, f.auftrag_typ, s.eg_id, s.mwst_frei, b.l_titel_nr, r.ret_gr_id,
         seg.seggrup_id, u.eindr_art, u.eindr_art_abo, e.typ, u.bu_ra, b.bu_la_id, f.staord_nr, f.auft_nr, m.kz_loeschen, s.vertreter_id,
         u.raproz, s.e_mandant, f.vertret_auft_typ, s.kz_manuell, u.e_mandant, s.land_e, u.lager_code
union
  select d.fibu_mandant, 'RT', r.ret_datum, w.l_ausg_nr, w.l_aufl_nr,
         a.adr_nr_re, a.person_nr_re, m.artikel_nr,
      to_number(translate(m.artikel_nr, '0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
         t.titel_such||'                                                                                                    ',
         l.auflage_nr, a.waehrung, 0, 0, 0, 0, p.a_typ,
         r.adr_gr, (case when o.benutzer_id is Null then '&$?&$?' else o.benutzer_id end),
         (case when o.sel_id is Null then 999999 else o.sel_id end), (case when g.sach_grp is Null then '&$?&$??&$?' else g.sach_grp end),
         l.aufl_dat_ist, sum(w.bew_menge)*(-1), 'F', b.herkunft, '  ', b.grup_id, (r.auft_nr*100000+r.auf_pos),'    ','F','   ',
	 b.prod_typ, ' ', null, '   ', 'F', ' ', '               ', ' ', b.l_titel_nr, r.ret_gr_id, seg.seggrup_id,
	 null, null, '  ', null, b.bu_la_id, null, r.auft_nr, '                    ', m.kz_loeschen, a.vertreter_id, null,
         a.e_mandant, a.vertret_auft_typ, a.kz_manuell, m.e_mandant, an.land_code, w.lager_code
  from  buretour r, buaufl l, bmandant d, bumanaus m, butitel t, bulagbew w,
          buauftra a LEFT OUTER JOIN (select o1.benutzer_id, o1.sel_id, o1.adr_gr, o1.adr_nr, o1.person_nr, o1.a_typ from selpool o1
		  group by o1.benutzer_id, o1.sel_id, o1.adr_gr, o1.adr_nr, o1.person_nr, o1.a_typ) o ON
                 a.adr_gr = o.adr_gr
                 and a.adr_nr_re = o.adr_nr
                 and a.person_nr_re = o.person_nr
             LEFT OUTER JOIN anschr an ON
                 a.adr_gr        = an.adr_gr
                 and a.adr_nr_re = an.adr_nr
             LEFT OUTER JOIN person p ON
                 a.adr_gr       = p.adr_gr
                 and a.adr_nr_re     = p.adr_nr
                 and a.person_nr_re  = p.person_nr,
          buausgab b LEFT OUTER JOIN bugruppe g ON
                        b.l_titel_nr    = g.l_titel_nr
		    LEFT OUTER JOIN busegagr seg ON
			b.grup_id = seg.grup_id
where a.auft_nr      = r.auft_nr
  and r.gut_menge is null
  and r.retour_nr    = w.retour_nr
  and r.auft_nr      = w.auft_nr
  and d.e_mandant    = r.e_mandant
  and m.e_mandant    = w.e_mandant
  and m.l_ausg_nr    = w.l_ausg_nr
  and w.l_ausg_nr    = l.l_ausg_nr
  and w.l_aufl_nr    = l.l_aufl_nr
  and w.l_ausg_nr    = b.l_ausg_nr
  and t.l_titel_nr    = b.l_titel_nr
  group by d.fibu_mandant, 'RT', r.ret_datum, w.l_ausg_nr, w.l_aufl_nr,
         a.adr_nr_re, a.person_nr_re, m.artikel_nr,
      to_number(translate(m.artikel_nr, '0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
         t.titel_such, l.auflage_nr, a.waehrung, 0, 0, 0, 0, p.a_typ,
         r.adr_gr, (case when o.benutzer_id is Null then '&$?&$?' else o.benutzer_id end),
         (case when o.sel_id is Null then 999999 else o.sel_id end), (case when g.sach_grp is Null then '&$?&$??&$?' else g.sach_grp end),
         l.aufl_dat_ist, 'F', b.herkunft, '  ', b.grup_id, (r.auft_nr*100000+r.auf_pos), '    ','F','   ', b.prod_typ, b.l_titel_nr,
         r.ret_gr_id, seg.seggrup_id, null, null, '  ', null, b.bu_la_id, null, r.auft_nr, m.kz_loeschen, a.vertreter_id, null,
         a.e_mandant, a.vertret_auft_typ, a.kz_manuell, m.e_mandant, an.land_code, w.lager_code;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUUMSTIT" ("E_MANDANT", "AUFTRAG_TYP", "DATUM", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "N_ARTIKEL_NR", "KURZTITEL", "AUFLAGE_NR", "VERLAGS_ID", "N_VERLAGS_ID", "SACH_GRP", "N_SACH_GRP", "WAEHRUNG", "SUM_BERECHNET", "SUM_FREI", "SUM_NETTO_BETR", "SUM_GUT_EXPL", "SUM_NETTO_GUTS", "SUM_POS_BETR", "GRUP_ID", "PROD_TYP", "HERKUNFT", "SO_POS_NR", "SUM_PARTIE", "SEGGRUP_ID", "KZ_LOESCHEN", "AUFL_DAT_IST", "SUM_SKONTO_NE", "SHOP_ID") AS
  select f.e_mandant, f.auftrag_typ, f.datum, f.l_ausg_nr, f.l_aufl_nr, f.artikel_nr,
      to_number(translate(f.artikel_nr, '0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
        t.titel_such, l.auflage_nr, b.verlags_id, 0,
        g.sach_grp, 0, f.waehrung,
        f.sum_berechnet, f.sum_frei,
        (select k.sum_netto_betr from bufaksum k
         where f.abruf_nr    = k.abruf_nr
           and f.l_ausg_nr   = k.l_ausg_nr
           and f.l_aufl_nr   = k.l_aufl_nr
           and f.auftrag_typ = k.auftrag_typ
           and f.preis_kat   = k.preis_kat
           and f.so_pos_id   = k.so_pos_id
           and f.so_pos_nr   = k.so_pos_nr
           and f.kz_eg       = k.kz_eg
           and f.kz_ust      = k.kz_ust
           and f.land_code   = k.land_code
           and f.steuer_code = k.steuer_code
           and f.waehrung    = k.waehrung
           and f.jahr_monat  = k.jahr_monat
           and f.datum       = k.datum
           and f.e_mandant   = k.e_mandant
           and f.mwst_satz   = k.mwst_satz
           and f.shop_id     = k.shop_id
           and f.auftrag_typ in ('B','R')),
        f.sum_remittend,
        (select i.sum_netto_betr from bufaksum i
         where f.abruf_nr    = i.abruf_nr
           and f.l_ausg_nr   = i.l_ausg_nr
           and f.l_aufl_nr   = i.l_aufl_nr
           and f.auftrag_typ = i.auftrag_typ
           and f.preis_kat   = i.preis_kat
           and f.so_pos_id   = i.so_pos_id
           and f.so_pos_nr   = i.so_pos_nr
           and f.kz_eg       = i.kz_eg
           and f.kz_ust      = i.kz_ust
           and f.land_code   = i.land_code
           and f.steuer_code = i.steuer_code
           and f.waehrung    = i.waehrung
           and f.jahr_monat  = i.jahr_monat
           and f.datum       = i.datum
           and f.e_mandant   = i.e_mandant
           and f.mwst_satz   = i.mwst_satz
           and f.shop_id     = i.shop_id
           and f.auftrag_typ = 'G'),
       f.sum_pos_betr, b.grup_id, b.prod_typ, b.herkunft, f.so_pos_nr, f.sum_partie, seg.seggrup_id, m.kz_loeschen, l.aufl_dat_ist,f.sum_skonto_ne, f.shop_id
from bufaksum f, buausgab b, bugruppe g, buaufl l, butitel t, busegagr seg, bumanaus m
where f.l_ausg_nr     = b.l_ausg_nr
  and b.l_titel_nr    = g.l_titel_nr (+)
  and b.grup_id       = seg.grup_id (+)
  and b.l_titel_nr    = t.l_titel_nr
  and f.l_ausg_nr     = l.l_ausg_nr
  and f.l_aufl_nr     = l.l_aufl_nr
  and f.auftrag_typ   in ('B','G','R','L')
  and f.l_ausg_nr     = m.l_ausg_nr (+)
  and f.e_mandant     = m.e_mandant (+)
  and f.preis_kat != '$NU%' and f.preis_kat != '$NU&';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUVGLVIE" ("STICHTAG", "LAGER_CODE", "REGAL_ID", "EBENE_ID", "PLATZ_ID", "E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "BES_MENGE", "ARTIKEL_NR", "AUFLAGE_NR", "L_TITEL_NR", "TITEL_SUCH", "ISBN", "BSI_MENGE", "BEW_NR") AS
  select  s.stichtag, w.lager_code, w.regal_id, w.ebene_id, w.platz_id, w.e_mandant, w.l_ausg_nr,
           w.l_aufl_nr, w.best_art, w.menge, m.artikel_nr, a.auflage_nr, t.l_titel_nr,
           t.titel_such, b.isbn, s.menge, s.bew_nr
 from bulagbes w, bumanaus m, buausgab b, butitel t, buaufl a, bulagbsi s
 where  m.l_ausg_nr  = w.l_ausg_nr and
            m.e_mandant  = w.e_mandant and
            b.l_ausg_nr  = w.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = w.l_ausg_nr and
            a.l_aufl_nr  = w.l_aufl_nr and
            s.e_mandant = w.e_mandant and
            s.l_ausg_nr = w.l_ausg_nr and
            s.l_aufl_nr = w.l_aufl_nr and
            s.lager_code = w.lager_code and
            s.regal_id = w.regal_id and
            s.ebene_id = w.ebene_id and
            s.platz_id = w.platz_id and
            s.menge != w.menge;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUVLVIEW" ("ADR_GR", "ADR_NR", "E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "VERLAGS_ID", "MIN_MENGE", "PARTIE_BER", "ADR_NR_VERLAG", "MIN_MENGE_VERLAG", "PARTIE_BER_VERLAG") AS
  select b.adr_gr, b.adr_nr, b.e_mandant, b.l_ausg_nr, b.l_aufl_nr, b.best_art, v.verlags_id, b.min_menge, b.partie_ber,
                      v.adr_nr,
        (select min_menge from bulieart b2 where
          b2.adr_gr  = v.adr_gr and
          b2.adr_nr  = v.adr_nr and
          b2.e_mandant   = b.e_mandant and
          b2.l_ausg_nr   = b.l_ausg_nr and
          b2.l_aufl_nr   = b.l_aufl_nr),
        (select partie_ber from bulieart b2 where
          b2.adr_gr  = v.adr_gr and
          b2.adr_nr  = v.adr_nr and
          b2.e_mandant   = b.e_mandant and
          b2.l_ausg_nr   = b.l_ausg_nr and
          b2.l_aufl_nr   = b.l_aufl_nr)
from  bulieart b, buverlag v
where b.adr_gr  = v.adr_gr and
      b.adr_nr  = v.adr_nr_li;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUVMVIEW" ("E_MANDANT", "AUFT_NR", "AUF_POS", "POS_MANDANT", "ADR_GR", "ADR_NR_RE", "PERSON_NR_RE", "ADR_NR_LE", "PERSON_NR_LE", "ADR_NR_BEST", "PERSON_NR_BEST", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "A_STATUS", "POS_STATUS", "AUFTRAG_TYP", "VORMERK_MENGE", "RESERVIERT_MENGE", "BER_MENGE", "POS_BETRAG", "BRUT_NET", "STEUER_CODE", "HERKUNFT", "VERTRETER_ID", "WAEHRUNG") AS
  select
s.e_mandant, s.auft_nr, s.auf_pos, s.e_mandant,
adr_gr, adr_nr_re, person_nr_re, adr_nr_le, person_nr_le, adr_nr_best, person_nr_best,
s.l_ausg_nr, s.l_aufl_nr, s.best_art, a.status, s.status,a.auftrag_typ,
s.vormerk_menge, s.reserviert_menge, s.ber_menge, s.pos_betrag, s.brut_net, s.steuer_code, a.herkunft,
(case when s.vertreter_id is not null then s.vertreter_id else a.vertreter_id end), a.waehrung
from buaufpos s, buauftra a
where a.auft_nr = s.auft_nr
and a.storno = 'F' and a.storno = 'F'
and a.status != 'E' and a.status != 'E'
and (s.vormerk_menge > 0 or s.reserviert_menge > 0);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUVWVIEW" ("AUFTRAG_VERW", "AUF_POS", "SUM_BER_MENGE", "SUM_FREI_MENGE", "SUM_RETOUR_MENGE") AS
  select a.auftrag_verw, s.auf_pos, sum(s.ber_menge), sum(s.frei_menge), sum(s.retour_menge)
from buaufpos s, buauftra a
where s.auft_nr  = a.auft_nr
            group by a.auftrag_verw, s.auf_pos;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUWAVIEW" ("L_AUSG_NR", "E_MANDANT", "L_TITEL_NR", "TITEL_SUCH", "ISBN", "PROD_TYP", "ARTIKEL_NR", "MELD_BEST", "MIN_BEST", "LAGER_CODE", "PREISKAT", "BEST_ART", "GUELTIG_AB", "L_AUFL_NR", "WAEHRUNG", "LIST_NR", "GES_MENGE", "WAEHRUNG_MAN", "VERLAGS_ID", "LAGER_MANDANT", "TITEL1", "GEWICHT", "ANZ_VORMERK", "KZ_HAUPTLAGER", "REGAL_ID", "EBENE_ID", "PLATZ_ID", "BEST_ART_LAGER", "KZ_AUFL_BEST", "KZ_AUFL_PREIS", "ANZ_RESERV", "N_ARTIKEL_NR", "HERKUNFT", "GRUP_ID", "KZ_LOESCHEN", "AUFL_DAT_SOLL", "AUFL_WAEHRUNG", "KZ_BEOBACHT", "AUFL_DAT_IST", "KZ_EIGEN", "STATUS", "MELD_NR") AS
