           m.artikel_nr, l.meld_best, l.min_best, l.lager_code, p.preiskat,
           p.best_art, p.gueltig_ab, a.l_aufl_nr, p.waehrung, p.list_nr, nvl(g.ges_menge,0),
           ma.waehrung, b.verlags_id, m.lager_mandant, t.titel1, b.gewicht, nvl(g.anz_vormerk,0),
           l.kz_hauptlager, l.regal_id, l.ebene_id, l.platz_id, g.best_art, b.kz_aufl_best, b.kz_aufl_preis, nvl(g.anz_reserv,0),
          to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
           b.herkunft, b.grup_id, m.kz_loeschen, a.aufl_dat_soll, a.waehrung, m.kz_beobacht, a.aufl_dat_ist,
           b.kz_eigen, a.status, a.meld_nr
  from bumanaus m, buausgab b, butitel t, bmandant ma, buaufl a, buplist p, bulagmin l, bulagges g
 where b.l_ausg_nr = m.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = m.l_ausg_nr and
            p.e_mandant  = m.e_mandant and
            p.l_ausg_nr = m.l_ausg_nr and
            b.kz_aufl_preis ='F' and
            l.e_mandant  = m.lager_mandant and
            l.l_ausg_nr  = a.l_ausg_nr and
            l.l_aufl_nr  = a.l_aufl_nr and
            g.l_ausg_nr (+)= l.l_ausg_nr and
            g.l_aufl_nr (+)= l.l_aufl_nr and
            g.lager_code (+)= l.lager_code and
            g.e_mandant (+)= l.e_mandant and
            ma.e_mandant = m.e_mandant
union
select distinct m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such,  b.isbn, b.prod_typ,
           m.artikel_nr, l.meld_best, l.min_best, l.lager_code, p.preiskat,
           p.best_art, p.gueltig_ab, a.l_aufl_nr, p.waehrung, p.list_nr, nvl(g.ges_menge,0),
           ma.waehrung, b.verlags_id, m.lager_mandant, t.titel1, b.gewicht, nvl(g.anz_vormerk,0),
           l.kz_hauptlager, l.regal_id, l.ebene_id, l.platz_id, g.best_art, b.kz_aufl_best, b.kz_aufl_preis, nvl(g.anz_reserv,0),
          to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
           b.herkunft, b.grup_id, m.kz_loeschen, a.aufl_dat_soll, a.waehrung, m.kz_beobacht, a.aufl_dat_ist,
           b.kz_eigen, a.status, a.meld_nr
  from bumanaus m, buausgab b, butitel t, bmandant ma, buaufl a, buplist p, bulagmin l, bulagges g
 where b.l_ausg_nr = m.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = m.l_ausg_nr and
            p.e_mandant  = m.e_mandant and
            p.l_ausg_nr = m.l_ausg_nr and
            p.l_aufl_nr = a.l_aufl_nr and
            b.kz_aufl_preis ='T' and
            l.e_mandant  = m.lager_mandant and
            l.l_ausg_nr  = a.l_ausg_nr and
            l.l_aufl_nr  = a.l_aufl_nr and
            g.l_ausg_nr (+)= l.l_ausg_nr and
            g.l_aufl_nr (+)= l.l_aufl_nr and
            g.lager_code (+)= l.lager_code and
            g.e_mandant (+)= l.e_mandant and
            ma.e_mandant = m.e_mandant
union
select distinct m.l_ausg_nr, m.e_mandant, t.l_titel_nr, t.titel_such,  b.isbn, b.prod_typ,
           m.artikel_nr, l.meld_best, l.min_best, l.lager_code, '    ', x.best_art ,
           TO_DATE(''), a.l_aufl_nr, '   ', 0, nvl(g.ges_menge,0),
           ma.waehrung, b.verlags_id, m.lager_mandant, t.titel1, b.gewicht, nvl(g.anz_vormerk,0),
           l.kz_hauptlager, l.regal_id, l.ebene_id, l.platz_id,g.best_art, b.kz_aufl_best, b.kz_aufl_preis, nvl(g.anz_reserv,0),
          to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
           b.herkunft, b.grup_id, m.kz_loeschen, a.aufl_dat_soll, a.waehrung, m.kz_beobacht, a.aufl_dat_ist,
           b.kz_eigen, a.status, a.meld_nr
from bumanaus m, buausgab b, butitel t, bmandant ma, buaufl a,  bulagmin l, bulagges g, bestart x
 where b.l_ausg_nr = m.l_ausg_nr and
            t.l_titel_nr  = b.l_titel_nr and
            a.l_ausg_nr  = m.l_ausg_nr and
            x.kz_standard = 'T' and
            not exists (select * from buplist p where
            p.e_mandant  = m.e_mandant and
            p.l_ausg_nr = m.l_ausg_nr) and
            l.e_mandant  = m.lager_mandant and
