            g.e_mandant (+)= l.e_mandant and
            g.best_art = x.best_art and
            ma.e_mandant = m.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."BUZUAVIE" ("BEW_NR", "LAGER_CODE", "L_AUSG_NR", "E_MANDANT", "BEST_ART", "L_AUFL_NR", "BEW_MENGE", "ARTIKEL_NR", "L_TITEL_NR", "TITEL1", "BEW_ART", "BEW_DAT", "BEW_TYP", "AB_ZU_BUCHUNG", "AUFT_NR", "AUF_POS", "HERKUNFT", "N_ARTIKEL_NR", "KZ_EIGEN", "GRUP_ID", "AUSG_TEXT", "PROD_TYP", "VERLAGS_ID", "AUFLAGE_NR", "AUFL_TEXT", "OBJ_NR", "PREISKAT_ABO", "DS_PREIS", "WAEHRUNG_DS", "RET_MENGE", "MANGEL_MENGE", "UPOS_SUM_BR", "AUFT_NR_GUT", "WB_ID", "HGRP_ID", "UGRP_ID", "PRODUKT", "RR_DATUM", "EK_NR", "KZ_LOESCHEN", "BEWERT_BASIS", "AUFL_DAT_SOLL", "WB_DS_PREIS", "RECH_NR", "RECH_DAT", "KZ_ERINNER") AS
  select  w.bew_nr, w.lager_code, w.l_ausg_nr, w.e_mandant, w.best_art, w.l_aufl_nr, w.bew_menge, m.artikel_nr,
           t.l_titel_nr, t.titel1, w.bew_art, w.bew_dat, w.bew_typ, w.ab_zu_buchung, w.auft_nr, w.auf_pos, b.herkunft,
           to_number(translate(m.artikel_nr,'0123456789^?!"???$%&/{([)]=}??\'`+*~#,;.:-_<>|??@ ABCDEFGHIJKLMNOPQRSTUVWXYZAOU','0123456789')),
           b.kz_eigen, b.grup_id, b.ausg_text, b.prod_typ, b.verlags_id, a.auflage_nr, a.aufl_text,
           (case when f.obj_nr is Null then w.obj_nr else f.obj_nr end), (case when f.preiskat_abo is Null then w.preiskat_abo else  f.preiskat_abo end),
           l.ds_preis, l.waehrung_ds, r.menge, r.mangel_menge, f.upos_sum_br, r.auft_nr_gut, coalesce (p.wb_id,'123'),
           coalesce (p.hgrp_id,'12345678'), coalesce(p.ugrp_id,'12345678'), coalesce(p.produkt,'123456789'),
           w.rr_datum, w.ek_nr, m.kz_loeschen, l.bewert_basis, a.aufl_dat_soll, l.wb_ds_preis, w.rech_nr, w.rech_dat, l.kz_erinner
 from bulagbew w, bumanaus m, buausgab b, butitel t, buaufl a, bufakupo f, bulawert l, buretour r, buartpro p
 where     m.l_ausg_nr  = w.l_ausg_nr and
           m.e_mandant  = w.e_mandant and
           b.l_ausg_nr  = w.l_ausg_nr and
           t.l_titel_nr  = b.l_titel_nr and
           a.l_ausg_nr  = w.l_ausg_nr and
           a.l_aufl_nr  = w.l_aufl_nr and
           f.e_mandant (+)  = w.e_mandant and
           f.rech_nr (+)  = w.rech_nr and
           f.rech_dat (+)  = w.rech_dat and
           f.auft_nr (+)  = w.auft_nr and
           f.auf_pos (+)  = w.auf_pos and
           f.preiskat != '$NU%' and f.preiskat != '$NU&' and
           l.l_ausg_nr   = w.l_ausg_nr and
           l.l_aufl_nr  = w.l_aufl_nr and
           l.e_mandant   = w.e_mandant and
           l.best_art  = w.best_art and
           r.retour_nr (+)  = w.retour_nr and
           p.l_ausg_nr(+) = w.l_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CDCVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "VORNAME", "NACHNAME", "A_TYP", "NAME1", "NAME2", "NAME3", "LAND_CODE", "PLZ_WOHN", "PLZ_POST", "WOHNORT", "POSTORT", "STRASSE", "POSTFACH", "ANW_REF_NR", "E_MANDANT_REF", "EG_UST_NR", "ENTITAET", "MODIFIED_ON", "AUFT_NR", "AUF_POS", "E_MANDANT_ABO", "OBJ_NR_ABO", "AUSG_ABO", "ABO_NR", "ADR_NR_LE", "PERSON_NR_LE", "TEL_ART", "SUCH_NUMMER", "UUID_AUFT") AS
  SELECT distinct
       p.adr_gr, p.adr_nr, p.person_nr,
       p.vorname, p.nachname, p.a_typ,
       a.name1, a.name2, a.name3, a.land_code, a.plz_wohn, a.plz_post,
       a.wohnort, a.postort, a.strasse, a.postfach,
       r.anw_ref_nr, r.e_mandant E_MANDANT_REF,
       i.eg_ust_nr,
       mod.entitaet, mod.modified_on,
       mod.auft_nr, mod.auf_pos,           -- BUAUFTRA
       mod.e_mandant E_MANDANT_ABO, mod.obj_nr OBJ_NR_ABO, mod.ausg AUSG_ABO, mod.abo_nr,   --ABOSTAMM
       mod.adr_nr_le, mod.person_nr_le,  ---BUAUFTRA, ABOSTAMM
       mod.tel_art, mod.such_nummer,     ---TELECOM
       u.uuid_auft
FROM  ANWREF r, anschr a  LEFT OUTER JOIN ainfo i ON
       a.adr_gr = i.adr_gr AND  a.adr_nr    = i.adr_nr,
--       person p LEFT OUTER JOIN ANWREF r ON
--       p.adr_gr  = r.adr_gr AND p.adr_nr = r.adr_nr AND p.person_nr = r.person_nr
       person p LEFT OUTER JOIN uuidref u ON
       p.adr_gr  = u.adr_gr AND p.adr_nr = u.adr_nr AND p.person_nr = u.person_nr,
       MODONview  mod
WHERE  p.adr_gr  = a.adr_gr    AND    p.adr_nr  = a.adr_nr
      AND
                 p.adr_gr  = r.adr_gr  AND    p.adr_nr  = r.adr_nr  AND p.person_nr  = r.person_nr
      AND
        ((p.adr_gr    = mod.adr_gr  and p.adr_nr    = mod.adr_nr  and p.person_nr    = mod.person_nr)
          or
         (p.adr_gr    = mod.adr_gr  and p.adr_nr    = mod.adr_nr_LE  and p.person_nr = mod.person_nr_LE)
       );


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CMAPVIEW" ("AUFT_NR", "WAEHRUNG", "STATUS", "BEST_DATUM", "BEST_TEXT", "RECH_NR", "RECH_DATUM", "BETRAG_BRUTTO", "BETRAG_NETTO", "E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "NAME3", "NACHNAME", "VORNAME", "ANREDE_CODE", "TITEL_CODE", "ADR_NR_RE", "PERSON_NR_RE", "HAUPT_NAME_RE", "HAUPT_PLZ_RE", "HAUPT_ORT_RE", "NAME1_RE", "NAME2_RE", "NAME3_RE", "NACHNAME_RE", "VORNAME_RE", "ANREDE_CODE_RE", "TITEL_CODE_RE") AS
  SELECT
      cma.auft_nr, cma.waehrung, cma.status, cma.best_datum, cma.best_text,
      cma.rech_nr, cma.rech_datum, cma.betrag_brutto, cma.betrag_netto, cma.e_mandant,
      a.adr_gr, a.adr_nr, p.person_nr, a.haupt_name, a.haupt_plz, a.haupt_ort, a.name1, a.name2, a.name3,
      p.nachname, p.vorname, p.anrede_code, p.titel_code,
      are.adr_nr, pre.person_nr, are.haupt_name, are.haupt_plz, are.haupt_ort, are.name1, are.name2, are.name3,
      pre.nachname, pre.vorname, pre.anrede_code, pre.titel_code
FROM cmauftra  cma
        LEFT OUTER JOIN anschr a ON
            cma.adr_gr        = a.adr_gr      and
            cma.adr_nr        = a.adr_nr
        LEFT OUTER JOIN person p ON
            cma.adr_gr        = p.adr_gr      and
            cma.adr_nr        = p.adr_nr      and
            cma.person_nr     = p.person_nr
        LEFT OUTER JOIN anschr are ON
            cma.adr_gr        = are.adr_gr    and
            cma.adr_nr_re     = are.adr_nr
        LEFT OUTER JOIN person pre ON
            cma.adr_gr        = pre.adr_gr    and
            cma.adr_nr_re     = pre.adr_nr    and
            cma.person_nr_re  = pre.person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CMOBJVIE" ("E_MANDANT", "OBJ_NR", "AUSG", "OBJEKTNAME", "OBJEKTNAME2", "OBJEKTART", "BEZEICHNUNG", "KZ_ABRECH", "VERLAG_NR", "KZ_LOESCHEN", "LAND_CODE", "STEUER_CODE", "ISSN_ISBN", "KZ_ONLINE", "HERKUNFT", "W_GRUPPE") AS
  select
      e.e_mandant, e.obj_nr, m.ausg, e.objektname, e.objektname2, e.objektart, m.bezeichnung, e.kz_abrech, e.verlag_nr, e.status, e.land_code, e.steuer_code, m.issn_isbn, m.kz_online, 'VZ', e.w_gruppe
from mobjtyp e, mobstamm m
where e.e_mandant=m.e_mandant and e.obj_nr=m.obj_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CMPOVIEW" ("CM_AUFTRAG_TYP", "E_MANDANT", "AUFT_NR", "AUF_POS", "AUF_UPOS_NR", "AUFT_NR_TEIL", "VERWEND_TYP_POS", "ADR_GR", "ADR_NR_BEST", "PERSON_NR_BEST", "HAUPT_NAME_BEST", "NACHNAME_BEST", "VORNAME_BEST", "ADR_NR_RE", "PERSON_NR_RE", "HAUPT_NAME_RE", "NACHNAME_RE", "VORNAME_RE", "ADR_NR_LE", "PERSON_NR_LE", "HAUPT_NAME_LE", "NACHNAME_LE", "VORNAME_LE", "BEST_DATUM", "L_VERS_DAT", "FAKT_SOLL_DAT", "AKT_ID", "UAKT_ID", "STAORD_NR", "BEG_DATUM_POS", "END_DATUM_POS", "L_AUSG_NR", "ARTIKEL_NR", "ISBN", "SO_POS_ID", "STATUS", "STATUS_POS", "STORNO_POS", "AUFTRAG_TYP", "RECH_NR", "RECH_DAT", "L_AUFL_NR", "HERKUNFT", "PRIO", "BER_MENGE", "FREI_MENGE", "GELIEF_MEN", "VERTRETER_ID", "OBJ_NR", "PREISKAT_ABO", "GRUP_ID", "BEW_ART", "AUSG", "ABO_NR", "ADR_NR_ABO", "PERSON_NR_ABO", "LIEFER_MENGE_ABO", "EINDR_ART", "BEST_TEXT", "REF_AUFT_NR", "R_ART", "KZ_KOMMISSION") AS
  select cma.auftrag_typ, cmpo.e_mandant, cmpo.auft_nr, cmpo.auf_pos, 0, cmpo.auft_nr_teil, cmpo.verwend_typ_pos,
       cma.adr_gr, cma.adr_nr, cma.person_nr, a1.haupt_name, p1.nachname, p1.vorname,
       cma.adr_nr_re, cma.person_nr_re, a2.haupt_name, p2.nachname, p2.vorname,
       cma.adr_nr_le, cma.person_nr_le, a3.haupt_name, p3.nachname, p3.vorname,
       cma.best_datum, cma.l_vers_dat, cma.fakt_soll_dat, cma.akt_id, cma.uakt_id, cmpo.staord_nr, (case when s.sto_beg is not Null then s.sto_beg else (case when m2.sto_datum is not Null then m2.sto_datum else m2.nov_dat end) end), s.sto_end,   --null, null
       cmpo.l_ausg_nr, m.artikel_nr, a.isbn, '      ', cma.status, cmpo.status, cmpo.storno, cma.auftrag_typ, -- ohne Sonderposition
       f.rech_nr, f.rech_dat, cmpo.l_aufl_nr, cma.herkunft, cma.prioritaet, cmpo.ber_menge, cmpo.frei_menge, cmpo.gelief_menge,
       cma.vertreter_id, vers.obj_nr, abo.preis_kat, a.grup_id, w.bew_art,
       vers.ausg,    ref.abo_nr, ref.adr_nr,   ref.person_nr,    vers.l_menge,     null,  cma.best_text, r.ref_auft_nr, cma.r_art, 'F' -- cma.kz_kommission
       --ABO-PK!!ausg,   abo_nr,   adr_nr_abo,   person_nr_abo,  liefer_menge_abo, eindr_art, best_text,  ref_auft_nr, r_art, kz_kommission)
from  cmaufpos cmpo
              LEFT OUTER JOIN cmposref ref ON
                   ref.auft_nr     = cmpo.auft_nr  and
                   ref.auf_pos     = cmpo.auf_pos  and
                   ref.auf_upos_nr = cmpo.auf_upos_nr
--ABOSTAMM und weitere
              LEFT OUTER JOIN abostamm abo ON
                   abo.e_mandant  = ref.e_mandant and
                   abo.obj_nr     = ref.obj_nr and
                   abo.ausg       = ref.ausg and
                   abo.adr_gr     = ref.adr_gr and
                   abo.adr_nr     = ref.adr_nr and
                   abo.person_nr  = ref.person_nr and
                   abo.abo_nr     = ref.abo_nr
              LEFT OUTER JOIN abovers vers ON
                   abo.e_mandant  = vers.e_mandant and
                   abo.obj_nr     = vers.obj_nr and
                   abo.ausg       = vers.ausg and
                   abo.adr_gr     = vers.adr_gr and
                   abo.adr_nr     = vers.adr_nr and
                   abo.person_nr  = vers.person_nr and
                   abo.abo_nr     = vers.abo_nr
--BUMANAUS, BUAUSGAB
              LEFT OUTER JOIN bumanaus m ON
                   m.e_mandant  = cmpo.e_mandant and
                   m.l_ausg_nr  = cmpo.l_ausg_nr
              LEFT OUTER JOIN bustaord s ON
                   s.e_mandant  = cmpo.e_mandant and
                   s.staord_nr  = cmpo.staord_nr
                       LEFT OUTER JOIN bumanaus m2 ON
                          m2.e_mandant  = s.e_mandant and
                          m2.l_ausg_nr  = s.l_ausg_nr_start
              LEFT OUTER JOIN buausgab a ON
                   a.l_ausg_nr  = cmpo.l_ausg_nr
              LEFT OUTER JOIN buaufref r ON
                   r.auft_nr = cmpo.auft_nr
--BUFAKUPO vs. CMFAKOPO
              LEFT OUTER JOIN bufakupo f ON
                   f.auft_nr = cmpo.auft_nr and
                   f.auf_pos = cmpo.auf_pos
                       LEFT OUTER JOIN bulagbew w ON
                            w.auft_nr = f.auft_nr and
                            w.auf_pos = f.auf_pos
--              LEFT OUTER JOIN  busopos o ON
--                   o.so_pos_id   = cmpo.so_pos_id
        , cmauftra cma LEFT OUTER JOIN person p1 ON
                   p1.adr_gr    = cma.adr_gr and
                   p1.adr_nr    = cma.adr_nr and
                   p1.person_nr = cma.person_nr
              LEFT OUTER JOIN  anschr a1 ON
                   a1.adr_gr    = cma.adr_gr and
                   a1.adr_nr    = cma.adr_nr
              LEFT OUTER JOIN  person p2 ON
                   p2.adr_gr    = cma.adr_gr and
                   p2.adr_nr    = cma.adr_nr_re and
                   p2.person_nr = cma.person_nr_re
              LEFT OUTER JOIN  anschr a2 ON
                   a2.adr_gr    = cma.adr_gr and
                   a2.adr_nr    = cma.adr_nr_re
              LEFT OUTER JOIN person p3 ON
                   p3.adr_gr    = cma.adr_gr and
                   p3.adr_nr    = cma.adr_nr_le and
                   p3.person_nr = cma.person_nr_le
              LEFT OUTER JOIN anschr a3 ON
                   a3.adr_gr    = cma.adr_gr and
                   a3.adr_nr    = cma.adr_nr_le
       where cma.auft_nr = cmpo.auft_nr
union
  select 'C3BUAUF ', s.e_mandant, s.auft_nr, s.auf_pos, 0,  s.auft_nr, 'BUCHC3          ',
       b.adr_gr, b.adr_nr_best, b.person_nr_best, a1.haupt_name, p1.nachname, p1.vorname,
       b.adr_nr_re, b.person_nr_re, a2.haupt_name, p2.nachname, p2.vorname,
       b.adr_nr_le, b.person_nr_le, a3.haupt_name, p3.nachname, p3.vorname,
       b.best_datum, b.l_vers_dat, b.fakt_soll_dat, b.akt_id, b.uakt_id, b.staord_nr, null, null,  -- s.beg_datum, s.end_datum
       s.l_ausg_nr, m.artikel_nr, a.isbn, o.so_pos_id, b.status, s.status, s.storno, b.auftrag_typ,
       f.rech_nr, f.rech_dat, s.l_aufl_nr, b.herkunft, b.prioritaet,
       s.ber_menge, s.frei_menge, s.gelief_menge, b.vertreter_id, s.obj_nr, s.preiskat_abo, a.grup_id, w.bew_art,
       s.ausg, s.abo_nr, s.adr_nr_abo, s.person_nr_abo, s.liefer_menge_abo, s.eindr_art, b.best_text, r.ref_auft_nr,
       b.r_art, b.kz_kommission
  from  buaufpos s LEFT OUTER JOIN bumanaus m ON
                   m.e_mandant  = s.e_mandant and
                   m.l_ausg_nr  = s.l_ausg_nr
              LEFT OUTER JOIN buausgab a ON
                   a.l_ausg_nr  = s.l_ausg_nr
              LEFT OUTER JOIN buaufref r ON
                   r.auft_nr = s.auft_nr
              LEFT OUTER JOIN bufakupo f ON
                   f.auft_nr = s.auft_nr and
                   f.auf_pos = s.auf_pos
                       LEFT OUTER JOIN bulagbew w ON
                            w.auft_nr = f.auft_nr and
                            w.auf_pos = f.auf_pos
              LEFT OUTER JOIN  busopos o ON
                   o.so_pos_id   = s.so_pos_id,
       buauftra b LEFT OUTER JOIN person p1 ON
                   p1.adr_gr     =b.adr_gr and
                   p1.adr_nr    = b.adr_nr_best and
                   p1.person_nr    = b.person_nr_best
              LEFT OUTER JOIN  anschr a1 ON
                   a1.adr_gr    = b.adr_gr and
                   a1.adr_nr     = b.adr_nr_best
              LEFT OUTER JOIN  person p2 ON
                   p2.adr_gr   = b.adr_gr and
                   p2.adr_nr    = b.adr_nr_re and
                   p2.person_nr  = b.person_nr_re
              LEFT OUTER JOIN  anschr a2 ON
                   a2.adr_gr     = b.adr_gr and
                   a2.adr_nr   = b.adr_nr_re
              LEFT OUTER JOIN person p3 ON
                   p3.adr_gr  = b.adr_gr and
                   p3.adr_nr   = b.adr_nr_le and
                   p3.person_nr  = b.person_nr_le
              LEFT OUTER JOIN anschr a3 ON
                   a3.adr_gr    = b.adr_gr and
                   a3.adr_nr    = b.adr_nr_le
  where b.auft_nr = s.auft_nr
  and not exists (select cma.auft_nr from cmauftra cma where cma.auft_nr=b.auft_nr)
union
  select 'C3ABO', abo.e_mandant, coalesce(abo.auftrags_nr,9999999999), abo.abo_nr, 0, 0, 'ABOC3',
       abo.adr_gr, abo.adr_nr, abo.person_nr, a1.haupt_name, p1.nachname, p1.vorname,
       abo.adr_nr_bv, abo.person_nr_bv, a2.haupt_name, p2.nachname, p2.vorname,
       abo.adr_nr,    abo.person_nr,    a3.haupt_name, p3.nachname, p3.vorname,
       abo.best_datum, null,           null,              abo.w_akt_id, abo.w_uakt_id, null,  coalesce(abo.vbeg_dat,r_beg_dat), coalesce(abo.vend_dat,r_ende_dat),
          --           abo.l_vers_dat, abo.fakt_soll_dat, abo.akt_id,   abo.uakt_id,   abo.staord_nr,
       null,             null,         null,   null,        abo.abostatus, abo.status, abo.kz_storno, 'ABO',
        --abo.l_ausg_nr, m.artikel_nr, a.isbn, o.so_pos_id, a.status,      pos.status, a.storno,      pos.auftrag_typ,
       null,        null,       null,          null,         1,
       --f.rech_nr, f.rech_dat, abo.l_aufl_nr, abo.herkunft, abo.prioritaet,
       abo.ber_menge,    avers.l_menge-abo.ber_menge,  avers.l_menge, null,       avers.obj_nr, abo.preis_kat,     null, null,
       -- pos.ber_menge, pos.frei_menge,                gelief_menge, vertreter_id, abo.obj_nr, preiskat_abo, a.grup_id, w.bew_art,
       avers.ausg,  avers.abo_nr, avers.adr_nr, avers.person_nr, avers.l_menge,    null,      abo.best_nr, '  ',       abo.r_art, null
       --PK!!  ausg,    abo_nr,   adr_nr_abo,   person_nr_abo,   liefer_menge_abo, eindr_art, best_text,  ref_auft_nr, r_art, kz_kommission)
   from abostamm abo LEFT OUTER JOIN person p1 ON
                   p1.adr_gr     = abo.adr_gr and
                   p1.adr_nr     = abo.adr_nr and
                   p1.person_nr  = abo.person_nr
              LEFT OUTER JOIN  anschr a1 ON
                   a1.adr_gr     = abo.adr_gr and
                   a1.adr_nr     = abo.adr_nr
              LEFT OUTER JOIN  person p2 ON
                   p2.adr_gr     = abo.adr_gr and
                   p2.adr_nr     = abo.adr_nr_bv and
                   p2.person_nr  = abo.person_nr_bv
              LEFT OUTER JOIN  anschr a2 ON
                   a2.adr_gr     = abo.adr_gr and
                   a2.adr_nr     = abo.adr_nr_bv
              LEFT OUTER JOIN person p3 ON
                   p3.adr_gr     = abo.adr_gr and
                   p3.adr_nr     = abo.adr_nr and
                   p3.person_nr  = abo.person_nr
              LEFT OUTER JOIN anschr a3 ON
                   a3.adr_gr     = abo.adr_gr and
                   a3.adr_nr     = abo.adr_nr
       , abovers avers	-- JOIN auf abobvers
   where abo.adr_gr = avers.adr_gr and abo.adr_nr = avers.adr_nr and abo.person_nr = avers.person_nr
     and abo.e_mandant = avers.e_mandant and abo.obj_nr = avers.obj_nr and abo.ausg = avers.ausg and abo.abo_nr = avers.abo_nr
     and not exists (select cmr.auft_nr from cmposref cmr where cmr.adr_gr=abo.adr_gr and cmr.adr_nr = abo.adr_nr and cmr.person_nr = abo.person_nr
                    and cmr.e_mandant=abo.e_mandant and cmr.obj_nr = abo.obj_nr and cmr.ausg = abo.ausg and cmr.abo_nr = abo.abo_nr)
union   -- Standing-Order-Auftrage / Fortsetzungsauftrage
select 'C3BUFO', s.e_mandant, s.staord_nr, 99999, 0, s.staord_nr, 'BUFOC3          ',
       s.adr_gr, s.adr_nr_best, s.person_nr_best, a1.haupt_name, p1.nachname, p1.vorname,
       s.adr_nr_re, s.person_nr_re, a2.haupt_name, p2.nachname, p2.vorname,
       s.adr_nr_le, s.person_nr_le, a3.haupt_name, p3.nachname, p3.vorname,
       s.best_datum, null, s.fakt_soll_dat, s.akt_id, s.uakt_id, s.staord_nr, (case when s.sto_beg is not Null then s.sto_beg else (case when m2.sto_datum is not Null then m2.sto_datum else m2.nov_dat end) end), s.sto_end,   --case anstatt s.sto_beg
       s.l_ausg_nr_k, m.artikel_nr, a.isbn, '', s.status, s.status, s.storno, s.auftrag_typ,
       null, null, 0, '', s.prioritaet,
       s.ber_menge, s.frei_menge, null, s.vertreter_id, '', '', a.grup_id, '',
       '', null, null, null, null, null, s.best_text, null,
       s.r_art, null
  --from  buaufpos s LEFT OUTER JOIN bumanaus m ON
    from  bustaord s LEFT OUTER JOIN bumanaus m ON
                   m.e_mandant  = s.e_mandant and
                   m.l_ausg_nr  = s.l_ausg_nr_k
           LEFT OUTER JOIN bumanaus m2 ON
                   m2.e_mandant  = s.e_mandant and
                   m2.l_ausg_nr  = s.l_ausg_nr_start
           LEFT OUTER JOIN buausgab a ON
                   a.l_ausg_nr  = s.l_ausg_nr_k
               LEFT OUTER JOIN person p1 ON
                   p1.adr_gr     =s.adr_gr and
                   p1.adr_nr    = s.adr_nr_best and
                   p1.person_nr  = s.person_nr_best
              LEFT OUTER JOIN  anschr a1 ON
                   a1.adr_gr    = s.adr_gr and
                   a1.adr_nr     = s.adr_nr_best
              LEFT OUTER JOIN  person p2 ON
                   p2.adr_gr   = s.adr_gr and
                   p2.adr_nr    = s.adr_nr_re and
                   p2.person_nr  = s.person_nr_re
              LEFT OUTER JOIN  anschr a2 ON
                   a2.adr_gr     = s.adr_gr and
                   a2.adr_nr   = s.adr_nr_re
              LEFT OUTER JOIN person p3 ON
                   p3.adr_gr  = s.adr_gr and
                   p3.adr_nr   = s.adr_nr_le and
                   p3.person_nr  = s.person_nr_le
              LEFT OUTER JOIN anschr a3 ON
                   a3.adr_gr    = s.adr_gr and
                   a3.adr_nr    = s.adr_nr_le
  where 1=1
  and not exists (select cmp.auft_nr_teil from cmaufpos cmp where cmp.staord_nr=s.staord_nr and verwend_typ_pos='BUFO');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CO_SB_B2B" ("ID_SB2CO_KR", "SB_KONTAKT_ID_HAUPT", "SB_ADR_ID_HAUPT", "CO_ADR_ID_HAUPT", "SB_KONTAKT_ID_UNTER", "SB_ADR_ID_UNTER", "CO_ADR_ID_UNTER", "VERWEISTYP", "STATUS", "AENDERUNG", "VERARBEITET") AS
  select r.id_sb2co,
h.sb_kontakt_id, ha.sb_adr_id, ha.co_adr_id,
u.sb_kontakt_id, ua.sb_adr_id, ua.co_adr_id,
r.art, r.status, r.aenderung, r.verarbeitet
from sb2co_kont_rel r, sb2co_kontakt h, sb2co_kontakt u, sb2co_adr ha, sb2co_adr ua
where r.id_sb_haupt=h.sb_kontakt_id and h.art='U' and h.sb_kontakt_id=ha.sb_kontakt_id and ha.standard=1
and   r.id_sb_unter=u.sb_kontakt_id and u.art='U' and u.sb_kontakt_id=ua.sb_kontakt_id and ua.standard=1;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."COVER_KBART_PRODUCT" ("RECORDIDENTIFIER", "PRODUCTFORM", "DISTINCTIVETITLE", "PRODUCTISBN13", "PRINTPRODUCTISBN13", "PRODUCTDOI", "LANGUAGEOFTEXT", "PRODUCTWEBSITELINK", "MAINSUBJECT", "PUBLISHERNAME", "PUBLCATIONDATE", "PRINTPUBLICATIONDATE", "OUTOFPRINTDATE", "PRODUCTAVAILABILITY", "INSTITUTIONALPRICE", "EDITIONNUMBER", "PACKAGEID", "PACKAGENAME", "LASTCHANGED", "ACCESS_TYPE", "OA_TYPE", "MEDIUM", "PUBLISHERORDERID") AS
  select
substr(to_char(k.l_ausg_nr),1,20), rtrim(k.ProductForm), rtrim(t.titel1), rtrim(a.isbn),
rtrim(p.isbn),
rtrim(a.doi), rtrim(t.sprach_code), rtrim(k.ProductWebsiteLink),
rtrim(k.MainSubject), rtrim(v.verlag_kurz),
to_char(k.PublicationDate,'YYYYMMDD'), to_char(k.PrintPublicationDate,'YYYYMMDD'), to_char(k.OutOfPrintDate, 'YYYYMMDD'),
rtrim(k.ProductAvailability),
ltrim(to_char(to_number(k.SinglePrice),'99999990D99')),
rtrim(k.EditionNumber), rtrim(k.PackageID), rtrim(k.PackageName),
to_char(k.LastChanged, 'YYYYMMDD'),
rtrim(k.access_type), rtrim(k.oa_type), rtrim(k.medium), rtrim(k.artikel_nr)
from bukbart k, buausgab a, butitel t, buverlag v, buausgab p
where k.l_ausg_nr = a.l_ausg_nr
and a.l_titel_nr = t.l_titel_nr
and v.verlags_id = a.verlags_id
and p.l_ausg_nr(+) = k.l_ausg_nr_print;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."COVER_KBART_PRODUCTCONTRIBUTOR" ("RECORDIDENTIFIER", "SEQUENCENUMBER", "CONTRIBUTORROLE", "NAMESBEFOREKEY", "KEYNAMES") AS
  select
substr(to_char(k.l_ausg_nr),1,20), 1, 'author',
(select trim(vorname) from buautor where l_titel_nr = k.l_titel_nr and autor_typ='A' and
sort = (select min(sort) from buautor where l_titel_nr = k.l_titel_nr and autor_typ='A')),
rtrim(k.first_author)
from bukbart k
where first_author is not null
union select
substr(to_char(k.l_ausg_nr),1,20), 2, 'editor',
(select trim(vorname) from buautor where l_titel_nr = k.l_titel_nr and autor_typ='H' and
sort = (select min(sort) from buautor where l_titel_nr = k.l_titel_nr and autor_typ='H')),
rtrim(k.first_editor)
from bukbart k
where first_editor is not null;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."COVER_KBART_PRODUCTSERIES" ("RECORDIDENTIFIER", "TITLEOFSERIES", "NUMBERWITHINSERIES") AS
  select
substr(to_char(k.l_ausg_nr),1,20),rtrim(k.TitleOfSeries), rtrim(k.NumberWithinSeries)
from bukbart k;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."COVSYNVI" ("E_MANDANT", "ADR_GR", "VERWEND_TYP", "BENUTZER_ID", "PASSWORT", "E_ANW", "SIGNATUR", "URL_WSDL", "ADR_GR_ZIEL", "E_MANDANT_ZIEL") AS
  SELECT c.e_mandant, c.adr_gr, s.verwend_typ, c.benutzer_id, c.passwort,
       c.e_anw, c.signatur, c.url_wsdl, c.adr_gr_ziel, c.e_mandant_ziel
FROM   covsync c, covsyncs s
WHERE c.e_mandant = s.e_mandant
AND   c.adr_gr    = s.adr_gr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CO2JD_V4" ("ID", "OBJEKT", "JAHR", "HEFT_NR", "AUSGABE", "AUFTRAGSSTATUS", "PRODUKT", "MOTIV_ID", "MOTIV", "PLAZIERUNG_ID", "PLAZIERUNG", "PLAZIERUNG_BEMERKUNG", "RUBRIK", "DISPOSITIONSART", "INSERTIONSART", "RESSORT_ID", "EVT_DATUM", "ANZEIGENERLOES", "DISPO_BEMERKUNG", "ABRECHNUNGSART_ID", "ANZEIGENART_ID", "FORMAT_ID", "FARB_ID", "MM_HOEHE_DISPO", "MM_BREITE_DISPO", "MM_HOEHE_DU", "MM_BREITE_DU", "ANSCHNITT_DU", "DU_BEMERKUNG", "DOKUMENT_PFAD", "ADR_NR", "SUCHNAME", "KUNDE", "PLZ", "ORT", "LAND", "CHANGE_ID", "AUFT_NR", "DISPO_NR") AS
  SELECT /*+ RULE */ -- ORACLE Hint '+ RULE' = Explicitly chooses rule-based optimization for a statement block.
  TRIM(TO_CHAR (p.adr_nr, '0000000000') || TO_CHAR (MOD (p.auft_nr, 100), 'fm00') || TO_CHAR (p.dispo_nr * 10 + p.dispopos_nr, 'fm0000') || DECODE(r.lfd_nr, NULL, '00', TO_CHAR (r.lfd_nr, 'fm00'))) ID
, DECODE(s.obj_nr, NULL, p.obj_nr, SUBSTR(s.eob_ssc,1,3)) objekt
, p.jahr jahr
, p.hnr heft_nr
, DECODE(s.obj_nr, NULL, p.ausg, SUBSTR(s.eob_ssc,5,2)) ausgabe
, REPLACE (p.status, 'L', 'S') auftragsstatus
, TRIM(NVL (p.abw_prod_bez, p.prodname)) produkt
, TO_CHAR (p.adr_nr * 10000 + p.lfd_nr_du) motiv_id
, TRIM(p.motiv) motiv
, TRIM(p.plazierungs_id) plazierung_id
, TRIM(p.plaz_ext) plazierung
, TRIM(p.plaz_int) plazierung_bemerkung
, TRIM(r.bezeichnung) rubrik
, REPLACE (r.bezeichnung, r.bezeichnung, 'Rubrikanzeige') dispositionsart
, TRIM(z.beschreibung) insertionsart
, TRIM(i.ressort_id) ressort_id
, k.datum_evt evt_datum
, TO_CHAR(d.netto_betrag / d.anz_anzeigen, 'FM9999999D00', 'NLS_NUMERIC_CHARACTERS = ,.') anzeigenerloes
, TRIM(o.notiz) dispo_bemerkung
, TRIM (d.abrech_id) abrechnungsart_id
, TRIM(d.anzart_id) anzeigenart_id
, TRIM(c.BEZ_KURZ) format_id
, d.farb_id farb_id
, d.anz_mm mm_hoehe_dispo
, decode(e.anzeige, 'TT', (d.anz_sp * f.mm_text_sp + (d.anz_sp-1) * f.mm_abst_text_sp), 'AT', (d.anz_sp * f.mm_anz_sp + (d.anz_sp-1) * f.mm_abst_anz_sp), 0) mm_breite_dispo
, u.mm_hoehe mm_hoehe_du
, u.mm_breite mm_breite_du
, u.kz_anschnitt anschnitt_du
, TRIM(u.notiz) du_bemerkung
, REPLACE (u.dat_nr, u.dat_nr, u.dtp_nr || u.dat_nr) dokument_pfad
, a.adr_nr adr_nr
, TRIM(a.haupt_name) suchname
, TRIM(TRIM(TRIM(TRIM(TRIM(a.name1) || ' ' || a.name2) || ' ' || a.name3) || ' ' || n.nachname) || ' ' || n.vorname) kunde
, TRIM(a.haupt_plz) plz
, TRIM(a.haupt_ort) ort
, TRIM(a.land_code) land
, NVL((to_number(u.DU_MANUSKR_AM - u.DATUM_NEU)*86400),0) + NVL((to_number(d.ZEIT_AEND - d.DATUM_NEU)*86400),0) change_id
, d.auft_nr auft_nr
, d.dispo_nr dispo_nr
 FROM
   anzart z
 , eobjfrmm e
 , eobjform f
 , adnotiz o
 , dispplaz i
 , drubrik r
 , dunterl u
 , person n
 , anschr a
 , kalendea k
 , dispo d
 , dispopos p
 , eobstass s
--  , (select OBJ_NR, AUSG, EOB_SSC from eobstass where e_mandant = '01' and anw_ref_nr = 'JD') s
 , format c
 WHERE p.auft_hist_nr = 0
 AND p.dispo_hist_nr = 0
-- AND p.e_mandant = '01'
 AND p.adr_gr = d.adr_gr
 AND p.adr_nr = d.adr_nr
 AND p.auft_nr = d.auft_nr
 AND p.auft_hist_nr = d.auft_hist_nr
 AND p.dispo_nr = d.dispo_nr
 AND p.dispo_hist_nr = d.dispo_hist_nr
 AND p.e_mandant = k.e_mandant
 AND p.obj_nr = k.obj_nr
 AND p.ausg = k.ausg
 AND p.jahr = k.jahr
 AND p.hnr = k.hnr
 AND p.adr_gr = a.adr_gr
 AND p.adr_nr = a.adr_nr
 AND p.adr_gr = n.adr_gr
 AND p.adr_nr = n.adr_nr
 AND n.person_nr = 0
 AND p.e_mandant = u.e_mandant(+)
 AND p.adr_gr = u.adr_gr(+)
 AND p.adr_nr = u.adr_nr(+)
 AND p.lfd_nr_du = u.lfd_nr_du(+)
 AND p.du_hist_nr = u.du_hist_nr(+)
 AND p.adr_gr = r.adr_gr(+)
 AND p.adr_nr = r.adr_nr(+)
 AND p.auft_nr = r.auft_nr(+)
 AND p.auft_hist_nr = r.auft_hist_nr(+)
 AND p.dispo_nr = r.dispo_nr(+)
 AND p.dispo_hist_nr = r.dispo_hist_nr(+)
 AND p.dispopos_nr = r.dispopos_nr(+)
 AND p.adr_gr = i.adr_gr(+)
 AND p.adr_nr = i.adr_nr(+)
 AND p.auft_nr = i.auft_nr(+)
 AND p.auft_hist_nr = i.auft_hist_nr(+)
 AND p.dispo_nr = i.dispo_nr(+)
 AND p.dispo_hist_nr = i.dispo_hist_nr(+)
 AND p.dispopos_nr = i.dispopos_nr(+)
 AND p.adr_gr = o.adr_gr(+)
 AND p.adr_nr = o.adr_nr(+)
 AND p.auft_nr = o.auft_nr(+)
 AND p.auft_hist_nr = o.auft_hist_nr(+)
 AND p.dispo_nr = o.dispo_nr(+)
 AND p.dispo_hist_nr = o.dispo_hist_nr(+)
 AND d.e_mandant = e.e_mandant(+)
 AND d.obj_nr = e.obj_nr(+)
 AND d.ausg = e.ausg(+)
 AND d.anzart_id = e.anzart_id(+)
 -- AND (e.anzeige in ('TT', 'AT') or e.anzeige is NULL)
 AND d.e_mandant = f.e_mandant(+)
 AND d.obj_nr = f.obj_nr(+)
 AND d.ausg = f.ausg(+)
 AND d.anzart_id = z.anzart_id
 AND d.anzart_id <> 'SK'
 AND p.obj_nr = s.obj_nr(+)
 AND p.ausg = s.ausg(+)
 AND s.anw_ref_nr = 'JD'
 AND d.format_id = c.format_id(+)
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CR_ABOVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "ABO_NR", "ADR_NR_BV", "PERSON_NR_BV", "ABOSTATUS", "ABOART", "VARIANTE", "KZ_STORNO", "BER_MENGE", "W_AKT_ID", "W_UAKT_ID", "VBEG_DAT", "VBEG_JAHR", "VBEG_HEFT", "VEND_DAT", "VEND_JAHR", "VEND_HEFT", "PREIS_KAT", "WAEHRUNG", "R_ART", "PREIS_KAT_NO", "NO_ENDE_DAT", "NO_ENDE_JAHR", "NO_ENDE_HNR", "R_BEG_DAT", "R_BEG_JAHR", "R_BEG_HNR", "R_ENDE_DAT", "R_ENDE_JAHR", "R_ENDE_HNR", "LAND_CODE", "KGS_BL", "VERSAND_ADR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "PLZ_WOHN", "WOHNORT", "STRASSE", "HAUSNR", "STRASSE2", "HAUSNR_ZUS", "PLZ_POST", "POSTORT", "POSTFACH", "PLZ_GK", "GKORT", "KGS") AS
  select s.adr_gr, s.adr_nr, s.person_nr, s.e_mandant, s.obj_nr, s.ausg, s.abo_nr,
       s.adr_nr_bv, s.person_nr_bv, s.abostatus, s.aboart, s.variante, s.kz_storno, s.ber_menge,
       s.w_akt_id, s.w_uakt_id,
       s.vbeg_dat, s.vbeg_jahr, s.vbeg_heft,
       s.vend_dat, s.vend_jahr, s.vend_heft,
       s.preis_kat, s.waehrung, s.r_art,
       s.preis_kat_no, s.no_ende_dat, s.no_ende_jahr, s.no_ende_hnr,
       s.r_beg_dat, s.r_beg_jahr, s.r_beg_hnr,
       s.r_ende_dat, s.r_ende_jahr, s.r_ende_hnr,
       a.land_code, a.kgs_bl, a.versand_adr, a.haupt_name, a.haupt_plz, a.haupt_ort,
       a.plz_wohn, a.wohnort, a.strasse, a.hausnr, a.strasse2, a.hausnr_zus,
       a.plz_post, a.postort, a.postfach,
       a.plz_gk, a.gkort, i.kgs
from abostamm s, anschr a, ainfo i
where s.adr_gr  = a.adr_gr
   and s.adr_nr = a.adr_nr
   and s.adr_gr = i.adr_gr
   and s.adr_nr = i.adr_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CRM_SELIMPORTV" ("MANDANT", "AKTION_ID", "UNTERAKTION_ID", "UNTERAKTION_BEZ", "SEL_BENUTZER_ID", "SEL_ID", "SEL_BEZ") AS
  SELECT m.e_mandant,m.akt_id,m.uakt_id,m.b_uaktid,m.benutzer_id,m.sel_id,v.bez
FROM
    muaktion m
    JOIN selverwa v ON (m.benutzer_id=v.benutzer_id and m.sel_id=v.sel_id and v.sel_form = 'S'
    AND NOT EXISTS (select * from svorschr r where r.benutzer_id=v.benutzer_id and r.sel_id=v.sel_id));


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."CRMVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "ADR_NR_VERW", "PERSON_NR_VERW", "BEREICH", "VERWEND_TYP", "VERWEND_TYP_BEZ", "PRIO", "A_TYP_VERW", "BESCHREIBUNG") AS
  select p1.adr_gr, p1.adr_nr, p1.person_nr,
	p1.privat_adr_nr, 0,
	'SY', 'PRIVATP', 'Privatperson',
	1, 'P',
	rtrim(p2.anrede_code)||','||rtrim(p2.titel_code)||', '||rtrim(p2.vorname)||' '||rtrim(p2.nachname)||', '||rtrim(a.haupt_plz)||' '||rtrim(a.haupt_ort)||', '||rtrim(a.strasse)
from PERSON p1, PERSON p2, ANSCHR a
where	p1.adr_gr = p2.adr_gr
and	p1.privat_adr_nr = p2.adr_nr
and	p1.adr_gr = a.adr_gr
and	p1.privat_adr_nr = a.adr_nr
union
select p1.adr_gr, p1.privat_adr_nr, 0,
	p1.adr_nr, p1.person_nr,
	'SY', 'MITARB', 'Mitarbeiter',
	1, 'M',
	rtrim(a.name1)||','||rtrim(p2.anrede_code)||','||rtrim(p2.titel_code)||', '||rtrim(p2.vorname)||' '||rtrim(p2.nachname)||', '||rtrim(a.haupt_plz)||' '||rtrim(a.haupt_ort)||', '||rtrim(a.strasse)
from PERSON p1, PERSON p2, ANSCHR a
where	p1.adr_gr = p2.adr_gr
and	p1.privat_adr_nr = p2.adr_nr
and	p1.adr_gr = a.adr_gr
and	p1.adr_nr = a.adr_nr
union
select v.adr_gr, v.adr_nr, v.person_nr,
	v.adr_nr_verw, v.person_nr_verw,
	'BU', 'BUREMP', 'abw.Rechempf.Buch',
	2, p2.a_typ,
