from AVERWEIS v, PERSON p2, ANSCHR a
where	v.verweistyp = 'BUREMP'
and	v.adr_gr = p2.adr_gr
and	v.adr_nr_verw = p2.adr_nr
and	v.person_nr_verw = p2.person_nr
and	v.adr_gr = a.adr_gr
and	v.adr_nr_verw = a.adr_nr
union
select v.adr_gr, v.adr_nr_verw, v.person_nr_verw,
	v.adr_nr, v.person_nr,
	'BU', 'BUREMPK', 'Buchkunde zu abw.Rechempf.',
	2, p2.a_typ,
	coalesce(rtrim(p2.vorname), rtrim(a.name1))||' '||coalesce(rtrim(p2.nachname), rtrim(a.name2))||', '||rtrim(a.haupt_plz)||' '||rtrim(a.haupt_ort)||', '||rtrim(a.strasse)
from AVERWEIS v, PERSON p2, ANSCHR a
where	v.verweistyp = 'BUREMP'
and	v.adr_gr = p2.adr_gr
and	v.adr_nr = p2.adr_nr
and	v.person_nr = p2.person_nr
