  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."C2WARTVI" ("BEREICH", "LFD_NR", "SKU", "E_MANDANT", "ADR_GR", "TRANSFER_ID", "L_AUSG_NR", "L_AUFL_NR", "AKT_ID", "UAKT_ID", "OBJ_NR", "AUSG", "LFD_NR_AKTVORB", "SHOP_STATUS", "SICHTBARKEIT", "PROD_VERW_TYP", "ABO_TYP", "SUCH_FELD_1", "SUCH_FELD_2", "WS_ID", "STORE_ID", "ROOT_KAT_ID", "WB_ID", "HGRP_ID", "UGRP_ID", "PRODUKT", "L_TITEL_NR", "PREIS_TYP", "BESTELL_MENGE_TYP", "KOMBITYP", "KZ_ELTERN_PRODUKT", "VERSAND_KOST_GRP") AS
  select	'BU', c.lfd_nr, c.sku, c.e_mandant, c.adr_gr, c.transfer_id, c.l_ausg_nr, c.l_aufl_nr,
	c.akt_id, c.uakt_id, c.obj_nr, c.ausg, c.lfd_nr_aktvorb, c.shop_status, c.sichtbarkeit,
	c.prod_verw_typ, c.abo_typ, upper(trim(m.artikel_nr)),
	upper(CASE WHEN (g.l_titel_nr = 0)
	THEN CASE WHEN (l.auflage_nr > 0)
	     THEN l.auflage_nr || ' / ' || COALESCE(trim(s.artikel_bez),trim(g.ausg_text))
	     ELSE
		  COALESCE(trim(s.artikel_bez),trim(g.ausg_text))
	     END
	ELSE CASE WHEN (l.auflage_nr > 0)
	     THEN l.auflage_nr || ' / ' || COALESCE (trim(t.titel_such),trim(g.ausg_text))
	     ELSE
	          COALESCE (trim(t.titel_such),trim(g.ausg_text))
	     END
	END),
	k.ws_id, k.store_id, k.root_kat_id, k.wb_id, k.hgrp_id, k.ugrp_id, k.produkt, c.l_titel_nr, c.preis_typ, c.bestell_menge_typ, g.kombityp, c.kz_eltern_produkt,
	c.versand_kost_grp
from C2WART c
JOIN BUMANAUS m ON (m.e_mandant = c.e_mandant and m.l_ausg_nr = c.l_ausg_nr)
JOIN BUAUSGAB g ON (g.l_ausg_nr = c.l_ausg_nr and g.herkunft is null)
LEFT JOIN BUAUFL l ON (l.l_ausg_nr = c.l_ausg_nr and l.l_aufl_nr = c.l_aufl_nr)
LEFT JOIN BUTITEL t ON (t.l_titel_nr = g.l_titel_nr)
LEFT JOIN BUAUSSPR s ON (s.l_ausg_nr = c.l_ausg_nr and s.sprach_code = 'D')
LEFT JOIN C2WARTK k ON (k.lfd_nr_c2wart = c.lfd_nr)
union
select	'VA', c.lfd_nr, c.sku, c.e_mandant, c.adr_gr, c.transfer_id, c.l_ausg_nr, c.l_aufl_nr,
	c.akt_id, c.uakt_id, c.obj_nr, c.ausg, c.lfd_nr_aktvorb, c.shop_status, c.sichtbarkeit,
	c.prod_verw_typ, c.abo_typ, upper(trim(m.artikel_nr)),
	upper(CASE WHEN (g.l_titel_nr = 0)
	THEN CASE WHEN (l.auflage_nr > 0)
	     THEN l.auflage_nr || ' / ' || COALESCE(trim(s.artikel_bez),trim(g.ausg_text))
	     ELSE
		  COALESCE(trim(s.artikel_bez),trim(g.ausg_text))
	     END
	ELSE CASE WHEN (l.auflage_nr > 0)
	     THEN l.auflage_nr || ' / ' || COALESCE (trim(t.titel_such),trim(g.ausg_text))
	     ELSE
	          COALESCE (trim(t.titel_such),trim(g.ausg_text))
	     END
	END),
	k.ws_id, k.store_id, k.root_kat_id, k.wb_id, k.hgrp_id, k.ugrp_id, k.produkt, c.l_titel_nr, c.preis_typ, c.bestell_menge_typ, g.kombityp, c.kz_eltern_produkt,
	c.versand_kost_grp
from C2WART c
JOIN BUMANAUS m ON (m.e_mandant = c.e_mandant and m.l_ausg_nr = c.l_ausg_nr)
JOIN BUAUSGAB g ON (g.l_ausg_nr = c.l_ausg_nr and g.herkunft = 'VA')
LEFT JOIN BUAUFL l ON (l.l_ausg_nr = c.l_ausg_nr and l.l_aufl_nr = c.l_aufl_nr)
LEFT JOIN BUTITEL t ON (t.l_titel_nr = g.l_titel_nr)
LEFT JOIN BUAUSSPR s ON (s.l_ausg_nr = c.l_ausg_nr and s.sprach_code = 'D')
LEFT JOIN C2WARTK k ON (k.lfd_nr_c2wart = c.lfd_nr)
union
select 'VZ', c.lfd_nr, c.sku, c.e_mandant, c.adr_gr, c.transfer_id, c.l_ausg_nr, c.l_aufl_nr,
	c.akt_id, c.uakt_id, c.obj_nr, c.ausg, c.lfd_nr_aktvorb, c.shop_status, c.sichtbarkeit,
	c.prod_verw_typ, c.abo_typ, upper(trim(c.obj_nr) || '-' || trim(c.ausg) || '-' || trim(c.akt_id) || '-' || c.uakt_id || '-' || c.lfd_nr_aktvorb),
	upper(CASE WHEN a.beschreibung is not null
	THEN trim(a.beschreibung)
	ELSE trim(h.b_aktid)
	END),
	k.ws_id, k.store_id, k.root_kat_id, k.wb_id, k.hgrp_id, k.ugrp_id, k.produkt, c.l_titel_nr, c.preis_typ, c.bestell_menge_typ, ' ', c.kz_eltern_produkt,
	c.versand_kost_grp
from C2WART c
JOIN AKTVORB a ON (a.e_mandant = c.e_mandant and a.akt_id = c.akt_id and a.obj_nr = c.obj_nr and a.ausg = c.ausg and a.lfd_nr = c.lfd_nr_aktvorb)
JOIN MHAKTION h ON (h.e_mandant = c.e_mandant and h.akt_id = c.akt_id)
LEFT JOIN C2WARTK k ON (k.lfd_nr_c2wart = c.lfd_nr);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."C2WMVIEW" ("AUFT_NR", "ADR_GR", "E_MANDANT", "ADR_NR_RE", "PERSON_NR_RE", "ADR_NR_LE", "PERSON_NR_LE", "ADR_NR_BEST", "PERSON_NR_BEST", "BEST_DATUM", "AUF_POS", "L_AUSG_NR", "L_AUFL_NR", "STATUS_POS", "GELIEF_MENGE", "ARTIKEL_NR", "LFD_NR_C2WART", "SHOP_STATUS", "LFD_NR", "STATUS", "VERWEND_TYP", "DATEIPFAD", "DATEINAME", "MEDIEN_URL") AS
  select	a.auft_nr, a.adr_gr, a.e_mandant, a.adr_nr_re, a.person_nr_re, a.adr_nr_le, a.person_nr_le,
	a.adr_nr_best, a.person_nr_best, a.best_datum, p.auf_pos, p.l_ausg_nr, p.l_aufl_nr, p.status, p.gelief_menge,
	u.artikel_nr, w.lfd_nr, w.shop_status, m.lfd_nr, m.status, m.verwend_typ,
	m.dateipfad, m.dateiname, m.medien_url
from	buauftra a, buaufpos p, bumanaus u, c2wart w, c2wartmed m
where	a.auft_nr = p.auft_nr and a.adr_gr = w.adr_gr and a.e_mandant = w.e_mandant
	and p.e_mandant = u.e_mandant and p.l_ausg_nr = u.l_ausg_nr
	and p.l_ausg_nr = w.l_ausg_nr and p.l_aufl_nr = w.l_aufl_nr
	and w.lfd_nr = m.lfd_nr_c2wart;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."C4APVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "NAME3", "PLZ_WOHN", "STRASSE", "HAUSNR", "STRASSE2", "HAUSNR_ZUS", "PLZ_POST", "POSTFACH", "POSTORT", "LAND_CODE", "F_TYP", "FIRMKZ_ID", "GENFILT_ID", "WOHNORT", "BEZIRK_ID", "KZ_LOESCHEN", "A_TYP", "NACHNAME", "VORNAME", "N_ZUSATZ", "TITEL_CODE", "ANREDE_CODE", "PRIVAT_ADR_NR", "AQUELL_CODE", "ABTEILUNG", "KZ_DUBL", "PLZ_GK", "GKORT", "KONZERN_ID", "VERLBER_ID", "KGS_BL", "NIELSEN_ID", "SPRACH_CODE", "POSITION", "BEMERKUNG", "VERSAND_ADR") AS
  SELECT a.adr_gr, a.adr_nr, p.person_nr, a.haupt_name, a.haupt_plz, a.haupt_ort,
       a.name1, a.name2, a.name3, a.plz_wohn, a.strasse, a.hausnr, a.strasse2, a.hausnr_zus,
       a.plz_post, a.postfach, a.postort, a.land_code, a.f_typ, a.firmkz_id, a.genfilt_id,
       a.wohnort, a.bezirk_id, p.kz_loeschen, p.a_typ, p.nachname, p.vorname, p.n_zusatz,
       p.titel_code, p.anrede_code, p.privat_adr_nr,
       a.aquell_code, p.abteilung, a.kz_dubl, a.plz_gk, a.gkort,
       a.konzern_id, a.verlber_id, a.kgs_bl, a.nielsen_id,
       p.sprach_code, p.position, p.bemerkung, a.versand_adr
FROM   anschr a, person p
WHERE  p.adr_gr            = a.adr_gr
AND    p.adr_nr            = a.adr_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."DBV_IVW" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "JAHR", "HNR", "ADR_NR_BV", "PERSON_NR_BV", "PREIS_KAT", "L_MENGE", "IVW_LIST", "ZUS_KAT", "RAB_KAT", "WAEHRUNG", "FAKT_ZR", "INAUS") AS
  select
      v.e_mandant,v.adr_gr,v.adr_nr,v.person_nr,v.u_obj_nr,v.u_ausg,v.abo_nr,v.jahr,v.hnr,a.adr_nr_bv,a.person_nr_bv,
      a.preis_kat,v.l_menge,v.ivw_list,az.rz_kat,ar.rz_kat,a.waehrung,a.fakt_zr,a.inaus
from vershist v, abostamm a, abofakt af
	left outer join aborab ar on
	ar.adr_gr=af.adr_gr
and	ar.adr_nr=af.adr_nr
and   	ar.person_nr=af.person_nr
and   	ar.obj_nr=af.obj_nr
and   	ar.ausg=af.ausg
and   	ar.e_mandant=af.e_mandant
and   	ar.abo_nr=af.abo_nr
	left outer join abozus az on
	az.adr_gr=af.adr_gr
and	az.adr_nr=af.adr_nr
and   	az.person_nr=af.person_nr
and   	az.obj_nr=af.obj_nr
and   	az.ausg=af.ausg
and   	az.e_mandant=af.e_mandant
and   	az.abo_nr=af.abo_nr

where	v.adr_gr=a.adr_gr
and	v.adr_nr=a.adr_nr
and   	v.person_nr=a.person_nr
and   	v.obj_nr=a.obj_nr
and   	v.ausg=a.ausg
and   	v.e_mandant=a.e_mandant
and   	v.abo_nr=a.abo_nr
and	af.adr_gr=a.adr_gr
and	af.adr_nr=a.adr_nr
and   	af.person_nr=a.person_nr
and   	af.obj_nr=a.obj_nr
and   	af.ausg=a.ausg
and   	af.e_mandant=a.e_mandant
and   	af.abo_nr=a.abo_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."DOKBVIEW" ("ERFASSER_ID", "DATUM_AKT", "LFD_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "VERFASSER_ID", "BETREFF", "TEXT_NR", "DOK_ART", "VERWEND_TYP", "BESCHREIBUNG", "B_ID_NEU", "DATUM_NEU", "ZIEL", "N_ART", "DOK_TYP", "LFD_NR_DOK") AS
  select  d.erfasser_id, d.datum_akt, d.lfd_nr, b.adr_gr, b.adr_nr,
                     b.person_nr, b.verfasser_id, b.betreff, b.text_nr,
                     d.dok_art, d.verwend_typ, d.beschreibung, d.b_id_neu,
                     d.datum_neu, d.ziel, d.n_art, d.dok_typ, d.lfd_nr_dok
from bericht b, dokberi d
where d.erfasser_id = b.erfasser_id and
               d.datum_akt = b.datum_akt and
               d.lfd_nr = b.lfd_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."DPLAVIEW" ("ADR_GR", "ADR_NR", "AUFT_NR", "AUFT_HIST_NR", "DISPO_NR", "DISPO_HIST_NR", "DISPOPOS_NR", "E_MANDANT", "OBJ_NR", "AUSG", "OBJ_NR_DISPO", "JAHR", "HNR", "HNR_NUM", "STATUS_DISPOPOS", "PRODUKT", "PRODNAME", "ABW_PROD_BEZ", "MOTIV", "MOTIV_FOLGE", "PLAZ_INT", "PLAZ_EXT", "SEITE", "ANZART_ID", "DATUM_NEU", "ANZ_SCHALTUNG", "FARB_ID", "ANZ_SI", "ANZ_MM", "ANZ_EINTRAG", "STATUS", "FORMAT_ID", "VOLUMEN_FA", "VOLUMEN_MM", "NETTO_BETRAG", "ANZEIGEN_BETRAG", "WA_PROV_BETRAG", "KOMBI_RABATT", "SONDER_RABATT", "VOLUMEN_RABATT", "WA_PROV_SATZ", "ANZ_ZEILEN", "ANZ_SP", "ANZ_ANZEIGEN", "ANZ_SEITEN", "AGV_NR", "RECH_NR", "RECH_NR_FAKT", "RECH_DATUM", "HAUPT_NAME", "ABRECH_ID", "BEZIRK_ID", "UMS_ANT_WT1", "WAEHRUNG", "VERWEND_TYP", "DATUM_EVT", "PLAZIERUNGS_ID", "RUBRIK_ID", "RUBRIK_BEZ", "ANZ_RUBRIK", "RESSORT_ID") AS
  select p.adr_gr, p.adr_nr, p.auft_nr, p.auft_hist_nr,
       p.dispo_nr, p.dispo_hist_nr, p.dispopos_nr, p.e_mandant, p.obj_nr,
       p.ausg, d.obj_nr, p.jahr, p.hnr, p.hnr_num, p.status, p.produkt, p.prodname,
       p.abw_prod_bez, p.motiv, p.motiv_folge, p.plaz_int, p.plaz_ext, p.seite,
       d.anzart_id, d.datum_neu, d.anz_schaltung, d.farb_id, d.anz_si, d.anz_mm,
       d.anz_eintrag, d.status, d.format_id,
       d.volumen_fa, d.volumen_mm, d.netto_betrag, d.anzeigen_betrag,
        d.wa_prov_betrag, d.kombi_rabatt, d.sonder_rabatt,
        d.volumen_rabatt, d.wa_prov_satz, d.anz_zeilen, d.anz_sp, d.anz_anzeigen,
        d.anz_seiten, d.agv_nr, d.rech_nr, d.rech_nr_fakt, d.rech_datum,
	a.haupt_name, d.abrech_id, b.bezirk_id,
        b.ums_anteil_proz, g.waehrung,
        g.verwend_typ, k.datum_evt, p.plazierungs_id, r.rubrik_id, r.bezeichnung,
        r.anz_belegung,z.ressort_id
from   dispopos p LEFT OUTER JOIN kalendea k ON
       p.e_mandant = k.e_mandant and p.obj_nr = k.obj_nr and
       p.ausg = k.ausg and p.jahr = k.jahr and p.hnr = k.hnr
                  LEFT OUTER JOIN drubrik r ON
       p.adr_gr = r.adr_gr  and p.adr_nr = r.adr_nr  and p.auft_nr = r.auft_nr
       and p.auft_hist_nr = r.auft_hist_nr  and p.dispo_nr = r.dispo_nr  and
       p.dispo_hist_nr = r.dispo_hist_nr  and p.dispopos_nr = r.dispopos_nr
                  LEFT OUTER JOIN dispplaz z ON
       p.adr_gr = z.adr_gr  and p.adr_nr = z.adr_nr  and p.auft_nr = z.auft_nr and
       p.auft_hist_nr = z.auft_hist_nr  and p.dispo_nr = z.dispo_nr  and
       p.dispo_hist_nr = z.dispo_hist_nr  and p.dispopos_nr = z.dispopos_nr ,
       dispo d, anschr a, adbezirk b, auftrag g
where  p.auft_hist_nr = 0 and p.dispo_hist_nr = 0 and
       p.adr_gr = d.adr_gr and p.adr_nr = d.adr_nr and p.auft_nr = d.auft_nr and
       p.auft_hist_nr = d.auft_hist_nr and p.dispo_nr = d.dispo_nr and
       p.dispo_hist_nr = d.dispo_hist_nr and
       p.adr_gr = a.adr_gr and p.adr_nr = a.adr_nr and
       p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr and p.auft_nr = b.auft_nr and
       b.auft_hist_nr = 0 and b.dispo_nr = 0 and b.dispo_hist_nr = 0 and
       b.f_typ_nr = 'WT1' and
       p.adr_gr = g.adr_gr and p.adr_nr = g.adr_nr and p.auft_nr = g.auft_nr and
       g.auft_hist_nr = 0 and g.kz_inaktiv='F';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."EACRMV_ANZEIGEN" ("MODIFIED_ON", "BESTELL_NR_EXTERN", "AUFTRAG_ID", "AUFTRAG_ID2", "LEISTUNGSEMPFAENGER_ID", "LEISTUNGSEMPFAENGER_NAME", "LEISTUNGSEMPFAENGER", "RECHNUNGEMPFAENGER_ID", "RECHNUNGSEMPFAENGER_NAME", "RECHNUNGSEMPFAENGER_ZH", "RECHNUNGSEMPFAENGER", "RECHNUNGSEMPFAENGER_PNR", "AGENTUR_ID", "AGENTUR_NAME", "AGENTUR", "ADRESS_GRUPPE", "ADRESS_NUMMER", "AUFTRAGS_NUMMER", "DISPO_NUMMER", "DISPOSITON_NUMMER", "DISPO_ID", "MANDANT", "WAEHRUNG", "AUFTRAG_OBJEKT", "AUFTRAG_TEILBELEGUNG", "AUFTRAG_HEFT_VON", "AUFTRAG_JAHR_VON", "AUFTRAG_HEFT_BIS", "AUFTRAG_JAHR_BIS", "AUFTRAG_LAUFZEIT_VON", "AUFTRAG_LAUFZEIT_BIS", "DISPO_OBJEKT", "DISPO_TEILBELEGUNG", "DISPO_STATUS", "AUFTRAG_VOM", "DISPOSITION_OBJEKT", "DISPOSITION_TEILBELEGUNG", "DISPOSITION_HEFT", "DISPOSITION_JAHR", "DISPOSITION_LAUFZEIT_VON", "DISPOSITION_LAUFZEIT_BIS", "DATUM_EVT", "DISPOSITION_STATUS", "PRODUKT", "MOTIV", "PLATZIERUNG_ID", "DU_STATUS", "ANZEIGENART_ID", "ANZEIGENART", "FORMAT_ID", "FARB_ID", "PREIS_LISTE", "ANZAHL_SCHALTUNGEN", "PREIS_GESAMT", "ZUSCHLAG_RABATT", "KOMBIRABATT_PROZ", "SONDERRABATT_PROZ", "AUFTRAGSRABATT_PROZ", "AUFTRAGSRABATT", "AGENTURPROVISION_PROZ", "AGENTURPROVISION", "NETTOBETRAG", "NETTOBETRAG_SCHALTUNG", "ABRECHNUNGSART", "ZAHLUNGSBEDINGUNG", "ZAHLUNGSART", "RECHNUNGSDATUM", "RECHNUNGS_NUMMER", "RECHNUNGS_NUMMER_FAKT", "FAKTURA_STATUS", "WERBEABGABE_BETRAG", "MWST_BASISBETRAG", "MWST_PROZ", "MWST_BETRAG", "RECHNUNGS_BETRAG", "DATUM_NEUANLAGE", "BENUTZER_NEUANLAGE", "DATUM_AENDERUNG", "BENUTZER_AENDERUNG", "VERTRETER") AS
  SELECT
  D.modified_on, TREF.key_ext_char_3,
	('anz-' || D.ADR_GR || '-' || D.ADR_NR || '-' || D.AUFT_NR),
  ('anz-' || D.ADR_GR || '-' || D.ADR_NR || '-' || D.AUFT_NR || '-' || D.DISPO_NR || '-' || DPOS.DISPOPOS_NR),
	('c-unt-' || D.adr_nr),
	TRIM (AA.name1),
  D.adr_nr,
  (CASE
    WHEN (PR.person_nr > 0) THEN
      ('c-mit-' || PR.adr_nr_beleg || '-' || PR.person_nr)
    ELSE
      ('c-unt-' || PR.adr_nr_beleg)
   END),
  AR.name1,
  (
		TRIM (PRR.nachname) || CASE
		WHEN (PRR.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (PRR.vorname)
	),
  PR.adr_nr_beleg,
  (CASE
    WHEN (PR.person_nr > 0) THEN
      (PR.person_nr)
    ELSE
      0
    END),
	(CASE
		WHEN (A.adr_nr_wa IS NULL) THEN
			''
		ELSE
			('c-age-' || A.adr_nr_wa)
		END),
	(CASE
		WHEN (A.adr_nr_wa IS NULL) THEN
			''
		ELSE
			TRIM (aw.name1)
		END),
  A.adr_nr_wa,
  A.adr_gr, A.adr_nr, A.auft_nr, DPOS.dispo_nr, DPOS.dispopos_nr,
  case when (D.datum_neu >= '08.02.2019') then
    ltrim(substr(DPOS.adr_nr+1000000,2,6),'0')||DPOS.e_mandant||substr(DPOS.auft_nr+10000,2,4)||substr(DPOS.dispo_nr+10000,2,4)||substr(DPOS.dispopos_nr+100,2,2)||'00'
  else
    ltrim(substr(DPOS.adr_nr+1000000,2,6),'0')||substr(DPOS.auft_nr+10000,2,4)||substr(DPOS.dispo_nr+10000,2,4)||substr(DPOS.dispopos_nr+100,2,2)||'00'
  end,
  A.e_mandant,
  A.waehrung,
  A.obj_nr,
  A.ausg,
  A.hnr_ab,
  A.jahr_ab,
  A.hnr_bis,
  A.jahr_bis,
  A.auftrag_vom,
  A.auftrag_bis,
 	D.obj_nr,
  D.ausg,
	D.STATUS,
	D.BDATUM,
  DPOS.obj_nr,
  DPOS.ausg,
  DPOS.hnr,
  DPOS.jahr,
  DPOS.schalt_von,
  DPOS.schalt_bis,
  KA.datum_evt,
  DPOS.status,
	DPOS.PRODUKT,
	DPOS.MOTIV,
	DPOS.PLAZIERUNGS_ID,
	DPOS.DRUCK_ID,
 	D.ANZART_ID,
	D.ANZART_BEZ,
	D.FORMAT_ID,
  D.FARB_ID,
 	D.ANZEIGEN_PREIS,
  D.anz_schaltung,
	D.ANZEIGEN_BETRAG,
	NVL (RABATT.RABATT, 0),
  D.kombi_rabatt,
  D.sonder_rabatt,
  D.volumen_rabatt,
	D.VOLRAB_BETRAG,
  D.wa_prov_satz,
	D.WA_PROV_BETRAG,
	D.netto_betrag,
  D.netto_betrag / coalesce(D.anz_schaltung,1),
	D.ABRECH_ID,
  D.z_bed_id,
	D.ZAHLUNGSART,
  D.rech_datum,
  (CASE
    WHEN (D.rech_nr > 0) THEN
      D.rech_nr
    ELSE
      null
    END),
  (CASE
    WHEN (D.rech_nr_fakt > 0) THEN
      D.rech_nr_fakt
    ELSE
      null
    END),
	(CASE
		WHEN (D.RECH_NR > 0) THEN
			'gestellt'
		ELSE
			'offen'
		END),
  RI.betrag_werbe_abg,
  RE.mwst_basis,
  RE.mwst_satz,
  RE.mwst_betrag,
  RE.vorzeichen * RE.rech_betrag,
	D.datum_neu,
	D.b_id_neu,
	D.datum_aend,
	D.B_id_aend,
	VER.vertreter
FROM
	DISPO D
LEFT JOIN AUFTRAG A ON (
	A.adr_gr = D.adr_gr
	AND A.adr_nr = D.adr_nr
	AND A.auft_nr = D.AUFT_NR
	AND A.AUFT_HIST_NR = D.AUFT_HIST_NR
)
LEFT JOIN APOSTWEG PR ON (
	PR.adr_gr = D.adr_gr
	AND PR.adr_nr = D.adr_nr
	AND PR.auft_nr = D.auft_nr
	AND PR.auft_hist_nr = D.auft_hist_nr
  AND PR.belegart_id = 'R'
)
LEFT JOIN anschr AA ON (
	A.adr_gr = AA.adr_gr
	AND A.adr_nr = AA.adr_nr
)
LEFT JOIN anschr AW ON (
	A.adr_gr = AW.adr_gr
	AND A.adr_nr_wa = AW.adr_nr
)
LEFT JOIN anschr AR ON (
	PR.adr_gr = AR.adr_gr
	AND PR.adr_nr_beleg = AR.adr_nr
)
LEFT JOIN person PRR ON (
	PRR.adr_gr = PR.adr_gr
	AND PRR.adr_nr = PR.adr_nr_beleg
  AND PRR.person_nr = PR.person_nr and PR.person_nr > 0
)
LEFT JOIN (
	SELECT
		DSO.adr_gr,
		DSO.adr_nr,
		DSO.auft_nr,
		DSO.dispo_nr,
		SUM (DSO.BETRAG) RABATT
	FROM
		DSOKOST DSO
	WHERE
		DSO.dispo_hist_nr = 0
	  AND DSO.auft_hist_nr = 0
	GROUP BY
		DSO.adr_gr,
		DSO.adr_nr,
		DSO.auft_nr,
		DSO.dispo_nr
) RABATT ON (
	RABATT.adr_gr = D.adr_gr
	AND RABATT.adr_nr = D.adr_nr
	AND RABATT.auft_nr = D.auft_nr
	AND RABATT.dispo_nr = D.dispo_nr
)
LEFT JOIN RECHNUNG RE ON (
	RE.RECH_NR = D.RECH_NR
  AND RE.RECH_DATUM = D.RECH_DATUM
)
LEFT JOIN RECHINFO RI ON (
	RI.RECH_NR = D.RECH_NR
  AND RI.RECH_DATUM = D.RECH_DATUM
)
LEFT JOIN (DISPOPOS DPOS LEFT JOIN KALENDEA KA ON
  DPOS.e_mandant = KA.e_mandant
  AND DPOS.obj_nr = KA.obj_nr
  AND DPOS.ausg = KA.ausg
  AND DPOS.jahr = KA.jahr
  AND DPOS.hnr = KA.hnr
  )
ON (
	DPOS.adr_gr = D.adr_gr
	AND DPOS.adr_nr = D.adr_nr
	AND DPOS.auft_nr = D.AUFT_NR
  AND DPOS.auft_hist_nr = D.AUFT_HIST_NR
	AND DPOS.dispo_nr = D.DISPO_NR
	AND DPOS.dispo_hist_nr = D.DISPO_HIST_NR
)
LEFT JOIN (
	SELECT
		adr_gr,
		adr_nr,
		auft_nr,
		listagg (TRIM(VERTRETER_ID), ',') WITHIN GROUP (ORDER BY VERTRETER_ID) vertreter
	FROM
		ADVERT
	WHERE
    auft_hist_nr = 0
		AND dispo_hist_nr = 0
	GROUP BY
		adr_gr,
		adr_nr,
		auft_nr
) VER ON (
	VER.adr_gr = D.adr_gr
	AND VER.ADR_NR = D.ADR_NR
	AND VER.AUFT_NR = D.AUFT_NR
)
LEFT JOIN transref TREF ON (
  TREF.transfer_id = 'COVCRM_' || d.e_mandant
  AND TREF.kunde = 'FAL'
  AND TREF.bereich = 'BUABO'
  AND TREF.verwend_typ = 'WSVIMP'
  AND TREF.referenz_typ = 'EXT_NR_AUFT_NR'
  AND TREF.key_cov_char_1 = d.adr_gr
	AND TREF.key_cov_char_3 = to_char(d.adr_nr)
	AND TREF.key_cov_char_4 = d.auft_nr
	AND TREF.key_cov_char_5 = to_char(d.dispo_nr)
)
WHERE
	D.DISPO_HIST_NR = 0
AND D.AUFT_HIST_NR = 0;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."EACRMV_WAFKTZU" ("MODIFIED_ON", "ADR_GR", "ADR_NR", "PRODUKT", "ADR_NR_WA", "WAFKT_ID", "WAFKT_BEZ", "AKTIV_BIS", "KZ_LOESCH", "HERKUNFT_ID", "WB_ID", "HGRP_ID", "UGRP_ID", "BEZ", "PERSON_NR_WA") AS
  select wt.modified_on, wa.adr_gr, wa.adr_nr, wa.produkt, wa.adr_nr_wa, wa.wafkt_id, wf.bez, wa.aktiv_bis,
	wt.kz_loesch, wt.herkunft_id, p.wb_id, p.hgrp_id, p.ugrp_id, p.bez, wp.person_nr
from WAFKTZU wa
left join (wafktps wp join person ps on wp.adr_gr = ps.adr_gr and wp.adr_nr_wa = ps.adr_nr and wp.person_nr = ps.person_nr and (ps.kz_loeschen is null or ps.kz_loeschen = 'F'))
on wa.adr_gr = wp.adr_gr and wa.adr_nr = wp.adr_nr and wa.produkt = wp.produkt and wa.adr_nr_wa = wp.adr_nr_wa
left join WAFKT wf on wa.wafkt_id = wf.wafkt_id
join WTPROD wt on wa.adr_gr  = wt.adr_gr and wa.adr_nr  = wt.adr_nr and wa.produkt = wt.produkt
join PRODUKT p on wa.produkt = p.produkt;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."EAISVIEW" ("ADR_GR", "ADR_NR", "AUFT_NR", "AUFT_HIST_NR", "DISPO_NR", "DISPO_HIST_NR", "DISPOPOS_NR", "E_MANDANT", "OBJ_NR", "AUSG", "OBJ_NR_DISPO", "JAHR", "HNR", "HNR_NUM", "STATUS_DISPOPOS", "ABRECH_ID", "ANZART_ID", "DATUM_NEU", "DATUM_AEND", "DATUM_AEND_AUFT", "ANZ_SCHALTUNG", "FARB_ID", "ANZ_SI", "ANZ_MM", "ANZ_EINTRAG", "STATUS", "FORMAT_ID", "VOLUMEN_FA", "VOLUMEN_MM", "VOLUMEN_TK", "NETTO_BETRAG", "ANZEIGEN_BETRAG", "WA_PROV_BETRAG", "VOLRAB_BETRAG", "WA_PROV_BASIS", "MWST_ANTEIL", "KOMBI_RABATT", "SONDER_RABATT", "VOLUMEN_RABATT", "WA_PROV_SATZ", "ANZ_ZEILEN", "ANZ_SP", "ANZ_ANZEIGEN", "ANZ_SEITEN", "BEZIRK_ID", "UMS_ANT_BEZIRK", "F_TYP_BEZIRK", "VERTRETER_ID", "UMS_ANT_VERT", "F_TYP_VERT", "KONZERN_ID", "HAUPT_NAME", "HAUPT_ORT", "KZ_LOESCHEN", "KZ_EINMAL_KD", "BEZIRK_ID_ANSCHR", "WAEHRUNG", "PRODUKT", "PRODUKT_NIE", "VERWEND_TYP", "DATUM_EVT", "ADR_NR_WA", "RUBRIK_ID", "RUB_BEZEICHNUNG", "RUB_ANZ_BELEGUNG", "SCHALT_VON", "SCHALT_BIS", "HERKUNFT_ID", "ANZ_GRAMM", "ANZART_BEZ", "BEZ_SI", "PLAZIERUNGS_ID", "PLAZ_EXT") AS
  select p.adr_gr, p.adr_nr, p.auft_nr, p.auft_hist_nr,
        p.dispo_nr, p.dispo_hist_nr, p.dispopos_nr, p.e_mandant, p.obj_nr,
        p.ausg, d.obj_nr, p.jahr, p.hnr, p.hnr_num, p.status,
	d.abrech_id, d.anzart_id, d.datum_neu, d.datum_aend, g.datum_aend,
        d.anz_schaltung, d.farb_id, d.anz_si, d.anz_mm,
        d.anz_eintrag, d.status, d.format_id,
	d.volumen_fa, d.volumen_mm, 0, d.netto_betrag, d.anzeigen_betrag,
        d.wa_prov_betrag, d.volrab_betrag, d.wa_prov_basis, d.mwst_anteil,
	d.kombi_rabatt, d.sonder_rabatt, d.volumen_rabatt,
        d.wa_prov_satz, d.anz_zeilen, d.anz_sp, d.anz_anzeigen,d.anz_seiten,
        b.bezirk_id, b.ums_anteil_proz, b.f_typ_nr,
        v.vertreter_id, v.um_ant_proz, v.f_typ_nr, a.konzern_id,
        a.haupt_name, a.haupt_ort, e.kz_loeschen, e.kz_einmal_kd, a.bezirk_id,
        g.waehrung, p.produkt, '', g.verwend_typ, k.datum_evt, g.adr_nr_wa,
        r.rubrik_id, r.bezeichnung, r.anz_belegung, p.schalt_von, p.schalt_bis, d.herkunft_id,
        d.anz_gramm, d.anzart_bez, d.bez_si, p.plazierungs_id, p.plaz_ext
from   dispopos p LEFT OUTER JOIN kalendea k ON
       p.e_mandant = k.e_mandant and p.obj_nr = k.obj_nr and
       p.ausg = k.ausg and p.jahr = k.jahr and p.hnr = k.hnr
                  LEFT OUTER JOIN adbezirk b ON
       p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr and p.auft_nr = b.auft_nr and
       p.auft_hist_nr = b.auft_hist_nr and b.dispo_nr = 0 and b.dispo_hist_nr = 0
                  LEFT OUTER JOIN advert v ON
       p.adr_gr = v.adr_gr and p.adr_nr = v.adr_nr and p.auft_nr = v.auft_nr and
       p.auft_hist_nr = v.auft_hist_nr and v.dispo_nr = 0 and v.dispo_hist_nr = 0
                  LEFT OUTER JOIN drubrik r ON
       p.adr_gr = r.adr_gr and p.adr_nr = r.adr_nr and p.auft_nr = r.auft_nr and
       p.auft_hist_nr = r.auft_hist_nr and
       p.dispo_nr = r.dispo_nr and p.dispo_hist_nr = r.dispo_hist_nr and
       p.dispopos_nr = r.dispopos_nr,
       dispo d, anschr a, person e, auftrag g
where
       p.adr_gr = d.adr_gr and
       p.adr_nr = d.adr_nr and p.auft_nr = d.auft_nr and
       p.auft_hist_nr = d.auft_hist_nr and p.dispo_nr = d.dispo_nr and
       p.dispo_hist_nr = d.dispo_hist_nr and
       p.adr_gr = a.adr_gr and p.adr_nr = a.adr_nr and
       p.adr_gr = e.adr_gr and p.adr_nr = e.adr_nr and e.person_nr = 0 and
       p.adr_gr = g.adr_gr and p.adr_nr = g.adr_nr and p.auft_nr = g.auft_nr and
       p.auft_hist_nr = g.auft_hist_nr and g.kz_inaktiv='F' and
       p.hnr_num > 2005000;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."EAKAVIEW" ("OBJ_NR", "AUSG", "JAHR", "HNR", "DISPO_NR", "ADR_GR", "ADR_NR", "HNR_NUM", "ANZART_ID", "ANZEIGEN_PREIS", "ANZ_SI", "FARB_ID", "FORMAT_ID", "KZ_SONDERPREIS", "ANZ_SEITEN", "ANZ_GRAMM", "PLAZ_EXT", "PLAZIERUNGS_ID", "PRODUKT", "KZ_EIGEN", "PRODNAME", "MOTIV", "ANZ_FORMAT", "ANZ_SCHALT", "ANZ_MM", "ANZ_SP", "VOLUMEN", "SEITE", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "LAND_CODE", "FIRMKZ_ID", "F_TYP", "GENFILT_ID", "WB_ID", "HGRP_ID", "UGRP_ID") AS
  SELECT k.obj_nr, k.ausg, k.jahr, k.hnr, k.dispo_nr, k.adr_gr, k.adr_nr,
       k.hnr_num, k.anzart_id, k.anzeigen_preis, k.anz_si,
       k.farb_id, k.format_id, k.kz_sonderpreis, k.anz_seiten, k.anz_gramm,
       k.plaz_ext, k.plazierungs_id, k.produkt, k.kz_eigen, k.prodname, k.motiv,
       k.anz_format, k.anz_schalt, k.anz_mm, k.anz_sp, k.volumen, k.seite,
       a.haupt_name, a.haupt_plz, a.haupt_ort, a.name1,
       a.land_code, a.firmkz_id, a.f_typ, a.genfilt_id,
       p.wb_id, p.hgrp_id, p.ugrp_id
FROM   kadispo k LEFT OUTER JOIN produkt p ON
       k.produkt = p.produkt,
       anschr a
WHERE  k.adr_gr        = a.adr_gr
AND    k.adr_nr        = a.adr_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."EARDVIEW" ("OBJ_NR", "AUSG", "JAHR", "HNR", "ADR_GR", "ADR_NR", "LFD_NR", "HNR_NUM", "E_MANDANT", "SEITE", "ART", "PRODUKT", "BEITRAG_NR", "STICHWORT", "STICHWORT1", "STICHWORT2", "B_ID_NEU", "DATUM_NEU", "B_ID_AEND", "DATUM_AEND", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "LAND_CODE", "FIRMKZ_ID", "F_TYP", "GENFILT_ID") AS
  SELECT r.obj_nr, r.ausg, r.jahr, r.hnr, r.adr_gr, r.adr_nr, r.lfd_nr,
       r.hnr_num, r.e_mandant, r.seite, r.art, r.produkt, r.beitrag_nr,
       r.stichwort, r.stichwort1, r.stichwort2,
       r.b_id_neu, r.datum_neu, r.b_id_aend, r.datum_aend,
       a.haupt_name, a.haupt_plz, a.haupt_ort, a.name1,
       a.land_code, a.firmkz_id, a.f_typ, a.genfilt_id
FROM   rdktver r, anschr a
WHERE  r.adr_gr        = a.adr_gr
AND    r.adr_nr        = a.adr_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ECWTRVIE" ("LFD_NR", "EAN_TYP", "SATZART", "ZU_SATZART", "AD5_TYP", "FELD", "TR_SATZ_ID", "TR_POS_NR", "AUFT_NR", "AUF_POS", "WERT") AS
  select e.lfd_nr, e.ean_typ, e.satzart, e.zu_satzart, e.ad5_typ, e.feld, e.tr_satz_id, e.tr_pos_nr,
t.auft_nr, t.auf_pos, e.wert
from ecwerte e, trbupos t
where e.transfer_id = t.transfer_id
and e.kunde_tr = t.kunde
and e.bereich_tr = t.bereich
and e.verwend_typ_tr = t.verwend_typ
and e.tr_satz_id = t.tr_satz_id
and e.tr_pos_nr = t.tr_pos_nr
and e.tr_pos_nr > 0
union
select e.lfd_nr, e.ean_typ, e.satzart, e.zu_satzart, e.ad5_typ, e.feld, e.tr_satz_id, 0,
(select max(t.auft_nr) from trbupos t
where e.transfer_id = t.transfer_id
and e.kunde_tr = t.kunde
and e.bereich_tr = t.bereich
and e.verwend_typ_tr = t.verwend_typ
and e.tr_satz_id = t.tr_satz_id ),
0, e.wert
from ecwerte e
where e.tr_pos_nr = 0;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."EMAIVIEW" ("ERFASSER_ID", "DATUM_AKT", "LFD_NR", "LFD_NR_ANSCHR", "ADR_GR", "ADR_NR", "PERSON_NR", "NACHNAME", "VORNAME", "VERFASSER_ID", "BETREFF", "DATUM_LOE", "TEXT_NR", "HERKUNFT_ID", "KONTO_ID", "MAIL_TO", "MAIL_FROM", "MAIL_DATE", "KZ_IN_OUT", "STATUS", "DATUM_WV_VERF", "E_MANDANT", "OBJ_NR", "N_ART", "KATEGORIE") AS
  select  b.erfasser_id, b.datum_akt, b.lfd_nr, b.lfd_nr_anschr, b.adr_gr, b.adr_nr,
           b.person_nr, b.nachname, b.vorname, b.verfasser_id, b.betreff, b.datum_loe,
           b.text_nr, m.herkunft_id, m.konto_id, m.mail_to, m.mail_from, m.mail_date,
           m.kz_in_out, m.status, s.datum_wv, o.e_mandant, o.obj_nr, b.n_art, m.kategorie
from bericht b LEFT OUTER JOIN briefkas s ON
      b.erfasser_id  = s.erfasser_id and
      b.datum_akt    = s.datum_akt and
      b.lfd_nr       = s.lfd_nr and
      b.verfasser_id = s.benutzer_id
       LEFT OUTER JOIN beriobj o ON
      b.erfasser_id  = o.erfasser_id and
      b.datum_akt    = o.datum_akt and
      b.lfd_nr       = o.lfd_nr
      , emaiberi m
where b.erfasser_id  = m.erfasser_id and
      b.datum_akt    = m.datum_akt and
      b.lfd_nr       = m.lfd_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."EOGRVIEW" ("E_MANDANT", "BENUTZER_ID", "GRP_ID", "BEZEICHNUNG", "BEREICH") AS
  select e_mandant, benutzer_id, grp_id, bezeichnung, 'EA'
from eogrupbe
union
select e_mandant, '000000', obj_nr, objektname, 'EA'
from eobjtyp
where objekttyp = 'G'
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FAKETVIE" ("E_MANDANT", "F_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "DATUM", "AUFTRAG_TYP", "WAEHRUNG", "AUFL_DAT_IST", "SUM_BERECHNET", "SUM_FREI", "SUM_REMITTEND", "SUM_PARTIE", "SUM_BRUTTO_BETR", "SUM_NETTO_BETR", "SUM_NETTO_PLUSMINUS", "SO_POS_NR") AS
  select f.e_mandant, f.f_mandant, f.l_ausg_nr, f.l_aufl_nr, f.artikel_nr, to_number(to_char(f.datum,'yyyymmdd')), f.auftrag_typ, f.waehrung, to_number(to_char(a.aufl_dat_ist,'yyyymmdd')),
        sum(f.sum_berechnet), sum(f.sum_frei), sum(f.sum_remittend), sum(f.sum_partie), sum(f.sum_brutto_betr), sum(f.sum_netto_betr),
    case auftrag_typ
          when 'G' then
             sum(f.sum_netto_betr)*(-1)
          else
             sum(f.sum_netto_betr)
          end , so_pos_nr
from   bufaksum f, buaufl a
where f.l_ausg_nr = a.l_ausg_nr and
      f.l_aufl_nr = a.l_aufl_nr
group by f.e_mandant, f.f_mandant, f.l_ausg_nr, f.l_aufl_nr, f.artikel_nr, f.datum, f.auftrag_typ, f.waehrung, a.aufl_dat_ist, so_pos_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FAKTMANK" ("E_MANDANT", "AUFTRAGS_NR", "ADR_GR", "ADR_NR", "HAUPT_NAME", "ADR_NR_OBJ", "HAUPT_NAME_OBJ", "ERF_DAT", "FAKT_DAT", "RECH_DAT", "RECH_NR", "BUCH_ART", "R_ART", "ABRUF_NR", "WAEHRUNG") AS
  select
      f.e_mandant,f.auftrags_nr,f.adr_gr,f.adr_nr,a.haupt_name,
      b.adr_nr,b.haupt_name,
      f.erf_dat,f.fakt_dat,f.rech_dat,f.rech_nr,f.buch_art,
      f.r_art,f.abruf_nr,f.waehrung
from anschr a, anschr b, faktman f
where f.adr_gr=a.adr_gr and f.adr_nr=a.adr_nr
and   f.adr_gr=b.adr_gr and f.adr_nr_obj=b.adr_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FAKTMANS" ("E_MANDANT", "AUFTRAGS_NR", "MAN_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "NAME1", "ORT", "ADR_NR_OBJ", "HAUPT_NAME_OBJ", "ERF_DAT", "FAKT_DAT", "RECH_DAT", "RECH_NR", "BUCH_ART", "R_ART", "ABRUF_NR", "WAEHRUNG", "ZB_MENGE", "PREIS_M1", "RABATT_BETR", "OBJ_NR", "AUSG") AS
  select distinct
      f.e_mandant,f.auftrags_nr,f.man_nr,f.adr_gr,f.adr_nr,f.person_nr,
      a.haupt_name,a.name1,a.wohnort,b.adr_nr,b.haupt_name,
      f.erf_dat,f.fakt_dat,f.rech_dat,f.rech_nr,f.buch_art,
      f.r_art,f.abruf_nr,f.waehrung,f.zb_menge,f.preis_m1,f.grab_proz,
      f.obj_nr,f.ausg
from anschr a, anschr b, faktman f
where f.adr_gr=a.adr_gr and f.adr_nr=a.adr_nr
and   f.adr_gr=b.adr_gr and f.adr_nr_obj=b.adr_nr
and   f.rech_nr is not NULL;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FAKTMPVIEW" ("E_MANDANT", "RECH_NR", "RE_DAT", "KOPIE_NR", "POSNR", "ABRUF_NR", "ADR_GR", "ADR_NR_RE", "PERSON_NR_RE", "LAND_CODE_RE", "EG_KZ_RE", "BUCH_ART", "R_ART", "WAEHRUNG", "MWST_FREI", "OBJ_NR", "AUSG", "FAKT_KAT", "STEUERSATZ", "SUMME") AS
  SELECT distinct
       a.e_mandant  ,a.rech_nr   ,a.re_dat,a.kopie_nr    ,  b.posnr, a.abruf_nr,
       a.adr_gr, a.adr_nr_re, a.person_nr_re, a.land_code_re, a.eg_kz_re,  a.buch_art, a.r_art,
       a.waehrung     ,a.mwst_frei , b.obj_nr, b.ausg, b.fakt_kat,
       b.steuersatz  ,
       sum(c.zb_menge) as summe

FROM   fakstamm a, faktpos b, faktupos c
WHERE  a.kopie_nr  = 0
AND    a.e_mandant = b.e_mandant
AND    a.rech_nr   = b.rech_nr
AND    a.re_dat    = b.re_dat
AND    a.abruf_nr  = b.abruf_nr
AND    a.kopie_nr  = b.kopie_nr
AND    a.e_mandant = c.e_mandant
AND    a.rech_nr   = c.rech_nr
AND    a.re_dat    = c.re_dat
AND    a.abruf_nr  = c.abruf_nr
AND    a.kopie_nr  = c.kopie_nr
AND    b.posnr     = c.posnr
group by
       a.e_mandant  ,a.rech_nr   ,a.re_dat,a.kopie_nr    ,  b.posnr, a.abruf_nr,
       a.adr_gr, a.adr_nr_re, a.person_nr_re, a.land_code_re, a.eg_kz_re,  a.buch_art, a.r_art,
       a.waehrung     ,a.mwst_frei , b.obj_nr, b.ausg, b.fakt_kat,
       b.steuersatz;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FAKTRECH" ("E_MANDANT", "ADR_GR", "RECH_NR", "RE_DAT", "R_ART", "WAEHRUNG", "DUPL", "POSNR", "FAKT_KAT", "SUM_BETR", "STEUERSATZ", "OBJ_NR", "AUSG", "UPOSNR", "ADR_NR_OBJ", "PNR_OBJ", "BTEXT1", "BTEXT2", "BTEXT3", "PREIS_KAT", "ANSCHR1", "ANSCHR2", "ANSCHR3", "ANSCHR4", "ANSCHR5", "ANSCHR6", "ANSCHR7", "BUCH_ART", "ADR_NR_RE", "HAUPT_NAME", "LIEFERSCHEIN", "SUM_BETR_BR", "ANSCHR8", "ANSCHR9", "ANSCHR10", "F_BEG_JAHR", "F_BEG_HNR", "F_ENDE_JAHR", "F_ENDE_HNR", "VERLBER_ID", "BETR_NET_POS", "LAND_CODE_RE", "BETR_NET_UP", "BETR_BR_UP", "ABRUF_NR") AS
  SELECT distinct
       a.e_mandant    ,a.adr_gr      ,a.rech_nr   ,a.re_dat    ,a.r_art,
       a.waehrung     ,a.dupl        ,b.posnr     ,b.fakt_kat  ,b.sum_betr,
       b.steuersatz   ,b.obj_nr      ,b.ausg        ,
       c.uposnr       ,c.adr_nr_obj  ,c.pnr_obj   ,c.btext1,
       c.btext2       ,c.btext3      ,c.preis_kat ,c.anschr1,
       c.anschr2      ,c.anschr3     ,c.anschr4   ,c.anschr5,
       c.anschr6      ,c.anschr7     ,c.buch_art   ,a.adr_nr_re ,
       d.haupt_name,
       a.lieferschein ,a.sum_betr_br ,c.anschr8,
       c.anschr9      ,c.anschr10    ,c.f_beg_jahr,c.f_beg_hnr,
       c.f_ende_jahr  ,c.f_ende_hnr  ,d.verlber_id ,b.betr_net_pos,
       a.land_code_re ,c.betr_net_up, c.betr_br_up, a.abruf_nr
FROM   fakstamm a, faktpos b, faktupos c, anschr d
WHERE  a.kopie_nr  = 0
AND    a.e_mandant = b.e_mandant
AND    a.rech_nr   = b.rech_nr
AND    a.re_dat    = b.re_dat
AND    a.abruf_nr  = b.abruf_nr
AND    a.kopie_nr  = b.kopie_nr
AND    a.e_mandant = c.e_mandant
AND    a.rech_nr   = c.rech_nr
AND    a.re_dat    = c.re_dat
AND    a.abruf_nr  = c.abruf_nr
AND    a.kopie_nr  = c.kopie_nr
AND    b.posnr     = c.posnr
AND    a.adr_nr_re = d.adr_nr
AND    a.adr_gr    = d.adr_gr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FAKTVIEW" ("E_MANDANT", "RECH_NR", "RE_DAT", "KOPIE_NR", "POSNR", "UPOSNR", "ABRUF_NR", "ADR_GR", "ADR_NR_RE", "PERSON_NR_RE", "LAND_CODE_RE", "EG_KZ_RE", "EG_IDNR", "BUCH_ART", "R_ART", "WAEHRUNG", "MWST_FREI", "OBJ_NR", "AUSG", "FAKT_KAT", "STEUERSATZ", "ADR_NR_OBJ", "PNR_OBJ", "ABO_NR", "LAND_CODE_HE", "EG_IDNR_HE", "BTEXT1", "BTEXT2", "BTEXT3", "F_BEG_DAT_E", "F_ENDE_DAT_E", "F_BEG_JAHR", "F_BEG_HNR", "F_ENDE_JAHR", "F_ENDE_HNR", "ZB_MENGE", "BETR_BR_UP", "BETR_NET_UP", "MWSTBUP", "ZUSBETR_BR", "ZUSBETR_NET", "RABBETR_BR", "RABBETR_NET", "STEUER_CODE", "FIBU_MANDANT", "E_PREIS_BR", "E_PREIS_NET", "ZBER_HEFT", "MAN_NR", "RAB_PROZ", "AKT_ID", "FAKT_ZR", "ARCHIV_DATUM", "PREIS_KAT", "KZ_SW", "KZ_ELEKTRON", "L_RNR", "Z_BED") AS
  SELECT
       a.e_mandant  ,a.rech_nr   ,a.re_dat,a.kopie_nr    ,  b.posnr, c.uposnr, a.abruf_nr,
       a.adr_gr, a.adr_nr_re, a.person_nr_re, a.land_code_re, a.eg_kz_re, a.eg_idnr, a.buch_art, a.r_art,
       a.waehrung     ,a.mwst_frei , b.obj_nr, b.ausg, b.fakt_kat,
       b.steuersatz  ,   c.adr_nr_obj  , c.pnr_obj   , c.abo_nr, c.land_code_he, c.eg_idnr_he, c.btext1, c.btext2,
       c.btext3, c.f_beg_dat_e,
       c.f_ende_dat_e, c.f_beg_jahr, c.f_beg_hnr, c.f_ende_jahr, c.f_ende_hnr, c.zb_menge, c.betr_br_up,
       c.betr_net_up, c.mwstbup, c.zusbetr_br, c.zusbetr_net, c.rabbetr_br, c.rabbetr_net, b.STEUER_CODE,a.fibu_mandant,
       c.E_PREIS_BR, c.E_PREIS_NET, c.ZBER_HEFT, c.MAN_NR, c.RAB_PROZ, c.akt_id, c.FAKT_ZR, a.ARCHIV_DATUM, c.PREIS_KAT, c.KZ_SW, c.KZ_ELEKTRON, a.l_rnr, a.Z_BED
FROM   fakstamm a, faktpos b, faktupos c
WHERE  a.kopie_nr  = 0
AND    a.e_mandant = b.e_mandant
AND    a.rech_nr   = b.rech_nr
AND    a.re_dat    = b.re_dat
AND    a.abruf_nr  = b.abruf_nr
AND    a.kopie_nr  = b.kopie_nr
AND    b.e_mandant = c.e_mandant
AND    b.rech_nr   = c.rech_nr
AND    b.re_dat    = c.re_dat
AND    b.abruf_nr  = c.abruf_nr
AND    b.kopie_nr  = c.kopie_nr
AND    b.posnr     = c.posnr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FAKUVIEW" ("E_MANDANT", "RECH_NR", "RE_DAT", "ABRUF_NR", "POSNR", "UPOSNR", "ADR_GR", "ADR_NR_BV", "PERSON_NR_BV", "ADR_NR", "PERSON_NR", "AUFTRAGS_NR", "OBJ_NR", "AUSG", "U_OBJ_NR", "U_AUSG", "HNR", "JAHR", "WAEHRUNG", "LAND_CODE_RE", "FAKT_ZR", "FAKT_KAT", "BUCH_ART", "R_ART", "SUM_BETR", "LAND_CODE_HE", "BUCH_MONAT", "BUCH_JAHR", "ZUSBETR", "RABBETR", "W_AKT_ID", "PREIS_KAT", "ABO_NR", "EG_KZ_RE", "MWST_BETR", "MWST_SATZ", "HEFT_WERT", "BUCHM_WERT", "RAB_PROZ", "F_BEG_DAT_E", "F_ENDE_DAT_E", "ZB_MENGE", "KGS_BL", "ISTATWCODE") AS
  SELECT a.e_mandant   ,a.rech_nr     ,a.re_dat    ,a.abruf_nr ,
       a.posnr       ,a.uposnr      ,a.adr_gr    ,a.adr_nr_bv,
       a.person_nr_bv,a.adr_nr      ,a.person_nr ,a.auftrags_nr,
       a.obj_nr      ,a.ausg        ,a.u_obj_nr  ,a.u_ausg,
       a.hnr         ,a.jahr        ,a.waehrung  ,a.land_code_re,
       a.fakt_zr     ,a.fakt_kat    ,a.buch_art  ,a.r_art,
       a.sum_betr    ,a.land_code_he,a.buch_monat,a.buch_jahr,
       a.zusbetr     ,a.rabbetr     ,a.w_akt_id  ,a.preis_kat,
       a.abo_nr      ,a.eg_kz_re    ,a.mwst_betr ,a.mwst_satz,
       a.heft_wert   ,a.buchm_wert  ,b.rab_proz  ,b.f_beg_dat_e,
       b.f_ende_dat_e,b.zb_menge, c.kgs_bl, d.ISTATWCODE
FROM   fakustat a, faktupos b, anschr c, mobjtyp d
WHERE  a.e_mandant = b.e_mandant
AND    a.rech_nr   = b.rech_nr
AND    a.re_dat    = b.re_dat
AND    a.abruf_nr  = b.abruf_nr
AND    a.posnr     = b.posnr
AND    a.uposnr    = b.uposnr
AND    b.kopie_nr  = 0
AND    c.adr_gr    = a.adr_gr
AND    c.adr_nr    = a.adr_nr
AND    d.e_mandant = a.e_mandant
AND    d.obj_nr    = a.obj_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FALVIEW" ("Auftrags ID", "Leistungsempfaenger ID", "Leistungsempfaenger Name", "Leistungsempfaenger ZH", "Rechnungsempfaenger ID", "Rechnungsempfaenger Name", "Rechnungsempfaenger ZH", "Besteller ID", "Besteller Name", "Besteller ZH", "Agentur ID", "Agentur Name", "Auftragsstatus", "Bestell-Datum", "Objekt", "Heft Nr", "Jahr", "Laufzeit Start", "Laufzeit Ende", "Produkt", "Motiv", "Plazierung", "DU-Status", "Anzeigenart", "Artikel-Nr", "Artikel Name", "Anzahl Artikel", "Aktions-ID", "Aktions-Bezeichnung", "Positionstext", "Format", "Preis Liste", "Preis Auftrag Gesamt", "Auftragsrabatt", "Preis Netto", "Preis MwSt", "Preis Brutto", "Abrechnungsart", "Zahlungsart", "Faktura-Status", "Rechnungs-Filename", "Abo-Status", "Lieferung Start Heft Nr", "Lieferung Start Jahr", "Lieferung Ende Heft Nr", "Lieferung Ende Jahr", "Kuendigung Grund", "Kuendigung Datum", "Notiz", "Created Date", "Created User", "Update Date", "Update User") AS
  SELECT
	('abo-'	||	AST.ADR_GR	||	'-'	||	AST.ADR_NR	||	'-'	||	AST.PERSON_NR	||	'-'	||	AST.ABO_NR)
	"Auftrags ID"
,	(
		CASE
			WHEN
				(
					P.A_TYP	=	'F'
				)
			THEN
				('c-unt-'	||	AST.ADR_NR)
			ELSE
				CASE
					WHEN
						(
							P.A_TYP	=	'M'
						)
					THEN
						('c-mit-'	||	AST.ADR_NR	||	'-'	||	AST.PERSON_NR)
					ELSE
						CASE
							WHEN
								(
									P.A_TYP	=	'P'
								)
							THEN
								('c-per-'	||	AST.ADR_NR)
							ELSE
								('c-err-'	||	AST.ADR_NR)
						END
				END
		END
	)
	"Leistungsempfaenger ID"
,	TRIM
(A.NAME1)
	"Leistungsempfaenger Name"
,	(TRIM
	(P.NACHNAME)	||
	CASE
		WHEN
			(P.VORNAME	IS	NULL)
		THEN
			''
		ELSE
			','
	END
	||	TRIM
	(P.VORNAME))
	"Leistungsempfaenger ZH"
,	CASE
		WHEN
			(AST.ADR_NR_BV	IS	NULL)
		THEN
			(
			CASE
				WHEN
					(
						P.A_TYP	=	'F'
					)
				THEN
					('c-unt-'	||	AST.ADR_NR)
				ELSE
					CASE
						WHEN
							(
								P.A_TYP	=	'M'
							)
						THEN
							('c-mit-'	||	AST.ADR_NR	||	'-'	||	AST.PERSON_NR)
						ELSE
							CASE
								WHEN
									(
										P.A_TYP	=	'P'
									)
								THEN
									('c-per-'	||	AST.ADR_NR)
								ELSE
									('c-err-'	||	AST.ADR_NR)
							END
					END
			END
		)
		ELSE
			(
			CASE
				WHEN
					(
						PBV.A_TYP	=	'F'
					)
				THEN
					('c-unt-'	||	AST.ADR_NR_BV)
				ELSE
					CASE
						WHEN
							(
								PBV.A_TYP	=	'M'
							)
						THEN
							('c-mit-'	||	AST.ADR_NR_BV	||	'-'	||	AST.PERSON_NR_BV)
						ELSE
							CASE
								WHEN
									(
										PBV.A_TYP	=	'P'
									)
								THEN
									('c-per-'	||	AST.ADR_NR_BV)
								ELSE
									('c-err-'	||	AST.ADR_NR_BV)
							END
					END
			END
		)
	END	"Rechnungsempfaenger ID"
,	CASE
		WHEN
			(AST.ADR_NR_BV	IS	NULL)
		THEN
			TRIM	(A.NAME1)
		ELSE
			TRIM	(ABV.NAME1)
	END	"Rechnungsempfaenger Name"
,	CASE
		WHEN
			(AST.ADR_NR_BV	IS	NULL)
		THEN
			(TRIM
			(P.NACHNAME)	||
			CASE
				WHEN
					(P.VORNAME	IS	NULL)
				THEN
					''
				ELSE
					','
			END
			||	TRIM
			(P.VORNAME))
		ELSE
			(TRIM
			(PBV.NACHNAME)	||
			CASE
				WHEN
					(PBV.VORNAME	IS	NULL)
				THEN
					''
				ELSE
					','
			END
			||	TRIM
			(PBV.VORNAME))
	END	"Rechnungsempfaenger ZH"
,	''
	"Besteller ID"
,	''
	"Besteller Name"
,	''
	"Besteller ZH"
,	''
	"Agentur ID"
,	''
	"Agentur Name"
,	''
	"Auftragsstatus"
,	AST.BEST_DATUM		"Bestell-Datum"
,	AST.OBJ_NR			"Objekt"
,	AST.VBEG_HEFT		"Heft Nr"
,	AST.VBEG_JAHR		"Jahr"
,	AST.VBEG_DAT		"Laufzeit Start"
,	AST.VEND_DAT		"Laufzeit Ende"
,	''
	"Produkt"
,	''
	"Motiv"
,	''
	"Plazierung"
,	''
	"DU-Status"
,	''
	"Anzeigenart"
,	''
	"Artikel-Nr"
,	''
	"Artikel Name"
,	AST.BER_MENGE	"Anzahl Artikel"
,	AST.W_AKT_ID	"Aktions-ID"
,	WA.BESCHREIBUNG	"Aktions-Bezeichnung"
,	''
	"Positionstext"
,	''
	"Format"
,	0
	"Preis Liste"
,	0
	"Preis Auftrag Gesamt"
,	0
	"Auftragsrabatt"
,	FAKT.NETTO						"Preis Netto"
,	(FAKT.BRUTTO	-	FAKT.NETTO)
	"Preis MwSt"
,	FAKT.BRUTTO		"Preis Brutto"
,	''
	"Abrechnungsart"
,	''
	"Zahlungsart"
,	''
	"Faktura-Status"
,	''
	"Rechnungs-Filename"
,	AST.ABOSTATUS			"Abo-Status"
,	AST.VBEG_HEFT			"Lieferung Start Heft Nr"
,	AST.VBEG_JAHR			"Lieferung Start Jahr"
,	AST.VEND_HEFT			"Lieferung Ende Heft Nr"
,	AST.VEND_JAHR			"Lieferung Ende Jahr"
,	AST.K_GRUND				"Kuendigung Grund"
,	AST.K_DATUM				"Kuendigung Datum"
,	''
	"Notiz"
,	AST.DATUM_NEU	"Created Date"
,	AST.B_ID_NEU	"Created User"
,	AST.DATUM_AEND	"Update Date"
,	AST.B_ID_AEND	"Update User"
FROM
	COVER.ABOSTAMM	AST
LEFT JOIN
	COVER.PERSON	P
ON
	(
		P.ADR_GR	=	AST.ADR_GR
	AND	P.ADR_NR	=	AST.ADR_NR
	AND	P.PERSON_NR	=	AST.PERSON_NR
	)
LEFT JOIN
	COVER.ANSCHR	A
ON
	(
		A.ADR_GR	=	AST.ADR_GR
	AND	A.ADR_NR	=	AST.ADR_NR
	)
LEFT JOIN
	COVER.PERSON	PBV
ON
	(
		PBV.ADR_GR		=	AST.ADR_GR
	AND	PBV.ADR_NR		=	AST.ADR_NR_BV
	AND	PBV.PERSON_NR	=	AST.PERSON_NR_BV
	)
LEFT JOIN
	COVER.ANSCHR	ABV
ON
	(
		ABV.ADR_GR	=	AST.ADR_GR
	AND	ABV.ADR_NR	=	AST.ADR_NR_BV
	)
LEFT JOIN
	COVER.AKTVORB	WA
ON
	(
		WA.AKT_ID	=	AST.W_AKT_ID
	)
LEFT JOIN
	(
		SELECT
			ADR_GR
		,	ADR_NR_OBJ
		,	PNR_OBJ
		,	ABO_NR
		,	SUM(GESPREIS_BR)	AS	BRUTTO
		,	SUM(GESPREIS_NET)	AS	NETTO
		FROM
			COVER.FAKTUPOS
		GROUP BY
			ADR_GR
		,	ADR_NR_OBJ
		,	PNR_OBJ
		,	ABO_NR
	)	FAKT
ON
	(
		FAKT.ADR_GR		=	AST.ADR_GR
	AND	FAKT.ADR_NR_OBJ	=	AST.ADR_NR
	AND	FAKT.PNR_OBJ	=	AST.PERSON_NR
	AND	AST.ABO_NR		=	FAKT.ABO_NR
	);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FASUOLVI" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "JAHR_MONAT", "AUFTRAG_TYP", "WAEHRUNG", "SUM_BERECHNET", "SUM_FREI", "SUM_REMITTEND", "SUM_BRUTTO_BETR", "SUM_PARTIE", "SUM_NETTO_BETR") AS
  select e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung,
          sum(sum_berechnet), sum(sum_frei), sum(sum_remittend), sum(sum_brutto_betr),
          sum(sum_partie), sum(sum_netto_betr)
from   bufaksum
where so_pos_nr = '0'
and (sum_berechnet != 0 or sum_partie != 0 or sum_frei != 0 or sum_remittend != 0 or sum_netto_betr != 0 or sum_brutto_betr != 0)
group by e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FASUVIEW" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "JAHR_MONAT", "AUFTRAG_TYP", "WAEHRUNG", "SUM_BERECHNET", "SUM_FREI", "SUM_REMITTEND", "SUM_BRUTTO_BETR", "SUM_PARTIE", "SUM_NETTO_BETR", "SO_POS_NR", "SHOP_ID", "PREIS_KAT") AS
  select e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung,
          sum(sum_berechnet), sum(sum_frei), sum(sum_remittend), sum(sum_brutto_betr),
          sum(sum_partie), sum(sum_netto_betr), so_pos_nr, shop_id, preis_kat
from   bufaksum
where preis_kat != '$NU%' and preis_kat != '$NU&'
group by e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung, so_pos_nr, shop_id, preis_kat;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FDDAVIEW" ("FD_TYP", "FD_ID", "LFD_NR_1", "ADR_GR", "ADR_NR", "PERSON_NR", "EXT_KEY", "DATUM_NEU", "B_ID_NEU", "ABRUF_NR", "LFD_NR_2", "MANDANT", "OBJ_NR", "AUSG", "TABELLE") AS
  select 	a.fd_typ, a.fd_id, a.lfd_nr, a.adr_gr, a.adr_nr,
	a.person_nr, a.ext_key, a.fd_erl_datum, a.b_id_neu,
	0, 0, '   ', '   ', '            ', 'FDDATEN '
from FDDATEN a
union
select 	'ABO       ', a.fd_id, 0, a.adr_gr, a.adr_nr_re,
	a.person_nr_re,
	'0                                       ',
	a.abruf_datum, a.b_id_neu||'  ', a.abruf_nr,
	a.lfd_nr, a.mandant, a.obj_nr, a.ausg, 'FDABODAT'
from FDABODAT a
where	a.empfaenger = 'R' and a.kz_pseudo <> 'T'
union
select 	'ABO       ', a.fd_id, 0, a.adr_gr, a.adr_nr_re,
	a.person_nr_re,
	'0                                       ',
	a.abruf_datum, a.b_id_neu||'  ', a.abruf_nr,
	a.lfd_nr, a.mandant, a.obj_nr, a.ausg, 'FDABODAT'
from FDABODAT a
where	a.empfaenger = 'L' and a.kz_pseudo <> 'T'
union
select 	'ABO       ', a.fd_id, 0, a.adr_gr, a.adr_nr_re,
	a.person_nr_re,
	'0                                       ',
	a.abruf_datum, a.b_id_neu||'  ', a.abruf_nr,
	a.lfd_nr, a.mandant, a.obj_nr, a.ausg, 'FDABODAT'
from FDABODAT a
where	a.empfaenger = 'P' and a.kz_pseudo <> 'T';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FOERDERERVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "ABO_NR", "ABOSTATUS", "L_MENGE", "BER_MENGE", "PREIS_KAT", "HAUPT_PLZ", "HAUPT_ORT", "HAUPT_NAME", "GENFILT_ID", "ADR_NR_BV", "PERSON_NR_BV", "HAUPT_PLZ_BV", "HAUPT_ORT_BV", "HAUPT_NAME_BV", "GENFILT_ID_BV", "S_ADNR", "S_PERSON_NR", "HAUPT_PLZ_S", "HAUPT_ORT_S", "HAUPT_NAME_S", "GENFILT_ID_S") AS
  select s.adr_gr, s.adr_nr, s.person_nr, s.e_mandant, s.obj_nr, s.ausg, s.abo_nr,
       s.abostatus, v.l_menge, s.ber_menge, s.preis_kat,
       a1.haupt_plz, a1.haupt_ort, a1.haupt_name, a1.genfilt_id,
       s.adr_nr_bv, s.person_nr_bv, a2.haupt_plz, a2.haupt_ort, a2.haupt_name, a2.genfilt_id,
       v.s_adnr, v.s_person_nr, a3.haupt_plz, a3.haupt_ort, a3.haupt_name, a3.genfilt_id
     from abostamm s, abovers v, anschr a1, anschr a2, anschr a3
  where s.adr_gr = v.adr_gr and s.adr_nr = v.adr_nr and s.person_nr = v.person_nr
    and s.e_mandant = v.e_mandant and s.obj_nr = v.obj_nr and s.ausg = v.ausg and s.abo_nr = v.abo_nr
    and a1.adr_gr = s.adr_gr and a1.adr_nr = s.adr_nr
    and a2.adr_gr = s.adr_gr and a2.adr_nr = s.adr_nr_bv
    and a3.adr_gr = v.adr_gr and a3.adr_nr = v.s_adnr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FRAVIEW" ("PAUSGHD_NR", "E_MANDANT", "EINLIEF_DAT", "M_NAME", "MANDANT1", "MANDANT2", "MANDANT3", "MANDANT4", "MANDANT5", "MANDANT6", "ABRNR", "ABRUNR", "KZ_MASSENVERS", "ERSTELL_DAT_LIS", "OBJ_NR_MV", "AUSG", "JAHR", "HNR", "KZ_GEDRUCKT_LIS", "PAUSGLS_NR", "EINLIEF_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "KST_ID", "PRUEF_ZIFF", "NAME1_EMPF", "NAME2_EMPF", "NAME3_EMPF", "VN_NAME", "ABT_NZUS", "STRASSE_EMPF", "PLZ_EMPF", "ORT_EMPF", "GEWICHT", "NACHNAHME", "ZUSATZ_LEIST", "ENTGELT", "KZ_PAKET", "POSITION", "KZ_FIBU_VERARB", "KORR_BETRAG", "KZ_GEDRUCKT_ETI", "SEITEN_NR", "OBJ_NR_EV", "IDENT_CODE", "LEIT_CODE", "FP_ZENTRUM", "ETI1", "ETI2", "ETI3", "ETI4", "ETI5", "ETI6", "ETI7", "ETI8", "ETI9", "ETI10", "DRUCKER_ID", "LABEL_ID", "ENTGELT_ERMAESS", "KUNDEN_KENN", "KUNDEN_NR", "SBUCHER_ID", "SBUCHER_NAME", "SBUCHER1", "SBUCHER2", "SBUCHER3", "SBUCHER4", "ERSTELL_DAT_ETI", "VERSAWEG_ID") AS
  SELECT
h.pausghd_nr, h.e_mandant, h.einlief_dat, h.m_name,
h.mandant1, h.mandant2, h.mandant3, h.mandant4, h.mandant5,
h.mandant6, h.abrnr, h.abrunr, h.kz_massenvers, h.erstell_dat,
h.obj_nr, h.ausg, h.jahr, h.hnr, h.kz_gedruckt,
l.pausgls_nr, l.einlief_nr, l.adr_gr, l.adr_nr, l.person_nr, l.kst_id,
l.pruef_ziff, l.name1_empf, l.name2_empf, l.name3_empf, l.vn_name,
l.abt_nzus, l.strasse_empf, l.plz_empf, l.ort_empf, l.gewicht,
l.nachnahme, l.zusatz_leist, l.entgelt, l.kz_paket, l.position,
l.kz_fibu_verarb, l.korr_betrag, l.kz_gedruckt, l.seiten_nr, l.obj_nr,
l.ident_code, l.leit_code, l.fp_zentrum, l.eti1, l.eti2, l.eti3,
l.eti4, l.eti5, l.eti6, l.eti7, l.eti8, l.eti9, l.eti10,
l.drucker_id, l.label_id, l.entgelt_ermaess, l.kunden_kenn,
l.kunden_nr, l.sbucher_id, l.sbucher_name, l.sbucher1,
l.sbucher2, l.sbucher3, l.sbucher4, l.erstell_dat, l.versaweg_id
FROM pausghd h, pausgls l
