  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FREIVIEW" ("ADR_GR", "ADR_NR", "FIRMKZ_ID", "BEZIRK_ID", "HAUPT_NAME", "EMPFAENGER", "PERSON_NR", "NACHNAME", "VORNAME", "KZ_PRIVAT", "E_MANDANT", "OBJ_NR", "AUSG", "OBJEKTNAME_KURZ", "AUSGNAME_KURZ", "ANZ_FREI", "HEFT_VON", "JAHR_VON", "HEFT_BIS", "JAHR_BIS", "BENUTZER_ID") AS
  select f.adr_gr, f.adr_nr, a.firmkz_id, a.bezirk_id, a.haupt_name, f.empfaenger,
       f.person_nr, p.nachname, p.vorname, f.kz_privat, f.e_mandant, f.obj_nr,
       f.ausg, e.objektname_kurz, s.ausgname_kurz, f.anz_frei, f.heft_von,
       f.jahr_von, f.heft_bis, f.jahr_bis, f.benutzer_id
from  freieinw f, anschr a, person p, eobjtyp e, eobstamm s
where f.adr_gr = a.adr_gr and f.adr_nr = a.adr_nr and
      f.adr_gr = p.adr_gr and f.adr_nr = p.adr_nr and f.person_nr = p.person_nr and
      f.e_mandant = e.e_mandant and f.obj_nr = e.obj_nr and
      f.e_mandant = s.e_mandant and f.obj_nr = s.obj_nr and f.ausg = s.ausg;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FRKSTSUM" ("PAUSGHD_NR", "EINLIEF_DAT", "KZ_MASSENVERS", "ENTGELT_ERMAESS", "PAUSGLS_NR", "KST_ID", "ENTGELT") AS
  select h.pausghd_nr, h.einlief_dat, h.kz_massenvers, h.entgelt_ermaess,
		      l.pausgls_nr, l.kst_id, l.entgelt
from pausghd h, pausgls l
where h.pausghd_nr = l.pausghd_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."FSUNVIEW" ("E_MANDANT", "F_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "ARTIKEL_NR", "JAHR", "MONAT", "AUFTRAG_TYP", "WAEHRUNG", "SUM_BERECHNET", "SUM_FREI", "SUM_REMITTEND", "SUM_PARTIE", "SUM_BRUTTO_BETR", "SUM_NETTO_BETR", "SUM_NETTO_PLUSMINUS", "SO_POS_NR") AS
  select e_mandant, f_mandant, l_ausg_nr, l_aufl_nr, artikel_nr, substr(jahr_monat,1,4), substr(jahr_monat,5,2),
          auftrag_typ, waehrung, sum(sum_berechnet), sum(sum_frei), sum(sum_remittend), sum(sum_partie),
          sum(sum_brutto_betr), sum(sum_netto_betr),
    case auftrag_typ
          when 'G' then
             sum(sum_netto_betr)*(-1)
          else
             sum(sum_netto_betr)
          end , so_pos_nr
from   bufaksum
group by e_mandant, f_mandant, l_ausg_nr, l_aufl_nr, artikel_nr, substr(jahr_monat,1,4), substr(jahr_monat,5,2),
          auftrag_typ, waehrung, so_pos_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."GEBVIE" ("REG_ID", "REG_CODE", "GEBIET") AS
  select a.reg_id, a.reg_code, a.gebiet
	 from gebview a
	      group by a.reg_id, a.reg_code, a.gebiet
	  ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."GEBVIEW" ("REG_ID", "REG_CODE", "KGS_VON", "KGS_BIS", "VON_MIN", "BIS_MIN", "VON_MAX", "BIS_MAX", "GEBIET") AS
  select  a.reg_id, a.reg_code, a.kgs_von, a.kgs_bis,
          (select min(a1.kgs_von) from regkgs a1 where a1.reg_code='GS' and a1.land_code='D'), (select min(a1.kgs_bis) from regkgs a1 where a1.reg_code='GS' and a1.land_code='D'),
          (select max(a2.kgs_von) from regkgs a2 where a2.reg_code='GS' and a2.land_code='D'), (select max(a2.kgs_bis) from regkgs a2 where a2.reg_code='GS' and a2.land_code='D'),
		  (case when (((select min(a1.kgs_von) from regkgs a1 where a1.reg_code='GS' and a1.land_code='D')) <= a.kgs_von and
					  ((select max(a2.kgs_bis) from regkgs a2 where a2.reg_code='GS' and a2.land_code='D')) >= a.kgs_bis) then 'GS' else 'GN' end)
	 from regkgs a
	   where a.land_code ='D' and
	         a.reg_id    = 'AGS'
	      group by a.reg_id, a.reg_code, a.kgs_von, a.kgs_bis;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."GGGPAVIEW" ("GG_AUFT_NR", "WAEHRUNG", "KZ_SPERR", "BESCHREIBUNG", "BDATUM", "BINFO", "GG_SEGM_ID", "BRUTTO_VOLUMEN", "NETTO_VOLUMEN", "STATUS", "PERSON_NR", "BER_NACHNAME", "BER_VORNAME", "BER_VERFASSER_ID", "BER_DATUM_LOE", "BER_TEXT_NR", "ADR_GR", "ADR_NR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "NAME3", "NACHNAME", "VORNAME", "E_MANDANT", "OBJ_NR", "DATUM_WV") AS
  SELECT
      g.gg_auftr_nr, g.waehrung, g.kz_sperr, g.beschreibung, g.bdatum, g.binfo, g.gg_segm_id,
      g.brutto_volumen, g.netto_volumen, g.status, g.person_nr,
      b.nachname, b.vorname,
      b.verfasser_id, b.datum_loe, b.text_nr,
      a.adr_gr, a.adr_nr, a.haupt_name, a.haupt_plz, a.haupt_ort, a.name1, a.name2, a.name3,
      p.nachname, p.vorname,
      o.e_mandant, o.obj_nr,
      s.datum_wv
FROM
      ggauftr g LEFT OUTER JOIN bericht b ON
            g.erfasser_id   = b.erfasser_id and
            g.datum_akt     = b.datum_akt   and
            g.ber_lfd_nr    = b.lfd_nr
        LEFT OUTER JOIN anschr a ON
            g.adr_gr        = a.adr_gr      and
            g.adr_nr        = a.adr_nr
        LEFT OUTER JOIN person p ON
            g.adr_gr        = p.adr_gr      and
            g.adr_nr        = p.adr_nr      and
            g.person_nr     = p.person_nr
        LEFT OUTER JOIN beriobj o ON
            b.erfasser_id   = o.erfasser_id and
            b.datum_akt     = o.datum_akt   and
            b.lfd_nr        = o.lfd_nr
        LEFT OUTER JOIN briefkas s ON
            b.erfasser_id   = s.erfasser_id and
            b.datum_akt     = s.datum_akt   and
            b.lfd_nr        = s.lfd_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."HERKVIEW" ("HERKUNFT_ID", "HERKUNFT_TYP", "BESCHREIBUNG", "GUELTIG_AB", "GUELTIG_BIS", "B_ID_AEND", "DATUM_AEND") AS
  select  h.herkunft_id||'   ', h.herkunft_typ, h.beschreibung||'                    ', h.gueltig_ab, h.gueltig_bis,
        h.b_id_aend, h.datum_aend
from HERKUNFT h
union
select  h.aquell_code, 'ADR   ', h.herkunft||'                              ',
        TO_DATE(''), TO_DATE(''),'      ', TO_DATE('')
from AQUELLE h
union
select  h.akt_id||'   ', 'MAKTIO', h.b_aktid, h.soll_beg, h.soll_ende,
        h.benutzer_id, h.dat_neu
from MHAKTION h;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."HOAUTUEB" ("L_TITEL_NR", "AUTOR_NR", "ADR_GR", "ADR_NR_AUT", "PERSON_NR_AUT", "L_AUSG_NR", "E_MANDANT", "HONART_ID", "VERWEND_TYP_HONART", "HON_NR", "L_AUFL_NR", "ADR_NR_HON", "PERSON_NR_HON", "KZ_PSEUDO", "KZ_STORNO", "STATUS", "VORSCHUSS", "TEILABRECHNUNG", "DAT_NEU", "ABRECH_DAT_VON", "ABRECH_DAT_BIS", "BELEG_NR", "BELEG_DAT", "BETRAG_NET", "WAEHRUNG", "ARTIKEL_NR") AS
  select
a.l_titel_nr, a.autor_nr, a.adr_gr, a.adr_nr_aut, a.person_nr_aut,
b.l_ausg_nr, b.e_mandant, b.honart_id, b.verwend_typ_honart, b.hon_nr, b.l_aufl_nr, b.adr_nr, b.person_nr, b.kz_pseudo, b.kz_storno, b.status, b.vorschuss, b.teilabrechnung, b.dat_neu,
b.abrech_dat_von, b.abrech_dat_bis, b.beleg_nr, b.beleg_dat, b.betrag_net, b.waehrung, d.artikel_nr
from buautor a, honorar b, bumanaus d
    where a.l_titel_nr = b.l_titel_nr
    and a.autor_nr = b.autor_nr
    and b.kz_re_ho = 'H'
    and b.l_ausg_nr = d.l_ausg_nr
    and b.e_mandant = d.e_mandant
    and b.kz_zw_abrech = 'F'
union
select
a.l_titel_nr, a.autor_nr, a.adr_gr, a.adr_nr_aut, a.person_nr_aut,
b.l_ausg_nr, b.e_mandant, b.honart_id, e.verwend_typ, 0, null, 0, 0, 'F', 'F', null, null, null, null,
null, null, null, null, null, b.waehrung, d.artikel_nr
from buautor a, hoautor b, bumanaus d, honart e
    where a.l_titel_nr = b.l_titel_nr
    and a.autor_nr = b.autor_nr
    and b.abr_pro_jahr > 0
    and b.l_ausg_nr = d.l_ausg_nr
    and b.e_mandant = d.e_mandant
    and e.honart_id = b.honart_id
and not exists
(select hon_nr from honorar c
    where b.l_titel_nr = c.l_titel_nr
    and b.l_ausg_nr = c.l_ausg_nr
    and b.autor_nr = c.autor_nr
    and b.honart_id = c.honart_id
    and c.kz_re_ho = 'H'
    and c.kz_zw_abrech = 'F'
    and b.e_mandant = c.e_mandant);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."HOAUTVW" ("L_TITEL_NR", "AUTOR_NR", "L_AUSG_NR", "E_MANDANT", "HONART_ID", "WAEHRUNG", "BANK_INDEX", "ADR_GR", "ADR_NR_AUT", "PERSON_NR_AUT", "VERWEND_TYP", "ABR_PRO_JAHR", "HERKUNFT") AS
  select h.l_titel_nr, h.autor_nr, h.l_ausg_nr, h.e_mandant, h.honart_id, h.waehrung,
       h.bank_index, b.adr_gr, b.adr_nr_aut, b.person_nr_aut, a.verwend_typ,
h.abr_pro_jahr, g.herkunft
from hoautor h, buautor b, honart a, buausgab g
where h.l_titel_nr = b.l_titel_nr and
      h.l_ausg_nr = g.l_ausg_nr and
      h.autor_nr  = b.autor_nr and
      h.honart_id = a.honart_id and
      not exists (select v.verweistyp from averweis v where
                  v.adr_gr = b.adr_gr and
                  v.adr_nr = b.adr_nr_aut and
                  v.person_nr = b.person_nr_aut and
                  v.verweistyp = 'HONORA' and
                  v.gueltig_ab <= sysdate and
                  (v.gueltig_bis is null or v.gueltig_bis >= sysdate))
union
select h.l_titel_nr, h.autor_nr, h.l_ausg_nr, h.e_mandant, h.honart_id, h.waehrung,
       h.bank_index, b.adr_gr, v.adr_nr_verw, v.person_nr_verw, a.verwend_typ,
h.abr_pro_jahr, g.herkunft
from hoautor h, buautor b, honart a, averweis v, buausgab g
where h.l_titel_nr = b.l_titel_nr and
      h.l_ausg_nr = g.l_ausg_nr and
      h.autor_nr  = b.autor_nr and
      h.honart_id = a.honart_id and
      v.adr_gr = b.adr_gr and
      v.adr_nr = b.adr_nr_aut and
      v.person_nr = b.person_nr_aut and
      v.verweistyp = 'HONORA' and
      v.gueltig_ab <= sysdate and
      (v.gueltig_bis is null or v.gueltig_bis >= sysdate) and
      not exists (select w.verweistyp from averweis w where
                  w.adr_gr = b.adr_gr and
                  w.adr_nr = b.adr_nr_aut and
                  w.person_nr = b.person_nr_aut and
                  w.verweistyp = 'HONORA' and
                  w.gueltig_ab <= sysdate and
                  (w.gueltig_bis is null or w.gueltig_bis >= sysdate) and
                  w.gueltig_ab > v.gueltig_ab)
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."HOBUREVI" ("BELEG_NR", "BELEG_DAT", "ABRUF_NR", "E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "WAEHRUNG", "POS_NR", "HON_NR", "HONART_ID", "VERWEND_TYP_HO", "L_TITEL_NR", "L_AUSG_NR", "L_AUFL_NR", "AUTOR_NR", "ARTIKEL_NR", "TITEL_SUCH", "TITEL1", "BESCHREIBUNG", "ABRECH_DAT_VON", "ABRECH_DAT_BIS", "BETRAG_NET_POS", "ABSATZ", "HON_PROZ", "ZU_JAHR", "KZ_STORNO", "AUFL_DAT", "N_ARTIKEL_NR", "PROD_TYP", "GRUP_ID") AS
  select
a.beleg_nr, a.beleg_dat, a.abruf_nr, a.e_mandant, a.adr_gr, a.adr_nr, a.person_nr, a.waehrung,
b.pos_nr, b.hon_nr, b.honart_id, b.verwend_typ_ho, b.l_titel_nr, b.l_ausg_nr, b.l_aufl_nr, b.autor_nr,
b.artikel_nr, b.titel_such, b.titel1, b.beschreibung,
b.abrech_dat_von, b.abrech_dat_bis,
b.betrag_net_pos, b.absatz, b.hon_proz,
coalesce(to_char(b.abrech_dat_von, 'YYYY'), to_char(b.beleg_dat,'YYYY')), c.kz_storno,
coalesce(d.aufl_dat_ist, d.aufl_dat_soll),
nvl(to_number(regexp_replace(b.artikel_nr,'[^[:digit:]]')),0),
e.prod_typ,e.grup_id
from horechn a, horepos b, honorar c, buaufl d, buausgab e
where a.beleg_nr = b.beleg_nr
and a.beleg_dat = b.beleg_dat
and a.obj_nr is null
and b.l_ausg_nr > 0
and c.adr_gr = a.adr_gr
and c.adr_nr = a.adr_nr
and c.person_nr = a.person_nr
and c.hon_nr = b.hon_nr
and d.l_ausg_nr = b.l_ausg_nr
and d.l_aufl_nr = coalesce(b.l_aufl_nr, 0)
and c.kz_pseudo = 'F'
and e.l_ausg_nr = b.l_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."HONAUSVW" ("ADR_GR", "ADR_NR", "PERSON_NR", "HON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "JAHR", "HNR", "BEITRAG_NR", "BETEIL_NR") AS
  select
a.adr_gr,a.adr_nr,a.person_nr,a.hon_nr,a.e_mandant,
b.obj_nr,b.ausg,b.jahr,b.hnr,
a.beitrag_nr,a.beteil_nr
from honorar a, honausg b
where
a.adr_gr = b.adr_gr and
a.adr_nr = b.adr_nr and
a.person_nr = b.person_nr and
a.e_mandant = b.e_mandant and
a.hon_nr = b.hon_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."HONOVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "HON_NR", "L_TITEL_NR", "AUTOR_NR", "L_AUSG_NR", "E_MANDANT", "HONART_ID", "NACHNAME", "HAUPT_NAME", "ARTIKEL_NR", "ABRUF_NR", "BELEG_NR", "BELEG_DAT", "ABRECH_DAT_VON", "ABRECH_DAT_BIS") AS
  select h.adr_gr, h.adr_nr, h.person_nr, h.hon_nr, h.l_titel_nr, h.autor_nr, h.l_ausg_nr, h.e_mandant,
           h.honart_id, b.nachname, b.haupt_name, m.artikel_nr, h.abruf_nr, h.beleg_nr, h.beleg_dat,
           h.abrech_dat_von, h.abrech_dat_bis
from honorar h, hoautor a, buautor b, bumanaus m
where a.l_titel_nr = h.l_titel_nr and
           a.autor_nr  = h.autor_nr and
           a.l_ausg_nr  = h.l_ausg_nr and
           a.e_mandant  = h.e_mandant and
           a.honart_id = h.honart_id and
           b.l_titel_nr = h.l_titel_nr and
           b.autor_nr  = h.autor_nr and
           m.l_ausg_nr  = h.l_ausg_nr and
           m.e_mandant  = h.e_mandant and
           h.kz_zw_abrech = 'F';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."HONVIEW" ("ADR_GR", "ADR_NR", "HAUPT_NAME", "HAUPT_ORT", "NAME1", "NAME2", "NAME3", "LAND_CODE", "PERSON_NR", "NACHNAME", "VORNAME", "HON_NR", "KZ_RE_HO", "E_MANDANT", "OBJ_NR", "SEITE", "HONART_ID", "RECH_NR", "RECH_DAT", "DAT_NEU", "BELEG_NR", "BELEG_DAT", "KZ_STORNO", "BESCHREIBUNG", "AUSG", "JAHR", "HNR", "DAT_VON", "DAT_BIS", "BEITRAG_NR", "BETEIL_NR") AS
  select a.adr_gr, a.adr_nr, a.haupt_name, a.haupt_ort, a.name1, a.name2, a.name3,
       a.land_code, b.person_nr, b.nachname, b.vorname, c.hon_nr, c.kz_re_ho,
       c.e_mandant, c.obj_nr, c.seite, c.honart_id, c.rech_nr, c.rech_dat,
       c.dat_neu, c.beleg_nr, c.beleg_dat, c.kz_storno, c.beschreibung, d.ausg,
       d.jahr, d.hnr, d.dat_von, d.dat_bis, c.BEITRAG_NR, c.BETEIL_NR
from anschr a, person b, honorar c, honausg d
where a.adr_gr = b.adr_gr and
      a.adr_nr = b.adr_nr and
      b.adr_gr = c.adr_gr and
      b.adr_nr = c.adr_nr and
      b.person_nr = c.person_nr and
      c.adr_gr = d.adr_gr and
      c.adr_nr = d.adr_nr and
      c.person_nr = d.person_nr and
      c.hon_nr = d.hon_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."HOSTAFVW" ("L_TITEL_NR", "AUTOR_NR", "L_AUSG_NR", "E_MANDANT", "HONART_ID", "AB_MENGE", "HON_BETRAG", "HON_PROZ", "LP_KUERZ_PROZ", "KZ_ERLEDIGT") AS
  select
l_titel_nr, autor_nr, l_ausg_nr, e_mandant, a.honart_id, ab_menge, hon_betrag,hon_proz,lp_kuerz_proz,kz_erledigt
from hostaff a, honart c
where a.honart_id = c.honart_id
and c.kz_hostafhi = 'F'
union
select l_titel_nr, autor_nr, l_ausg_nr, e_mandant, a.honart_id, ab_menge, hon_betrag,hon_proz,lp_kuerz_proz,kz_erledigt
from hostafhi a, honart c
where gueltig_ab =
(select max(gueltig_ab) from hostafhi b
where b.l_titel_nr = a.l_titel_nr
and b.autor_nr = a.autor_nr
and b.l_ausg_nr = a.l_ausg_nr
and b.e_mandant = a.e_mandant
and b.honart_id = a.honart_id
and b.ab_menge = a.ab_menge)
and a.honart_id = c.honart_id
and c.kz_hostafhi = 'T';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."JXV_ADM_EOBSTEAUFT" ("E_MANDANT", "OBJ_NR", "AUSG", "U_OBJ_NR", "U_AUSG", "HNR_NUM_VON", "HNR_NUM_BIS", "OBJEKT", "UNTEROBJEKT", "HEFTNUMMER_VON", "HEFTNUMMER_BIS", "ERLOES_ANT") AS
  WITH p AS
(
SELECT e_mandant, obj_nr, ausg, u_obj_nr
, u_ausg_nr																u_ausg
, TO_NUMBER(TRIM(jahr_ab) || LPAD(hnr_ab,3,'0'))						hnr_num_von
, TRIM(e_mandant) || '/' || TRIM(obj_nr) || '/' || TRIM(ausg)			objekt
, TRIM(e_mandant) || '/' || TRIM(u_obj_nr) || '/' || TRIM(u_ausg_nr)	unterobjekt
, TRIM(jahr_ab) || '/' || LPAD(hnr_ab,2,'0')							heftnummer
, erloes_ant
FROM eobsteauft
)
SELECT e_mandant, obj_nr, ausg, u_obj_nr, u_ausg, hnr_num_von
,  NVL((SELECT MIN(hnr_num_von)-1
   FROM p p2
   WHERE p2.e_mandant=p.e_mandant AND p2.obj_nr=p.obj_nr AND p2.ausg=p.ausg AND p2.u_obj_nr=p.u_obj_nr AND p2.u_ausg=p.u_ausg
   AND p2.hnr_num_von>p.hnr_num_von),9999999) hnr_num_bis
, objekt
, unterobjekt
, heftnummer heftnummer_von
,  REPLACE(TO_CHAR(NVL((SELECT (MIN(hnr_num_von)-1)
   FROM p p2
   WHERE p2.e_mandant=p.e_mandant AND p2.obj_nr=p.obj_nr AND p2.ausg=p.ausg AND p2.u_obj_nr=p.u_obj_nr AND p2.u_ausg=p.u_ausg
   AND p2.hnr_num_von>p.hnr_num_von),9999001)/1000,'9999.999'),'.','/') heftnummer_bis
, erloes_ant
FROM p
--WHERE e_mandant='AV';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."JXV_ADM_EOBSTEAUFT_OBJEKT" ("E_MANDANT", "OBJEKT", "UNTEROBJEKT", "HEFTNUMMER_AB", "ERLOES_ANTEIL") AS
  SELECT e_mandant
, TRIM(e_mandant) || '/' || TRIM(obj_nr) || '/' || TRIM(ausg)			OBJEKT
, TRIM(e_mandant) || '/' || TRIM(u_obj_nr) || '/' || TRIM(u_ausg_nr)	UNTEROBJEKT
, TRIM(jahr_ab) || '/' || LPAD(hnr_ab,2,'0')							HEFTNUMMER_AB
, erloes_ant
FROM eobsteauft;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."KOBUKVIE" ("E_MANDANT", "ARTIKEL_NR", "L_AUSG_NR", "L_AUFL_NR", "AUFLAGE_NR", "STATUS", "AUFL_DAT_SOLL", "AUFL_DAT_IST", "PROV_GRP", "VERTRETER_ID", "EQUIP_ID", "EQUIP_BEZ", "EQUIP_MENGE") AS
  select c.e_mandant, c.artikel_nr,
       a.l_ausg_nr, a.l_aufl_nr, a.auflage_nr, a.status, a.aufl_dat_soll, a.aufl_dat_ist,
	   c.prov_grp, c.vertreter_id,
	   b.equip_id,
	   d.bez,
	   e.menge
from buaufl a, koorequi b, bumanaus c, koequipm d, koorequi e
where a.l_ausg_nr = b.l_ausg_nr
and   a.l_ausg_nr = c.l_ausg_nr
and   a.l_aufl_nr = b.l_aufl_nr
and   b.equip_id  = d.equip_id
and   a.l_ausg_nr = e.l_ausg_nr
and   a.l_aufl_nr = e.l_aufl_nr
and   b.equip_id  = e.equip_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."KOMMPVIE" ("E_MANDANT", "PROFIL_NR", "BEZEICHNUNG", "KZ_STANDARD", "VERWENDUNG", "VERW_TYP", "TEL_ART", "PRIO", "KZ_AKTIV") AS
  select k.E_MANDANT, k.PROFIL_NR, k.BEZEICHNUNG,k.KZ_STANDARD,p.VERWENDUNG,p.VERW_TYP,t.TEL_ART,t.PRIO,p.kz_aktiv
from kommprof k, kommppos p, kommptel t
where k.profil_nr   = p.profil_nr
  and k.e_mandant   = p.e_mandant
  and t.profil_nr   = p.profil_nr
  and t.e_mandant   = p.e_mandant
  and t.VERWENDUNG  = p.VERWENDUNG;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."KOMWEGVW" ("ADR_GR", "ADR_NR", "PERSON_NR", "TEL_ART", "NUMMER", "VERW_ID", "KOM_TYP") AS
  select
t.adr_gr, t.adr_nr, t.person_nr, t.tel_art, t.nummer, a.verw_id, k.kom_typ
from telecom t, teleart a, komweg k
