  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."KOMWEGVW1" ("ADR_GR", "ADR_NR", "PERSON_NR", "TEL_ART", "NUMMER", "VERW_ID", "KOM_TYP") AS
  select
t.adr_gr, t.adr_nr, t.person_nr, t.tel_art, t.nummer, a.verw_id, k.kom_typ
