t.adr_gr = k.adr_gr and
t.adr_nr = k.adr_nr and
t.person_nr = k.person_nr and
t.tel_art = k.tel_art and
a.tel_art = t.tel_art;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."KONDVIEW" ("LFD_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "AKT_ID", "ABO_KOND", "A_TYP", "Q_CODE", "Q_AUSP_CODE", "GUELTIG_AB", "HERKUNFT", "UPOS_NR", "NGRUPPE", "VERTRETER_ID", "VERTRETER_TYP", "REG_ID", "REG_CODE", "WAEHRUNG", "STEUER_CODE", "STATUS", "LANDART", "BETRAG", "PROV_SATZ", "BUCH_BETRAG", "BUCH_PROZ", "PROV_GRP", "L_AUSG_NR", "VERTRET_AUFT_TYP", "KZ_SBS_PROVISION", "KZ_RAB_ABZUG", "KZ_ABO_BRINGER", "KZ_MENGEN_ABH") AS
  SELECT 	v.lfd_nr, v.adr_gr, v.adr_nr, v.person_nr, v.e_mandant, v.obj_nr, v.ausg, v.akt_id, v.abo_kond,
		v.a_typ, v.q_code, v.q_ausp_code, v.gueltig_ab, v.herkunft,
		u.upos_nr, u.ngruppe, u.vertreter_id, u.vertreter_typ, u.reg_id, u.reg_code, u.waehrung,
		u.steuer_code, u.status, u.landart, u.betrag, u.prov_satz, u.buch_betrag, u.buch_proz, u.prov_grp,
		u.l_ausg_nr, u.vertret_auft_typ, u.kz_sbs_provision, u.kz_rab_abzug, u.kz_abo_bringer, u.kz_mengen_abh
FROM   	vzverkon v, vzveruko u
WHERE	v.lfd_nr     = u.lfd_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."LANDV" ("LAND_CODE", "LAND_KURZ", "WAEHRUNG", "LAND", "LANDINT", "TEL_VORWAHL", "EG_KZ", "L_POST", "PF_TEXT", "TEXT_EGID", "PLZ_MO", "PLZ_TEXT", "ZH_TEXT", "MWST_TEXT", "KZ_LUFT", "LAND_GR", "ISTATBEST", "ERSTMAHN_TAGE", "PLZ_LAENGE", "LKZ_ISO2", "LKZ_KFZ", "ERDTEIL", "PLZ_SCHEMA") AS
  select LAND_CODE, LAND_KURZ, WAEHRUNG, LAND, LANDINT, TEL_VORWAHL, EG_KZ, L_POST, PF_TEXT, TEXT_EGID, PLZ_MO, PLZ_TEXT, ZH_TEXT, MWST_TEXT, KZ_LUFT, LAND_GR, ISTATBEST, ERSTMAHN_TAGE, PLZ_LAENGE, LKZ_ISO2, LKZ_KFZ, ERDTEIL, PLZ_SCHEMA
from land
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."LWVTITEL" ("MANDANT", "ARTIKEL_NR", "TITEL", "PREIS", "PREISKAT", "MELDE_NR", "MELDE_TEXT", "ISBN", "AUFLAGE_NR", "LIST_NR") AS
  select m.e_mandant, m.artikel_nr, t.titel1,s.preis, p.preiskat, l.meld_nr, n.meld_text ,b.isbn, l.auflage_nr,p.list_nr
  from  butitel t, buausgab b, bumanaus m, buaufl l,
        buplist p, bumpreis s, bumeldnr n
 where  b.l_titel_nr = t.l_titel_nr
   and  m.l_ausg_nr  = b.l_ausg_nr
   and  l.l_ausg_nr  = b.l_ausg_nr
   and  ((b.kz_aufl_preis = 'T' and p.l_aufl_nr = l.l_aufl_nr) or (b.kz_aufl_preis = 'F' and p.l_aufl_nr = 0))
   and  m.l_ausg_nr  = p.l_ausg_nr
   and  m.e_mandant  = p.e_mandant
   and  p.preiskat  IN ('LP','VP')
   and  p.waehrung = 'EUR'
   and  p.list_nr    = s.list_nr
   and  s.menge      = 1
   and  l.meld_nr    = n.meld_nr
   and  (p.gueltig_ab = (select max(f.gueltig_ab) from buplist f
                        where  m.l_ausg_nr  = f.l_ausg_nr
                          and  f.preiskat   = 'LP'
                          and  f.waehrung   = 'EUR'
                          and  f.gueltig_ab <= '1.12.2017')
   or p.gueltig_ab = (select max(f.gueltig_ab) from buplist f
                        where  m.l_ausg_nr  = f.l_ausg_nr
                          and  f.preiskat   = 'VP'
                          and  f.waehrung   = 'EUR'
                          and  f.gueltig_ab <= '1.12.2017'));


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MAERVIEW" ("E_MANDANT", "AKT_ID", "UAKT_ID", "KZ_EF", "ID_VUAKT", "SOLL_ANZ_ADR", "IST_ANZ_ADR", "ER_CODE", "F_UAKT_ID", "VERWEND_TYP", "VERWEND_TYP_2", "WANDL_PROZ") AS
  select	r.e_mandant, r.akt_id, r.uakt_id, u.kz_ef, u.id_vuakt,
	u.soll_anz_adr, u.ist_anz_adr, r.er_code, r.f_uakt_id,
	e.verwend_typ, e.verwend_typ_2, u.wandl_proz
from respvorg r, ereignis e, muaktion u
where r.er_code   = e.er_code
and   r.e_mandant = u.e_mandant
and   r.akt_id    = u.akt_id
and   r.f_uakt_id = u.uakt_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MAJOBVIE" ("JOBNR", "BENUTZER_ID", "JOBSTATUS", "JOBTYP", "HOSTNAME", "STARTZEIT", "JOBSTART", "PROTOKOLL", "E_MANDANT", "AKT_ID", "UAKT_ID") AS
  select
d.jobnr, d.benutzer_id, d.jobstatus, d.jobtyp, d.hostname, d.startzeit, d.jobstart, d.protokoll,
trim(a.wert), trim(b.wert), trim(c.wert)
from jobtab d
inner join jobparam a on
   a.jobnr = d.jobnr and
   a.lfdnr = 1
inner join jobparam b on
   b.jobnr = d.jobnr and
   b.lfdnr = 7
inner join jobparam c on
   c.jobnr = d.jobnr and
   c.lfdnr = 8
where d.esname = 'VZMA220B';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MATNPABO" ("ADR_GR", "E_MANDANT", "AKT_ID", "UAKT_ID", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR") AS
  select  t.adr_gr,t.e_mandant,t.akt_id,t.uakt_id,t.adr_nr,t.person_nr,d.obj_nr,d.ausg,d.abo_nr
from fdabodat d,fdabruf r, muaktion u, teilnemp t, abostamm a
where u.e_mandant=t.e_mandant and u.akt_id=t.akt_id and u.uakt_id=t.uakt_id
and r.mandant=t.e_mandant and r.w_akt_id=t.akt_id and r.w_uakt_id=t.uakt_id and r.w_start_id=t.start_id
and r.kopie_von_abr=u.fd_abruf_nr
and d.abruf_nr=r.abruf_nr
and ((r.empfaenger = 'L' and d.adr_nr_le= t.adr_nr and d.person_nr_le= t.person_nr) or
     (r.empfaenger = 'R' and d.adr_nr_re= t.adr_nr and d.person_nr_re= t.person_nr) or
     (r.empfaenger = 'P' and d.adr_nr_pr= t.adr_nr and d.person_nr_pr= t.person_nr))
and d.adr_gr=t.adr_gr
and a.e_mandant=t.e_mandant and a.adr_gr=d.adr_gr and a.adr_nr=t.adr_nr and a.person_nr=t.person_nr and a.obj_nr=d.obj_nr and a.ausg=d.ausg and a.abo_nr=d.abo_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MAVBVIEW" ("E_MANDANT", "AKT_ID", "UAKT_ID", "MODUL", "L_AUSG_NR", "L_AUSG_NR_MA", "L_AUFL_NR") AS
  select e_mandant, akt_id, uakt_id, modul, l_ausg_nr, 0, -1
from MUAKTOBJ o
where l_ausg_nr > 0
union
select e_mandant, akt_id, uakt_id, 'BU', l_ausg_nr_zu, l_ausg_nr, -1
from MHAKTIZU z
union
select v.e_mandant, v.akt_id, v.uakt_id, 'VZ', a.l_ausg_nr, 0, a.l_aufl_nr
from AKTVORB v, AKTVORBA a
where v.e_mandant = a.e_mandant
and v.akt_id = a.akt_id
and v.obj_nr = a.obj_nr
and v.ausg = a.ausg;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MAZYKVIE" ("HAUPT_NR", "E_MANDANT", "AKT_ID", "UAKT_ID", "KZ_AKTIV") AS
  select a.haupt_nr, substr(b.wert,1,2), substr(c.wert,1,12), substr(d.wert,1,4), 'T'
from zykhaupt a, zykparam b, zykparam c, zykparam d
where a.haupt_nr = b.haupt_nr
and b.folge_nr = 0
and b.lfdnr = 1
and a.haupt_nr = c.haupt_nr
and c.folge_nr = 0
and c.lfdnr = 7
and a.haupt_nr = d.haupt_nr
and d.folge_nr = 0
and d.lfdnr = 8
and a.esname = 'VZMA220B'
and ((a.art = 'W' and (so = 'T' or mo = 'T' or di = 'T' or mi = 'T' or do = 'T' or fr = 'T' or sa = 'T'))
     or (a.art = 'M' and (tag is not null or wochentag is not null)))
union
select a.haupt_nr, substr(b.wert,1,2), substr(c.wert,1,12), substr(d.wert,1,4), 'F'
from zykhaupt a, zykparam b, zykparam c, zykparam d
where a.haupt_nr = b.haupt_nr
and b.folge_nr = 0
and b.lfdnr = 1
and a.haupt_nr = c.haupt_nr
and c.folge_nr = 0
and c.lfdnr = 7
and a.haupt_nr = d.haupt_nr
and d.folge_nr = 0
and d.lfdnr = 8
and a.esname = 'VZMA220B'
and (not((a.art = 'W' and (so = 'T' or mo = 'T' or di = 'T' or mi = 'T' or do = 'T' or fr = 'T' or sa = 'T'))
     or (a.art = 'M' and (tag is not null or wochentag is not null))) or a.art is null);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MEGABLUBB" ("SUCHTITEL", "TITEL", "SPRACHE", "ORIGINALTITEL", "ORIGINALSPRACHE", "SACHGRUPPE", "ISBN", "EAN", "PRODUKTTYP", "REIHEN_CODE", "KOMBITYP", "ISSN", "AUSGABENBEZEICHNUNG", "ARTIKELGRUPPE", "BAND_NR", "GEWICHT", "VERLAGS_ID", "EINKAUFSRABATTGRUPPE", "BREITE", "HOEHE", "DICKE", "BESTAND", "EIGENTITEL", "SPERR_GRUND", "E_MANDANT", "ARTIKEL_NR", "STEUER_CODE", "BRUT_NET", "LAGER_MANDANT", "PROVISIONSGRUPPE", "RABATTGRUPPE", "NOVITATENDATUM", "LOSCHKENNZEICHEN", "NACHNAME", "VORNAME", "ADR_NR_AUT", "PERSON_NR_AUT", "AUTOR_TYP", "AUFLAGENNUMMER", "AUFLAGENBEZEICHNUNG", "ETGEPLANT", "ETIST", "MELDENUMMER", "MERKMAL", "AUSPRAGUNG", "KOMBIARTIKELNUMMER", "GULTIGKEITSDATUM", "PREISKATEGORIE", "WAEHRUNG", "SUBSKRIPTIONSENDE", "MENGE", "PREIS", "LAGER_CODE", "GES_MENGE", "ABRECHNUNGSVERLAG") AS
  select   t.titel_such Suchtitel, t.titel1 Titel, t.sprach_code Sprache, t.orig_titel Originaltitel, t.org_spr_code Originalsprache, g.sach_grp Sachgruppe,
           b.isbn, b.ean, b.prod_typ Produkttyp,  b.reihen_code, b.kombityp, b.issn, b.ausg_text Ausgabenbezeichnung, b.grup_id Artikelgruppe, b.band_nr,b.gewicht, b.verlags_id,b.ek_rab_gr Einkaufsrabattgruppe,
           b.breite,b.hoehe,b.dicke,b.kz_bestand Bestand,b.kz_eigen Eigentitel,b.sperr_grund,
           m.e_mandant, m.artikel_nr, m.steuer_code,m.brut_net,m.lager_mandant,m.prov_grp Provisionsgruppe,m.rab_grp Rabattgruppe,m.nov_dat Novitatendatum, m.kz_loeschen Loschkennzeichen,
           a.nachname, a.vorname,a.adr_nr_aut,a.person_nr_aut,a.autor_typ, l.auflage_nr Auflagennummer, l.aufl_text Auflagenbezeichnung, l.aufl_dat_soll ETgeplant, l.aufl_dat_ist ETIst,
           l.meld_nr Meldenummer, q.qm_id Merkmal, q.qaus Auspragung, m1.artikel_nr KOMBIArtikelnummer,
           p.gueltig_ab Gultigkeitsdatum, p.preiskat Preiskategorie, p.waehrung, p.subs_dat1 Subskriptionsende, pr.menge,pr.preis, x.lager_code, x.ges_menge,
           (case when m.artikel_nr like '69%' then '920' when m.artikel_nr like '67%' then '921' when m.artikel_nr like '53%' then '930' when m.artikel_nr like '70%' then '940' end) Abrechnungsverlag
  from  xxx.buautor a, xxx.butitel t, xxx.buausgab b, xxx.bumanaus m, xxx.buaufl l, xxx.bugruppe g, xxx.buartqa q, xxx.bukombi k, xxx.bumanaus m1, xxx.buplist p, xxx.bumpreis pr, xxx.bulagges x, xxx.bulagmin i
 where t.l_titel_nr = a.l_titel_nr (+) and
            b.l_titel_nr  = t.l_titel_nr and
            m.l_ausg_nr (+) = b.l_ausg_nr and
            g.l_titel_nr (+)  = b.l_titel_nr and
            l.l_ausg_nr = b.l_ausg_nr and
            q.l_ausg_nr (+) = b.l_ausg_nr and
            q.prod_typ (+) = b.prod_typ and
            k.u_ausg_nr (+) = l.l_ausg_nr and
            k.l_aufl_nr (+) = l.l_aufl_nr and
            m1.l_ausg_nr (+) = k.l_ausg_nr and
            p.e_mandant (+)  = m.e_mandant and
            p.l_ausg_nr (+) = m.l_ausg_nr and
            pr.list_nr (+) = p.list_nr and
            i.l_ausg_nr  = l.l_ausg_nr and
            i.l_aufl_nr  = l.l_aufl_nr and
            x.l_ausg_nr (+)= i.l_ausg_nr and
            x.l_aufl_nr (+)= i.l_aufl_nr and
            x.lager_code (+)= i.lager_code and
            x.e_mandant (+)= i.e_mandant and
            not exists (select * from buartref r where ref_id='TOIS' and r.l_ausg_nr=b.l_ausg_nr);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MENUVIEW" ("POS", "KOPF", "KTYP", "KBESCHREIBUNG", "PTYP", "PBESCHREIBUNG", "PAUFRUF", "PLOG_ES", "SORTIERUNG") AS
  select pos.knotenid, kopf.knotenid, kopf.knotentyp, kopf.beschreibung,
       pos.knotentyp, pos.beschreibung, pos.aufruf, pos.log_es_name,
       kante.sortierung
  from menue kopf, menuverb kante, menue pos
 where kopf.knotentyp = 'M'
   and kopf.knotenid = kante.menunr
   and kante.menupnr = pos.knotenid
union
select favor.knotenid, -1, 'M',
       favor.benutzer_id||'                        ',
       m.knotentyp, favor.beschreibung, m.aufruf, m.log_es_name,
       favor.sortierung
  from menufavo favor, menue m
 where favor.knotenid = m.knotenid;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MESSEBVI" ("MESSE_ID", "BENUTZER_ID", "LFD_NR", "WEBACC_NAME", "GUELTIG_AB", "GUELTIG_BIS", "E_MANDANT", "ADR_GR", "BERECHT_C4SOURCE") AS
  select
a.messe_id, b.benutzer_id, b.lfd_nr, c.webacc_name, a.gueltig_ab, a.gueltig_bis, a.e_mandant, a.adr_gr, c.berecht_c4source
from messe a, messeben b, benwebacc c
where a.messe_id = b.messe_id
and b.benutzer_id = c.benutzer_id
and b.lfd_nr = c.lfd_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MODONVIEW" ("ENTITAET", "MODIFIED_ON", "ADR_GR", "ADR_NR", "PERSON_NR", "AUFT_NR", "AUF_POS", "E_MANDANT", "ADR_NR_LE", "PERSON_NR_LE", "OBJ_NR", "AUSG", "ABO_NR", "TEL_ART", "SUCH_NUMMER") AS
  SELECT 'PERSON', modified_on, adr_gr, adr_nr, person_nr,
       0, 0,
       null, null, null,
       null, null, null,
       null, null
FROM person p
UNION
SELECT 'ANSCHR', modified_on, adr_gr, adr_nr, 0,
       0, 0,
       null, null, null,
       null, null, null,
       null, null
FROM anschr a
UNION
SELECT 'AINFO', modified_on, adr_gr, adr_nr, 0,
       0, 0,
       null, null, null,
       null, null, null,
       null, null
FROM ainfo ai
UNION
SELECT 'BUAUFTRA', modified_on, adr_gr, adr_nr_RE, person_nr_RE,
       auft_nr, 0,
       e_mandant, adr_nr_LE, person_nr_LE,
       null, null, null,
       null, null
FROM buauftra bu
UNION
SELECT 'ABOSTAMM', modified_on, adr_gr, adr_nr_BV, person_nr_BV,
       auftrags_NR, 0,
       e_mandant, adr_nr, person_nr,
       obj_nr, ausg, abo_nr,
       null, null
FROM abostamm abo
UNION
SELECT 'TELECOM', modified_on, adr_gr, adr_nr, person_nr,
       0, 0,
       null, null, null,
       null, null, null,
      tel_art, such_nummer
FROM telecom tel;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MPAKTVIE" ("ADR_GR", "ADR_NR", "PERSON_NR", "VORNAME", "NACHNAME", "LAND_CODE", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "E_MANDANT", "AKT_ID", "UAKT_ID", "L_AUSG_NR", "L_AUFL_NR", "GUELTIG_AB", "L_TITEL_NR", "ARTIKEL_NR", "ADR_NR_VA", "LAND_CODE_VA", "HAUPT_NAME_VA", "HAUPT_PLZ_VA", "HAUPT_ORT_VA", "NAME1_VA", "NAME2_VA", "NAME3_VA") AS
  select
b.adr_gr, b.adr_nr_aut, b.person_nr_aut,
c.vorname, c.nachname,
d.land_code, d.haupt_name, d.haupt_plz, d.haupt_ort,
a.e_mandant, a.akt_id, a.uakt_id,a.l_ausg_nr, a.l_aufl_nr, a.gueltig_ab,
f.l_titel_nr,
i.artikel_nr,
g.adr_nr,
h.land_code, h.haupt_name, h.haupt_plz, h.haupt_ort,h.name1, h.name2, h.name3
from muaktva a
   inner join buausgab f on
   a.l_ausg_nr = f.l_ausg_nr and
   f.kz_loeschen = 'F'
      left outer join busperr k on
      k.sperr_grund = f.sperr_grund and
      k.sperre_fuer != 'A'
      inner join buautor b on
      b.l_titel_nr = f.l_titel_nr and
      b.kz_hpaut = 'T'
         inner join person c on
         c.adr_gr = b.adr_gr and
         c.adr_nr = b.adr_nr_aut and
         c.person_nr = b.person_nr_aut
            inner join anschr d on
            d.adr_gr = c.adr_gr and
            d.adr_nr = c.adr_nr
   inner join bumanaus i on
   i.l_ausg_nr = a.l_ausg_nr and
   i.e_mandant = a.e_mandant and
   i.kz_loeschen = 'F'
   left outer join buliefer g on
   g.l_ausg_nr = a.l_ausg_nr
      left outer join anschr h on
      h.adr_gr = g.adr_gr and
      h.adr_nr = g.adr_nr
where not exists
(select x.l_ausg_nr from
muaktva x where
x.l_ausg_nr = a.l_ausg_nr and
x.l_aufl_nr = a.l_aufl_nr and
x.gueltig_ab > a.gueltig_ab and
x.gueltig_ab <= sysdate);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MUAKERVI" ("E_MANDANT", "AKT_ID", "UAKT_ID", "B_UAKTID", "KZ_EF", "ID_VUAKT", "KZ_LWIED", "N_VAKT", "SOLL_START", "LIST_START", "TN_CODE", "KZ_ALSTEU", "KZ_FORTLAUFEND", "SOLL_ENDE", "AKT_CODE", "B_AKTID", "SOLL_BEG_H", "SOLL_ENDE_H", "IST_ENDE_H", "MODUL", "ER_CODE", "VERWEND_TYP", "VERWEND_TYP_2", "BEZ_ER", "ANZ_FOLGEAKT", "BENUTZER_ID_H", "ABRUF_ART") AS
  select
u.e_mandant, u.akt_id, u.uakt_id, u.b_uaktid, u.kz_ef, u.id_vuakt, u.kz_lwied, u.n_vakt,
u.soll_start, u.list_start, u.tn_code, u.kz_alsteu, u.kz_fortlaufend, u.soll_ende,
h.akt_code, h.b_aktid, h.soll_beg, h.soll_ende, h.ist_ende, h.modul,
u.er_code, e.verwend_typ, e.verwend_typ_2, e.bez,
(select count(*) from muaktion f where
 f.e_mandant = u.e_mandant and
 f.akt_id = u.akt_id and
 f.id_vuakt = u.uakt_id),
h.benutzer_id, u.abruf_art
from muaktion u
  inner join  mhaktion h on
  h.e_mandant = u.e_mandant and
  h.akt_id = u.akt_id
  inner join ereignis e on
  e.er_code = u.er_code
  where u.er_code is not null
union
select
u.e_mandant, u.akt_id, u.uakt_id, u.b_uaktid, u.kz_ef, u.id_vuakt, u.kz_lwied, u.n_vakt,
u.soll_start, u.list_start, u.tn_code, u.kz_alsteu, u.kz_fortlaufend, u.soll_ende,
h.akt_code, h.b_aktid, h.soll_beg, h.soll_ende, h.ist_ende, h.modul,
r.er_code, e.verwend_typ, e.verwend_typ_2, e.bez,
(select count(*) from muaktion f where
 f.e_mandant = u.e_mandant and
 f.akt_id = u.akt_id and
 f.id_vuakt = u.uakt_id),
h.benutzer_id, u.abruf_art
from muaktion u
  inner join  mhaktion h on
  h.e_mandant = u.e_mandant and
  h.akt_id = u.akt_id
  inner join respvorg r on
  r.e_mandant = u.e_mandant and
  r.akt_id = u.akt_id and
  r.uakt_id = u.uakt_id
  inner join ereignis e on
  e.er_code = r.er_code
where u.er_code is null;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MUAKTIVI" ("E_MANDANT", "AKT_ID", "UAKT_ID", "START_ID", "KZ_EF", "ER_CODE", "ADR_GR", "ADR_NR", "PERSON_NR") AS
  select
u.e_mandant, u.akt_id, u.uakt_id, t.start_id, u.kz_ef, u.er_code, t.adr_gr, t.adr_nr,t.person_nr
from muaktion u
inner join teilnemp t on
  t.e_mandant = u.e_mandant and
  t.akt_id = u.akt_id and
  t.uakt_id = u.uakt_id
where er_code is not null
union
select
u.e_mandant, u.akt_id, u.uakt_id, t.start_id, u.kz_ef, r.er_code, t.adr_gr, t.adr_nr,t.person_nr
from muaktion u
inner join teilnemp t on
  t.e_mandant = u.e_mandant and
  t.akt_id = u.akt_id and
  t.uakt_id = u.uakt_id
  inner join respvorg r on
  r.e_mandant = u.e_mandant and
  r.akt_id = u.akt_id and
  r.f_uakt_id = u.uakt_id
  inner join ereignis e on
  e.er_code = r.er_code
where u.er_code is null and t.start_id <> 9999 and
  (e.verwend_typ = 'VZ' or
   e.verwend_typ = 'BU' or
   ((e.verwend_typ = 'WERBEH') and (e.verwend_typ_2 = 'PH' or e.verwend_typ_2 = 'INTER')) or
   e.verwend_typ = 'SONS');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MUAKTVVI" ("E_MANDANT", "AKT_ID", "UAKT_ID", "L_AUSG_NR", "L_AUFL_NR", "GUELTIG_AB", "TITEL_SUCH", "AUSG_TEXT", "ARTIKEL_NR", "AUFLAGE_NR", "AUFL_TEXT", "KZ_MULTI_GS") AS
  select
a.e_mandant, a.akt_id, a.uakt_id, a.l_ausg_nr, a.l_aufl_nr, a.gueltig_ab,
d.titel_such, b.ausg_text, c.artikel_nr, e.auflage_nr, e.aufl_text,a.kz_multi_gs
from muaktva a
inner join bumanaus c on
c.l_ausg_nr = a.l_ausg_nr and
c.e_mandant = a.e_mandant and
c.kz_loeschen = 'F'
inner join buaufl e on
e.l_ausg_nr = a.l_ausg_nr and
e.l_aufl_nr = a.l_aufl_nr
inner join  buausgab b on
b.l_ausg_nr = a.l_ausg_nr and
b.kz_loeschen = 'F' and
b.kombityp != 'R' and
(b.kombityp != 'B' or b.einzel_fakt = 'T') and
b.kz_aufl_best = 'T'
inner join butitel d on
d.l_titel_nr = b.l_titel_nr
left outer join busperr f on
f.sperr_grund = b.sperr_grund and
f.sperre_fuer != 'A'
where not exists
(select x.l_ausg_nr from
muaktva x where
x.l_ausg_nr = a.l_ausg_nr and
x.l_aufl_nr = a.l_aufl_nr and
x.gueltig_ab > a.gueltig_ab and
x.gueltig_ab <= sysdate)
union
select
a.e_mandant, a.akt_id, a.uakt_id, a.l_ausg_nr, a.l_aufl_nr, a.gueltig_ab,
d.titel_such, b.ausg_text, c.artikel_nr,null, '                                                                                                                                                      ',a.kz_multi_gs
from muaktva a
inner join bumanaus c on
c.l_ausg_nr = a.l_ausg_nr and
c.e_mandant = a.e_mandant and
c.kz_loeschen = 'F'
inner join buaufl e on
e.l_ausg_nr = a.l_ausg_nr and
e.l_aufl_nr = a.l_aufl_nr
inner join  buausgab b on
b.l_ausg_nr = a.l_ausg_nr and
b.kz_loeschen = 'F' and
b.kombityp != 'R' and
(b.kombityp != 'B' or b.einzel_fakt = 'T') and
b.kz_aufl_best = 'F'
inner join butitel d on
d.l_titel_nr = b.l_titel_nr
left outer join busperr f on
f.sperr_grund = b.sperr_grund and
f.sperre_fuer != 'A'
where not exists
(select x.l_ausg_nr from
muaktva x where
x.l_ausg_nr = a.l_ausg_nr and
x.l_aufl_nr = a.l_aufl_nr and
x.gueltig_ab > a.gueltig_ab and
x.gueltig_ab <= sysdate);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MUAKVIEW" ("E_MANDANT", "AKT_ID", "UAKT_ID", "B_UAKTID", "KZ_EF", "ID_VUAKT", "KZ_LWIED", "N_VAKT", "SOLL_START", "LIST_START", "TN_CODE", "KZ_ALSTEU", "KZ_FORTLAUFEND", "SOLL_ENDE", "AKT_CODE", "B_AKTID", "SOLL_BEG_H", "SOLL_ENDE_H", "IST_ENDE_H", "MODUL", "ER_CODE", "VERWEND_TYP", "VERWEND_TYP_2", "BEZ_ER", "ANZ_FOLGEAKT", "BENUTZER_ID_H", "ABRUF_ART") AS
  select
u.e_mandant, u.akt_id, u.uakt_id, u.b_uaktid, u.kz_ef, u.id_vuakt, u.kz_lwied, u.n_vakt,
u.soll_start, u.list_start, u.tn_code, u.kz_alsteu, u.kz_fortlaufend, u.soll_ende,
h.akt_code, h.b_aktid, h.soll_beg, h.soll_ende, h.ist_ende, h.modul,
r.er_code, e.verwend_typ, e.verwend_typ_2, e.bez,
(select count(*) from muaktion f where
 f.e_mandant = u.e_mandant and
 f.akt_id = u.akt_id and
 f.id_vuakt = u.uakt_id),
h.benutzer_id, u.abruf_art
from muaktion u
  inner join  mhaktion h on
  h.e_mandant = u.e_mandant and
  h.akt_id = u.akt_id
  left outer join respvorg r on
