    left outer join ereignis e on
    e.er_code = r.er_code;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MUAKVIEW2" ("E_MANDANT", "AKT_ID", "UAKT_ID", "B_UAKTID", "KZ_EF", "ID_VUAKT", "KZ_LWIED", "N_VAKT", "SOLL_START", "LIST_START", "TN_CODE", "KZ_ALSTEU", "KZ_FORTLAUFEND", "SOLL_ENDE", "AKT_CODE", "B_AKTID", "SOLL_BEG_H", "SOLL_ENDE_H", "IST_ENDE_H", "MODUL", "ER_CODE", "VERWEND_TYP", "VERWEND_TYP_2") AS
  select
u.e_mandant, u.akt_id, u.uakt_id, u.b_uaktid, u.kz_ef, u.id_vuakt, u.kz_lwied, u.n_vakt,
u.soll_start, u.list_start, u.tn_code, u.kz_alsteu, u.kz_fortlaufend, u.soll_ende,
h.akt_code, h.b_aktid, h.soll_beg, h.soll_ende, h.ist_ende, h.modul,
r.er_code, e.verwend_typ, e.verwend_typ_2
from muaktion u
  inner join  mhaktion h on
  h.e_mandant = u.e_mandant and
  h.akt_id = u.akt_id
  left outer join respvorg r on
  r.e_mandant = u.e_mandant and
  r.akt_id = u.akt_id and
  r.f_uakt_id = u.uakt_id
    left outer join ereignis e on
    e.er_code = r.er_code;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."MULTIPVI" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "L_TITEL_NR", "AUTOR_NR", "ADR_GR", "ADR_NR_AUT", "PERSON_NR_AUT", "BU_LA_ID", "KZ_AUFL_BEST", "VERTRETER_ID", "SACH_GRP", "ADR_NR_LI") AS
  select m.e_mandant, a.l_ausg_nr, f.l_aufl_nr, a.l_titel_nr,
b.autor_nr, b.adr_gr, b.adr_nr_aut, b.person_nr_aut,
a.bu_la_id, a.kz_aufl_best, m.vertreter_id, g.sach_grp, l.adr_nr
from buausgab a
inner join buautor b on
b.l_titel_nr = a.l_titel_nr and
b.kz_hpaut = 'T'
inner join bumanaus m on
m.l_ausg_nr = a.l_ausg_nr
inner join buaufl f on
f.l_ausg_nr = a.l_ausg_nr and
f.l_aufl_nr = 0
left outer join bugruppe g on
g.l_titel_nr = a.l_titel_nr
left outer join buliefer l on
l.l_ausg_nr = a.l_ausg_nr
where a.herkunft = 'VA' and
a.kz_aufl_best = 'F'
union
select m.e_mandant, a.l_ausg_nr, f.l_aufl_nr, a.l_titel_nr,
b.autor_nr, b.adr_gr, b.adr_nr_aut, b.person_nr_aut,
a.bu_la_id, a.kz_aufl_best, m.vertreter_id, g.sach_grp, l.adr_nr
from buausgab a
inner join buautor b on
b.l_titel_nr = a.l_titel_nr and
b.kz_hpaut = 'T'
inner join bumanaus m on
m.l_ausg_nr = a.l_ausg_nr
inner join buaufl f on
f.l_ausg_nr = a.l_ausg_nr and
f.l_aufl_nr > 0
left outer join bugruppe g on
g.l_titel_nr = a.l_titel_nr
left outer join buliefer l on
l.l_ausg_nr = a.l_ausg_nr
where a.herkunft = 'VA' and
a.kz_aufl_best = 'T';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."NEWSVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "TEL_ART", "WM_CODE", "HIST_NR", "B_ID_NEU", "DATUM_NEU", "B_ID_AEND", "DATUM_AEND", "OPT_IN", "GUELTIG_AB", "GUELTIG_BIS", "K_GRUND", "VALIDITAET", "EINGANG_KUEND", "NUMMER", "VERW_ID") AS
  select n.adr_gr, n.adr_nr, n.person_nr, n.tel_art, n.wm_code, n.hist_nr, n.b_id_neu, n.datum_neu, n.b_id_aend, n.datum_aend,
       n.opt_in, n.gueltig_ab, n.gueltig_bis, n.k_grund, n.validitaet, n.eingang_kuend, t.nummer, l.verw_id
from   newslett n, telecom t, teleart l
where  t.tel_art = l.tel_art and
       n.adr_gr = t.adr_gr and
       n.adr_nr = t.adr_nr and
       n.person_nr = t.person_nr and
       n.tel_art = t.tel_art;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."NLVIEW" ("ADR_GR", "ADR_NR", "FIRMA1", "FIRM2", "FIRMA3", "STRASSE", "PLZ", "ORT", "LAND", "PERSON_NR", "ANREDE_CODE", "TITEL_CODE", "VORNAME", "NACHNAME", "EMAIL", "TEL", "FAX", "MOBILE", "MERKMAL_CODE", "AUSP_CODE", "BEGINN", "ENDE", "STATUS", "HERKUNFT", "DATUM_AEND") AS
  select a.adr_gr,a.adr_nr,a.name1,a.name2,a.name3,a.strasse,a.haupt_plz,a.haupt_ort,a.land_code,
p.person_nr,p.anrede_code,p.titel_code,p.vorname,p.nachname,
case p.a_typ when 'M' then (select nummer from telecom t where p.adr_gr=t.adr_gr and p.adr_nr=t.adr_nr and p.person_nr=t.person_nr and t.tel_art='EMP')
                      else (select nummer from telecom t where p.adr_gr=t.adr_gr and p.adr_nr=t.adr_nr and p.person_nr=t.person_nr and t.tel_art='EM') end as email,
case p.a_typ when 'M' then (select nummer from telecom t where p.adr_gr=t.adr_gr and p.adr_nr=t.adr_nr and p.person_nr=t.person_nr and t.tel_art='TPP')
                      else (select nummer from telecom t where p.adr_gr=t.adr_gr and p.adr_nr=t.adr_nr and p.person_nr=t.person_nr and t.tel_art='TEL') end as tel,
case p.a_typ when 'M' then (select nummer from telecom t where p.adr_gr=t.adr_gr and p.adr_nr=t.adr_nr and p.person_nr=t.person_nr and t.tel_art='FXP')
                      else (select nummer from telecom t where p.adr_gr=t.adr_gr and p.adr_nr=t.adr_nr and p.person_nr=t.person_nr and t.tel_art='FAX') end as fax,
(select nummer from telecom t where p.adr_gr=t.adr_gr and p.adr_nr=t.adr_nr and p.person_nr=t.person_nr and t.tel_art='MOB') as mobile,
q.q_code,q.q_ausp_code,q.gueltig_von,q.gueltig_bis,q.status,q.herkunft_id,q.datum_aend
from anschr a, person p, persqkat m, qwerte q
where a.adr_gr=p.adr_gr and a.adr_nr=p.adr_nr
and p.adr_gr=m.adr_gr and p.adr_nr=m.adr_nr and p.person_nr=m.person_nr and p.a_typ=m.a_typ
and q.adr_gr=m.adr_gr and q.adr_nr=m.adr_nr and q.person_nr=m.person_nr and q.a_typ=m.a_typ and q.q_code=m.q_code
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXAUFLAGE1" ("L_AUSG_NR", "L_AUFL_NR", "AUFLAGE_NR", "AUFL_TEXT", "AUFL_HOEHE", "MELD_NR", "EK_PREIS", "WAEHRUNG", "AUFL_DAT_SOLL", "AUFL_DAT_IST", "STATUS", "GEWICHT", "BREITE", "DICKE", "HOEHE", "SPERR_GRUND", "WARN_ID", "L_AUSG_NR_NEU", "L_AUFL_NR_NEU", "ZEIT_VON", "ZEIT_BIS") AS
