  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_BUGRUPPE" ("L_AUSG_NR", "SACH_GRP") AS
  select a.l_ausg_nr, min(g.sach_grp)
from buausgab a, bugruppe g
where g.l_titel_nr = a.l_titel_nr
group by a.l_ausg_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCT" ("RECORDIDENTIFIER", "RECORDREFERENCE", "NOTIFICATIONTYPE", "PUBLISHERORDERID", "PRODUCTISBN13", "PRODUCTEAN", "PRODUCTFORM", "PRODUCTFORMDETAIL", "DISTINCTIVETITLE", "SUBTITLE", "ORIGINALTITLE", "ORIGINALSUBTITLE", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR", "EDITIONNUMBER", "EDITIONSTATEMENT", "NOEDITION", "LANGUAGEOFTEXT", "ORIGINALLANGUAGE", "NUMBEROFPAGES", "PAGESROMAN", "PAGESARABIC", "PUBLISHERCODE", "PUBLISHERNAME", "PUBLISHERWEBSITE", "PUBLISHINGSTATUS", "PUBLICATIONDATEYEAR", "PUBLICATIONDATEMONTH", "PUBLICATIONDATEDAY", "PUBLICATIONDATE", "PRODUCTHEIGHT", "PRODUCTWIDTH", "PRODUCTTHICKNESS", "PRODUCTWEIGHT", "REPLACESISBN", "REPLACEDBYISBN", "PRODUCTAVAILABILITY", "EXPECTEDSHIPDATEYEAR", "EXPECTEDSHIPDATEMONTH", "EXPECTEDSHIPDATEDAY", "ONSALEDATE", "UNPRICEDITEMTYPE", "VLBSCHEMENEW", "EPUBFORMAT", "EPUBTYPE", "COUNTRYOFPUBLICATION", "COUNTRYOFPRODUCTION", "PRODUCTWEBSITEROLE", "PRODUCTWEBSITELINK", "TRADECLASSIFICATION", "PANTHEMASUBJECT", "PRODUCTDOI") AS
  select
substr(to_char(bp.l_ausg_nr),1,20), rtrim(bp.ean), '03', rtrim(bp.artikel_nr), rtrim(bp.ean), rtrim(bp.ean),
rtrim(vi.onix),trim(h.einbandart),
trim(t.titel1), trim(t.titel_unter), trim(t.orig_titel), trim(t.orig_u_titel),
rtrim(bp.ContributorStatement), bp.NoContributor,
rtrim(b.bestuhlung), trim(bp.aufl_text),
(case when b.bestuhlung is null and bp.aufl_text is null then 1 else 0 end),
trim(t.sprach_code), trim(t.org_spr_code),
trim(h.umfang),  trim(h.seiten_roem),trim(h.bibl_seiten_arab),
decode(a.verlags_id, null, null, (decode(trim(bv.verkehrs_nr), null, '05/'||trim(bv.kenn_nr), '04/'||trim(substr(bv.verkehrs_nr,1,5))))),
decode(a.verlags_id, null, null,trim(bv.verlag_lang)),
decode(a.verlags_id, null, null,trim(bv.website)),
trim(bp.meld_nr), bp.ist_jahr, bp.ist_monat, bp.ist_tag,to_char(bp.aufl_dat_ist,'YYYYMMDD'),
decode(round((a.hoehe * 10), 0),0,null,round((a.hoehe * 10), 0)), decode(round((a.breite * 10),0),0,null,round((a.breite * 10),0)), decode(round((a.dicke * 10),0),0,null,round((a.dicke * 10),0)), decode(a.gewicht,0,null,a.gewicht),
bp.ReplacesIsbn, bp.ReplacedByISBN,
trim(bp.meld_nr), bp.soll_jahr, bp.soll_monat, bp.soll_tag,
to_char(b.aufl_dat_ist,'YYYYMMDD'), bp.UnpricedItemType, rtrim(bp.vlbschemenew),
trim(decode (pty.kz_elektron, 'T',h.einbandart,null)), trim(decode (pty.kz_elektron, 'T',h.einbandart,null)),
'DE', 'DE', decode(QR.qaus, null, null, '02'), trim(QR.qaus), trim(pty.istatwcode),
trim(pt.pan_id),   trim(a.doi)
from
buausgab a,
butitel t, buoxprod bp,  buaufl b,
buherste h, buverlag bv,
buartqa QR, bupantit pt, buoxref vi, buprotyp pty
where
a.l_titel_nr = t.l_titel_nr and
bp.l_ausg_nr  = a.l_ausg_nr and
bp.l_ausg_nr = b.l_ausg_nr and
bp.l_aufl_nr = b.l_aufl_nr and
h.l_ausg_nr (+) = a.l_ausg_nr and
h.l_aufl_nr(+) = 0 and
bv.verlags_id (+) = a.verlags_id and
QR.l_ausg_nr(+) = a.l_ausg_nr and
QR.prod_typ(+) = a.prod_typ and
QR.qm_id(+) = 'QR' and
pt.l_titel_nr(+) = a.l_titel_nr and
pt.pan_typ(+) = 'SUBJEC' and
pt.sortierung(+) = 1 and
vi.typ(+) = 'VLB_INDEX' and
trim(vi.cover_1(+)) = trim(a.prod_typ) and
trim(vi.cover_2(+)) = trim(h.einbandart) and
pty.prod_typ = a.prod_typ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTCONTAINEDITEM" ("RECORDIDENTIFIER", "PUBLISHERORDERID", "PRODUCTISBN13", "PRODUCTEAN", "PRODUCTFORM", "PRODUCTFORMDETAIL", "ITEMQUANTITY") AS
  select
substr(to_char(a.l_ausg_nr),1,20), rtrim(mb.artikel_nr), rtrim(b.EAN), rtrim(b.EAN),
rtrim(hb.einbandart),rtrim(hb.einbandart),
k.menge
from buoxprod bp, buausgab a, buausgab b, bumanaus mb, buherste hb,
bukombi k
where a.l_ausg_nr = bp.l_ausg_nr
and a.bundle in('E','F','G', 'H')
and a.l_ausg_nr = k.l_ausg_nr
and b.l_ausg_nr = k.u_ausg_nr
and mb.e_mandant = bp.e_mandant
and mb.l_ausg_nr = b.l_ausg_nr
and hb.l_ausg_nr = b.l_ausg_nr
and hb.l_aufl_nr = k.l_aufl_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTCONTRIBUTOR" ("RECORDIDENTIFIER", "SEQUENCENUMBER", "CONTRIBUTORROLE", "NAMESBEFOREKEY", "KEYNAMES", "SORTORDER", "PERSONNAMEIDENTIFIER") AS
  select
substr(to_char(bp.RecordIdentifier),1,20), b.sort, rtrim(b.autor_typ),
rtrim(b.vorname), rtrim(b.nachname),
b.sort,
(case when (select rtrim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('ISN') and
           b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr) is not null then
             '16/'||(select rtrim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('ISN') and
              b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr)
else null end)
from buoxprod bp, buautor b
where
bp.l_titel_nr = b.l_titel_nr and
b.sort > 0;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTCONTRIBUTOR1" ("RECORDIDENTIFIER", "SEQUENCENUMBER", "CONTRIBUTORROLE", "NAMESBEFOREKEY", "KEYNAMES", "SORTORDER") AS
  select
substr(to_char(bp.l_ausg_nr),1,20), b.sort, rtrim(b.autor_typ),
rtrim(b.vorname), rtrim(b.nachname),
b.sort
from buoxprod bp, buautor b
where
bp.l_titel_nr = b.l_titel_nr and
b.sort > 0
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTILLUSTRATIONS" ("RECORDIDENTIFIER", "ILLUSTRATIONTYPE", "ILLUSTRATIONTYPEDESCRIPTION", "NUMBEROFILLUSTRATIONS", "SORTORDER") AS
  select
bp.l_ausg_nr,
'00',
(case when (h.anz_abb_sw + h.anz_abb_2c + h.anz_abb_farb > 0 and h.tab_anz_sw + h.tab_anz_2c + h.tab_anz_farb > 0)
        then (h.anz_abb_sw + h.anz_abb_2c + h.anz_abb_farb) || ' Abb.' || (h.tab_anz_sw + h.tab_anz_2c + h.tab_anz_farb) || ' Tab.'
      when  (h.anz_abb_sw + h.anz_abb_2c + h.anz_abb_farb > 0)
        then (h.anz_abb_sw + h.anz_abb_2c + h.anz_abb_farb) || ' Abb.'
     when (h.tab_anz_sw + h.tab_anz_2c + h.tab_anz_farb > 0)
        then (h.tab_anz_sw + h.tab_anz_2c + h.tab_anz_farb) || ' Tab.'
     else null
end),
null,1
from buoxprod bp, buherste h
where h.l_ausg_nr = bp.l_ausg_nr
and h.l_aufl_nr = 0
and (h.anz_abb_sw + h.anz_abb_2c + h.anz_abb_farb > 0 or h.tab_anz_sw + h.tab_anz_2c + h.tab_anz_farb > 0)
union select
bp.l_ausg_nr,
'17',
null,
(nvl(h.anz_abb_sw,0) + nvl(h.anz_abb_2c,0) + nvl(h.anz_abb_farb,0)),
2
from buoxprod bp, buherste h
where h.l_ausg_nr = bp.l_ausg_nr
and h.l_aufl_nr = 0
and (nvl(h.anz_abb_sw,0) + nvl(h.anz_abb_2c,0) + nvl(h.anz_abb_farb,0) > 0)
union select
bp.l_ausg_nr,
'11',
null,
(h.tab_anz_sw + h.tab_anz_2c + h.tab_anz_farb),
3
from buoxprod bp, buherste h
where h.l_ausg_nr = bp.l_ausg_nr
and h.l_aufl_nr = 0
and (h.tab_anz_sw + h.tab_anz_2c + h.tab_anz_farb > 0)
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTKEYWORD" ("RECORDIDENTIFIER", "SUBJECTSCHEMEIDENTIFIER", "SUBJECTSCHEMENAME", "SUBJECTCODE", "SUBJECTHEADINGTEXT", "SORTORDER") AS
  select
cast(bp.l_ausg_nr as varchar(20)), '20', null,null,rtrim(s.stichwort),  (coalesce(s.sortierung ,999) + 9000)
from
bustichw s, buoxprod bp
where
bp.l_titel_nr = s.l_titel_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTMEDIAFILE" ("RECORDIDENTIFIER", "MEDIAFILETYPECODE", "MEDIAFILELINKTYPECODE", "MEDIAFILELINK", "MEDIAFILEDATE", "MEDIAFILEFORMATCODE") AS
  select
substr(to_char(a.l_ausg_nr),1,20), '04', '01',
'http://meta.narr.de/u1/'||a.ean||'.jpg', null,'03'
from buausgab a,  buoxprod bp
where bp.l_ausg_nr = a.l_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCT_NFA" ("RECORDIDENTIFIER", "RECORDREFERENCE", "NOTIFICATIONTYPE", "PUBLISHERORDERID", "PRODUCTISBN13", "PRODUCTEAN", "PRODUCTFORM", "PRODUCTFORMDETAIL", "DISTINCTIVETITLE", "SUBTITLE", "ORIGINALTITLE", "ORIGINALSUBTITLE", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR", "EDITIONNUMBER", "EDITIONSTATEMENT", "NOEDITION", "LANGUAGEOFTEXT", "ORIGINALLANGUAGE", "NUMBEROFPAGES", "PAGESROMAN", "PAGESARABIC", "PUBLISHERCODE", "PUBLISHERNAME", "PUBLISHERWEBSITE", "PUBLISHINGSTATUS", "PUBLICATIONDATEYEAR", "PUBLICATIONDATEMONTH", "PUBLICATIONDATEDAY", "PUBLICATIONDATE", "PRODUCTHEIGHT", "PRODUCTWIDTH", "PRODUCTTHICKNESS", "PRODUCTWEIGHT", "REPLACESISBN", "REPLACEDBYISBN", "PRODUCTAVAILABILITY", "EXPECTEDSHIPDATEYEAR", "EXPECTEDSHIPDATEMONTH", "EXPECTEDSHIPDATEDAY", "ONSALEDATE", "UNPRICEDITEMTYPE", "VLBSCHEMENEW", "EPUBFORMAT", "COUNTRYOFPUBLICATION", "PRODUCTWEBSITEROLE", "PRODUCTWEBSITELINK", "TRADECLASSIFICATION", "PANTHEMASUBJECT") AS
  select
bp.l_ausg_nr, bp.ean, '03', rtrim(bp.artikel_nr), bp.ean, bp.ean,
substr(vwg.vlb_wg, 1,1),trim(h.einbandart),
trim(t.titel1), trim(t.titel_unter), trim(t.orig_titel), trim(t.orig_u_titel),
rtrim(bp.ContributorStatement), bp.NoContributor,
b.bestuhlung, trim(bp.aufl_text),
(case when b.bestuhlung is null and bp.aufl_text is null then 1 else 0 end),
trim(t.sprach_code), trim(t.org_spr_code),
trim(h.umfang),  trim(h.seiten_roem),trim(h.bibl_seiten_arab),
decode(a.verlags_id, null, null, (decode(trim(bv.verkehrs_nr), null, '05/'||trim(bv.kenn_nr), '04/'||trim(substr(bv.verkehrs_nr,1,5))))),
decode(a.verlags_id, null, null,trim(bv.verlag_lang)),
decode(a.verlags_id, null, null,trim(bv.website)),
trim(bp.meld_nr), bp.ist_jahr, bp.ist_monat, bp.ist_tag,to_char(bp.aufl_dat_ist,'YYYYMMDD'),
decode(round((a.hoehe * 10), 0),0,null,round((a.hoehe * 10), 0)), decode(round((a.breite * 10),0),0,null,round((a.breite * 10),0)), decode(round((a.dicke * 10),0),0,null,round((a.dicke * 10),0)), decode(a.gewicht,0,null,a.gewicht),
bp.ReplacesIsbn, bp.ReplacedByISBN,
trim(bp.meld_nr), bp.soll_jahr, bp.soll_monat, bp.soll_tag,
to_char(b.aufl_dat_ist,'YYYYMMDD'), bp.UnpricedItemType, vwg.vlb_wg,
trim(decode (a.prod_typ, 'EBOO',h.einbandart,null)),
'DE', decode(QR.qaus, null, null, '02'), trim(QR.qaus), decode(a.prod_typ, 'EBOO', '49019900', '49019900'),
trim(pt.pan_id)
from
buausgab a,
butitel t, buoxprod bp,  buaufl b,
buherste h, buverlag bv, onix_vlb_wg vwg,
buartqa QR, bupantit pt
where
a.l_titel_nr = t.l_titel_nr and
bp.l_ausg_nr  = a.l_ausg_nr and
bp.l_ausg_nr = b.l_ausg_nr and
bp.l_aufl_nr = b.l_aufl_nr and
a.kombityp in ('E','B', 'V', 'M', 'Z', 'S') and
a.ean is not null and
a.isbn is not null and
a.kz_aufl_best = 'F' and
h.l_ausg_nr (+) = a.l_ausg_nr and
bv.verlags_id (+) = a.verlags_id and
vwg.l_ausg_nr(+) = a.l_ausg_nr
and
QR.l_ausg_nr(+) = a.l_ausg_nr and
QR.prod_typ(+) = a.prod_typ and
QR.qm_id(+) = 'QR' and
pt.l_titel_nr(+) = a.l_titel_nr and
pt.pan_typ(+) = 'SUBJEC' and
pt.sortierung(+) = 1;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTOTHERTEXT" ("RECORDIDENTIFIER", "TEXTTYPECODE", "TEXTFORMAT", "TEXTCASE", "TEXTLANGUAGE", "TEXT", "STARTDATE", "ENDDATE", "SORTORDER") AS
  select
substr(to_char(bp.l_ausg_nr),1,20), rtrim(t.verw_typ), '06', '00',
rtrim(t.sprach_code), rtrim(substr(to_char(t.aufl_text),1,4000)), null,null, t.verw_typ
from buoxprod bp, buaufl b, buoxprtx t
where
bp.l_ausg_nr = b.l_ausg_nr and
b.l_ausg_nr = t.l_ausg_nr and
b.l_aufl_nr = t.l_aufl_nr and
b.l_aufl_nr = 0 and
t.e_mandant = bp.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTPRICE" ("RECORDIDENTIFIER", "PRICETYPECODE", "PRICESTATUS", "PRICEAMOUNT", "CURRENCYCODE", "COUNTRYCODE", "PRICEEFFECTIVEFROM", "PRICEEFFECTIVEUNTIL", "BATCHQUANTITY", "MINIMUMORDERQUANTITY", "TAXRATECODE1", "TAXRATEPERCENT1", "PRICEAMOUNTTAX1", "TAXRATECODE2", "TAXRATEPERCENT2", "PRICEAMOUNTTAX2", "DISCOUNTCODETYPE", "DISCOUNTCODETYPENAME", "DISCOUNTCODE", "SORTORDER") AS
  select
rtrim(op.RecordIdentifier), rtrim(op.pricetypecode), rtrim(op.PriceStatus),
ltrim(to_char(to_number(op.PriceAmount),'99999990D99')),
rtrim(op.CurrencyCode), rtrim(op.CountryCode),
to_char(op.PriceEffectiveFrom,'YYYYMMDD'),
to_char(op.PriceEffectiveUntil,'YYYYMMDD'),
op.BatchQuantity,  op.MinimumOrderQuantity,
rtrim(op.TaxRateCode1), op.TaxRatePercent1,
ltrim(to_char(to_number(op.PriceAmountTax1),'99999990D99')),
