rtrim(op.preiskat)
from buoxpric op;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTRELATEDPRODUCT" ("RECORDIDENTIFIER", "RELATIONCODE", "PRODUCTEAN", "PRODUCTISBN13", "PUBLISHERORDERID", "PRODUCTFORM", "SORTORDER") AS
  select
trim(o.l_ausg_nr),
'13',
trim(b.ean),trim(b.isbn),trim(o.artikel_nr),
substr(vwg.vlb_wg, 1,1), b.l_ausg_nr
from buausgab a, buausgab b,  buoxprod o,
buaufl aa, buaufl ba, onix_vlb_wg vwg
where a.l_titel_nr = b.l_titel_nr
and a.l_ausg_nr != b.l_ausg_nr
and a.l_titel_nr != 0
and a.herkunft is null
and b.herkunft is null
and
a.l_ausg_nr = o.l_ausg_nr
and
a.prod_typ = 'EBOO' and b.prod_typ = 'BUCH'
and b.ean is not null
and aa.l_ausg_nr = a.l_ausg_nr
and aa.l_aufl_nr = 0
and ba.l_ausg_nr = b.l_ausg_nr
and ba.l_aufl_nr = 0
and ba.bestuhlung = aa.bestuhlung
and vwg.l_ausg_nr = b.l_ausg_nr
union
select
trim(o.l_ausg_nr),
'27',
trim(b.ean),trim(b.isbn),trim(o.artikel_nr),
substr(vwg.vlb_wg, 1,1), b.l_ausg_nr
from buausgab a, buausgab b,  buoxprod o,
buaufl aa, buaufl ba, onix_vlb_wg vwg
where a.l_titel_nr = b.l_titel_nr
and a.l_ausg_nr != b.l_ausg_nr
and a.l_titel_nr != 0
and a.herkunft is null
and b.herkunft is null
and
a.l_ausg_nr = o.l_ausg_nr
and
a.prod_typ = 'BUCH' and b.prod_typ = 'EBOO'
and b.ean is not null
and aa.l_ausg_nr = a.l_ausg_nr
and aa.l_aufl_nr = 0
and ba.l_ausg_nr = b.l_ausg_nr
and ba.l_aufl_nr = 0
and ba.bestuhlung = aa.bestuhlung
and vwg.l_ausg_nr = b.l_ausg_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTRELATION" ("RECORDIDENTIFIER", "RELATIONCODE", "PRODUCTEAN", "PRODUCTISBN13", "PRODUCTFORM", "PRODUCTFORMDETAIL", "SORTORDER") AS
  select
substr(to_char(a.l_ausg_nr),1,20),
