and   l.linktyp = 'P'
and   ag.l_ausg_nr = a.l_ausg_nr
and   h.l_ausg_nr = b.l_ausg_nr
union
select
substr(to_char(a.l_ausg_nr),1,20),
'27',
rtrim(b.ean),rtrim(b.ean),
rtrim(h.einbandart),rtrim(h.einbandart),
rtrim(h.einbandart)
from buoxprod a, buherste h,
buausgab ag, buausgab b, bumanlin l
where l.l_ausg_nr_link = a.l_ausg_nr
and   l.l_ausg_nr = b.l_ausg_nr
and   l.linktyp = 'P'
and   ag.l_ausg_nr = a.l_ausg_nr
and   h.l_ausg_nr = b.l_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTSERIES" ("RECORDIDENTIFIER", "SERIESID", "TITLEOFSERIES", "NUMBERWITHINSERIES", "SORTORDER") AS
  select
substr(to_char(bp.l_ausg_nr),1,20),
