  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXCOVERPRODUCTSUBJECT" ("RECORDIDENTIFIER", "SUBJECTSCHEMEIDENTIFIER", "SUBJECTSCHEMENAME", "SUBJECTCODE", "SUBJECTHEADINGTEXT", "SORTORDER") AS
  select
substr(to_char(bp.l_ausg_nr),1,20),
(case when rtrim(p.pan_typ) = 'SUBJEC' then '93'
      when rtrim(p.pan_typ) = 'GEOGRA' then '94'
      when rtrim(p.pan_typ) = 'LANGUA'then  '95'
      when rtrim(p.pan_typ) = 'TIME' then  '96'
      when rtrim(p.pan_typ) = 'EDUCAT' then  '97'
      when rtrim(p.pan_typ) = 'INTAGE' then  '98'
      when rtrim(p.pan_typ) = 'STYLE' then  '99'
      else 'XXX'
end),
null,  rtrim(p.pan_id), rtrim(t.bezeichnung),
(case when rtrim(p.pan_typ) = 'SUBJEC' then 93
      when rtrim(p.pan_typ) = 'GEOGRA' then 94
      when rtrim(p.pan_typ) = 'LANGUA'then  95
      when rtrim(p.pan_typ) = 'TIME' then  96
      when rtrim(p.pan_typ) = 'EDUCAT' then  97
      when rtrim(p.pan_typ) = 'INTAGE' then  98
      when rtrim(p.pan_typ) = 'STYLE' then  99
      else 100
end)
from  buoxprod bp,  bupantit p, bupanthe t
where
bp.l_titel_nr = p.l_titel_nr and
t.pan_id = p.pan_id and
(p.pan_typ != 'SUBJEC' or p.sortierung = 99);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXHISTORIE" ("L_AUSG_NR", "DATIM") AS
  select a.l_ausg_nr, max(h.datim)
from historie h, buausgab a
where
(h.entitaet in ('BUAUSGAB', 'BUMANAUS', 'BUAUFL', 'BUARTQA') and
 a.l_ausg_nr = h.key_num_1)
or
(h.entitaet in ('BUTITEL', 'BUGRUPPE', 'BUAUTOR') and
 a.l_titel_nr = h.key_num_1)
group by a.l_ausg_nr
union
select a.l_ausg_nr, a.aend_datum
from buausgab a where
not exists (select * from historie h where
            h.key_num_1 = a.l_ausg_nr or
            h.key_num_1 = a.l_titel_nr)

;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_HP_PREISLAND" ("LIST_NR", "LAND_CODE") AS
