and m2.e_mandant = om.e_mandant
and mk2.l_ausg_nr = b.l_ausg_nr and mk2.e_mandant = om.e_mandant and mk2.u_ausg_nr = m2.l_ausg_nr
and b2.l_ausg_nr = m2.l_ausg_nr and
st2.steuer_code = m2.steuer_code and st2.land_code = 'A' and
st2.datum_ab = (select max(datum_ab) from stsatz dm where dm.land_code='A' and dm.steuer_code=m2.steuer_code and dm.datum_ab<=sysdate) and
l.best_art = '1' and
l.l_aufl_nr = 0 and
l.akt_id is null and
l.m_preis_grp is null and
l.list_nr = m.list_nr and
m.menge = 1 and
l.e_mandant = om.e_mandant and
exists
(select list_nr from buplist x where
x.l_ausg_nr = l.l_ausg_nr and
x.best_art = l.best_art and
