and mk1.l_ausg_nr = b.l_ausg_nr and mk1.e_mandant = om.e_mandant and mk1.u_ausg_nr = m1.l_ausg_nr
and b1.l_ausg_nr = m1.l_ausg_nr
and st1.steuer_code = m1.steuer_code and st1.land_code = 'A' and
