  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_HP_PRODUCTSUBJECT" ("RECORDIDENTIFIER", "SUBJECTSCHEMEIDENTIFIER", "SUBJECTSCHEMENAME", "SUBJECTCODE", "SUBJECTHEADINGTEXT") AS
  select
a.l_ausg_nr, '20', null, null, trim(s.stichwort)
from
buausgab a,  bustichw s, bumanaus m, onixmandant om
where
a.l_titel_nr = s.l_titel_nr and
a.kombityp in ('E','B', 'V', 'M', 'Z') and
a.kz_eigen = 'T' and
a.kz_aufl_best = 'F' and
a.ean is not null and
a.isbn is not null and
a.l_ausg_nr = m.l_ausg_nr and
m.e_mandant = om.e_mandant
union
select
a.l_ausg_nr, '23', trim(q.qm_id), trim(translate(q.qaus,'&','+')), trim(qa.bez)
from buausgab a, buartqa q, buqaus qa
where
a.l_ausg_nr = q.l_ausg_nr and
a.prod_typ = q.prod_typ and
q.qm_id like 'R_GEBIET-%' and
qa.prod_typ = q.prod_typ and
qa.qm_id = q.qm_id and
qa.qaus_id = q.qaus
union
select
a.l_ausg_nr, '23', 'KURZKOM', trim(a.prod_typ), null
from buausgab a
union
select
a.l_ausg_nr, '23', 'SUCHTITEL', trim(t.titel_such), null
from buausgab a, butitel t
where a.l_titel_nr = t.l_titel_nr
union
select
a.l_ausg_nr, '23', trim(q.qm_id),
trim(q.qaus),
trim(q.qaus)
from buausgab a, buartqa q
where
a.l_ausg_nr = q.l_ausg_nr and
a.prod_typ = q.prod_typ and
q.qm_id in('ZUBEHOR 1','ZUBEHOR 2','ZUBEHOR 3','LN DATUM','LEXISNEXIS')
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXKEINAUTOR" ("L_AUSG_NR", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR") AS
  select
a.l_ausg_nr, t.autor_verweis, 0
from buausgab a, butitel t
where
a.l_titel_nr = t.l_titel_nr and
exists (select l_titel_nr from buautor b
        where b.l_titel_nr = a.l_titel_nr
        and b.sort > 0)
union
select
l_ausg_nr, null, 1
from buausgab a
where
not exists (select l_titel_nr from buautor b
        where b.l_titel_nr = a.l_titel_nr
        and b.sort > 0)
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXKEINAUTOR_KOH" ("L_AUSG_NR", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR") AS
  select
a.l_ausg_nr, null, decode(t.rank_id,null,'0',t.rank_id)
from buausgab a, butitel t
where
a.l_titel_nr = t.l_titel_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXMAINSERIES" ("RECORDIDENTIFIER", "RECORDREFERENCE", "NOTIFICATIONTYPE", "SERIESID", "VLBXNUMMER", "DISTINCTIVETITLE", "SUBTITLE", "LASTCHANGE") AS
  select
