  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXMAINSERIESOTHERTEXT" ("RECORDIDENTIFIER", "TEXTTYPECODE", "TEXTFORMAT", "TEXTCASE", "TEXTLANGUAGE", "OTHERTEXT") AS
