(b.bundle not in ('E','F','G', 'H') or b.bundle is null) and
m1.l_ausg_nr = b.l_ausg_nr
and m1.e_mandant = om.e_mandant
and st1.steuer_code = m1.steuer_code and st1.land_code = 'D' and
st1.datum_ab = (select max(datum_ab) from stsatz dm where dm.land_code='D' and dm.steuer_code=m1.steuer_code and dm.datum_ab<=sysdate) and
l.best_art = '1' and
l.l_aufl_nr = 0 and
l.akt_id is null and
l.m_preis_grp is null and
l.preiskat in ('CA', 'LP', 'LPA','MIT', 'SER', 'SUB','UVP') and
l.list_nr = m.list_nr and
m.menge = 1 and
l.e_mandant = om.e_mandant and
not exists
(select list_nr from buplist x where
x.l_ausg_nr = l.l_ausg_nr and
x.best_art = l.best_art and
x.l_aufl_nr = l.l_aufl_nr and
x.preiskat = l.preiskat and
x.e_mandant = l.e_mandant and
to_char(x.gueltig_ab, 'YYYYMMDD') <= to_char(sysdate, 'YYYYMMDD') and
x.waehrung = l.waehrung)and
l.gueltig_ab =
(select min(gueltig_ab) from buplist x where
x.l_ausg_nr = l.l_ausg_nr and
x.best_art = l.best_art and
x.l_aufl_nr = l.l_aufl_nr and
x.preiskat = l.preiskat and
x.e_mandant = l.e_mandant and
x.waehrung = l.waehrung) and
opl.list_nr (+) = l.list_nr;


