  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXPRODUCTCONTAINEDITEM" ("RECORDIDENTIFIER", "PRODUCTIDENTIFIER", "PRODUCTISBN13", "PRODUCTEAN", "PRODUCTFORM", "ITEMQUANTITY") AS
  select a.ISBN,
(case when b.isbn is not null
     then b.isbn
     else b.band_nr
     end),
b.ISBN, b.EAN,
(select trim(bxr.onix) from buoxref bxr where bxr.typ='MEDIENTYP' and bxr.cover_1=h.einbandart and bxr.cover_2 = '0' and bxr.cover_3 = '0'),
k.menge
from buausgab a, bukombi k, buausgab b, bumankom c, onixmandant om, buherste h
where
a.bundle in('E','F','G', 'H')
and a.l_ausg_nr = k.l_ausg_nr
and b.l_ausg_nr = k.u_ausg_nr
and c.l_ausg_nr = k.l_ausg_nr
and c.u_ausg_nr = k.u_ausg_nr
and h.l_ausg_nr = b.l_ausg_nr
and h.l_aufl_nr = 0
and c.e_mandant = om.e_mandant;


