  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXPRODUCTPRICE" ("RECORDIDENTIFIER", "PRICETYPECODE", "PRICESTATUS", "PRICEAMOUNT", "CURRENCYCODE", "COUNTRYCODE", "PRICEEFFECTIVEFROM", "PRICEEFFECTIVEUNTIL", "BATCHQUANTITY", "ID1", "TAXRATECODE1", "TAXRATEPERCENT1", "TAXABLEAMOUNT1", "TAXAMOUNT1", "ID2", "TAXRATECODE2", "TAXRATEPERCENT2", "TAXABLEAMOUNT2", "TAXAMOUNT2", "DISCOUNTPERCENT") AS
  select
a.isbn, trim(pl.preiskat), '02',
pl.preis, trim(pl.waehrung), trim(pl.land_code),
pl.gueltig_ab, pl.subs_dat1,
pl.anzahl,
pl.ID1,
pl.TaxRateCode1, pl.TaxRatePercent1,
pl.TaxableAmount1, pl.TaxAmount1,
pl.ID2,
pl.TaxRateCode2, pl.TaxRatePercent2,
pl.TaxableAmount2, pl.TaxAmount2,
(case when m.rab_grp is not null
      then (select trim(bxr.onix) from buoxref bxr where bxr.typ='RAB_GRP_RAB' and bxr.cover_1=m.rab_grp and bxr.cover_2 = '0' and bxr.cover_3 = '0')
 else null
 end)
from buausgab a, onixpreisliste pl, bupktext pt, bumanaus m, onixproduct o
