  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_VLB_PRODUCT" ("RECORDIDENTIFIER", "RECORDREFERENCE", "NOTIFICATIONTYPE", "PUBLISHERORDERID", "PRODUCTISBN13", "PRODUCTEAN", "BARCODE", "PRODUCTFORM", "PRODUCTFORMDETAIL", "DISTINCTIVETITLE", "SUBTITLE", "ORIGINALTITLE", "ORIGINALSUBTITLE", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR", "EDITIONNUMBER", "EDITIONSTATEMENT", "NOEDITION", "LANGUAGEOFTEXT", "ORIGINALLANGUAGE", "NUMBEROFPAGES", "PUBLISHERCODE", "PUBLISHERNAME", "PUBLISHERWEBSITE", "PUBLISHINGSTATUS", "PUBLICATIONDATEYEAR", "PUBLICATIONDATEMONTH", "PUBLICATIONDATEDAY", "COPYRIGHTYEAR", "PRODUCTHEIGHT", "PRODUCTWIDTH", "PRODUCTTHICKNESS", "PRODUCTWEIGHT", "REPLACESISBN", "REPLACEDBYISBN", "PRODUCTAVAILABILITY", "EXPECTEDSHIPDATEYEAR", "EXPECTEDSHIPDATEMONTH", "EXPECTEDSHIPDATEDAY", "ONSALEDATE", "UNPRICEDITEMTYPE", "VLBSCHEMENEW") AS
  select
a.l_ausg_nr, a.ean, '03', trim(m.artikel_nr), a.ean, a.ean, trim(q1.qaus),
trim(h.einbandart), trim(h.einbandart),trim(t.titel1), trim(t.titel_unter), trim(t.orig_titel), trim(t.orig_u_titel), trim(k.ContributorStatement),
k.NoContributor,
b0.auflage_nr, trim(b0.aufl_text),decode(b0.aufl_text,null,1,0),
trim(t.sprach_code), trim(t.org_spr_code), trim(h.umfang),
decode(a.verlags_id, null, null, (decode(trim(bv.verkehrs_nr), null, '05/'||trim(bv.kenn_nr), '04/'||trim(substr(bv.verkehrs_nr,1,5))))), decode(a.verlags_id, null, null,trim(bv.verlag_lang)),
decode(a.verlags_id, null, null,trim(bv.website)), trim(b0.meld_nr),
b0.ist_jahr, b0.ist_monat, b0.ist_tag,
null, decode(round((a.hoehe * 10), 0),0,null,round((a.hoehe * 10), 0)), decode(round((a.breite * 10),0),0,null,round((a.breite * 10),0)), decode(round((a.dicke * 10),0),0,null,round((a.dicke * 10),0)), decode(a.gewicht,0,null,a.gewicht), a2.ean, a3.ean,
trim(b0.meld_nr), b0.soll_jahr, b0.soll_monat, b0.soll_tag,
to_char(m.nov_dat,'YYYYMMDD'), o.UnpricedItemType, vwg.vlb_wg
from
buausgab a, buausgab a2, buausgab a3, bumanaus m, bumanaus m2,
butitel t, buoxaufl b0,  bugruppe g,
buartqa q1,
onix_vlb_ohnepreis o, onixkeinautor k, buherste h, onixmandant om, buverlag bv, onix_vlb_wg vwg
where
a.l_titel_nr = t.l_titel_nr and
a.l_ausg_nr = m.l_ausg_nr and
a2.l_ausg_nr (+) = m2.l_ausg_nr and
a3.l_ausg_nr (+) = m.l_ausg_nr_neu and
b0.l_ausg_nr  = a.l_ausg_nr and
g.l_titel_nr (+) = a.l_titel_nr and
q1.l_ausg_nr (+) = a.l_ausg_nr and
q1.prod_typ (+) = a.prod_typ and
q1.qm_id (+) = 'BARCODE' and
a.kombityp in ('E','B', 'V', 'M', 'Z', 'S') and
a.ean is not null and
a.isbn is not null and
m2.e_mandant (+) = m.e_mandant and
m2.l_ausg_nr_neu (+) = m.l_ausg_nr and
a.kz_aufl_best = 'F' and
a.kz_eigen = 'T' and
o.l_ausg_nr (+) = a.l_ausg_nr and
k.l_ausg_nr = a.l_ausg_nr and
h.l_ausg_nr (+) = a.l_ausg_nr and
m.e_mandant = om.e_mandant and
m.nov_dat is not null and
bv.verlags_id (+) = a.verlags_id and
vwg.l_ausg_nr(+) = a.l_ausg_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_VLB_PRODUCTCONTRIBUTOR" ("RECORDIDENTIFIER", "SEQUENCENUMBER", "CONTRIBUTORROLE", "NAMESBEFOREKEY", "KEYNAMES", "PERSONNAMEORCID", "PERSONNAMEISNI", "PERSONNAMEIDENTIFIER") AS
  select
a.l_ausg_nr, b.sort, trim(b.autor_typ),
trim(b.vorname), trim(b.nachname),
(select trim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('ORC') and
           b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr),
(select trim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('ISN') and
           b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr),
(case when (select trim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('GND') and
           b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr) is not null then
             '25/GND/'||(select trim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('GND') and
              b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr)
else null end)
from buausgab a, buautor b, bumanaus m, onixmandant om
where
a.l_titel_nr = b.l_titel_nr and
b.sort > 0 and
a.kombityp in ('E','B', 'V', 'M', 'Z') and
a.kz_aufl_best = 'F' and
a.ean is not null and
a.isbn is not null and
a.kz_eigen = 'T' and
a.l_ausg_nr = m.l_ausg_nr and
m.e_mandant = om.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_VLB_PRODUCTFORMFEATURE" ("RECORDIDENTIFIER", "FEATURETYPE", "FEATUREVALUE", "SORTORDER") AS
  select
p.l_ausg_nr,
trim(p.hgrp_id), trim(p.ugrp_id),
row_number() over (partition by p.l_ausg_nr order by p.l_ausg_nr)
from buartpro p
where
p.wb_id = 'ONC' and
p.hgrp_id is not null and
p.ugrp_id is not null;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_VLB_PRODUCTOTHERTEXT" ("RECORDIDENTIFIER", "TEXTTYPECODE", "TEXTFORMAT", "TEXTCASE", "TEXTLANGUAGE", "OTHERTEXT", "STARTDATE", "ENDDATE") AS
  select
a.l_ausg_nr, trim(t.verw_typ), '06', '00',
trim(t.sprach_code), trim(substr(to_char(t.aufl_text),1,4000)) ,null,null
from buausgab a, buaufl b, buoxtxt t, onixmandant om
where
a.l_ausg_nr = b.l_ausg_nr and
b.l_ausg_nr = t.l_ausg_nr and
b.l_aufl_nr = t.l_aufl_nr and
b.l_aufl_nr = 0 and
a.kombityp in ('E','B', 'V', 'M', 'Z') and
a.kz_aufl_best = 'F' and
a.ean is not null and
a.isbn is not null and
a.kz_eigen = 'T' and
t.e_mandant = om.e_mandant
union
select a.l_ausg_nr,trim(q.qm_id),'06','00',
'D',trim(q.qaus),null,null
from buausgab a, buartqa q
where a.l_ausg_nr = q.l_ausg_nr
and a.prod_typ = q.prod_typ
and q.qm_id = 'OPEN-LIZENZ';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_VLB_PRODUCTSUBJECT" ("RECORDIDENTIFIER", "SUBJECTSCHEMEIDENTIFIER", "SUBJECTSCHEMENAME", "SUBJECTSCHEMEVERSION", "SUBJECTCODE", "SUBJECTHEADINGTEXT") AS
  select
a.l_ausg_nr, '20', null, null,null, trim(s.stichwort)
from
buausgab a,  bustichw s, bumanaus m, onixmandant om
where
a.l_titel_nr = s.l_titel_nr and
a.kombityp in ('E','B', 'V', 'M', 'Z') and
a.kz_eigen = 'T' and
a.kz_aufl_best = 'F' and
a.ean is not null and
a.isbn is not null and
a.l_ausg_nr = m.l_ausg_nr and
m.e_mandant = om.e_mandant
union
select
a.l_ausg_nr, '23', trim(q.qm_id), null,trim(translate(q.qaus,'&','+')), trim(qa.bez)
from buausgab a, buartqa q, buqaus qa
where
a.l_ausg_nr = q.l_ausg_nr and
a.prod_typ = q.prod_typ and
q.qm_id like 'R_GEBIET-%' and
qa.prod_typ = q.prod_typ and
qa.qm_id = q.qm_id and
qa.qaus_id = q.qaus
union
select
a.l_ausg_nr, '23', 'KURZKOM', null,trim(a.prod_typ), b.bez
from buausgab a, buprotyp b
where a.prod_typ = b.prod_typ
union
select
a.l_ausg_nr, '23', 'SUCHTITEL', null,trim(t.titel_such), null
from buausgab a, butitel t
where a.l_titel_nr = t.l_titel_nr
union
select
a.l_ausg_nr, '23', trim(q.qm_id), null,
trim(q.qaus),
trim(q.qaus)
from buausgab a, buartqa q
where
a.l_ausg_nr = q.l_ausg_nr and
a.prod_typ = q.prod_typ and
q.qm_id in('ZUBEHOR 1','ZUBEHOR 2','ZUBEHOR 3','LN DATUM','LEXISNEXIS','LN LINK','STAND', 'LINK EBOOK', 'BUCHCOVER', 'INHALT DAT', 'LESE DAT')
union
select
a.l_ausg_nr, '23',trim(q.qm_id), null,
trim(q.qaus),
trim(q.qaus)
from buausgab a, buartqa q
where
a.l_ausg_nr = q.l_ausg_nr and
a.prod_typ = q.prod_typ and
q.qm_id ='HOMEPAGE'
union
select
a.l_ausg_nr,
(case when rtrim(p.pan_typ) = 'SUBJEC' then '93'
      when rtrim(p.pan_typ) = 'GEOGRA' then '94'
      when rtrim(p.pan_typ) = 'LANGUA'then  '95'
      when rtrim(p.pan_typ) = 'TIME' then  '96'
      when rtrim(p.pan_typ) = 'EDUCAT' then  '97'
      when rtrim(p.pan_typ) = 'INTAGE' then  '98'
      when rtrim(p.pan_typ) = 'STYLE' then  '99'
      else 'XXX'
end),
null, rtrim(t.version), rtrim(p.pan_id), rtrim(t.bezeichnung)
from buausgab a, bupantit p, bupanthe t
where
a.l_titel_nr = p.l_titel_nr and
t.pan_id = p.pan_id and
(p.pan_typ != 'SUBJEC' or p.sortierung = 99)
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX_VLB_WG" ("L_AUSG_NR", "VLB_WG") AS
  select a.l_ausg_nr, trim(v1.onix)||trim(v2.onix)
from buausgab a, buoxref v1, onix_bugruppe o, buherste h, buoxref v2
where
o.l_ausg_nr = a.l_ausg_nr and
h.l_ausg_nr = a.l_ausg_nr and
h.L_aufl_nr = 0 and
v1.typ = 'MEDIENTYP' and
v1.cover_1 = a.prod_typ and
v1.cover_2 = h.einbandart
and
v2.typ = 'SACH_GRP' and
v2.cover_1 = o.sach_grp
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIXZWISCHENEBENE" ("L_AUSG_NR", "U_AUSG_NR") AS
  select
k.l_ausg_nr, k.u_ausg_nr
from bukombi k, buausgab a1, buausgab a2
where
k.l_ausg_nr = a1.l_ausg_nr and
k.u_ausg_nr = a2.l_ausg_nr and
a1.kombityp in ('S','V','M') and
a2.kombityp = 'Z'

;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCT" ("RECORDIDENTIFIER", "RECORDREFERENCE", "NOTIFICATIONTYPE", "RECORDSOURCETYPE", "RECORDSOURCEIDENTIFIERTYPE", "RECORDSOURCEIDENTIFIER", "RECORDSOURCENAME", "PUBLISHERORDERID", "PRODUCTISBN13", "PRODUCTEAN", "BARCODE", "PRODUCTFORM", "PRODUCTFORMDETAIL", "DISTINCTIVETITLE", "SUBTITLE", "ORIGINALTITLE", "ORIGINALSUBTITLE", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR", "EDITIONTYPECODE", "EDITIONNUMBER", "EDITIONSTATEMENT", "NOEDITION", "LANGUAGEOFTEXT", "ORIGINALLANGUAGE", "NUMBEROFPAGES", "PAGESROMAN", "PAGESARABIC", "FILESIZE", "DURATIONTIME", "DURATIONTIMEUNIT", "NUMBEROFILLUSTRATIONS", "ILLUSTRATIONSNOTE", "VLBSCHEMENEW", "PUBLISHERCODE", "PUBLISHERNAME", "PUBLISHERWEBSITE", "PUBLISHINGSTATUS", "PUBLICATIONDATEYEAR", "PUBLICATIONDATEMONTH", "PUBLICATIONDATEDAY", "COPYRIGHTYEAR", "PRODUCTHEIGHT", "PRODUCTWIDTH", "PRODUCTTHICKNESS", "PRODUCTWEIGHT", "REPLACESISBN", "REPLACEDBYISBN", "PRODUCTAVAILABILITY", "EXPECTEDSHIPDATEYEAR", "EXPECTEDSHIPDATEMONTH", "EXPECTEDSHIPDATEDAY", "ONSALEDATE", "UNPRICEDITEMTYPE", "PANTHEMASUBJECT", "PRODUCTWEBSITELINK", "COUNTRYOFPRODUCTION", "TRADECLASSIFICATION", "EPUBTECHNICALPROTECTION", "PUBLICATIONDATE", "EXPECTEDSHIPDATE", "PRODUCTDOI", "SORTORDER", "IMPORTEDAT", "SHOPITEM", "BODITEM", "PARTNERITEM", "COMMERCIALITEM", "MEMBERSONLY", "ONIXITEM", "COPYRIGHTHOLDERTYPE", "COPYRIGHTHOLDER", "PRODUCTCOMPOSITION", "PRIMARYCONTENTTYPE") AS
  select
substr(to_char(a.l_ausg_nr),1,20), a.ean, '03', '01', '04', '15659', 'Schlutersche Fachmedien GmbH', trim(m.artikel_nr), a.ean, a.ean,
(case when trim(q1.qaus) is not null then trim(q1.qaus) else '0' end),
trim(decode(trim(a.prod_typ),
         '1',trim(h.einbandart),
         '9',decode(substr(h.einbandart,1,2),'DG','DG',
                                              'DH','DH',
                                              trim(a.prod_typ)) ,
          trim(a.prod_typ))),
trim(decode(trim(a.prod_typ),'9',(decode(substr(h.einbandart,1,2),'DH',null,
                                                                  h.einbandart)),
                                  h.einbandart)),
trim(t.titel1), trim(t.titel_unter), trim(t.orig_titel), trim(t.orig_u_titel), trim(k.ContributorStatement),
k.NoContributor,
trim(b0.aufl_text), b0.auflage_nr, trim(b0.aufl_text),
(case when (b0.aufl_text is null and trim(q2.qaus) is null) then 1 else 0 end),
trim(t.sprach_code), trim(t.org_spr_code),
(case when h.umfang_einheit!='M' and h.umfang_einheit is not null then trim(h.umfang) else null end),
trim(h.bibl_seiten_arab), trim(h.bibl_seiten_roem),
trim(h.dateigroesse),
(case when h.umfang_einheit='M' then trim(h.umfang) else null end),
(case when h.umfang_einheit='M' then '05' else null end),
trim(q6.qaus), trim(h.abbildung),
(case when a.prod_typ != 'AJ' then (trim(a.prod_typ)||trim(g.sach_grp))
                         else ('9'||trim(g.sach_grp)) end),
decode(a.verlags_id, null, null, (decode(trim(bv.verkehrs_nr), null, '05/'||trim(bv.kenn_nr), '04/'||trim(substr(bv.verkehrs_nr,1,5))))), decode(a.verlags_id, null, null,trim(bv.verlag_lang)),
decode(a.verlags_id, null, null,trim(bv.website)), trim(b0.meld_nr),
b0.ist_jahr, b0.ist_monat, b0.ist_tag,
null, decode(round((a.hoehe * 10), 0),0,null,round((a.hoehe * 10), 0)), decode(round((a.breite * 10),0),0,null,round((a.breite * 10),0)), decode(round((a.dicke * 10),0),0,null,round((a.dicke * 10),0)), decode(a.gewicht,0,null,a.gewicht), null, null,
trim(b0.meld_nr), b0.soll_jahr, b0.soll_monat, b0.soll_tag,
to_char(m.nov_dat,'YYYYMMDD'), o.UnpricedItemType,
(SELECT LISTAGG(trim(PAN_ID),  ';') WITHIN GROUP (ORDER BY PAN_ID) FROM bupantit where pan_typ='SUBJEC' and l_titel_nr=a.l_titel_nr), null,
(case when q7.qaus is not null then trim(q7.qaus) else 'DE' end),
trim(pr.istatwcode),
(case when pr.kz_elektron= 'T' then rtrim(h.drm_code) else null end),
(case when b0.aufl_dat_ist is not null then to_char(b0.aufl_dat_ist,'YYYYMMDD') else to_char(b0.aufl_dat_soll,'YYYYMMDD') end),
(case when b0.aufl_dat_ist is not null then to_char(b0.aufl_dat_ist,'YYYYMMDD') else to_char(b0.aufl_dat_soll,'YYYYMMDD') end),
rtrim(a.doi), substr(to_char(a.l_ausg_nr),1,20), to_char(sysdate,'YYYYMMDD'),
'0', '0', '0', '0', '0', '0',
null, null,
(case when a.kombityp in ('S','V') then '10' else '00' end),
(case when (a.bundle is not null and a.bundle != 'K')
      then 'WW'
      else rtrim(h.einbandart)
end)
from
buausgab a, bumanaus m,
butitel t, buoxaufl b0,  bugruppe g,
buartqa q1, buartqa q2, buartqa q4, buartqa q6, buartqa q7,
onixohnepreis o, onixkeinautor k, buherste h, onixmandant om, buverlag bv,
buprotyp pr
where
a.l_titel_nr = t.l_titel_nr and
a.l_ausg_nr = m.l_ausg_nr and
b0.l_ausg_nr  = a.l_ausg_nr and
g.l_titel_nr (+) = a.l_titel_nr and
q1.l_ausg_nr (+) = a.l_ausg_nr and
q1.prod_typ (+) = a.prod_typ and
q1.qm_id (+) = 'BARCODE' and
q2.l_ausg_nr (+) = a.l_ausg_nr and
q2.prod_typ (+) = a.prod_typ and
q2.qm_id (+) = 'EDIT_TYP' and
q4.l_ausg_nr (+) = a.l_ausg_nr and
q4.prod_typ (+) = a.prod_typ and
q4.qm_id (+) = 'DATEIGR' and
q6.l_ausg_nr (+) = a.l_ausg_nr and
q6.prod_typ (+) = a.prod_typ and
q6.qm_id (+) = 'ANZAHLABB' and
q7.l_ausg_nr (+) = a.l_ausg_nr and
q7.prod_typ (+) = a.prod_typ and
q7.qm_id (+) = 'HERSTLAND' and
a.kombityp in ('E','B', 'V', 'M', 'Z', 'S') and
a.ean is not null and
a.isbn is not null and
a.kz_aufl_best = 'F' and
a.kz_eigen = 'T' and
o.l_ausg_nr (+) = a.l_ausg_nr and
k.l_ausg_nr = a.l_ausg_nr and
h.l_ausg_nr (+) = a.l_ausg_nr and
m.e_mandant = om.e_mandant and
bv.verlags_id (+) = a.verlags_id and
m.nov_dat is not null and
a.herkunft is null and
pr.prod_typ = a.prod_typ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTCONTACT" ("ID", "RECORDIDENTIFIER", "PRODUCTCONTACTROLE", "PRODUCTCONTACTIDENTIFIER", "PRODUCTCONTACTNAME", "CONTACTNAME", "TELEPHONENUMBER", "FAXNUMBER", "EMAILADDRESS", "STREETADDRESS", "LOCATIONNAME", "POSTALCODE", "COUNTRYCODE", "SORTORDER") AS
  select
  ROW_NUMBER() OVER (ORDER BY b.l_ausg_nr), substr(to_char(b.l_ausg_nr),1,20), '10',
  null, trim(s.name1), (case when trim(s.nachname) is null then null else trim(s.vorname)||' '||trim(s.nachname) end),
  (select trim(nummer) from teleview t where t.adr_gr=s.adr_gr and t.adr_nr=s.adr_nr and t.person_nr=s.person_nr and verw_id in ('Z','P') and rownum=1),
  (select trim(nummer) from teleview t where t.adr_gr=s.adr_gr and t.adr_nr=s.adr_nr and t.person_nr=s.person_nr and verw_id in ('X','Y') and rownum=1),
  (select trim(nummer) from teleview t where t.adr_gr=s.adr_gr and t.adr_nr=s.adr_nr and t.person_nr=s.person_nr and verw_id in ('E','I') and rownum=1),
  trim(s.strasse), trim(s.HAUPT_ort), trim(s.HAUPT_plz),
  trim(s.land_code), '0010'
 from buoxprod o, buausgab b, sapiview s
where
  o.recordidentifier = b.l_ausg_nr and
  s.q_code = 'GPSR' and
  trim(s.q_ausp_code) = trim(b.prod_typ);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTCONTAINEDITEM" ("RECORDIDENTIFIER", "PUBLISHERORDERID", "PRODUCTIDENTIFIER", "PRODUCTISBN13", "PRODUCTFORM", "PRODUCTFORMDETAIL", "ITEMQUANTITY", "SORTORDER", "PRIMARYPART") AS
  select
-- RecordIdentifier
substr(to_char(k.l_ausg_nr), 1,20),
-- PublisherOrderId
trim(m2.artikel_nr),
-- ProductIdentifier
case when (a2.ean is not null)
     then null
     else ('01/SCH/'||rtrim(a1.ean)||'-'||rtrim((select count(*) from bukombi kk where kk.l_ausg_nr = a1.l_ausg_nr and kk.u_ausg_nr <= a2.l_ausg_nr)))
end,
-- ProductISBN13
a2.ean,
-- ProductForm
rtrim(hb.einbandart),
-- ProductFormDetail
rtrim(hb.einbandart),
-- ItemQuantity
k.menge,
-- SortOrder
rtrim(m2.artikel_nr),
-- PrimaryPart
case when (rtrim(m2.artikel_nr) like '%-P') then '1'
     else null
end
from buausgab a1, bukombi k, bumanaus m2, buausgab a2, onixmandant om, buherste hb
where
a2.l_ausg_nr = m2.l_ausg_nr and
k.u_ausg_nr = a2.l_ausg_nr and
k.l_ausg_nr = a1.l_ausg_nr and
a1.kombityp in ('S', 'V', 'M', 'Z') and
a2.kombityp = 'B' and
a2.kz_aufl_best = 'F' and
((a1.ean is not null and a1.isbn is not null )
 or a1.l_ausg_nr in (select l_ausg_nr from buartref where ref_id='VLB-X'
 and ref_art_nr is not null)) and
a2.ean is not null and
a2.isbn is not null and
a2.kz_eigen = 'T' and
a1.kz_eigen = 'T' and
a2.herkunft is null and
k.menge > 0 and
m2.e_mandant = om.e_mandant  and
hb.l_ausg_nr = a2.l_ausg_nr   and
hb.l_aufl_nr = k.l_aufl_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTCONTRIBUTOR" ("RECORDIDENTIFIER", "SEQUENCENUMBER", "CONTRIBUTORROLE", "NAMESBEFOREKEY", "KEYNAMES", "CORPORATENAME", "SORTORDER", "PERSONNAMEORCID", "PERSONNAMEISNI") AS
  select
-- RecordIdentifier
substr(to_char(a.l_ausg_nr),1,20),
-- SequenceNumber
b.sort,
-- ContributorRole
trim(b.autor_typ),
-- NamesBeforeKey
trim(b.vorname),
-- KeyNames
trim(b.nachname),
-- CorporateName
null,
-- SortOrder
b.sort,
(select trim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('ORC') and
           b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr),
(select trim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('ISN') and
           b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr)
from buausgab a, buautor b, bumanaus m, onixmandant om
where
a.l_titel_nr = b.l_titel_nr and
b.sort > 0 and
b.autor_typ != 'L' and
a.kombityp in ('E','B', 'V', 'M', 'Z') and
a.kz_aufl_best = 'F' and
a.ean is not null and
a.isbn is not null and
a.kz_eigen = 'T' and
a.herkunft is null and
a.l_ausg_nr = m.l_ausg_nr and
m.e_mandant = om.e_mandant and
(b.adr_gr is null or b.adr_nr_aut is null or b.person_nr_aut > 0 or b.person_nr_aut is null or b.vorname is not null or
( b.person_nr_aut = 0 and b.adr_nr_aut > 0 and
(select a_typ from person p where p.adr_gr=b.adr_gr and p.adr_nr = b.adr_nr_aut and p.person_nr = b.person_nr_aut) != 'F'))
union
select
-- RecordIdentifier
substr(to_char(a.l_ausg_nr),1,20),
-- SequenceNumber
b.sort,
-- ContributorRole
trim(b.autor_typ),
-- NamesBeforeKey
null,
-- KeyNames
null,
-- CorporateName
rtrim(b.nachname),
-- SortOrder
b.sort,
(select trim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('ORC') and
           b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr),
(select trim(a1.externe_nr) from anwref a1, refstamm r where a1.e_mandant=r.e_mandant and a1.anw_ref_nr=r.anw_ref_nr and verwend_typ in ('ISN') and
           b.adr_gr = a1.adr_gr and b.adr_nr_aut = a1.adr_nr and b.person_nr_aut = a1.person_nr)
from buausgab a, buautor b, bumanaus m, onixmandant om
where
a.l_titel_nr = b.l_titel_nr and
b.sort > 0 and
b.autor_typ != 'L' and
a.kombityp in ('E','B', 'V', 'M', 'Z') and
a.kz_aufl_best = 'F' and
a.ean is not null and
a.isbn is not null and
a.kz_eigen = 'T' and
a.herkunft is null and
a.l_ausg_nr = m.l_ausg_nr and
m.e_mandant = om.e_mandant and
(b.adr_gr is not null and b.adr_nr_aut is not null and b.person_nr_aut = 0 and b.vorname is null and
(select a_typ from person p where p.adr_gr=b.adr_gr and p.adr_nr = b.adr_nr_aut and p.person_nr = b.person_nr_aut) = 'F');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTFORMFEATURE" ("RECORDIDENTIFIER", "FEATURETYPE", "FEATUREVALUE", "FEATUREDESCRIPTION", "SORTORDER") AS
  select
cast(bp.l_ausg_nr as varchar(20)),
'09', rtrim(p.hgrp_id),
Null,
'003'
from buoxprod bp, buartpro p
where
bp.l_ausg_nr = p.l_ausg_nr and
p.wb_id = '196' and
p.hgrp_id is not null
union
select
cast(bp.l_ausg_nr as varchar(20)),
'12', '00',
Null,
'001'
from buoxprod bp, buausgab b
where
bp.l_ausg_nr = b.l_ausg_nr and
(b.prod_typ = 'EBOO' or b.prod_typ = 'EPUB')
union
select
cast(bp.l_ausg_nr as varchar(20)),
'09', '00',
rtrim(tr."DEFAULT"),
'004'
from transdef tr, buoxprod bp
where
tr.transfer_id='NFA-REF' and
tr.kunde = 'NFA' and
tr.bereich = 'PROD' and
tr.verwend_typ = 'DATEXP' and
tr.tabelle = 'AUTOIMPORT' and
tr.feld = 'BARRIERE' and
exists (select * from  buartpro p where
bp.l_ausg_nr = p.l_ausg_nr and
p.wb_id = '196' and
p.hgrp_id is not null) and rownum=1;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTKEYWORD" ("RECORDIDENTIFIER", "SUBJECTSCHEMEIDENTIFIER", "SUBJECTSCHEMEVERSION", "SUBJECTCODE", "SUBJECTHEADINGTEXT", "SORTORDER") AS
  select
cast(bp.l_ausg_nr as varchar(20)), '20',null,null,rtrim(s.stichwort),  (coalesce(s.sortierung ,999) + 9000)
from
bustichw s, buoxprod bp
where
bp.l_titel_nr = s.l_titel_nr
union
select
cast(bp.l_ausg_nr as varchar(20)),
(case when rtrim(p.pan_typ) = 'SUBJEC' then '93'
      when rtrim(p.pan_typ) = 'GEOGRA' then '94'
      when rtrim(p.pan_typ) = 'LANGUA'then  '95'
      when rtrim(p.pan_typ) = 'TIME' then  '96'
      when rtrim(p.pan_typ) = 'EDUCAT' then  '97'
      when rtrim(p.pan_typ) = 'INTAGE' then  '98'
      when rtrim(p.pan_typ) = 'STYLE' then  '99'
      else 'XXX'
end),
 rtrim(t.version), rtrim(p.pan_id), rtrim(t.bezeichnung),
(case when rtrim(p.pan_typ) = 'SUBJEC' then 93
      when rtrim(p.pan_typ) = 'GEOGRA' then 94
      when rtrim(p.pan_typ) = 'LANGUA'then  95
      when rtrim(p.pan_typ) = 'TIME' then  96
      when rtrim(p.pan_typ) = 'EDUCAT' then  97
      when rtrim(p.pan_typ) = 'INTAGE' then  98
      when rtrim(p.pan_typ) = 'STYLE' then  99
      else 100
end)
from  buoxprod bp,  bupantit p, bupanthe t
where
bp.l_titel_nr = p.l_titel_nr and
t.pan_id = p.pan_id and
(p.pan_typ != 'SUBJEC' or p.sortierung = 99);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTMEDIAFILE" ("RECORDIDENTIFIER", "RESOURCEMODE", "RESOURCEFORM", "CONTENTAUDIENCE", "MEDIAFILETYPECODE", "MEDIAFILELINK", "MEDIAFILEDATE", "MEDIAFILEFORMATCODE") AS
  select
-- Recordidentifier
substr(to_char(a.l_ausg_nr),1,20),
-- ResourceMode
'03',
-- ResourceForm
'02',
-- ContentAudience
'00',
-- MediaFileTypeCode
trim(a.bild_typ),
-- MediaFileLink
trim(a.verzeichnis)||trim(a.dateiname),
-- MediaFileDate
null,
-- MediaFileFormatCode  (vorher 03)
trim(a.bild_typ)
from buaufbil a , onix3_Cover_product o
where o.recordidentifier = a.l_ausg_nr and
a.l_aufl_nr = 0 and
a.verzeichnis like 'http%';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTOTHERTEXT" ("RECORDIDENTIFIER", "TEXTTYPECODE", "TEXTFORMAT", "TEXTCASE", "TEXTLANGUAGE", "TEXT", "STARTDATE", "ENDDATE", "SORTORDER") AS
  select
cast(bp.l_ausg_nr as varchar(20)), rtrim(t.verw_typ), '06', '00',
rtrim(t.sprach_code), rtrim(substr(t.aufl_text,1,4000)), null, null, t.verw_typ
from buoxprod bp, buaufl b, buoxprtx t, buausgab a
where
bp.l_ausg_nr = b.l_ausg_nr and
b.l_ausg_nr = t.l_ausg_nr and
b.l_aufl_nr = t.l_aufl_nr and
b.l_aufl_nr = 0 and
t.e_mandant = bp.e_mandant and
bp.l_ausg_nr = a.l_ausg_nr and
((a.prod_typ != '2' and t.verw_typ in ('28','29')) or
(a.prod_typ = '2' and t.verw_typ in ('43')));


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTPRICE" ("RECORDIDENTIFIER", "PRICETYPECODE", "PRICETYPEDESCRIPTION", "PRICESTATUS", "PRICEAMOUNT", "CURRENCYCODE", "COUNTRYCODE", "TAXRATECODE1", "PRICEEFFECTIVEFROM", "PRICEEFFECTIVEUNTIL", "BATCHQUANTITY", "MINIMUMORDERQUANTITY", "TAXRATEPERCENT1", "PRICEAMOUNTTAX1", "TAXRATECODE2", "TAXRATEPERCENT2", "PRICEAMOUNTTAX2", "DISCOUNTCODETYPE", "DISCOUNTCODETYPENAME", "DISCOUNTCODE", "DISCOUNTCODETYPE2", "DISCOUNTCODETYPENAME2", "DISCOUNTCODE2", "SORTORDER") AS
