  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTPUBLISHER" ("RECORDIDENTIFIER", "PUBLISHERROLE", "PUBLISHERCODE", "PUBLISHERNAME", "FUNDINGIDENTIFIER") AS
  select
substr(to_char(a.l_ausg_nr),1,20), '16',
(case when r.externe_nr is not null then '32/'||rtrim(r.externe_nr)
else null end),
