r.adr_gr(+) = b.adr_gr and
r.adr_nr(+) = b.adr_nr_aut and
r.person_nr(+) = b.person_nr_aut and
r.anw_ref_nr(+) = 'FD' and
r1.l_ausg_nr (+) = a.l_ausg_nr and
r1.ref_id (+) = 'FBNR';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTRELATION" ("RECORDIDENTIFIER", "RELATIONCODE", "PRODUCTEAN", "PRODUCTISBN13", "PUBLISHERORDERID", "PRODUCTFORM", "PRODUCTFORMDETAIL", "SORTORDER") AS
  select
substr(to_char(a.l_ausg_nr),1,20),
trim(decode(trim(a.prod_typ),'9','13','06')),
trim(b.ean),trim(b.isbn),
rtrim(m.artikel_nr),
rtrim(h.einbandart), rtrim(h.einbandart),
null
from buausgab a, buausgab b, buherste h, onix3_Cover_product o, bumanaus m, onixmandant om
where a.l_titel_nr = b.l_titel_nr
and a.l_ausg_nr != b.l_ausg_nr
and a.l_titel_nr != 0
and a.herkunft is null
and b.herkunft is null
and
h.l_ausg_nr (+) = b.l_ausg_nr
and a.l_ausg_nr = o.RecordIdentifier
and
(
  (o.ProductForm in ('DG','DH') and (b.prod_typ != '9' or substr(h.einbandart,1,2) not in ('DG','DH')))
  or
  (o.ProductForm not in ('DG','DH') and (b.prod_typ = '9' and substr(h.einbandart,1,2) in ('DG','DH')))
)
and b.ean is not null
and b.prod_typ is not null
and m.l_ausg_nr = b.l_ausg_nr and m.e_mandant = om.e_mandant
union
select
substr(to_char(a.l_ausg_nr),1,20),
'03',
trim(a2.ean),trim(a2.isbn),
rtrim(m2.artikel_nr),
rtrim(h.einbandart), rtrim(h.einbandart),
null
from buausgab a, buausgab a2, buherste h, onix3_Cover_product o, onixmandant om, bumanaus m2
where a.l_ausg_nr != a2.l_ausg_nr
and a.l_titel_nr != 0
and a.herkunft is null
and a2.herkunft is null
and h.l_ausg_nr (+) = a2.l_ausg_nr
and a.l_ausg_nr = o.RecordIdentifier
and a2.ean is not null
and a2.prod_typ is not null
and m2.l_ausg_nr = a2.l_ausg_nr
and m2.e_mandant (+) = om.e_mandant and m2.l_ausg_nr_neu (+) = a.l_ausg_nr
union
select
substr(to_char(a.l_ausg_nr),1,20),
'05',
trim(a3.ean),trim(a3.isbn),
rtrim(m3.artikel_nr),
rtrim(h.einbandart), rtrim(h.einbandart),
null
from buausgab a, buausgab a3, buherste h, onix3_Cover_product o, onixmandant om, bumanaus m3, bumanaus m
where a.l_ausg_nr != a3.l_ausg_nr
and a.l_titel_nr != 0
and a.herkunft is null
and a3.herkunft is null
and h.l_ausg_nr (+) = a3.l_ausg_nr
and a.l_ausg_nr = o.RecordIdentifier
and a3.ean is not null
and a3.prod_typ is not null
and m.l_ausg_nr = a.l_ausg_nr and m.e_mandant = om.e_mandant
and m3.l_ausg_nr = a3.l_ausg_nr and m3.e_mandant = om.e_mandant
and a3.l_ausg_nr (+) = m.l_ausg_nr_neu;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTSERIES" ("RECORDIDENTIFIER", "SERIESID", "TITLEOFSERIES", "NUMBERWITHINSERIES", "SORTORDER") AS
