  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTSUBJECT" ("RECORDIDENTIFIER", "SUBJECTSCHEMEIDENTIFIER", "SUBJECTSCHEMENAME", "SUBJECTSCHEMEVERSION", "SUBJECTCODE", "SUBJECTHEADINGTEXT") AS
  select
