t.l_aufl_nr = 0 and
t.verw_typ = 'SW' and
t.e_mandant = bp.e_mandant
union
select substr(to_char(bp.l_ausg_nr),1,20), '23', 'Warengruppe Forum', null,trim(q.qaus),null
from buoxprod bp, buartqa q, buausgab a
where
a.l_ausg_nr = bp.l_ausg_nr and
bp.l_ausg_nr = q.l_ausg_nr and
a.prod_typ = q.prod_typ and
q.qm_id = 'FORUMWAREN'
union
select substr(to_char(bp.l_ausg_nr),1,20), '24', 'BroCom Warnzahl', null,to_char(l.meld_best),null
from buoxprod bp, bulagmin l
where
bp.l_ausg_nr = l.l_ausg_nr and
l.l_aufl_nr = 0 and
l.lager_code = 'BRO' and
l.meld_best > 0
union
select
substr(to_char(bp.l_ausg_nr),1,20),
