                 'GEOGRA','94',
                 'LANGUA', '95',
                 'TIME', '96',
                 'EDUCAT', '97',
                 'INTAGE', '98',
                 'STYLE', '99', 'XXX'),
null, trim(t.version), trim(p.pan_id), trim(t.bezeichnung)
from buoxprod bp,  bupantit p, bupanthe t
where
bp.l_titel_nr = p.l_titel_nr and
t.pan_id = p.pan_id and
(p.pan_typ != 'SUBJEC' or p.sortierung = 99)
union
select
substr(to_char(o.l_ausg_nr),1,20),
'23',
'utb Fachbereich',null,
trim(hg.bez),null
from buoxprod o, buartpro p, hauptgrp hg
where
o.l_ausg_nr=p.l_ausg_nr
and (p.wb_id='UTB')
and hg.wb_id=p.wb_id
and hg.hgrp_id=p.hgrp_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_COVER_PRODUCTWEBSITE" ("RECORDIDENTIFIER", "WEBSITEID", "WEBSITEROLE", "WEBSITEDESCRIPTION", "WEBSITELINK", "SORTORDER") AS
