  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_PRODUCT" ("RECORDIDENTIFIER", "RECORDREFERENCE", "NOTIFICATIONTYPE", "PUBLISHERORDERID", "PRODUCTISBN13", "PRODUCTEAN", "PRODUCTFORM", "PRODUCTFORMDETAIL", "DISTINCTIVETITLE", "SUBTITLE", "ORIGINALTITLE", "ORIGINALSUBTITLE", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR", "EDITIONNUMBER", "EDITIONSTATEMENT", "NOEDITION", "LANGUAGEOFTEXT", "ORIGINALLANGUAGE", "NUMBEROFPAGES", "PAGESROMAN", "PAGESARABIC", "PUBLISHERCODE", "PUBLISHERNAME", "PUBLISHERWEBSITE", "PUBLISHINGSTATUS", "PUBLICATIONDATEYEAR", "PUBLICATIONDATEMONTH", "PUBLICATIONDATEDAY", "PRODUCTHEIGHT", "PRODUCTWIDTH", "PRODUCTTHICKNESS", "PRODUCTWEIGHT", "REPLACESISBN", "REPLACEDBYISBN", "PRODUCTAVAILABILITY", "EXPECTEDSHIPDATEYEAR", "EXPECTEDSHIPDATEMONTH", "EXPECTEDSHIPDATEDAY", "ONSALEDATE", "UNPRICEDITEMTYPE", "VLBSCHEMENEW", "EPUBFORMAT", "PRODUCTDOI", "COUNTRYOFPUBLICATION", "PRODUCTWEBSITEROLE", "PRODUCTWEBSITELINK", "PANTHEMASUBJECT") AS
  select
bp.l_ausg_nr, bp.ean, '03', rtrim(bp.artikel_nr), bp.ean, bp.ean,
rtrim(h.einbandart),rtrim(h.einbandart),
rtrim(t.titel1), rtrim(t.titel_unter), rtrim(t.orig_titel), rtrim(t.orig_u_titel),
rtrim(bp.ContributorStatement), bp.NoContributor,
b.bestuhlung, rtrim(bp.aufl_text),
(case when b.bestuhlung is null and bp.aufl_text is null then 1 else 0 end),
rtrim(t.sprach_code), rtrim(t.org_spr_code),
rtrim(h.umfang),  rtrim(h.seiten_roem),rtrim(h.bibl_seiten_arab),
(case when a.verlags_id is null
      then null
      else (case when bv.verkehrs_nr is null
                 then '05/'||rtrim(bv.kenn_nr)
                 else '04/'||rtrim(substr(bv.verkehrs_nr,1,5))
            end)
end),
(case when a.verlags_id is null
      then null
      else rtrim(bv.verlag_lang)
end),
(case when a.verlags_id is null
      then null
      else rtrim(bv.website)
end),
rtrim(bp.meld_nr), bp.ist_jahr, bp.ist_monat, bp.ist_tag,
(case when a.hoehe = 0
      then null
      else (round((a.hoehe * 10), 0))end),
(case when a.breite = 0 then null
      else (round((a.breite * 10), 0))end),
(case when a.dicke = 0 then null
      else (round((a.dicke * 10), 0))end),
(case when a.gewicht = 0 then null
      else a.gewicht end),
bp.ReplacesIsbn, bp.ReplacedByISBN,
rtrim(bp.meld_nr), bp.soll_jahr, bp.soll_monat, bp.soll_tag,
to_char(m.nov_dat,'YYYYMMDD'), bp.UnpricedItemType,
bp.vlbschemenew,
(case when oxeb.onix = 'T' then h.einbandart
                           else null end),
a.doi,
'DE',
(case when a.link is null then null else '02' end), rtrim(a.link),
rtrim(pt.pan_id)
from
bumanaus m,
butitel t, buoxprod bp,  buaufl b, buausgab a
left outer join BUHERSTE h on
  h.l_ausg_nr = a.l_ausg_nr
left outer join BUVERLAG bv on
  bv.verlags_id = a.verlags_id
left outer join BUPANTIT pt on
 pt.l_titel_nr = a.l_titel_nr and
 pt.pan_typ = 'SUBJEC' and
 pt.sortierung = 1
left outer join BUOXREF OXEB on
 oxeb.cover_1=a.prod_typ and
 oxeb.typ='EPUB'
where
a.l_titel_nr = t.l_titel_nr and
m.l_ausg_nr = bp.l_ausg_nr and
m.e_mandant = bp.e_mandant and
a.l_ausg_nr  = bp.l_ausg_nr and
a.kombityp in ('E','B', 'V', 'M', 'Z', 'S') and
a.ean is not null and
a.isbn is not null and
a.kz_aufl_best = 'F'and
a.kz_eigen = 'T' and
bp.l_ausg_nr = b.l_ausg_nr and
bp.l_aufl_nr = b.l_aufl_nr
;


