and ba.l_aufl_nr = 0
and ba.bestuhlung = aa.bestuhlung
and h.l_ausg_nr = b.l_ausg_nr
and ag.l_ausg_nr = a.l_ausg_nr
and bg.l_ausg_nr = b.l_ausg_nr
and (select oxr.onix from buoxref oxr where oxr.typ='EPUB' and oxr.cover_1=bg.prod_typ and oxr.cover_2 = '0' and oxr.cover_3 = '0') = 'T'
and
((select oxr.onix from buoxref oxr where oxr.typ='EPUB' and oxr.cover_1=ag.prod_typ and oxr.cover_2 = '0' and oxr.cover_3 = '0') = 'F'
or (select oxr.onix from buoxref oxr where oxr.typ='EPUB' and oxr.cover_1=ag.prod_typ and oxr.cover_2 = '0' and oxr.cover_3 = '0') is null)
