  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_PRODUCTSUBJECT" ("RECORDIDENTIFIER", "SUBJECTSCHEMEIDENTIFIER", "SUBJECTSCHEMENAME", "SUBJECTSCHEMEVERSION", "SUBJECTCODE", "SUBJECTHEADINGTEXT", "SORTIERUNG") AS
  select
bp.l_ausg_nr, '20', null,null,null,rtrim(s.stichwort),  coalesce(s.sortierung ,999)
from
bustichw s, buoxprod bp
where
bp.l_titel_nr = s.l_titel_nr
union
select
bp.l_ausg_nr,
(case when rtrim(p.pan_typ) = 'SUBJEC' then '93'
      when rtrim(p.pan_typ) = 'GEOGRA' then '94'
      when rtrim(p.pan_typ) = 'LANGUA'then  '95'
      when rtrim(p.pan_typ) = 'TIME' then  '96'
      when rtrim(p.pan_typ) = 'EDUCAT' then  '97'
      when rtrim(p.pan_typ) = 'INTAGE' then  '98'
      when rtrim(p.pan_typ) = 'STYLE' then  '99'
      else 'XXX'
end),
null, rtrim(t.version), rtrim(p.pan_id), rtrim(t.bezeichnung),1
from buausgab a, buoxprod bp,  bupantit p, bupanthe t
where
bp.l_titel_nr = p.l_titel_nr and
t.pan_id = p.pan_id and
(p.pan_typ != 'SUBJEC' or p.sortierung = 99)
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONIX3_RODUCTOTHERTEXT" ("RECORDIDENTIFIER", "TEXTTYPECODE", "TEXTFORMAT", "TEXTCASE", "TEXTLANGUAGE", "OTHERTEXT", "STARTDATE", "ENDDATE") AS
  select
bp.l_ausg_nr, trim(t.verw_typ), '06', '00',
trim(t.sprach_code), trim(substr(to_char(t.aufl_text),1,4000)), null,null
from buoxprod bp, buaufl b, buoxprtx t
where
bp.l_ausg_nr = b.l_ausg_nr and
b.l_ausg_nr = t.l_ausg_nr and
b.l_aufl_nr = t.l_aufl_nr and
b.l_aufl_nr = 0 and
t.e_mandant = bp.e_mandant
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ONLDVIEW" ("ADR_GR", "ADR_NR", "AUFT_NR", "AUFT_HIST_NR", "DISPO_NR", "DISPO_HIST_NR", "DISPOPOS_NR", "E_MANDANT", "OBJ_NR", "AUSG", "SCHALT_VON", "SCHALT_BIS", "PLAZIERUNGS_ID", "PLAZ_EXT", "MOTIV", "PRODUKT", "DRUCK_ID", "DUNTERLAGEN", "DUART_ID", "STATUS_DISPOPOS", "ANZART_ID", "DATUM_NEU", "ANZ_SCHALTUNG", "ANZ_EINTRAG", "ANZ_ANZEIGEN", "STATUS", "VOLUMEN_TK", "NETTO_BETRAG", "ANZEIGEN_BETRAG", "SONDER_RABATT", "VOLUMEN_RABATT", "WA_PROV_SATZ", "HAUPT_NAME", "BEZIRK_ID", "UMS_ANT_WT1", "KZ_LOESCHEN", "KZ_EINMAL_KD", "WAEHRUNG", "ABRECH_ID", "ADR_NR_WA", "PREIS_KRITERIUM", "ABRECH_ZEIT", "FAKT_ART") AS
  select p.adr_gr, p.adr_nr, p.auft_nr, p.auft_hist_nr,
       p.dispo_nr, p.dispo_hist_nr, p.dispopos_nr, p.e_mandant, p.obj_nr,
       p.ausg, p.schalt_von, p.schalt_bis, p.plazierungs_id, p.plaz_ext, p.motiv,
       p.produkt, p.druck_id, p.dunterlagen, p.duart_id, p.status,
       d.anzart_id, d.datum_neu, d.anz_schaltung, d.anz_eintrag,
       d.anz_anzeigen, d.status, d.volumen_tk, d.netto_betrag,
       d.anzeigen_betrag, d.sonder_rabatt, d.volumen_rabatt, d.wa_prov_satz,
       a.haupt_name,
       b.bezirk_id, b.ums_anteil_proz,
       e.kz_loeschen, e.kz_einmal_kd,
       g.waehrung, g.abrech_id, g.adr_nr_wa,
       o.preis_kriterium, o.abrech_zeit, o.fakt_art
from   dispopos p, dispo d, anschr a, adbezirk b, person e, auftrag g, onlauftr o
where  p.auft_hist_nr = 0 and p.dispo_hist_nr = 0
       and p.adr_gr = d.adr_gr and p.adr_nr = d.adr_nr and p.auft_nr = d.auft_nr
       and p.auft_hist_nr = d.auft_hist_nr and p.dispo_nr = d.dispo_nr
       and p.dispo_hist_nr = d.dispo_hist_nr
       and p.adr_gr = a.adr_gr and p.adr_nr = a.adr_nr
       and p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr and p.auft_nr = b.auft_nr
       and b.auft_hist_nr = 0 and b.dispo_nr = 0 and b.dispo_hist_nr = 0
       and b.f_typ_nr = 'WT1'
       and p.adr_gr = e.adr_gr and p.adr_nr = e.adr_nr and e.person_nr = 0
       and p.adr_gr = g.adr_gr and p.adr_nr = g.adr_nr and p.auft_nr = g.auft_nr
       and g.auft_hist_nr = 0 and g.kz_inaktiv='F'
       and p.adr_gr = o.adr_gr and p.adr_nr = o.adr_nr and p.auft_nr = o.auft_nr
       and o.auft_hist_nr = 0;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."OXTEST" ("A", "B", "C", "D", "E", "F", "G", "H") AS
  select
case when a.verlags_id='IA' then rtrim(v.verkehrs_nr) else null end,
case when a.verlags_id='IA' then rtrim(v.verkehrs_nr) else null end,
case when a.verlags_id='IA' then rtrim(v.verlag_lang) else null end,
case when a.verlags_id='IA' then rtrim(v.website) else null end,
(case when a.verlags_id='IA' then to_char(bp.aufl_dat_ist, 'YYYY') else null end),
case when a.verlags_id='IA' then '1' else null end,
case when a.verlags_id='IA' then rtrim(v.verlag_lang) else null end,
case when a.verlags_id='IA' then rtrim(qe.qaus) else null end
from buausgab a, buverlag v, buaufl bp, buartqa qe
where a.l_ausg_nr = bp.l_ausg_nr and bp.l_aufl_nr = 0
and a.l_titel_nr = 460
and a.verlags_id = v.verlags_id
and qe.l_ausg_nr(+) = a.l_ausg_nr
and qe.qm_id(+) = 'ISBN_OR';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."OXTMP" ("RECORDIDENTIFIER", "SEQUENCENUMBER", "CONTRIBUTORROLE", "NAMESBEFOREKEY", "KEYNAMES") AS
