  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."POSTVIEW" ("PLZ_PLZ", "PLZ_ALORT", "PLZ_ART_A", "PLZ_ONAME", "PLZ_ONAME24", "PLZ_OZUSATZ", "PLZ_ART_OZU", "PLZ_KGS", "PLZ_ART_AP", "PLZ_ART_AW", "B_ID_MAN", "DATUM_MAN", "STR_SCHL", "STR_HNRVON_N", "STR_HNRBIS_N", "STR_NAME46", "STR_NAME22", "STR_HNRTYP", "PF_NRVON", "PF_NRBIS", "PF_ALORG", "GE_ID_NR", "GE_NAME") AS
  select p.plz_plz, p.plz_alort, p.plz_art_a, p.plz_oname, p.plz_oname24,
          p.plz_ozusatz, p.plz_art_ozu, p.plz_kgs, p.plz_art_ap, p.plz_art_aw,
          p.b_id_man, p.datum_man,
          s.str_schl, s.str_hnrvon_n, s.str_hnrbis_n, s.str_name46, s.str_name22, s.str_hnrtyp,
          o.pf_nrvon, o.pf_nrbis, o.pf_alorg,
          g.ge_id_nr, g.ge_name
from plzda p LEFT OUTER JOIN strada s ON
     p.plz_plz = s.str_plz and
     p.plz_alort = s.str_alort
     LEFT OUTER JOIN pofada o ON
     p.plz_plz = o.pf_plz and
     p.plz_alort = o.pf_alort
     LEFT OUTER JOIN grossda g ON
     p.plz_plz = g.ge_plz and
     p.plz_alort = g.ge_alort;


