       translate(l.aufl_text,'0123456789-+/_*\.^?!"?$%&(=)?`{'}[~]??|ABCDEFGHIJKLMNOPQRSTUVWXYZAUO@?#,abcdefghijklmnopqrstuvwxyzaou ','0123456789')
  from  buausgab b, buaufl l
 where  l.l_ausg_nr  = b.l_ausg_nr and
        b.herkunft = 'VA'
;


