           prov.vertreter_id, concat(per.nachname, per.vorname), per.nachname, per.vorname, concat(ans.name1, ans.haupt_name), ans.name1, ans.haupt_name,
		   prov.vertreter_typ, typ.bezeichnung, prov.vertragsende, vert.reg_id, vert.reg_code, geb.gebiet,
		   prov.adr_gr, prov.adr_nr_le, prov.person_nr_le, prov.adr_nr_re, prov.person_nr_re, prov.e_mandant, prov.obj_nr, prov.ausg, obj.objektname, ausg.bezeichnung, prov.abo_nr,
           prov.k_grund, prov.land_code_le, prov.rech_nr, prov.re_dat, prov.abruf_nr_fakt, prov.kopie_nr, prov.posnr, prov.uposnr,
	  	   prov.a_typ, prov.q_code, prov.q_ausp_code, prov.abo_kond, abk.bez, abs(abk.laufzeit_max - abk.laufzeit_min), prov.preis_kat, prov.preis_kat_no, abo.preis_kat_no,
		   (case when abo.preis_kat like 'SCH%' then 'SCH' when abo.preis_kat='PO' then 'PO' when abo.preis_kat='FREI' then 'FREI' when abo.preis_kat_no ='NO' then 'NO' else 'ABO' end),
		   prov.ber_menge, prov.akt_id, prov.uakt_id, prov.rab_proz,
	  	   prov.prov_bet_br, prov.prov_bet_net, prov.waehrung, prov.steuer_code, prov.steuer_satz, prov.status, prov.vorschuss,
	  	   prov.prov_art, prov.prov_art_bez, prov.abschlag_satz_prov_schnorrer,
		   prov.kz_sbs_provision, prov.kz_abo_bringer, prov.kz_zahlung_pk_no,
		   prov.l_ausg_nr, prov.l_aufl_nr, prov.prov_grp, prov.vertret_auft_typ, prov.auft_nr, prov.auf_pos,
		   abo.k_datum, abo.r_datum, abo.abo_dauer, abo.vbeg_dat, abo.vend_dat, abo.vbeg_heft, abo.vbeg_jahr, abo.vend_heft, abo.vend_jahr,
		   abo.no_ende_dat, abo.no_ende_jahr, abo.no_ende_hnr, kal.edat_ist, kal.versand_ist,
		   abo.abostatus, abo.inaus, abo.bestellg, lis.preis_m1,
		   bum.artikel_nr,
		   fak.l_rnr, fak.l_rdat, fak.l_rbetrag, fak.f_ende_dat_e, fak.f_ende_hnr, fak.f_ende_jahr, fak.g_bis_hnr, fak.g_bis_jahr,
		   concat(case when fak.l_rdat is not null then concat(to_char(fak.l_rdat, 'YY'), '-') end, lpad(fak.l_rnr, 7, '0')),
		   fak.l_zber_heft, fak.heft_anz, fak.ra_fakt,
		   akt.soll_beg, akt.soll_ende, akt.ist_ende, wek.anz_adr_eakt
    from vzveprov prov 	LEFT OUTER JOIN abostamm abo ON
										prov.adr_gr         = abo.adr_gr         and
										prov.adr_nr_le      = abo.adr_nr         and
										prov.person_nr_le   = abo.person_nr      and
										prov.adr_nr_re      = abo.adr_nr_bv      and
										prov.person_nr_re   = abo.person_nr_bv   and
										prov.e_mandant      = abo.e_mandant      and
										prov.obj_nr         = abo.obj_nr         and
										prov.ausg           = abo.ausg           and
										prov.abo_nr         = abo.abo_nr
										LEFT OUTER JOIN abofakt fak ON
														abo.adr_gr       = fak.adr_gr         	and
														abo.adr_nr       = fak.adr_nr         	and
														abo.person_nr    = fak.person_nr      	and
														abo.e_mandant    = fak.e_mandant      	and
														abo.obj_nr       = fak.obj_nr         	and
														abo.ausg         = fak.ausg           	and
														abo.abo_nr       = fak.abo_nr
										LEFT OUTER JOIN kalender kal ON
														abo.e_mandant    = kal.e_mandant      	and
														abo.obj_nr       = kal.obj_nr         	and
														abo.ausg         = kal.ausg           	and
														abo.no_ende_jahr = kal.jahr           	and
														abo.no_ende_hnr  = kal.hnr
										LEFT OUTER JOIN mobplnr lnr ON
														abo.e_mandant    = lnr.e_mandant      	and
														abo.obj_nr       = lnr.obj_nr           and
														lnr.gueltig_ab  <= sysdate              and
														lnr.gueltig_bis >= sysdate
										LEFT OUTER JOIN mobplist lis ON
														lnr.e_mandant    = lis.e_mandant   		and
														lnr.obj_nr       = lis.obj_nr      		and
														lnr.list_nr      = lis.list_nr          and
														abo.obj_nr       = lis.obj_nr           and
														abo.ausg         = lis.ausg             and
														abo.preis_kat    = lis.preis_kat        and
														abo.inaus        = lis.inaus            and
														abo.fakt_zr      = lis.fakt_zr          and
														abo.waehrung     = lis.waehrung
										LEFT OUTER JOIN konto kon ON
														abo.adr_gr       = kon.adr_gr         	and
														abo.adr_nr       = kon.adr_nr_abo     	and
														abo.person_nr    = kon.person_nr_abo  	and
														abo.e_mandant    = kon.e_mandant  		and
														abo.obj_nr       = kon.obj_nr     		and
														abo.ausg         = kon.ausg       		and
														abo.abo_nr       = kon.abo_nr
														LEFT OUTER JOIN bumanaus bum ON
																		prov.e_mandant = bum.e_mandant   and
																		prov.l_ausg_nr = bum.l_ausg_nr
						LEFT OUTER JOIN mobjtyp obj ON
										prov.e_mandant      = obj.e_mandant      and
										prov.obj_nr         = obj.obj_nr
						LEFT OUTER JOIN mobstamm ausg ON
										prov.e_mandant      = ausg.e_mandant     and
										prov.obj_nr         = ausg.obj_nr        and
										prov.ausg           = ausg.ausg
						LEFT OUTER JOIN vzvertre vert ON
						                prov.e_mandant      = vert.e_mandant     and
										prov.vertreter_id   = vert.vertreter_id
						                LEFT OUTER JOIN anschr ans ON
														vert.adr_gr      = ans.adr_gr         	and
														vert.adr_nr      = ans.adr_nr
										LEFT OUTER JOIN person per ON
														vert.adr_gr      = per.adr_gr        	and
														vert.adr_nr      = per.adr_nr         	and
														vert.person_nr   = per.person_nr
										LEFT OUTER JOIN gebvie geb ON
														vert.reg_id      = geb.reg_id         	and
														vert.reg_code    = geb.reg_code
						LEFT OUTER JOIN vzabokon abk ON
						                prov.abo_kond       = abk.abo_kond
						LEFT OUTER JOIN mhaktion akt ON
										prov.e_mandant      = akt.e_mandant      and
										prov.akt_id         = akt.akt_id
						LEFT OUTER JOIN provwekv wek ON
										prov.akt_id         = wek.akt_id,
						vzvertyp typ
	where
										prov.vertreter_typ  = typ.vertreter_typ
  ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."PROVWEKV" ("AKT_ID", "ANZ_ADR_EAKT") AS
  select wek.akt_id, max(anz_adr_eakt)  from wekview wek, vzveprov prov
            where wek.mandant = prov.e_mandant and wek.akt_id = prov.akt_id and	wek.uakt_id = prov.uakt_id and wek.soll_ist = 'IST'
			group by wek.akt_id
  ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."QSTEAVIE" ("LFD_NR", "E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "A_TYP", "Q_CODE", "Q_AUSP_CODE", "QSTEUER_ID", "GUELTIG_AB", "GUELTIG_BIS", "Q_AUSP_PRIO") AS
  SELECT a.lfd_nr,a.e_mandant,a.l_ausg_nr, a.l_aufl_nr, w.adr_gr, w.adr_nr, w.person_nr,
          w.a_typ, w.q_code, w.q_ausp_code, s.qsteuer_id, a.gueltig_ab, a.gueltig_bis, s.q_ausp_prio
FROM qsteart a, qwerte w, qsteausp s
WHERE a.lfd_nr = s.lfd_nr and
      s.adr_gr = w.adr_gr and
      s.a_typ = w.a_typ and
      s.q_code = w.q_code and
      s.q_ausp_code = w.q_ausp_code;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."QUALVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "A_TYP", "Q_CODE", "Q_AUSP_CODE", "HERKUNFT_ID", "STATUS", "DATUM", "FKT_BEREICH", "PRODUKT", "WB_ID", "HGRP_ID", "UGRP_ID", "ADR_NR_WT", "SUCHFELD", "BEZEICHNUNG") AS
  select q.adr_gr, q.adr_nr, q.person_nr, q.a_typ, q.q_code, q.q_ausp_code, q.herkunft_id, q.status,
	coalesce(q.datum_aend,q.datum_neu), '   ', '         ', '   ', '        ', '        ', 0,
	q.q_code||q.q_ausp_code, a.q_auspraeg||'                    '
from QWERTE q LEFT OUTER JOIN QAUSP a ON
q.adr_gr = a.adr_gr
and   q.a_typ  = a.a_typ
and   q.q_code = a.q_code
and   q.q_ausp_code = a.q_ausp_code
union
select f.adr_gr, f.adr_nr, f.person_nr, 'M', '        ', '               ', '            ', '  ',
	f.datum_neu, f.fkt_bereich, '         ', '   ', '        ', '        ', 0,
	f.fkt_bereich||'                    ', b.beschreibung||'                                                  '
from FKTPERSON f, FKTBER b
where f.fkt_bereich = b.fkt_bereich
union
select wt.adr_gr, wt.adr_nr, 0, pe.a_typ, '        ', '               ',
	wt.herkunft_id, '  ', wt.datum_neu, '   ', wt.produkt, p.wb_id, p.hgrp_id,
	p.ugrp_id, 0, wt.produkt||'              ', p.bez
from WTPROD wt, PRODUKT p, PERSON pe
where	wt.produkt   = p.produkt
and 	wt.adr_gr    = pe.adr_gr
and 	wt.adr_nr    = pe.adr_nr
and 	pe.person_nr = 0
and   wt.datum_aend is null
and     (wt.kz_loesch = 'F'
or     wt.kz_loesch is null)
union
select wt.adr_gr, wt.adr_nr, 0, pe.a_typ, '        ', '               ',
	wt.herkunft_id, '  ', wt.datum_aend, '   ', wt.produkt, p.wb_id, p.hgrp_id,
	p.ugrp_id, 0, wt.produkt||'              ', p.bez
from WTPROD wt, PRODUKT p, PERSON pe
where	wt.produkt   = p.produkt
and 	wt.adr_gr    = pe.adr_gr
and 	wt.adr_nr    = pe.adr_nr
and 	pe.person_nr = 0
and   wt.datum_aend is not null
and     (wt.kz_loesch = 'F'
or     wt.kz_loesch is null)
union
select wa.adr_gr, wa.adr_nr_wa, 0, pe.a_typ, '        ', '               ',
	wt.herkunft_id, '  ', wt.datum_neu, '   ', wa.produkt, p.wb_id, p.hgrp_id,
	p.ugrp_id, wt.adr_nr, wa.produkt||'              ', p.bez
from WAFKTZU wa, PRODUKT p, WTPROD wt, PERSON pe
where	wa.produkt    = p.produkt
and	wa.adr_gr     = wt.adr_gr
and	wa.adr_nr     = wt.adr_nr
and 	wa.produkt    = wt.produkt
and 	wa.adr_gr     = pe.adr_gr
and 	wa.adr_nr_wa  = pe.adr_nr
and 	pe.person_nr = 0
and   wt.datum_aend is null
and     (wt.kz_loesch = 'F'
or     wt.kz_loesch is null)
union
select wa.adr_gr, wa.adr_nr_wa, 0, pe.a_typ, '        ', '               ',
	wt.herkunft_id, '  ', wt.datum_aend, '   ', wa.produkt, p.wb_id, p.hgrp_id,
	p.ugrp_id, wt.adr_nr, wa.produkt||'              ', p.bez
from WAFKTZU wa, PRODUKT p, WTPROD wt, PERSON pe
where	wa.produkt    = p.produkt
and	wa.adr_gr     = wt.adr_gr
and	wa.adr_nr     = wt.adr_nr
and 	wa.produkt    = wt.produkt
and 	wa.adr_gr     = pe.adr_gr
and 	wa.adr_nr_wa  = pe.adr_nr
and 	pe.person_nr = 0
and   wt.datum_aend is not null
and     (wt.kz_loesch = 'F'
or     wt.kz_loesch is null);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."RECHVIEW" ("RECH_NR", "RECH_DATUM", "ADR_GR", "ADR_NR_RECH", "ADR_NR_BEST", "FAKT_MANDANT", "BEREICH", "RECH_TYP", "VORZEICHEN", "ZAHL_BED", "WAEHRUNG", "NETTO_BETRAG", "MWST_BETRAG", "RECH_BETRAG", "MWST_SATZ", "MWST_SATZ2", "VORGANG_NR", "OBJ_NR", "AUSG", "ETIKETT_1", "ETIKETT_2", "ETIKETT_3", "ETIKETT_4", "ETIKETT_5", "ETIKETT_6", "ETIKETT_7", "ETIKETT_8", "ETIKETT_9", "ETIKETT_10", "LAND_CODE", "UST_ID_NR") AS
  select 	r.rech_nr, r.re_dat, r.adr_gr, r.adr_nr_re, 0, r.fibu_mandant,
	'VZ', r.buch_art||'  ', 1, r.z_bed, r.waehrung,
	abs(r.sum_betr_net),
	abs(r.summwstb1)+abs(r.summwstb2)+abs(r.summwstb3),
	abs(r.sum_betr_br), r.mwst_proz1, r.mwst_proz2,
	0, '   ', '            ', r.anschr1, r.anschr2, r.anschr3,
        r.anschr4, r.anschr5, r.anschr6, r.anschr7, r.anschr8,
        r.anschr9, r.anschr10,
        a.land_code, i.eg_ust_nr
from FAKSTAMM r, AINFO i, ANSCHR a
where r.kopie_nr=0 and r.buch_art = 'S' and
      r.adr_gr = a.adr_gr and r.adr_nr_re = a.adr_nr and
      r.adr_gr = i.adr_gr(+) and r.adr_nr_re = i.adr_nr(+)
union
select 	r.rech_nr, r.re_dat, r.adr_gr, r.adr_nr_re, 0, r.fibu_mandant,
	'VZ', r.buch_art||'  ', -1, r.z_bed, r.waehrung,
	abs(r.sum_betr_net),
	abs(r.summwstb1)+abs(r.summwstb2)+abs(r.summwstb3),
	abs(r.sum_betr_br), r.mwst_proz1, r.mwst_proz2,
	0, '   ', '            ', r.anschr1, r.anschr2, r.anschr3,
        r.anschr4, r.anschr5, r.anschr6, r.anschr7, r.anschr8,
        r.anschr9, r.anschr10,
        a.land_code, i.eg_ust_nr
from FAKSTAMM r, AINFO i, ANSCHR a
where r.kopie_nr=0 and r.buch_art = 'H' and
      r.adr_gr = a.adr_gr and r.adr_nr_re = a.adr_nr and
      r.adr_gr = i.adr_gr(+) and r.adr_nr_re = i.adr_nr(+)
union
select 	r.rech_nr, r.rech_dat, r.adr_gr, r.adr_nr_e, 0, r.f_mandant,
	'BU', r.rech_typ||' ', 1, r.zahlbed, r.waehrung,
	r.re_netto, r.re_mwst, r.re_brutto, r.mw_proz_1, r.mw_proz_2,
	0, '   ', '            ', r.eti_1_e, r.eti_2_e, r.eti_3_e,
        r.eti_4_e, r.eti_5_e, r.eti_6_e, r.eti_7_e, r.eti_8_e,
        r.eti_9_e, r.eti_10_e,
        a.land_code, i.eg_ust_nr
from BUFAKST r, AINFO i, ANSCHR a
where r.rech_typ like 'R%' and
      r.adr_gr = a.adr_gr and r.adr_nr_e = a.adr_nr and
      r.adr_gr = i.adr_gr(+) and r.adr_nr_e = i.adr_nr(+)
      and not (r.rech_typ = 'RO' and r.r_art = 'P')
union
select 	r.rech_nr, r.rech_dat, r.adr_gr, r.adr_nr_e, 0, r.f_mandant,
	'BU', r.rech_typ||' ', -1, r.zahlbed, r.waehrung,
	r.re_netto, r.re_mwst, r.re_brutto, r.mw_proz_1, r.mw_proz_2,
	0, '   ', '            ', r.eti_1_e, r.eti_2_e, r.eti_3_e,
        r.eti_4_e, r.eti_5_e, r.eti_6_e, r.eti_7_e, r.eti_8_e,
        r.eti_9_e, r.eti_10_e,
        a.land_code, i.eg_ust_nr
from BUFAKST r, AINFO i, ANSCHR a
where r.rech_typ like 'G%' and
      r.adr_gr = a.adr_gr and r.adr_nr_e = a.adr_nr and
      r.adr_gr = i.adr_gr(+) and r.adr_nr_e = i.adr_nr(+)
union
select 	r.rech_nr, r.rech_datum, r.adr_gr, r.rech_empf, r.adr_nr, r.f_mandant,
	'EA', r.rech_typ, r.vorzeichen, r.z_bed_id, r.waehrung,
	r.wa_netto_betrag, r.mwst_betrag, r.rech_betrag, r.mwst_satz, 0,
	0, r.obj_nr, r.ausg||'          ', r.adresse_1, r.adresse_2, r.adresse_3,
        r.adresse_4, r.adresse_5, r.adresse_6, r.adresse_7, r.adresse_8,
        '                                        ',
        '                                        ',
        a.land_code, i.eg_ust_nr
from RECHNUNG r, AINFO i, ANSCHR a
where r.adr_gr = a.adr_gr and r.rech_empf = a.adr_nr and
      r.adr_gr = i.adr_gr(+) and r.rech_empf = i.adr_nr(+);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."REDZRVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "ADR_NR_RECH", "PERSON_NR_RECH", "ADR_NR_LIEF", "PERSON_NR_LIEF", "BEREICH", "VORG_TYP", "VORGANG", "MANDANT", "REF_NR", "TYP", "STATUS", "KZ_STORNO", "OBJ_NR", "AUSG", "WAEHRUNG", "NETTO_BETRAG", "MENGE", "RECH_ART", "BESTELL_DATUM", "LAUFZEIT_VON", "LAUFZEIT_BIS", "TEXT", "HNR_NUM", "HNR_NUM_BIS", "DATUM_NEU", "B_ID_NEU", "DATUM_AEND", "B_ID_AEND", "ATTR_1", "ATTR_2", "ATTR_3", "ATTR_4", "ATTR_5") AS
  select  d.adr_gr, d.adr_nr, 0,
	0, 0, 0, 0,
	'RD', 'REDKT', 'REDKT',
	d.e_mandant, d.lfd_nr*(-1), ' ', '         ', ' ',
	d.obj_nr, d.ausg||'          ', '   ', 0, 1,
	'  ', d.datum_neu, d.datum_neu, d.datum_neu,
	d.stichwort1,
	d.hnr_num, d.hnr_num,
	d.datum_neu, d.b_id_neu, d.datum_aend, d.b_id_aend,
	'', '', d.art, d.seite, 0
from RDKTVER d
union
select  t.adr_gr, t.adr_nr, t.person_nr,
	d.lfd_nr, t.lfd_nr, d.adr_nr, 0,
	'RD', 'REDKT', 'REDZB',
	d.e_mandant, d.beitrag_nr*(-1), ' ', '         ', ' ',
	d.obj_nr, d.ausg||'          ', '   ', 0, 1,
	'  ', d.datum_neu, d.datum_neu, d.datum_neu,
	d.stichwort1,
	d.hnr_num, d.hnr_num,
	d.datum_neu, d.b_id_neu, d.datum_aend, d.b_id_aend,
	'', '', d.art, d.seite, 0
from ZRBETEIL t, RDKTVER d
where t.beitrag_nr = d.beitrag_nr
and t.beteil_typ = 'BELEG'
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."REKLVIEW" ("ERFASSER_ID", "DATUM_AKT", "LFD_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "VERFASSER_ID", "BETREFF", "DATUM_BES", "TEXT_NR", "DATUM_WV_VERF", "REKLAGRUND", "STATUS", "DATUM_ZWI", "DATUM_ERLED", "KOSTEN", "EINGANGS_ART", "REAKTIONS_ID", "VORGANG_TYP", "VORGANG_KEY", "VORGANG_NR", "POS_NR", "E_MANDANT", "ARTIKEL_NR", "AUFLAGE_NR", "VERLAGS_ID") AS
  SELECT  r.erfasser_id, r.datum_akt, r.lfd_nr, b.adr_gr, b.adr_nr,
                     b.person_nr, b.verfasser_id, b.betreff, b.datum_bes, b.text_nr,
                     s.datum_wv, r.reklagrund, r.status, r.datum_zwi, r.datum_erled,
                     r.kosten, r.eingangs_art, r.reaktions_id, r.vorgang_typ, r.vorgang_key,
                     r.vorgang_nr, p.pos_nr, p.e_mandant, p.artikel_nr, p.auflage_nr, p.verlags_id
FROM bericht b LEFT OUTER JOIN briefkas s ON
      b.erfasser_id  = s.erfasser_id and
      b.datum_akt    = s.datum_akt and
      b.lfd_nr       = s.lfd_nr and
      b.verfasser_id = s.benutzer_id
      , REKLA r LEFT OUTER JOIN REKLAPOS P ON
           r.erfasser_id  = p.erfasser_id and
           r.datum_akt    = p.datum_akt and
           r.lfd_nr       = p.lfd_nr
WHERE r.erfasser_id = b.erfasser_id and
               r.datum_akt = b.datum_akt and
               r.lfd_nr = b.lfd_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."RELATEDPRODUCTS" ("L_TITEL_NR", "L_AUSG_NR_1", "EAN1", "PROD_TYP_1", "AUSG_TEXT_1", "L_AUSG_NR_2", "EAN2", "PROD_TYP_2", "AUSG_TEXT_2") AS
  select
b1.l_titel_nr, b1.l_ausg_nr, b1.ean, b1.prod_typ,b1.ausg_text,
b2.l_ausg_nr, b2.ean, b2.prod_typ,b2.ausg_text
from buausgab b1, buausgab b2
where b1.l_titel_nr = b2.l_titel_nr
and b1.l_ausg_nr != b2.l_ausg_nr
and b1.l_titel_nr != 0
and b1.herkunft is null;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."RESPVIEW" ("E_MANDANT", "AKT_ID", "UAKT_ID", "KZ_EF", "BEZ_1", "ER_CODE", "F_UAKT_ID", "BEZ_2") AS
  select
a.e_mandant, a.akt_id, a.uakt_id, a.kz_ef, a.b_uaktid, b.er_code, b.f_uakt_id, c.b_uaktid
from  muaktion a
  LEFT OUTER JOIN respvorg b ON
     b.akt_id = a.akt_id and
     b.uakt_id = a.uakt_id
     left outer join muaktion c on
       c.akt_id = b.akt_id and
       c.uakt_id = b.f_uakt_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."RTV_ELO_AUFTRAG" ("adr_nr", "auft_nr", "dispo_nr", "dispo_status", "rech_nr", "versand_auftrag", "versand_rechnung", "anzeigen_preis", "anzeigen_betrag", "netto_betrag") AS
  SELECT
  trim(auftrag.adr_nr) AS "adr_nr",
  trim(dispo.auft_nr) AS "auft_nr",
  trim(dispo.dispo_nr) AS "dispo_nr",
  trim(dispo.status) AS "dispo_status",
  trim(dispo.rech_nr) AS "rech_nr",
  trim(apostweg_auftrag.versandart) AS "versand_auftrag",
  trim(apostweg_rechnung.versandart) AS "versand_rechnung",
  trim(dispo.anzeigen_preis) AS "anzeigen_preis",
  trim(dispo.anzeigen_betrag) AS "anzeigen_betrag",
  trim(dispo.netto_betrag) AS "netto_betrag"
FROM auftrag
INNER JOIN dispo
  ON auftrag.adr_gr = dispo.adr_gr
  AND auftrag.adr_nr = dispo.adr_nr
  AND auftrag.auft_nr = dispo.auft_nr
  AND auftrag.auft_hist_nr = dispo.auft_hist_nr
LEFT JOIN apostweg apostweg_auftrag
  ON auftrag.adr_gr = apostweg_auftrag.adr_gr
  AND auftrag.adr_nr = apostweg_auftrag.adr_nr
  AND auftrag.auft_nr = apostweg_auftrag.auft_nr
  AND auftrag.auft_hist_nr = apostweg_auftrag.auft_hist_nr
  AND apostweg_auftrag.belegart_id = 'A'
LEFT JOIN apostweg apostweg_rechnung
  ON auftrag.adr_gr = apostweg_rechnung.adr_gr
  AND auftrag.adr_nr = apostweg_rechnung.adr_nr
  AND auftrag.auft_nr = apostweg_rechnung.auft_nr
  AND auftrag.auft_hist_nr = apostweg_rechnung.auft_hist_nr
  AND apostweg_rechnung.belegart_id = 'R'
WHERE auftrag.auft_hist_nr = 0
AND dispo.dispo_hist_nr = 0
AND auftrag.adr_gr = 'DSV';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."RTV_ELO_KUNDE" ("adr_nr", "name1", "name2", "name3", "land_code", "land", "plz_wohn", "wohnort", "email_auftrag", "email_rechnung", "bezirk_id", "bezirk", "firmkz_id", "firmenkennzeichnung", "verlber_id", "branche") AS
  SELECT
  trim(anschr.adr_nr) AS "adr_nr",
  trim(anschr.name1) AS "name1",
  trim(anschr.name2) AS "name2",
  trim(anschr.name3) AS "name3",
  trim(anschr.land_code) AS "land_code",
  trim(land.land) AS "land",
  trim(anschr.plz_wohn) AS "plz_wohn",
  trim(anschr.wohnort) AS "wohnort",
  trim(telecom_ema.nummer) as "email_auftrag",
  trim(telecom_emr.nummer) as "email_rechnung",
  trim(anschr.bezirk_id) as "bezirk_id",
  trim(bezirk.bezirk) as "bezirk",
  trim(anschr.firmkz_id) as "firmkz_id",
  trim(firmkz.bez) as "firmenkennzeichnung",
  trim(anschr.verlber_id) as "verlber_id",
  trim(verlber.beschreibung) as "branche"
FROM anschr
LEFT JOIN telecom telecom_emr
  ON anschr.adr_gr = telecom_emr.adr_gr
  AND anschr.adr_nr = telecom_emr.adr_nr
  AND telecom_emr.person_nr = 0
  AND telecom_emr.tel_art = 'EMR'
LEFT JOIN telecom telecom_ema
  ON anschr.adr_gr = telecom_ema.adr_gr
  AND anschr.adr_nr = telecom_ema.adr_nr
  AND telecom_ema.person_nr = 0
  AND telecom_ema.tel_art = 'EMA'
LEFT JOIN land
  ON anschr.land_code = land.land_code
LEFT JOIN bezirk
  ON anschr.bezirk_id = bezirk.bezirk_id
  AND anschr.adr_gr = bezirk.adr_gr
LEFT JOIN firmkz
  ON anschr.firmkz_id = firmkz.firmkz_id
LEFT JOIN verlber
  ON anschr.verlber_id = verlber.verlber_id
WHERE anschr.adr_gr = 'DSV';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."RTV_ELO_LEADS" ("ADR_NR", "LEAD_JAHR", "LEAD_TYP", "LEAD_INAKTIV", "NEU_AM", "AEND_AM", "AEND_ZEIT") AS
  SELECT
  trim(qwerte.adr_nr)       AS "ADR_NR",
  trim(qwerte.q_code)       AS "LEAD_JAHR",
  trim(qwerte.q_ausp_code)  AS "LEAD_TYP",
  trim(qwerte.status     )  AS "LEAD_INAKTIV", --IN=INaktiv, null sonst
  qwerte.datum_neu    AS "NEU_AM",
  qwerte.datum_aend   AS "AEND_AM",
  qwerte.zeit_aend    AS "AEND_ZEIT"
FROM  qwerte
WHERE q_code like 'LEAD%'
AND qwerte.adr_gr = 'DSV'
AND qwerte.person_nr = 0;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SAPCVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "PLZ_WOHN", "PLZ_POST", "LAND_CODE", "F_TYP", "FIRMKZ_ID", "WOHNORT", "KZ_LOESCHEN", "A_TYP", "NACHNAME", "VORNAME", "TITEL_CODE", "ANREDE_CODE", "ANZ_AUFT", "ANZ_ABO", "TEL_ZENTRALE") AS
  SELECT a.adr_gr, a.adr_nr, p.person_nr, a.haupt_name, a.haupt_plz, a.haupt_ort,
       a.name1, a.name2, a.plz_wohn, a.plz_post, a.land_code, a.f_typ, a.firmkz_id,
       a.wohnort,p.kz_loeschen, p.a_typ, p.nachname, p.vorname, p.titel_code, p.anrede_code,
       -1, -1, '                                                            '
FROM   anschr a, person p
WHERE  a.adr_gr        = p.adr_gr
AND    a.adr_nr        = p.adr_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SAPIVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "Q_CODE", "Q_AUSP_CODE", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "NAME3", "PLZ_WOHN", "PLZ_POST", "PLZ_GK", "WOHNORT", "POSTORT", "GKORT", "STRASSE", "STRASSE2", "HAUSNR", "HAUSNR_ZUS", "POSTFACH", "LAND_CODE", "AQUELL_CODE", "A_TYP", "SPRACH_CODE", "ANREDE_CODE", "TITEL_CODE", "NACHNAME", "VORNAME", "N_ZUSATZ", "ABTEILUNG", "ETIKETTART", "KZ_LOESCHEN", "B_ID_NEU", "DATUM_NEU", "B_ID_AEND", "DATUM_AEND", "DATUM_UEB", "B_ID_UEB", "EG_UST_NR", "VERB_CODE", "WSPERR_CODE", "ASPERR_CODE", "GENFILT_ID", "BAG_NR") AS
  SELECT a.adr_gr,a.adr_nr,p.person_nr,q.q_code,q.q_ausp_code,
       a.haupt_name,a.haupt_plz,a.haupt_ort,
       a.name1,a.name2,a.name3,a.plz_wohn,a.plz_post,a.plz_gk,
       a.wohnort,a.postort,a.gkort,a.strasse,a.strasse2,a.hausnr,a.hausnr_zus,
       a.postfach,a.land_code,a.aquell_code,
       p.a_typ,p.sprach_code,p.anrede_code,p.titel_code,
       p.nachname,p.vorname,p.n_zusatz,p.abteilung,p.etikettart,p.kz_loeschen,
       p.b_id_neu,p.datum_neu,p.b_id_aend,p.datum_aend,
       p.datum_ueb,p.b_id_ueb,i.eg_ust_nr,i.verb_code,
       i.wsperr_code,i.asperr_code, a.genfilt_id,i.bag_nr
FROM   anschr a  LEFT OUTER JOIN ainfo i ON
       a.adr_gr = i.adr_gr AND  a.adr_nr    = i.adr_nr,
       person p LEFT OUTER JOIN qwerte q ON
       p.adr_gr  = q.adr_gr AND p.adr_nr = q.adr_nr AND p.person_nr = q.person_nr
WHERE  p.adr_gr  = a.adr_gr
AND    p.adr_nr  = a.adr_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SAPNVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "PLZ_WOHN", "STRASSE", "HAUSNR", "STRASSE2", "HAUSNR_ZUS", "PLZ_POST", "POSTFACH", "POSTORT", "LAND_CODE", "F_TYP", "FIRMKZ_ID", "GENFILT_ID", "WOHNORT", "BEZIRK_ID", "KZ_LOESCHEN", "A_TYP", "NACHNAME", "VORNAME", "N_ZUSATZ", "TITEL_CODE", "ANREDE_CODE", "PRIVAT_ADR_NR", "ANZ_AUFT", "ANZ_FLIESS", "ANZ_ABO", "ANZ_BUCH", "AQUELL_CODE", "ABTEILUNG", "KZ_DUBL", "PLZ_GK", "GKORT", "NAME3", "KONZERN_ID", "VERLBER_ID", "KGS_BL", "NIELSEN_ID", "SPRACH_CODE", "POSITION", "BEMERKUNG", "VERSAND_ADR") AS
