  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SAPVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "NAME3", "PLZ_WOHN", "PLZ_POST", "PLZ_GK", "WOHNORT", "POSTORT", "GKORT", "STRASSE", "STRASSE2", "HAUSNR", "HAUSNR_ZUS", "POSTFACH", "LAND_CODE", "AQUELL_CODE", "F_TYP", "A_TYP", "SPRACH_CODE", "ANREDE_CODE", "TITEL_CODE", "NACHNAME", "VORNAME", "N_ZUSATZ", "ABTEILUNG", "POSITION", "ETIKETTART", "KZ_LOESCHEN", "KZ_KEIN_MAIL", "B_ID_NEU", "DATUM_NEU", "B_ID_AEND", "DATUM_AEND", "DATUM_UEB", "B_ID_UEB", "KZ_DUBL") AS
