  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SAPWVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "HAUPT_PLZ", "HAUPT_ORT", "NAME1", "NAME2", "NAME3", "PLZ_WOHN", "PLZ_POST", "PLZ_GK", "WOHNORT", "POSTORT", "GKORT", "STRASSE", "STRASSE2", "HAUSNR", "HAUSNR_ZUS", "POSTFACH", "LAND_CODE", "AQUELL_CODE", "F_TYP", "A_TYP", "SPRACH_CODE", "ANREDE_CODE", "TITEL_CODE", "NACHNAME", "VORNAME", "N_ZUSATZ", "ABTEILUNG", "POSITION", "ETIKETTART", "KZ_LOESCHEN", "KZ_KEIN_MAIL", "B_ID_NEU", "DATUM_NEU", "B_ID_AEND", "DATUM_AEND", "DATUM_UEB", "B_ID_UEB", "KZ_DUBL", "AKT_ID", "UAKT_ID", "IN_OUT") AS
  SELECT w.adr_gr,w.adr_nr,w.person_nr,a.haupt_name,a.haupt_plz,a.haupt_ort,
       a.name1,a.name2,a.name3,a.plz_wohn,a.plz_post,a.plz_gk,
       a.wohnort,a.postort,a.gkort,a.strasse,a.strasse2,a.hausnr,a.hausnr_zus,
       a.postfach,a.land_code,a.aquell_code,a.f_typ,
       p.a_typ,p.sprach_code,p.anrede_code,p.titel_code,
       p.nachname,p.vorname,p.n_zusatz,p.abteilung,p.position,
       p.etikettart,p.kz_loeschen,p.kz_kein_mail,
       p.b_id_neu,p.datum_neu,p.b_id_aend,p.datum_aend,
       p.datum_ueb,p.b_id_ueb,a.kz_dubl,w.akt_id,w.uakt_id,w.in_out
FROM   anschr a, person p, werbehis w
WHERE  p.adr_gr    = a.adr_gr
AND    p.adr_nr    = a.adr_nr
and    p.adr_gr    = w.adr_gr
and    p.adr_nr    = w.adr_nr
and    p.person_nr = w.person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SELASPVI" ("ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "TABNAME", "ASPERR_CODE", "ASPERR_VON", "ASPERR_BIS") AS
  select b.adr_gr, b.adr_nr, 0, b.e_mandant, 'BUKUNDEN',
       b.asperr_code||' ', to_date('01.01.1900'), to_date('31.12.2099')
from bukunden b
union
select p.adr_gr, p.adr_nr, p.person_nr, 'P_', 'PERSON',
       p.sperrgrund, to_date('01.01.1900'), to_date('31.12.2099')
from person p
union
select a.adr_gr, a.adr_nr, 0, 'A_', 'AINFO',
       a.asperr_code||' ', a.abosperr_von, a.abosperr_bis
from ainfo a;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SELMODVI" ("BENUTZER_ID", "SEL_ID", "WAKT", "TABNAME_VORS", "FELDNAME_VORS", "TABNAME_FILT", "FELDNAME_FILT", "MODUL") AS
  select s.benutzer_id, s.sel_id, s.wakt,
	v.tabellenname, v.feldname,
	f.tabellenname, f.feldname, f.modul
from SELVERWA s, SVORSCHR v LEFT OUTER JOIN SELFILT f ON
		v.tabellenname = f.tabellenname
		and v.feldname = f.feldname
where s.benutzer_id = v.benutzer_id
and   s.sel_id = v.sel_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SELMPVIE" ("BENUTZER_ID", "SEL_ID", "ADR_GR", "ADR_NR", "PERSON_NR", "VERWEIS_NR", "A_TYP", "BENUTZER_ID_REF", "SEL_ID_REF", "ADR_GR_REF", "ADR_NR_REF", "PERSON_NR_REF", "VERWEIS_NR_REF", "A_TYP_REF", "VERGLEICH") AS
  select s.benutzer_id, s.sel_id, s.adr_gr, s.adr_nr, s.person_nr, s.verweis_nr, s.a_typ,
          r.benutzer_id, r.sel_id, r.adr_gr, r.adr_nr, r.person_nr, r.verweis_nr, r.a_typ,
          s.adr_gr||s.adr_nr||s.person_nr
from   selpool s, person p, selpool r
where  s.adr_gr = p.adr_gr and s.adr_nr = p.adr_nr and s.person_nr = p.person_nr and
       r.adr_gr = s.adr_gr and r.adr_nr = p.privat_adr_nr and r.person_nr = 0
union
select s.benutzer_id, s.sel_id, s.adr_gr, s.adr_nr, s.person_nr, s.verweis_nr, s.a_typ,
          r.benutzer_id, r.sel_id, r.adr_gr, r.adr_nr, r.person_nr, r.verweis_nr, r.a_typ,
          r.adr_gr||r.adr_nr||r.person_nr
from   selpool s, person p, selpool r
where  s.adr_gr = p.adr_gr and s.adr_nr = p.privat_adr_nr and p.person_nr > 0 and
       r.adr_gr = s.adr_gr and r.adr_nr = p.adr_nr and r.person_nr = p.person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SELPHVIE" ("BENUTZER_ID", "SEL_ID", "ADR_GR", "ADR_NR", "PERSON_NR", "VERWEIS_NR", "VERWEND_TYP", "A_TYP", "ANREDE_CODE", "VORNAME", "NACHNAME", "FIRMA", "HAUPT_NAME", "LAND_CODE", "PLZ", "ORT", "STRASSE", "HAUSNR", "STRASSE_HNR", "ABTEILUNG") AS
  select
s.benutzer_id, s.sel_id, s.adr_gr, s.adr_nr, s.person_nr, s.verweis_nr,
p.verwend_typ, p.a_typ, p.anrede_code, p.vorname, p.nachname, p.firma, p.haupt_name,
p.land_code, p.plz, p.ort, p.strasse, p.hausnr, p.strasse_hnr, p.abteilung
from selpool s, phoncd2 p
where
s.adr_gr = p.adr_gr and
s.adr_nr = p.adr_nr and
s.person_nr = p.person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SELVIEW" ("BENUTZER_ID", "SEL_ID", "ADR_GR", "ADR_NR", "PERSON_NR", "VERWEIS_NR", "A_TYP", "HAUPT_NAME", "HAUPT_ORT", "HAUPT_PLZ", "NAME1", "NAME2", "NAME3", "PLZ_WOHN", "PLZ_POST", "PLZ_GK", "WOHNORT", "POSTORT", "GKORT", "STRASSE", "STRASSE2", "HAUSNR", "HAUSNR_ZUS", "POSTFACH", "VERSAND_ADR", "LAND_CODE", "BEZIRK_ID", "FIRMKZ_ID", "BRIEFTEXT", "F_TYP", "GENFILT_ID", "KONZERN_ID", "SPRACH_CODE", "ANREDE_CODE", "TITEL_CODE", "NACHNAME", "VORNAME", "PRIVAT_ADR_NR", "KZ_ABTEILUNG", "ABTEILUNG", "KZ_POSITION", "POSITION", "PF_TEXT", "LAND_KURZ", "LAND", "GEB_DAT", "ETIKETTART", "KZ_PERSFIRM", "ABW_BRIEF_ANR") AS
  select s.benutzer_id, s.sel_id, s.adr_gr, s.adr_nr, s.person_nr, s.verweis_nr, s.a_typ,
       a.haupt_name, a.haupt_ort, a.haupt_plz, a.name1, a.name2, a.name3,
       a.plz_wohn, a.plz_post, a.plz_gk, a.wohnort, a.postort, a.gkort, a.strasse, a.strasse2,
       a.hausnr, a.hausnr_zus, a.postfach, a.versand_adr,
       a.land_code, a.bezirk_id, a.firmkz_id, a.brieftext, a.f_typ, a.genfilt_id, a.konzern_id,
       p.sprach_code, p.anrede_code, p.titel_code, p.nachname, p.vorname, p.privat_adr_nr,
       p.kz_abteilung, p.abteilung, p.kz_position, p.position,
       l.pf_text, l.land_kurz, l.land, p.geb_dat, p.etikettart, p.kz_persfirm, p.abw_brief_anr
from   selpool s, anschr a LEFT OUTER JOIN land l ON
	a.land_code = l.land_code,
       person p
where  s.adr_gr = a.adr_gr and s.adr_nr = a.adr_nr and
       s.adr_gr = p.adr_gr and s.adr_nr = p.adr_nr and s.person_nr = p.person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_ADRESSEN" ("ADR_GR", "ADR_NR", "PERSON_NR", "LEKTORAT", "ADRESS_TYP", "VORNAME", "NACHNAME", "NAME1", "NAME2", "NAME3", "ANREDE_CODE", "ANREDE_ETIKETT", "TITEL_CODE", "TITEL_ETIKETT", "LAND_CODE", "PLZ", "ORT", "STRASSE", "DATUM_AEND") AS
  select
p.adr_gr, p.adr_nr, p.person_nr,
ql.q_ausp_code, 'A',
p.vorname, p.nachname,
a.name1, a.name2, a.name3,
p.anrede_code, ar.etikett, p.titel_code, ti.titel_etikett,
a.land_code, a.haupt_plz, a.haupt_ort, a.strasse,
greatest((coalesce (p.datum_aend, p.datum_neu)),(coalesce (ql.datum_aend, ql.datum_neu)))
from ANSCHR a, PERSON p, QWERTE ql, ANREDE ar, TITEL ti
where
a.adr_gr = p.adr_gr and a.adr_nr = p.adr_nr and
ql.adr_gr(+) = p.adr_gr and ql.adr_nr(+) = p.adr_nr and ql.person_nr(+) = p.person_nr and ql.q_code(+) = 'LEKTORAT' and
ar.anrede_code(+) = p.anrede_code and ar.sprach_code(+) = 'D' and
ti.titel_code(+) = p.titel_code and
exists (select * from buautor b where p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr_aut and p.person_nr = b.person_nr_aut)
UNION
select
p.adr_gr, p.adr_nr, p.person_nr,
null, 'D',
p.vorname, p.nachname,
a.name1, a.name2, a.name3,
p.anrede_code, ar.etikett, p.titel_code, ti.titel_etikett,
a.land_code, a.haupt_plz, a.haupt_ort, a.strasse,
coalesce (p.datum_aend, p.datum_neu)
from ANSCHR a, PERSON p,  ANREDE ar, TITEL ti
where
a.adr_gr = p.adr_gr and a.adr_nr = p.adr_nr and p.person_nr = 0 and
ar.anrede_code(+) = p.anrede_code and ar.sprach_code(+) = 'D' and
ti.titel_code(+) = p.titel_code and
exists (select * from buaufdru b where p.adr_gr = b.adr_gr and p.adr_nr = b.adr_nr)
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_EMAILADRESSEN" ("ADR_GR", "ADR_NR", "PERSON_NR", "TEL_ART", "EMAIL") AS
  select
distinct a.adr_gr, a.adr_nr, a.person_nr, t.tel_art, t.nummer
from sf_adressen a, teleview t
where a.adr_gr = t.adr_gr
and a.adr_nr = t.adr_nr
and a.person_nr = t.person_nr
and (t.verw_id = 'I' or t.verw_id = 'E')
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_KATEGORIEN" ("HGRP_ID", "UGRP_ID", "UGRP_BEZ") AS
  select
hgrp_id, ugrp_id, bez from ugruppe
where wb_id = 'WK'
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_KEINAUTOR" ("L_AUSG_NR", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR") AS
  select
a.l_ausg_nr, null, decode(t.rank_id,null,'0',t.rank_id)
from buausgab a, butitel t
where
a.l_titel_nr = t.l_titel_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_KOMBI" ("E_MANDANT", "L_AUSG_NR", "U_AUSG_NR_1", "U_AUSG_NR_2") AS
  select
a.e_mandant, a.l_ausg_nr,
(select u_ausg_nr from bukombi k
where k.l_ausg_nr = a.l_ausg_nr
and
((case when k.sortierung > 0
then k.sortierung
else k.u_ausg_nr
end) ) =
(select min((case when b.sortierung > 0
                  then b.sortierung
                  else b.u_ausg_nr
        end) ) from bukombi b where b.l_ausg_nr = a.l_ausg_nr)
),
(select u_ausg_nr from bukombi k
where k.l_ausg_nr = a.l_ausg_nr
and
((case when k.sortierung > 0
then k.sortierung
else k.u_ausg_nr
end) ) =
(select max((case when b.sortierung > 0
                  then b.sortierung
                  else b.u_ausg_nr
        end) ) from bukombi b where b.l_ausg_nr = a.l_ausg_nr)
)
from bumankom a;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_LEKTOR" ("L_TITEL_NR", "LEKTOR_ID", "BENUTZER_ID") AS
  select t.l_titel_nr, tl.lektor_id,l.benutzer_id
from butitel t, butitlek tl, bulektor l
where
t.l_titel_nr = tl.l_titel_nr and
tl.lektor_id = l.lektor_id and
tl.kz_haupt_lektor = 'T'
union
select t.l_titel_nr, tl.lektor_id, l.benutzer_id
from butitel t, butitlek tl, bulektor l
where
t.l_titel_nr = tl.l_titel_nr and
tl.lektor_id = l.lektor_id and
(select count(*) from butitlek tl2 where tl2.l_titel_nr = t.l_titel_nr) = 1 and
not exists
(select * from butitlek tl3 where t.l_titel_nr = tl3.l_titel_nr and tl3.kz_haupt_lektor ='T');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_MANDANT" ("E_MANDANT") AS
  select e_mandant from bmandant where e_mandant = 'VB';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_OHNEPREIS" ("L_AUSG_NR", "UNPRICEDITEMTYPE") AS
  select
m.l_ausg_nr , '02' UnpricedItemType
from bumanaus m, SF_mandant om
where
not exists
(select * from SF_preisliste o
where o.l_ausg_nr = m.l_ausg_nr)
and m.e_mandant = om.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PREISLAND" ("LIST_NR", "LAND_CODE", "LAND") AS
  select
p.list_nr,
(case when waehrung='OEU' then 'A'
      else
       (case when waehrung='SFR' then 'CH' else 'D' end)
 end) ,
(case when waehrung='OEU' then 'Osterreich'
      else
       (case when waehrung='SFR' then 'Schweiz' else 'Deutschland' end)
 end)
from buplist p where waehrung in ('EUR','OEU','SFR')
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PREISLISTE" ("LIST_NR", "L_AUSG_NR", "PREISKAT", "PREISKAT_LAND", "WAEHRUNG", "GUELTIG_AB", "SUBS_DAT1", "PREIS", "AEND_DAT", "LAND", "ANZAHL", "MENGE", "LAND_CODE", "GUELTIG_BIS") AS
  select
l.list_nr,l.l_ausg_nr, preiskat, trim(l.preiskat)||'-'||opl.land, l.waehrung,
to_char(l.gueltig_ab, 'YYYYMMDD'), to_char(l.subs_dat1,'YYYYMMDD'), m.preis, m.aend_dat, opl.land,1, m.menge, opl.land_code,
  to_char((select min(gueltig_ab)-1 from buakview x where
    x.l_ausg_nr = l.l_ausg_nr and
    x.best_art = l.best_art and
    x.preiskat = l.preiskat and
    x.e_mandant = l.e_mandant and
    to_char(x.gueltig_ab, 'YYYYMMDD') > to_char(l.gueltig_ab, 'YYYYMMDD') and
    x.waehrung = l.waehrung),'YYYYMMDD')
from buakview l, bumpreis m, SF_mandant om, SF_preisland opl
where
l.best_art = '1' and
(l.l_aufl_nr = 0 or l.l_aufl_nr is null) and
l.akt_id is null and
l.preiskat in ('CA', 'LP', 'LPA','MIT', 'SER', 'SUB','UVP', 'MP') and
l.list_nr = m.list_nr and
l.e_mandant = om.e_mandant and
exists
(select list_nr from buakview x where
x.l_ausg_nr = l.l_ausg_nr and
x.best_art = l.best_art and
x.preiskat = l.preiskat and
x.e_mandant = l.e_mandant and
to_char(x.gueltig_ab, 'YYYYMMDD') <= to_char(sysdate, 'YYYYMMDD') and
x.waehrung = l.waehrung) and
l.gueltig_ab >=
(select max(gueltig_ab) from buakview x where
x.l_ausg_nr = l.l_ausg_nr and
x.best_art = l.best_art and
x.preiskat = l.preiskat and
x.e_mandant = l.e_mandant and
to_char(x.gueltig_ab, 'YYYYMMDD') <= to_char(sysdate, 'YYYYMMDD') and
x.waehrung = l.waehrung) and
opl.list_nr (+) = l.list_nr
union
select
l.list_nr,l.l_ausg_nr, preiskat, trim(l.preiskat)||'-'||opl.land, l.waehrung,
to_char(l.gueltig_ab, 'YYYYMMDD'), to_char(l.subs_dat1,'YYYYMMDD'), m.preis, m.aend_dat, opl.land, 1, m.menge, opl.land_code, null
 from buakview l, bumpreis m, SF_mandant om, SF_preisland opl
where
l.best_art = '1' and
(l.l_aufl_nr = 0 or l.l_aufl_nr is null)  and
l.akt_id is null and
l.preiskat in ('CA', 'LP', 'LPA','MIT', 'SER', 'SUB','UVP','MP') and
l.list_nr = m.list_nr and
l.e_mandant = om.e_mandant and
not exists
(select list_nr from buakview x where
x.l_ausg_nr = l.l_ausg_nr and
x.best_art = l.best_art and
x.preiskat = l.preiskat and
x.e_mandant = l.e_mandant and
to_char(x.gueltig_ab, 'YYYYMMDD') <= to_char(sysdate, 'YYYYMMDD') and
x.waehrung = l.waehrung)and
l.gueltig_ab =
(select min(gueltig_ab) from buakview x where
x.l_ausg_nr = l.l_ausg_nr and
x.best_art = l.best_art and
x.preiskat = l.preiskat and
x.e_mandant = l.e_mandant and
x.waehrung = l.waehrung) and
opl.list_nr (+) = l.list_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCT" ("RECORDIDENTIFIER", "RECORDREFERENCE", "NOTIFICATIONTYPE", "PUBLISHERORDERID", "PRODUCTISBN13", "PRODUCTEAN", "L_AUSG_NR", "IDEEN_NR", "VLB_REIHE", "KOH_REIHE", "OBJ_NR", "BARCODE", "PRODUCTFORM", "PRODUCTFORMDETAIL", "AUSLEITUNG", "DISTINCTIVETITLE", "SUBTITLE", "ORIGINALTITLE", "ORIGINALSUBTITLE", "EDITIONNUMBER", "EDITIONSTATEMENT", "NOEDITION", "LANGUAGEOFTEXT", "ORIGINALLANGUAGE", "NUMBEROFPAGES", "PAGESROMAN", "PAGESARABIC", "ILLUSTRATIONSNOTE", "CASEITEN", "PUBLISHERCODE", "PUBLISHERNAME", "PUBLISHINGSTATUS", "PUBLISHINGSTATUSNOTE", "MELDETEXT", "PUBLICATIONDATEYEAR", "PUBLICATIONDATEMONTH", "PUBLICATIONDATEDAY", "PRODUCTHEIGHT", "PRODUCTWIDTH", "PRODUCTTHICKNESS", "PRODUCTWEIGHT", "REPLACESISBN", "REPLACEDBYISBN", "PRODUCTAVAILABILITY", "EXPECTEDSHIPDATEYEAR", "EXPECTEDSHIPDATEMONTH", "EXPECTEDSHIPDATEDAY", "ONSALEDATE", "LASTCHANGE", "INVORSCHAU", "ERSCHEINUNG", "VLBSCHEMENEW", "VORAUSSICHT_ERSCH_DATUM", "QUARTAL_MONAT", "INDEX_VLB", "PRODUKTTYP", "GESAMTBESTAND", "PREISBIND", "SPERRKZ", "KDSTAFRAB", "MWST", "HEFTNUMMER", "JAHRGANG", "JAHRZAEHL", "NOCONTRIBUTOR", "GRUP_ID", "BEIWERK_1", "BEIWERK_2", "BEIWERK_3", "BEIWERK_4", "DOI", "PRODUCTLINK", "BENUTZER_ID_LEKTOR", "KZ_BASIS_BAND", "STAND", "DRUCKAUFLAGE", "VERKAUFSAUFLAGE", "PRODUCTCLASSIFICATIONCODE", "PRODUCTCLASSIFICATIONTYPE", "EXTENTVALUE", "EXTENTTYPE", "EXTENTUNIT", "COUNTRYOFFINALMANUFACTURE", "TEXTTYPECODE", "SEITEN_VON", "SEITEN_BIS", "RPV_EBSICHTBAR", "PV_EBSICHTBAR", "SATZANWEISUNG", "BARFR") AS
  select
trim(m.artikel_nr), decode(a.ean, null, a.band_nr, a.ean), '03', trim(m.artikel_nr), a.isbn, decode(a.ean, null, a.band_nr, a.ean), a.l_ausg_nr,a.ideen_nr,
trim(qVLBR.qaus),
(case when a.kombityp = 'R' then trim(m.artikel_nr) else null end),
trim(ivw.obj_nr),
trim(q1.qaus),
(select trim(bxr.onix) from buoxref bxr where bxr.typ='MEDIENTYP' and bxr.cover_1=h.einbandart and bxr.cover_2 = '0' and bxr.cover_3 = '0'),
(select trim(bxr.onix) from buoxref bxr where bxr.typ='EINBANDART' and bxr.cover_1=h.einbandart and bxr.cover_2 = '0' and bxr.cover_3 = '0'),
(select trim(bxr.onix) from buoxref bxr where bxr.typ='AUSLEITUNG' and bxr.cover_1=a.prod_typ and bxr.cover_2 = '0' and bxr.cover_3 = '0'),
trim(t.titel1), trim(t.titel_unter),
trim(t.orig_titel), trim(t.orig_u_titel),
b1.bestuhlung, trim(b0.aufl_text),
(case when b0.auflage_nr is null and b0.aufl_text is null then 1 else 0 end),
trim(t.sprach_code), trim(t.org_spr_code),
trim(h.bibl_seiten_arab), trim(h.seiten_roem),trim(h.bibl_seiten_roem), trim(h.abbildung), trim(h.ca_seiten_2),
decode(a.verlags_id, null, null, (decode(trim(bv.verkehrs_nr), null,
'05/'||trim(bv.kenn_nr), '04/'||trim(substr(bv.verkehrs_nr,1,5))))), decode(a.verlags_id,
null, null,trim(bv.verlag_lang)),
 trim(b0.status), trim(b0.meld_nr), trim(b0.meld_text),
b0.ist_jahr, b0.ist_monat, b0.ist_tag,
decode(round((a.hoehe * 10), 0),0,null,round((a.hoehe * 10), 0)),
decode(round((a.breite * 10),0),0,null,round((a.breite * 10),0)), decode(round((a.dicke *
10),0),0,null,round((a.dicke * 10),0)), decode(a.gewicht,0,null,a.gewicht),
a2.isbn, a3.isbn,
trim(b0.meld_nr), b0.soll_jahr, b0.soll_monat, b0.soll_tag,
'        ',
b0.datum_aend,
trim(q4.qaus),
(case when b0.aufl_dat_ist is not null
      then to_char(b0.aufl_dat_ist,'DD.MM.YYYY')
 else (case when b0.aufl_dat_soll is not null
            then  to_char(b0.aufl_dat_soll,'DD.MM.YYYY')
       else (case when b0.waehrung is not null and b0.soll_jahr is not null
                  then (select trim(bxr.onix) from buoxref bxr where bxr.typ='WAEHRUNG' and bxr.cover_3='0' and bxr.cover_2='0' and trim(bxr.cover_1) = trim(substr(b0.waehrung,3,1)))||' '||b0.soll_jahr
             else ' '
             end)
       end)
 end),
trim(q3.qaus)||trim(q2.qaus), to_char(b0.aufl_dat_soll,'YYYYMMDD'),
(case when b0.waehrung is not null and b0.soll_jahr is not null
      then (select trim(bxr.onix) from buoxref bxr where bxr.typ='WAEHRUNG' and bxr.cover_3='0' and bxr.cover_2='0' and trim(bxr.cover_1) = trim(substr(b0.waehrung,3,1)))||' '||b0.soll_jahr
      else ' '
 end),
trim(q3.qaus), trim(a.prod_typ),
(select l.ges_menge from bulagges l where l.l_ausg_nr = b0.l_ausg_nr and l.best_art = '1' and l.e_mandant = m.lager_mandant and l.l_aufl_nr = 0 and l.lager_code = 'HLA'),
 a.preisbind, a.sperr_grund, m.rab_grp, m.steuer_code,
trim(qhnr.qaus), trim(qjahr.qaus),trim(qjz.qaus),
OKA.NoContributor,
a.GRUP_ID, h.BEIWERK_1, h.BEIWERK_2, h.BEIWERK_3, h.BEIWERK_4,
(case when a.DOI is not null and FKT.wert is not null
      then trim(FKT.wert)||trim(a.doi)
      else null
end),
(case when pt.doi_link is not null and a.link is not null
     then trim(pt.doi_link)||trim(a.link)
     else null
end),
lek.benutzer_id, a.kz_basis_band,
bav.stand, b1.aufl_hoehe, (select sum(aufl_hoehe_ist) from buaufdru dru where dru.l_ausg_nr=b0.l_ausg_nr and dru.l_aufl_nr=b0.l_aufl_nr),
trim(pt.istatwcode), '04',
h.dateigroesse, decode(h.dateigroesse, null, null,'22'), decode(h.dateigroesse, null, null,'19'),
ld.lkz_iso2, decode(ld.lkz_iso2,null,null,'99'),
(case when a.prod_typ in ('ZSOE','ZSOP')
   then h.seiten_von
   else null end),
(case when a.prod_typ in ('ZSOE','ZSOP')
   then h.seiten_bis
   else null end),
trim(b0.rpv_ebsichtbar),trim(b0.pv_ebsichtbar), trim(vtr.notiz), trim(bar.qaus)
from
buausgab a, buausgab a2, buausgab a3, bumanaus m, bumanaus m2 ,
butitel t, busfaufl b0,  buaufl b1,
buartqa q1,
buherste h, SF_mandant om, buverlag bv, bumeldnr bm, buartqa q2, buartqa q3, buartqa q4, buprotyp pt,
buartqa qhnr, buartqa qjahr, buartqa qjz, buartqa bar,
SF_KeinAutor OKA, sykndfkt FKT,
buartqa qVLBR, buivwauf ivw, SF_LEKTOR lek, buaufvor bav,land ld, verwtyp vtr
where
a.l_titel_nr = t.l_titel_nr and
a.l_ausg_nr = m.l_ausg_nr and
b0.l_ausg_nr  = a.l_ausg_nr and
bm.meld_nr(+) = b0.meld_nr and
q1.l_ausg_nr (+) = a.l_ausg_nr and
q1.prod_typ (+) = a.prod_typ and
q1.qm_id (+) = 'BARCODE' and
a.kombityp in ('E','B', 'V', 'M', 'Z', 'S','R') and
a.kz_aufl_best = 'F' and
h.l_ausg_nr (+) = a.l_ausg_nr and
m.e_mandant = om.e_mandant and
bv.verlags_id (+) = a.verlags_id and
b1.l_ausg_nr = b0.l_ausg_nr and
b1.l_aufl_nr = b0.l_aufl_nr and
a2.l_ausg_nr (+) = m2.l_ausg_nr and
m2.l_ausg_nr_neu (+) = m.l_ausg_nr and
m2.e_mandant (+) = m.e_mandant and
a3.l_ausg_nr (+) = m.l_ausg_nr_neu and
q2.l_ausg_nr(+) = a.l_ausg_nr and
q2.prod_typ(+) = a.prod_typ and
q2.qm_id(+) = 'VLB_WARENG' and
q3.l_ausg_nr(+) = a.l_ausg_nr and
q3.prod_typ(+) = a.prod_typ and
q3.qm_id(+) = 'INDEX_VLB' and
q4.l_ausg_nr(+) = a.l_ausg_nr and
q4.prod_typ(+) = a.prod_typ and
q4.qm_id(+) = 'INVORSCHAU' and
qhnr.l_ausg_nr(+) = a.l_ausg_nr and
qhnr.prod_typ(+) = a.prod_typ and
qhnr.qm_id(+) = 'HEFTNUMMER'and
qjahr.l_ausg_nr(+) = a.l_ausg_nr and
qjahr.prod_typ(+) = a.prod_typ and
qjahr.qm_id(+) = 'JAHRGANG' and
qjz.l_ausg_nr(+) = a.l_ausg_nr and
qjz.prod_typ(+) = a.prod_typ and
qjz.qm_id(+) = 'JAHRZAEHL' and
bar.l_ausg_nr(+) = a.l_ausg_nr and
bar.prod_typ(+) = a.prod_typ and
bar.qm_id(+) = 'BARFR' and
OKA.l_ausg_nr(+) = a.l_ausg_nr and
FKT.kunde='KOH' and FKT.funktion='BU_DOI' and
qVLBR.l_ausg_nr (+) = a.l_ausg_nr and
qVLBR.prod_typ (+) = a.prod_typ and
qVLBR.qm_id (+) = 'VLBREIHEN' and
ivw.e_mandant(+) = m.e_mandant and
ivw.l_ausg_nr(+) = m.l_ausg_nr and
ivw.l_aufl_nr(+) = 0 and
lek.l_titel_nr (+) = a.l_titel_nr and
bav.l_ausg_nr(+) = b0.l_ausg_nr and
bav.l_aufl_nr(+) = b0.l_aufl_nr
and pt.prod_typ = a.prod_typ and
ld.land_code(+) = a.land_code and
vtr.verwend_typ(+) = h.reihenangabe and
vtr.tabelle(+) = 'BUHERSTE' and
vtr.feldname(+) = 'REIHENANGABE';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTAUFLAGE" ("RECORDIDENTIFIER", "L_AUSG_NR", "L_AUFL_NR", "AUFLAGE_NR", "AUFLAGE_TEXT", "STATUS", "STATUS_TEXT") AS
  select
trim(m.artikel_nr), a.l_ausg_nr, a.l_aufl_nr, a.auflage_nr, a.aufl_text, a.status, v.beschreibung
from bumanaus m, buaufl a, sf_mandant sm, verwtyp v
where m.e_mandant = sm.e_mandant
and m.l_ausg_nr = a.l_ausg_nr
and v.tabelle = 'BUAUFL' and v.feldname='STATUS' and v.verwend_typ=a.status
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTBEARBEITER" ("RECORDIDENTIFIER", "ROLLE", "BENUTZER_ID", "KZ_HAUPT_LEKTOR", "NAME") AS
  select
trim(m.artikel_nr), 'L', l.benutzer_id, tl.kz_haupt_lektor, l.name
from bumanaus m, sf_mandant sm, butitlek tl, bulektor l, buausgab a
where
m.e_mandant = sm.e_mandant and
m.l_ausg_nr = a.l_ausg_nr and
a.l_titel_nr = tl.l_titel_nr and
tl.lektor_id = l.lektor_id
UNION
select
trim(m.artikel_nr), 'B', b.benutzer_id, 'F', b.nachname
from bumanaus m, sf_mandant sm, bubearb b
where
m.e_mandant = sm.e_mandant and
m.l_ausg_nr = b.l_ausg_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTCONTAINEDITEM" ("RECORDIDENTIFIER", "PRODUCTIDENTIFIER", "PRODUCTISBN13", "PRODUCTEAN", "AUSLEITUNG", "ITEMQUANTITY", "ANTEIL", "PRODUCTFORM") AS
  select
trim(ma.artikel_nr), trim(mb.artikel_nr),
b.ISBN, decode(b.EAN, null, b.band_nr, b.ean),
(select trim(bxr.onix) from buoxref bxr where bxr.typ='AUSLEITUNG' and bxr.cover_1=b.prod_typ and bxr.cover_2 = '0' and bxr.cover_3 = '0'),
k.menge, c.erloesanteil,
(select trim(bxr.onix) from buoxref bxr where bxr.typ='MEDIENTYP' and bxr.cover_1=h.einbandart and bxr.cover_2 = '0' and bxr.cover_3 = '0')
from buausgab a, bukombi k, buausgab b, bumankom c, onixmandant om,  bumanaus ma, bumanaus mb,
buherste h, buoxref bxr
where
a.bundle in('E','F','G', 'H')
and a.l_ausg_nr = k.l_ausg_nr
and b.l_ausg_nr = k.u_ausg_nr
and c.l_ausg_nr = k.l_ausg_nr
and c.u_ausg_nr = k.u_ausg_nr
and c.e_mandant = om.e_mandant
and ma.e_mandant = om.e_mandant
and ma.l_ausg_nr = a.l_ausg_nr
and mb.e_mandant = om.e_mandant
and mb.l_ausg_nr = b.l_ausg_nr
and h.l_ausg_nr (+) = a.l_ausg_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTCONTRIBUTOR" ("RECORDIDENTIFIER", "SEQUENCENUMBER", "CONTRIBUTORROLE", "NAMESBEFOREKEY", "KEYNAMES", "ADR_GR", "ADR_NR", "PERSON_NR", "ORCID", "ISNI", "GND") AS
  select
o.RecordIdentifier, (case when b.sort > 0 then b.sort else (100 + b.autor_nr) end),
trim(decode(oxr.onix, null, b.autor_typ, oxr.onix)),
trim(b.vorname), trim(b.nachname), b.adr_gr, b.adr_nr_aut, b.person_nr_aut,
trim(r.externe_nr), trim(r2.externe_nr), trim(r3.externe_nr)
from buausgab a, buautor b, buoxref oxr, SF_product o, anwref r, anwref r2, anwref r3
where
a.l_ausg_nr = o.l_ausg_nr and
a.l_titel_nr = b.l_titel_nr and
oxr.typ = 'AUTOR_TYP' and
oxr.cover_1 = b.autor_typ and
oxr.cover_2 = '0' and
oxr.cover_3 = '0' and
r.adr_gr(+) = b.adr_gr and
r.adr_nr(+) = b.adr_nr_aut and
r.person_nr(+) = b.person_nr_aut and
r.anw_ref_nr(+) = 'OR' and
r2.adr_gr(+) = b.adr_gr and
r2.adr_nr(+) = b.adr_nr_aut and
r2.person_nr(+) = b.person_nr_aut and
r2.anw_ref_nr(+) = 'GN' and
r3.adr_gr(+) = b.adr_gr and
r3.adr_nr(+) = b.adr_nr_aut and
