  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTDIENSTLEISTER" ("RECORDIDENTIFIER", "L_AUSG_NR", "L_AUFL_NR", "AUFLAGE_NR", "DL_TYP_ID", "DL_TYP_BEZ", "ADR_GR", "ADR_NR", "PERSON_NR") AS
