  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTFORMFEATURE" ("RECORDIDENTIFIER", "FEATURETYPE", "FEATUREVALUE", "SORTORDER") AS
  select
o.RecordIdentifier, '51', trim(e.dds_ref_nr)||'+'||trim(e.pruef_nr), '51'
from euentwald e, SF_product o
