e.kz_na = 'T';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTLEKTOR" ("RECORDIDENTIFIER", "ROLLE", "BENUTZER_ID", "KZ_HAUPT_LEKTOR", "NAME") AS
