  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTPACKAGE" ("RECORDIDENTIFIER", "TITLE", "SERIESID", "TITLEOFSERIES", "SUBTITLEOFSERIES", "WKONIXEXP") AS
  select
trim(m2.artikel_nr),trim(t2.titel1), trim(m1.artikel_nr),
trim(t1.titel1), trim(t1.titel_unter), qw.qaus
from
buausgab a1, buausgab a2, butitel t1, butitel t2,
bukombi k,
bumanaus m1, SF_mandant om, SF_product o, bumanaus m2,  buartqa qW
where
k.l_ausg_nr = a1.l_ausg_nr and
k.u_ausg_nr = a2.l_ausg_nr and
a1.l_titel_nr = t1.l_titel_nr and
a2.l_titel_nr = t2.l_titel_nr and
a1.kombityp in ('R','Z') and
a2.kombityp in ('B','E','R','Z','S','V') and
a1.prod_typ ='PEBK' and
m1.l_ausg_nr = a1.l_ausg_nr and
m1.e_mandant = om.e_mandant and
m2.l_ausg_nr = a2.l_ausg_nr and
m2.e_mandant = om.e_mandant and
a2.l_ausg_nr = o.l_ausg_nr and
qW.l_ausg_nr(+) = a1.l_ausg_nr and
qW.prod_typ(+) = a1.prod_typ and
qW.qm_id(+) = 'WKONIXEXP';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTPRICE" ("RECORDIDENTIFIER", "PRICETYPECODE", "PRICESTATUS", "PRICEAMOUNT", "CURRENCYCODE", "COUNTRYCODE", "PRICEEFFECTIVEFROM", "PRICEEFFECTIVEUNTIL", "BATCHQUANTITY", "DISCOUNTPERCENT", "DISCOUNTGROUP", "MINIMUMORDERQUANTITY", "TAXRATECODE1", "TAXRATEPERCENT1", "TAXABLEAMOUNT1", "TAXAMOUNT1", "TAXRATECODE2", "TAXRATEPERCENT2", "TAXABLEAMOUNT2", "TAXAMOUNT2") AS
  select
trim(m.artikel_nr), trim(pl.preiskat_land),
(case when pl.preiskat = 'CA' then '01' else '02' end),
pl.preis, trim(pl.waehrung), trim(pl.land),
pl.gueltig_ab, (case when pl.subs_dat1 is not null then pl.subs_dat1 else pl.gueltig_bis end),
pl.anzahl,
(case when m1.rab_grp is not null
      then (select trim(bxr.onix) from buoxref bxr where bxr.typ='RAB_GRP_RAB' and bxr.cover_1=m1.rab_grp and bxr.cover_2 = '0' and bxr.cover_3 = '0')
 else null
 end),
(case when m1.rab_grp is not null
      then (select trim(bxr.onix) from buoxref bxr where bxr.typ='RAB_GRP_TXT' and bxr.cover_1=m1.rab_grp and bxr.cover_2 = '0' and bxr.cover_3 = '0')
 else null
 end),
pl.menge,
trim(m1.steuer_code),st1.steuersatz, pl.preis,
round(((pl.preis * st1.steuersatz/100)/(1 + st1.steuersatz/100)),2),
null, null, null, null
from SF_preisliste pl, bupktext pt, bumanaus m1, bumanaus m, SF_mandant om, buausgab a, stsatz st1
where
m.e_mandant = om.e_mandant and
m.l_ausg_nr = pl.l_ausg_nr and
pt.preiskat (+) = pl.preiskat and
pt.sprach_code (+) = 'D' and
m.l_ausg_nr = m1.l_ausg_nr and
om.e_mandant = m1.e_mandant and
a.l_ausg_nr = m.l_ausg_nr and
(a.bundle = 'K' or a.bundle is null) and
trim(st1.steuer_code) = trim(m1.steuer_code) and
trim(st1.land_code) = trim(pl.land_code) and
st1.datum_ab = (select max(datum_ab) from stsatz dm where trim(dm.land_code)=trim(pl.land_code) and trim(dm.steuer_code)=trim(m1.steuer_code) and dm.datum_ab<=sysdate)
and trim(pl.land_code) != 'CH'
UNION
select
trim(m.artikel_nr), trim(pl.preiskat_land),
(case when pl.preiskat = 'CA' then '01' else '02' end),
pl.preis, trim(pl.waehrung), trim(pl.land),
pl.gueltig_ab, (case when pl.subs_dat1 is not null then pl.subs_dat1 else pl.gueltig_bis end),
pl.anzahl,
(case when m1.rab_grp is not null
      then (select trim(bxr.onix) from buoxref bxr where bxr.typ='RAB_GRP_RAB' and bxr.cover_1=m1.rab_grp and bxr.cover_2 = '0' and bxr.cover_3 = '0')
 else null
 end),
(case when m1.rab_grp is not null
      then (select trim(bxr.onix) from buoxref bxr where bxr.typ='RAB_GRP_TXT' and bxr.cover_1=m1.rab_grp and bxr.cover_2 = '0' and bxr.cover_3 = '0')
 else null
 end),
pl.menge,
trim(m1.steuer_code),st1.steuersatz,
round((pl.preis * mk1.erloesanteil/100),2) - round((((pl.preis * mk1.erloesanteil/100) * st1.steuersatz/100)/(1 + st1.steuersatz/100)),2),
round((((pl.preis * mk1.erloesanteil/100) * st1.steuersatz/100)/(1 + st1.steuersatz/100)),2),
trim(m2.steuer_code),st2.steuersatz,
round((pl.preis * mk2.erloesanteil/100),2) - round((((pl.preis * mk2.erloesanteil/100) * st2.steuersatz/100)/(1 + st2.steuersatz/100)),2),
round((((pl.preis * mk2.erloesanteil/100) * st2.steuersatz/100)/(1 + st2.steuersatz/100)),2)
from SF_preisliste pl, bupktext pt, bumanaus m1, bumanaus m, SF_mandant om, buausgab a, stsatz st1, stsatz st2,
bumanaus m2, bumankom mk1, bumankom mk2
where
m.e_mandant = om.e_mandant and
m.l_ausg_nr = pl.l_ausg_nr and
pt.preiskat (+) = pl.preiskat and
pt.sprach_code (+) = 'D' and
 a.l_ausg_nr = m.l_ausg_nr and
a.bundle in('E','F','G','H') and
trim(pl.land_code) != 'CH' and
m1.l_ausg_nr = (select u_ausg_nr from bukombi x
where x.l_ausg_nr = m.l_ausg_nr and
coalesce(x.sortierung, x.u_ausg_nr) =
(select min(coalesce(x2.sortierung, x2.u_ausg_nr)) from bukombi x2 where x2.l_ausg_nr = m.l_ausg_nr))
and
m1.e_mandant = om.e_mandant and
mk1.e_mandant = om.e_mandant and
mk1.u_ausg_nr = m1.l_ausg_nr and
trim(st1.steuer_code) = trim(m1.steuer_code) and
trim(st1.land_code) = trim(pl.land_code) and
st1.datum_ab = (select max(datum_ab) from stsatz dm where trim(dm.land_code)=trim(pl.land_code) and trim(dm.steuer_code)=trim(m1.steuer_code) and dm.datum_ab<=sysdate)
and
m2.l_ausg_nr = (select u_ausg_nr from bukombi x
where x.l_ausg_nr = m.l_ausg_nr and
coalesce(x.sortierung, x.u_ausg_nr) =
(select max(coalesce(x2.sortierung, x2.u_ausg_nr)) from bukombi x2 where x2.l_ausg_nr = m.l_ausg_nr))
and
m2.e_mandant = om.e_mandant and
mk2.e_mandant = om.e_mandant and
mk2.u_ausg_nr = m2.l_ausg_nr and
trim(st2.steuer_code) = trim(m2.steuer_code) and
trim(st2.land_code) = trim(pl.land_code) and
st2.datum_ab = (select max(datum_ab) from stsatz dm where trim(dm.land_code)=trim(pl.land_code) and trim(dm.steuer_code)=trim(m2.steuer_code) and dm.datum_ab<=sysdate)
UNION
select
trim(m.artikel_nr), trim(pl.preiskat_land),
(case when pl.preiskat = 'CA' then '01' else '02' end),
pl.preis, trim(pl.waehrung), trim(pl.land),
pl.gueltig_ab, (case when pl.subs_dat1 is not null then pl.subs_dat1 else pl.gueltig_bis end),
pl.anzahl,
(case when m1.rab_grp is not null
      then (select trim(bxr.onix) from buoxref bxr where bxr.typ='RAB_GRP_RAB' and bxr.cover_1=m1.rab_grp and bxr.cover_2 = '0' and bxr.cover_3 = '0')
 else null
 end),
(case when m1.rab_grp is not null
      then (select trim(bxr.onix) from buoxref bxr where bxr.typ='RAB_GRP_TXT' and bxr.cover_1=m1.rab_grp and bxr.cover_2 = '0' and bxr.cover_3 = '0')
 else null
 end),
pl.menge,
(case when a.prod_typ = 'BUND' and pl.preiskat = 'LP' then 'H' else null end),
null,null,
null,
null, null, null, null
from SF_preisliste pl, bupktext pt, bumanaus m1, bumanaus m, SF_mandant om, buausgab a
where
m.e_mandant = om.e_mandant and
m.l_ausg_nr = pl.l_ausg_nr and
pt.preiskat (+) = pl.preiskat and
pt.sprach_code (+) = 'D' and
m.l_ausg_nr = m1.l_ausg_nr and
om.e_mandant = m1.e_mandant and
a.l_ausg_nr = m.l_ausg_nr and
trim(pl.land_code) = 'CH'
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTRELATEDPRODUCT" ("RECORDIDENTIFIER", "RELATIONCODE", "PRODUCTIDENTIFIER", "PRODUCTFORM") AS
  select
trim(o.artikel_nr),
(case when (substr(a.prod_typ,1,1)='E' and substr(b.prod_typ,1,1) ='E')
          then '06'
          else (case when (substr(a.prod_typ,1,1)='E')
                            then '13'
                            else '27' end)end),
trim(bm.artikel_nr),
trim(b.prod_typ)
from buausgab a, buausgab b, BUMANAUS o,bumanaus bm, sf_mandant om,
buaufl aa, buaufl ba
where a.l_titel_nr = b.l_titel_nr
and a.l_ausg_nr != b.l_ausg_nr
and a.l_titel_nr != 0
and a.herkunft is null
and b.herkunft is null
and a.l_ausg_nr = o.l_ausg_nr
and a.prod_typ != 'EKAP'
and b.prod_typ != 'EKAP'
and a.prod_typ != 'FODO' and a.prod_typ != 'BUON'
and b.prod_typ != 'FODO' and b.prod_typ != 'BUON'
and
(
  (substr(a.prod_typ,1,1) = 'E' and substr(b.prod_typ,1,1) ='E')
  or
  (substr(a.prod_typ,1,1) = 'E' and substr(b.prod_typ,1,1) !='E')
  or
  (substr(a.prod_typ,1,1) != 'E' and substr(b.prod_typ,1,1) ='E')
)
and b.prod_typ is not null
and aa.l_ausg_nr = a.l_ausg_nr
and aa.l_aufl_nr = 0
and ba.l_ausg_nr = b.l_ausg_nr
and ba.l_aufl_nr = 0
and ba.bestuhlung = aa.bestuhlung
and bm.l_ausg_nr = b.l_ausg_nr
and bm.e_mandant = om.e_mandant
