and c.e_mandant = m.e_mandant
and b.l_ausg_nr = c.l_ausg_nr
and c.linktyp = 'D'
and bm.l_ausg_nr = b.l_ausg_nr
and bm.e_mandant = m.e_mandant
union select
trim(o.artikel_nr),
'97',
trim(bm.artikel_nr),
trim(b.prod_typ)
from buausgab a, buausgab b, BUMANAUS o,bumanaus bm, sf_mandant om,
buaufl aa, buaufl ba
where a.l_titel_nr = b.l_titel_nr
and a.l_ausg_nr != b.l_ausg_nr
and a.l_titel_nr != 0
and a.herkunft is null
and b.herkunft is null
and a.l_ausg_nr = o.l_ausg_nr
and a.prod_typ = 'FODO'
and b.prod_typ != 'FODO' and substr(b.prod_typ,1,1) != 'E' and b.prod_typ != 'BUON'
and aa.l_ausg_nr = a.l_ausg_nr
and aa.l_aufl_nr = 0
and ba.l_ausg_nr = b.l_ausg_nr
and ba.l_aufl_nr = 0
and ba.bestuhlung = aa.bestuhlung
and bm.l_ausg_nr = b.l_ausg_nr
and bm.e_mandant = om.e_mandant
union select
trim(o.artikel_nr),
'98',
trim(bm.artikel_nr),
trim(b.prod_typ)
from buausgab a, buausgab b, BUMANAUS o,bumanaus bm, sf_mandant om,
buaufl aa, buaufl ba
where a.l_titel_nr = b.l_titel_nr
and a.l_ausg_nr != b.l_ausg_nr
and a.l_titel_nr != 0
and a.herkunft is null
and b.herkunft is null
and a.l_ausg_nr = o.l_ausg_nr
and b.prod_typ = 'FODO'
and a.prod_typ != 'FODO' and substr(a.prod_typ,1,1) != 'E' and a.prod_typ != 'BUON'
and aa.l_ausg_nr = a.l_ausg_nr
and aa.l_aufl_nr = 0
and ba.l_ausg_nr = b.l_ausg_nr
and ba.l_aufl_nr = 0
and ba.bestuhlung = aa.bestuhlung
and bm.l_ausg_nr = b.l_ausg_nr
and bm.e_mandant = om.e_mandant
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTSERIES" ("RECORDIDENTIFIER", "TITLE", "SERIESID", "TITLEOFSERIES", "SUBTITLEOFSERIES", "NUMBERWITHINSERIES", "VLB_REIHE", "KOH_REIHE", "WKONIXEXP", "WKSHOPEXP", "SORTIERUNG") AS
