k.l_ausg_nr = a1.l_ausg_nr and
k.u_ausg_nr = a2.l_ausg_nr and
a1.l_titel_nr = t1.l_titel_nr and
a2.l_titel_nr = t2.l_titel_nr and
a1.kombityp in ('R','Z') and
a2.kombityp in ('B','E','R','Z') and
a1.kz_eigen = 'T' and
a1.prod_typ = 'REIH' and
m1.l_ausg_nr = a1.l_ausg_nr and
m1.e_mandant = om.e_mandant and
m2.l_ausg_nr = a2.l_ausg_nr and
m2.e_mandant = om.e_mandant and
a2.l_ausg_nr = o.l_ausg_nr and
qV.l_ausg_nr(+) = a1.l_ausg_nr and
qV.prod_typ(+) = a1.prod_typ and
qV.qm_id(+) = 'VLBREIHEN' and
qW.l_ausg_nr(+) = a1.l_ausg_nr and
qW.prod_typ(+) = a1.prod_typ and
qW.qm_id(+) = 'WKONIXEXP' and
qS.l_ausg_nr(+) = a1.l_ausg_nr and
qS.prod_typ(+) = a1.prod_typ and
qS.qm_id(+) = 'WKSHOPEXP'
;


