  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_PRODUCTSUBJECT" ("RECORDIDENTIFIER", "SUBJECTSCHEMEIDENTIFIER", "SUBJECTSCHEMENAME", "SUBJECTSCHEMEVERSION", "SUBJECTCODE", "SUBJECTHEADINGTEXT") AS
  select
m.artikel_nr, '20', null, null, null, trim(s.stichwort)
from
buausgab a,  bustichw s, bumanaus m
where
a.l_ausg_nr = m.l_ausg_nr and m.e_mandant = '01' and
a.l_titel_nr = s.l_titel_nr
union
select
m.artikel_nr, '23',
'BISAC',null,trim(p.produkt),
trim(p.produkt)
from buartpro p,  bumanaus m
where
m.l_ausg_nr = p.l_ausg_nr and
p.wb_id = 'BIS' and
p.hgrp_id is not null and
p.ugrp_id is not null
union
select
m.artikel_nr, '23',
trim(q.qm_id), null,trim(q.qaus), decode(q2.qaus_id, null, trim(q.qaus), trim(q2.bez))
from buausgab a, buartqa q,  bumanaus m, buqaus q2
where
a.l_ausg_nr = m.l_ausg_nr and m.e_mandant = '01' and
a.l_ausg_nr = q.l_ausg_nr and
a.prod_typ = q.prod_typ and
q2.qm_id(+) = q.qm_id and
q2.prod_typ(+) = q.prod_typ and
q2.qaus_id(+) = q.qaus and
not exists (select * from buoxref r where r.typ = 'QM_ID' and r.cover_1 = q.qm_id)
union
select
m.artikel_nr, '23',
trim(r.onix), null,trim(q.qaus), decode(q2.qaus_id, null, trim(q.qaus), trim(q2.bez))
from buausgab a, buartqa q,  bumanaus m, buqaus q2, buoxref r
where
a.l_ausg_nr = m.l_ausg_nr and m.e_mandant = '01' and
a.l_ausg_nr = q.l_ausg_nr and
a.prod_typ = q.prod_typ and
q2.qm_id(+) = q.qm_id and
q2.prod_typ(+) = q.prod_typ and
q2.qaus_id(+) = q.qaus and
r.typ = 'QM_ID' and
r.cover_1 = q.qm_id
union
select
m.artikel_nr, '93-MAIN',
null, t.version, p.pan_id, trim(t.bezeichnung)
from buausgab a,  bumanaus m, bupantit p, bupanthe t
where
a.l_titel_nr = p.l_titel_nr and
a.l_ausg_nr = m.l_ausg_nr and m.e_mandant = '01' and
t.pan_id = p.pan_id and
p.pan_typ = 'SUBJEC' and
p.sortierung = 1
union
select
m.artikel_nr,
decode(trim(p.pan_typ),'SUBJEC', '93',
                 'GEOGRA','94',
                 'LANGUA', '95',
                 'TIME', '96',
                 'EDUCAT', '97',
                 'INTAGE', '98',
                 'STYLE', '99', 'XXX'),
null, t.version, p.pan_id, trim(t.bezeichnung)
from buausgab a,  bumanaus m, bupantit p, bupanthe t
where
a.l_titel_nr = p.l_titel_nr and
a.l_ausg_nr = m.l_ausg_nr and m.e_mandant = '01' and
t.pan_id = p.pan_id and
(p.pan_typ != 'SUBJEC' or p.sortierung = 99)
union
select
m.artikel_nr, '100-MAIN',
'WK-HAUPT',null,trim(p.produkt),
trim(p.produkt)
from buartpro p,  bumanaus m
where
m.l_ausg_nr = p.l_ausg_nr and
p.wb_id = 'WK' and
p.hgrp_id is not null and
p.ugrp_id is not null and
p.produkt is not null and
p.KZ_HAUPTGRP = 'T'
union
select
m.artikel_nr, '100',
'WK',null,trim(p.produkt),
trim(p.produkt)
from buartpro p,  bumanaus m
where
m.l_ausg_nr = p.l_ausg_nr and
p.wb_id = 'WK' and
p.hgrp_id is not null and
p.ugrp_id is not null and
p.produkt is not null and
(p.KZ_HAUPTGRP = 'F' or p.KZ_HAUPTGRP is null)
union
select
m.artikel_nr, '26',
'VLBSchemeNew', null,trim(qIV.qaus)||trim(qVWG.qaus), null
from buausgab a, buartqa qIV, buartqa qVWG,  bumanaus m
where
a.l_ausg_nr = m.l_ausg_nr and m.e_mandant = '01' and
a.l_ausg_nr = qIV.l_ausg_nr and
a.prod_typ = qIV.prod_typ and
a.l_ausg_nr = qVWG.l_ausg_nr and
a.prod_typ = qVWG.prod_typ and
qVWG.qm_id = 'VLB_WARENG' and
qIV.qm_id = 'INDEX_VLB'
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_WK_KATEGORIEN" ("KAT_1_ID", "KAT_2_ID", "KAT_2_BEZ", "KAT_2_BEZ_ENGL", "EBENE") AS
  select h.wb_id, h.hgrp_id, h.bez, s.text, '1 HAUPTGRUPPE'
from hauptgrp h, sprachmp s
  where h.wb_id = 'WK' and
      s.sprach_code(+) = 'E' and
      s.verwend_typ(+) = 'HGRP_I' and
      s.key_cov_1(+) = rtrim(h.wb_id) and
      s.key_cov_2(+) = rtrim(h.hgrp_id)
union
select u.hgrp_id, u.ugrp_id, u.bez, s.text, '2 UNTERGRUPPE'
from ugruppe u, sprachmp s
  where u.wb_id = 'WK' and
      s.sprach_code(+) = 'E' and
      s.verwend_typ(+) = 'UGRP_I' and
      s.key_cov_1(+) = rtrim(u.wb_id) and
      s.key_cov_2(+) = rtrim(u.hgrp_id) and
      s.key_cov_3(+) = rtrim(u.ugrp_id)
union
select a.ugrp_id, a.produkt, a.bez, b.bez, '3 PRODUKT'
from produkt a , prodsp b
where a.wb_id = 'WK'
and b.produkt(+)= a.produkt
and b.sprach_code(+) = 'E';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SF_WK_KATEGORIEN_2" ("KAT_1_ID", "KAT_2_ID", "KAT_2_BEZ", "KAT_2_BEZ_ENGL", "EBENE") AS
  select h.wb_id, h.hgrp_id, h.bez, s.text, '1 HAUPTGRUPPE'
from hauptgrp h, sprachmp s
  where h.wb_id = 'WK' and
      s.sprach_code(+) = 'E' and
      s.verwend_typ(+) = 'HGRP_I' and
      s.key_cov_1(+) = rtrim(h.wb_id) and
      s.key_cov_2(+) = rtrim(h.hgrp_id)
union
select u.hgrp_id, u.ugrp_id, sd.text, se.text, '2 UNTERGRUPPE'
from ugruppe u, sprachmp se, sprachmp sd
  where u.wb_id = 'WK' and
      se.sprach_code(+) = 'E' and
      se.verwend_typ(+) = 'UGRP_I' and
      se.key_cov_1(+) = rtrim(u.wb_id) and
      se.key_cov_2(+) = rtrim(u.hgrp_id) and
      se.key_cov_3(+) = rtrim(u.ugrp_id)
      and
      sd.sprach_code(+) = 'D' and
      sd.verwend_typ(+) = 'UGRP_I' and
      sd.key_cov_1(+) = rtrim(u.wb_id) and
      sd.key_cov_2(+) = rtrim(u.hgrp_id) and
      sd.key_cov_3(+) = rtrim(u.ugrp_id)
union
select a.ugrp_id, a.produkt, c.bez, b.bez, '3 PRODUKT'
from produkt a , prodsp b, prodsp c
where a.wb_id = 'WK'
and b.produkt(+)= a.produkt
and b.sprach_code(+) = 'E'
and c.produkt(+)= a.produkt
and c.sprach_code(+) = 'D';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SUAAVIEW" ("ADR_GR", "ADR_NR", "ABO_NR", "AUFTR_NR", "STATUS", "E_MANDANT", "OBJ_NR", "AUSG", "VERWEND_TYP", "HEFT_JAHR", "HEFT_NR", "HNR_NUM", "SAP_NR", "ADR_NR_RE", "PERSON_NR_RE", "ZUSATZ_TEXT_RE", "PREIS_STK", "PREIS_GES", "FRHT_STK", "FRHT_GES", "RVG_STK", "RVG_GES", "ANZ_ANZEIGEN", "RCHN_MENGE", "RCHN_NR", "RCHN_DATUM", "RCHN_BETRAG", "MWST_KEY", "Z_ART_CODE", "Z_ZIEL_CODE", "WAEHRUNG", "STORNO", "DATUM_NEU", "B_ID_NEU", "DATUM_AEND", "B_ID_AEND", "VERSANDART", "RVG_SEP_RYTHM", "RVG_DATUM", "RVG_NR", "RVG_BETRAG", "FRHT_BETRAG", "ABO_BETRAG", "ORIG_RCHN_MENGE", "ORIG_RCHN_NR", "ORIG_RCHN_DATUM", "ORIG_RCHN_BETRAG", "ORIG_RVG_NR", "ORIG_RVG_DATUM", "ORIG_RVG_BETRAG", "ZUSATZ_BELEG_TEXT", "ABRECH_ZEIT", "VERWEND_ERLKONTO", "ABO_RVG_STK", "ABO_VBEG_HEFT", "ABO_VEND_HEFT", "ABO_VBEG_DAT", "ABO_VEND_DAT", "ABO_BEST_MENGE", "ABO_LIEF_MENGE", "ABO_RCHN_MENGE") AS
  select 	a.adr_gr, a.adr_nr, a.abo_nr, a.auftr_nr,
	a.status, a.e_mandant, a.obj_nr, a.ausg, a.verwend_typ, a.heft_jahr, a.heft_nr, a.hnr_num,
	a.sap_nr, a.adr_nr_re, a.person_nr_re, a.zusatz_text_re,
	a.preis_stk, a.preis_ges, a.frht_stk, a.frht_ges, a.rvg_stk, a.rvg_ges, a.anz_anzeigen,
	a.rchn_menge, a.rchn_nr, a.rchn_datum, a.rchn_betrag, a.mwst_key, a.z_art_code, a.z_ziel_code, a.waehrung,
	a.storno, a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend, a.versandart,
	a.rvg_sep_rythm, a.rvg_datum, a.rvg_nr, a.rvg_betrag, a.frht_betrag, a.abo_betrag,
	a.orig_rchn_menge, a.orig_rchn_nr, a.orig_rchn_datum, a.orig_rchn_betrag, a.orig_rvg_nr, a.orig_rvg_datum, a.orig_rvg_betrag,
	a.zusatz_beleg_text, a.abrech_zeit, a.verwend_erlkonto,
	b.rvg_stk, b.vbeg_jahr*1000+b.vbeg_heft, b.vend_jahr*1000+b.vend_heft, b.vbeg_dat, b.vend_dat, b.best_menge, b.lief_menge, b.rchn_menge
from SUAUFTRA a, SUABOSTA b
where	a.adr_gr = b.adr_gr
and	a.adr_nr = b.adr_nr
and	a.abo_nr = b.abo_nr
union
select 	b.adr_gr, b.adr_nr, b.abo_nr, 0,
	' ', b.e_mandant, b.obj_nr, b.ausg, b.verwend_typ, 0, 0, 0,
	'                ', b.adr_nr_re, b.person_nr_re, b.zusatz_text_re,
	b.preis_stk, b.preis_ges, b.frachtpreis_stk, b.frachtpreis_pausch, b.rvg_stk, b.rvg_ges, b.anz_werbe_leist,
	b.rchn_menge, '               ', b.vertr_beg, 0, b.mwst_key, b.z_art_code, b.z_ziel_code, b.waehrung,
	' ', b.datum_neu, b.b_id_neu||'    ', b.datum_aend, b.b_id_aend||'    ', ' ',
	b.rvg_sep_rythm, to_date('31.12.2099'), 0, b.betr_rvg, 0, 0,
	0, '               ', to_date('31.12.2099'), 0, 0, to_date('31.12.2099'), 0,
	'', b.abrech_zeit, b.verwend_erlkonto,
	b.rvg_stk, b.vbeg_jahr*1000+b.vbeg_heft, b.vend_jahr*1000+b.vend_heft, b.vbeg_dat, b.vend_dat, b.best_menge, b.lief_menge, b.rchn_menge
from SUABOSTA b;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."SYCRMVIEW_FAL" ("MODIFIED_ON", "FIRMENNAME", "HAUPT_NAME", "VORNAME", "NACHNAME", "ADRESSTYP", "FIRMENTYP_COVER", "MIG_ID", "ADRESS_GRUPPE", "ADRESS_NUMMER", "PERSON_NUMMER", "HERKUNFT", "SPRACH_CODE", "ANREDE_CODE", "TITEL_CODE", "POSITION", "DUBLETTEN_ID", "STRASSE", "STRASSE2", "WOHNORT_PLZ", "WOHNORT", "LAND_CODE", "LAND", "BEZIRK", "GENERALFILTER", "EG_UST_NR", "STATUS", "STATUSGRUND", "BEMERKUNG", "DATUM_NEUANLAGE", "DATUM_AENDERUNG", "TELEFON", "MOBIL", "E_MAIL", "E_MAIL_RECH", "HOMEPAGE", "WERBE_ERLAUBNIS", "BRANCHE_WT", "MERKMALE", "FKT_BEREICHE", "WSPERRE", "WSPERRE_PERSOENLICH", "WSPERRE_OBJEKT", "EXT_ID_CORE", "FREIEINWEISUNGEN") AS
  SELECT P.MODIFIED_ON, TRIM(A.NAME1)||' '||TRIM(A.NAME2)||' '||TRIM(A.NAME3), A.HAUPT_NAME,
    P.VORNAME, P.NACHNAME,
    CASE WHEN (P.A_TYP='F') THEN 'Unternehmen' ELSE CASE WHEN (P.A_TYP='P') THEN 'Privatperson' ELSE 'Mitarbeiter' END END, A.F_TYP,
    CASE WHEN (P.A_TYP='F') THEN CASE WHEN (A.F_TYP = 'WA') THEN 'c-age-' ELSE 'c-unt-' END || A.ADR_NR ELSE CASE WHEN (P.A_TYP='P') THEN 'c-per-' || A.ADR_NR ELSE 'c-mit-' || A.ADR_NR ||'-'||P.PERSON_NR END END,
	  A.ADR_GR, A.ADR_NR,	P.PERSON_NR, A.AQUELL_CODE,
    P.SPRACH_CODE, P.ANREDE_CODE, P.TITEL_CODE, P.POSITION,
    ANW.NUMMER,
    A.STRASSE, A.STRASSE2, A.PLZ_WOHN, A.WOHNORT, LA.LKZ_ISO2, LA.LAND, A.BEZIRK_ID, A.GENFILT_ID, AI.EG_UST_NR,
    CASE WHEN (P.KZ_SPERR='T' OR P.KZ_LOESCHEN='T') THEN 0 ELSE	1 END,
    CASE WHEN (P.KZ_LOESCHEN='T') THEN	'geloescht' ELSE CASE WHEN (P.KZ_SPERR='T') THEN 'gesperrt' ELSE '' END END,
    P.BEMERKUNG, P.DATUM_NEU, P.DATUM_AEND,
    TTEL.TEL, TMOB.MOBIL, TEMA.EMAIL, TEMR.EMAIL, TWEB.WEB, WERL.WERBE_ERLAUBNIS,
    BRWT.PROD, QM.MERKM,
    FKTB.fkt_bereich,
    AI.wsperr_code, WSP.wsp, WSO.wsp,
    TREF.ADR_NR_EXT, FREINW.FREIEINWEISUNGEN
FROM
    anschr A
    JOIN person P ON (A.adr_gr=P.adr_gr and A.adr_nr=P.adr_nr)
    JOIN land LA ON (A.LAND_CODE=LA.LAND_CODE)
    LEFT JOIN ainfo AI ON (A.ADR_GR=AI.ADR_GR and A.ADR_NR=AI.ADR_NR)
    LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(nummer), ',') WITHIN GROUP (ORDER BY nummer) tel FROM	telecom	WHERE tel_art IN ('T','TM','TMA','T2','T3') GROUP BY adr_gr,adr_nr,person_nr) TTEL ON (TTEL.adr_gr=P.adr_gr and TTEL.adr_nr=P.adr_nr and TTEL.person_nr=P.person_nr)
    LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(nummer), ',') WITHIN GROUP (ORDER BY nummer) mobil FROM	telecom	WHERE tel_art IN ('MT','MT2') GROUP BY adr_gr,adr_nr,person_nr) TMOB ON (TMOB.adr_gr=P.adr_gr and TMOB.adr_nr=P.adr_nr and TMOB.person_nr=P.person_nr)
    LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(nummer), ',') WITHIN GROUP (ORDER BY nummer) email FROM	telecom	WHERE tel_art IN ('E','EM','ER','E2') GROUP BY adr_gr,adr_nr,person_nr) TEMA ON (TEMA.adr_gr=P.adr_gr and TEMA.adr_nr=P.adr_nr and TEMA.person_nr=P.person_nr)
    LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(nummer), ',') WITHIN GROUP (ORDER BY nummer) email FROM	telecom	WHERE tel_art IN ('ER') GROUP BY adr_gr,adr_nr,person_nr) TEMR ON (TEMR.adr_gr=P.adr_gr and TEMR.adr_nr=P.adr_nr and TEMR.person_nr=P.person_nr)
    LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(nummer), ',') WITHIN GROUP (ORDER BY nummer) web FROM	telecom	WHERE tel_art IN ('HP','HP2') GROUP BY adr_gr,adr_nr,person_nr) TWEB ON (TWEB.adr_gr=P.adr_gr and TWEB.adr_nr=P.adr_nr and TWEB.person_nr=P.person_nr)
    LEFT JOIN (SELECT	adr_gr,adr_nr,person_nr,LISTAGG (TRIM(EXTERNE_NR), ',') WITHIN GROUP (ORDER BY EXTERNE_NR) nummer	FROM anwref	WHERE anw_ref_nr IN ('D1','D2','D3','D4','D5','D6','D7','D8','D9') GROUP BY adr_gr,adr_nr,person_nr) ANW ON (ANW.adr_gr=P.adr_gr and ANW.adr_nr=P.adr_nr and ANW.person_nr=P.person_nr)
    LEFT JOIN (SELECT	adr_gr,adr_nr,person_nr,LISTAGG (TRIM(TEL_ART)||'/'||TRIM(KZ_ERLAUB), ',') WITHIN GROUP (ORDER BY TEL_ART) werbe_erlaubnis FROM werbeerl WHERE hist_nr=0 GROUP BY adr_gr,adr_nr,person_nr) WERL ON (WERL.adr_gr=P.adr_gr and WERL.adr_nr=P.adr_nr and WERL.person_nr=P.person_nr)
    LEFT JOIN (SELECT adr_gr,adr_nr,LISTAGG (TRIM(PRODUKT), ',') WITHIN GROUP (ORDER BY PRODUKT) prod FROM wtprod WHERE kz_loesch='F' GROUP BY adr_gr,adr_nr) BRWT ON (BRWT.adr_gr=P.adr_gr and BRWT.adr_nr=P.adr_nr and P.person_nr=0)
    LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(Q_CODE)||'/'||TRIM(Q_AUSP_CODE), ',') WITHIN GROUP (ORDER BY Q_CODE,Q_AUSP_CODE) merkm FROM qwerte WHERE status is null GROUP BY adr_gr,adr_nr,person_nr) QM ON (QM.adr_gr=P.adr_gr and QM.adr_nr=P.adr_nr and QM.person_nr=P.person_nr)
    LEFT JOIN (SELECT	adr_gr,adr_nr,person_nr,LISTAGG (TRIM(FKT_BEREICH), ',') WITHIN GROUP (ORDER BY FKT_BEREICH) fkt_bereich FROM fktperson GROUP BY adr_gr,adr_nr,person_nr) FKTB ON (FKTB.adr_gr=P.adr_gr and FKTB.adr_nr=P.adr_nr and FKTB.person_nr=P.person_nr)
    LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(wsperr_code), ',') WITHIN GROUP (ORDER BY wsperr_code) wsp FROM	personws GROUP BY adr_gr,adr_nr,person_nr) WSP ON (WSP.adr_gr=P.adr_gr and WSP.adr_nr=P.adr_nr and WSP.person_nr=P.person_nr)
    LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(obj_nr)||'/'||TRIM(wsperr_code), ',') WITHIN GROUP (ORDER BY obj_nr,wsperr_code) wsp FROM	mobjwsp GROUP BY adr_gr,adr_nr,person_nr) WSO ON (WSO.adr_gr=P.adr_gr and WSO.adr_nr=P.adr_nr and WSO.person_nr=P.person_nr)
    LEFT JOIN (SELECT key_cov_char_3,key_cov_char_4,key_cov_char_5,LISTAGG(TRIM(key_ext_char_3), ',') WITHIN GROUP (ORDER BY key_ext_char_3) adr_nr_ext FROM transref WHERE transfer_id like 'COVCRM%' and kunde='FAL' and bereich='BUABO' and verwend_typ='WSVIMP' and referenz_typ='EXT_NR_ADR_NR' GROUP BY key_cov_char_3,key_cov_char_4,key_cov_char_5) TREF ON (TREF.key_cov_char_3=P.adr_gr and TREF.key_cov_char_4=P.adr_nr and TREF.key_cov_char_5=P.person_nr)
LEFT JOIN (SELECT adr_gr,adr_nr,person_nr,LISTAGG (TRIM(OBJ_NR)||'/'||TRIM(AUSG)||'/'||TRIM(ANZ_FREI)||'/'||TRIM(HEFT_VON)||'/'||TRIM(JAHR_VON)||'/'||TRIM(HEFT_BIS)||'/'||TRIM(JAHR_BIS)||'/'||TRIM(B_ID_VERANL)||'/'||TRIM(EMPFAENGER), ',') WITHIN GROUP (ORDER BY OBJ_NR,AUSG,JAHR_VON,HEFT_VON) freieinweisungen FROM freieinw GROUP BY adr_gr,adr_nr,person_nr) FREINW ON (FREINW.adr_gr=P.adr_gr and FREINW.adr_nr=P.adr_nr and FREINW.person_nr=P.person_nr);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TAGVIEW" ("ADR_GR", "ADR_NR", "AUFT_NR", "AUFT_HIST_NR", "DISPO_NR", "DISPO_HIST_NR", "DISPOPOS_NR", "E_MANDANT", "BANK_SATZ_NR", "OBJ_NR", "AUSG", "ABRECH_ID", "ANZART_ID", "ANZEIGEN_PREIS", "ANZ_ABO_SI", "ANZ_MM", "ANZ_EINTRAG", "ANZ_SI", "ANZ_SCHALTUNG", "ANZ_SP", "ANZ_ZEILEN", "BDATUM", "BINFO", "BZEICHEN", "B_ID_AEND", "B_ID_NEU", "DRUCK_ID", "FARB_ID", "FORMAT_ID", "KOMBI_RABATT", "SONDER_RABATT", "STATUS", "VOLUMEN_RABATT", "WA_PROV_SATZ", "AKTION", "KZ_BEST", "VERSANDART", "PRODNAME", "DUNTERLAGEN", "HNR", "JAHR", "HNR_NUM", "PLAZ_EXT", "LFD_NR", "ANZ_BELEGUNG", "BEZEICHNUNG", "KZ_PREIS_UNBEKANNT", "DATUM_NEU", "DATUM_AEND", "MOTIV", "ABW_PROD_BEZ", "BEZ_SI", "DUNT_ID", "STATUS_DISPOPOS", "ANZ_ANZEIGEN") AS
  select p.adr_gr, p.adr_nr, p.auft_nr, p.auft_hist_nr, p.dispo_nr, p.dispo_hist_nr,
       p.dispopos_nr, p.e_mandant, d.bank_satz_nr, p.obj_nr, p.ausg, d.abrech_id,
       d.anzart_id, d.anzeigen_betrag, d.anz_abo_si, d.anz_mm, d.anz_eintrag,
       d.anz_si, d.anz_schaltung, d.anz_sp, d.anz_zeilen, d.bdatum, d.binfo,
       d.bzeichen, d.b_id_aend, d.b_id_neu, d.druck_id, d.farb_id, d.format_id,
       d.kombi_rabatt, d.sonder_rabatt, d.status, d.volumen_rabatt, d.wa_prov_satz,
       d.aktion, d.kz_best, d.best_art, p.prodname, p.dunterlagen, p.hnr, p.jahr,
       p.hnr_num, p.plaz_ext, r.lfd_nr, r.anz_belegung, r.bezeichnung,
       d.kz_preis_unbekannt, d.datum_neu, d.datum_aend, p.motiv, p.abw_prod_bez,
       d.bez_si, p.druck_id, p.status, d.anz_anzeigen
from   dispo d, dispopos p LEFT OUTER JOIN drubrik r ON	
	p.adr_gr = r.adr_gr and
	p.adr_nr = r.adr_nr and
	p.auft_nr = r.auft_nr and
	p.auft_hist_nr = r.auft_hist_nr and
	p.dispo_nr = r.dispo_nr and
	p.dispo_hist_nr = r.dispo_hist_nr and
	p.dispopos_nr = r.dispopos_nr
where	p.adr_gr = d.adr_gr and p.adr_nr = d.adr_nr and p.auft_nr = d.auft_nr and
	p.auft_hist_nr = d.auft_hist_nr and p.dispo_nr = d.dispo_nr and
	p.dispo_hist_nr = d.dispo_hist_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TEILVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "AKT_ID", "UAKT_ID", "START_ID", "VORNAME", "NACHNAME", "A_TYP", "NAME1", "NAME2", "PLZ_WOHN", "PLZ_POST", "PLZ_GK", "WOHNORT", "POSTORT", "GKORT", "STRASSE", "HAUSNR", "HAUSNR_ZUS", "POSTFACH", "TEL_VORWAHL", "LAND_CODE") AS
  SELECT t.adr_gr, t.adr_nr, t. person_nr, t.e_mandant,
       t.akt_id, t.uakt_id, t.start_id,
       p.vorname, p.nachname, p.a_typ,
       a.name1, a.name2, a.plz_wohn, a.plz_post, a.plz_gk,
       a.wohnort, a.postort, a.gkort,
       a.strasse, a.hausnr, a.hausnr_zus, a.postfach,
       l.tel_vorwahl, l.land_code
FROM   teilnemp t, person p, anschr a, land l
WHERE  p.adr_gr    = t.adr_gr
AND    p.adr_nr    = t.adr_nr
AND    p.person_nr = t.person_nr
AND    a.adr_gr    = t.adr_gr
AND    a.adr_nr    = t.adr_nr
AND    a.land_code = l.land_code;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TELAVIEW" ("TEL_ART", "BEZ", "VERW_ID", "VORBELEGUNG", "KZ_GRUPPE", "SORTIERUNG") AS
  select	tel_art||'   ',bez,verw_id||'               ',vorbelegung,'F',1
from teleart
union
