  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TEMPAVIEW" ("ADR_GR", "ADR_NR", "ADR_NR_BV", "INAUS", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "ABO_NR", "BER_MENGE", "VBEG_DAT", "VBEG_JAHR", "VBEG_HEFT", "VEND_DAT", "VEND_JAHR", "VEND_HEFT", "PREIS_KAT", "WAEHRUNG", "R_ART", "R_BEG_DAT", "R_BEG_JAHR", "R_BEG_HNR", "R_ENDE_DAT", "R_ENDE_JAHR", "R_ENDE_HNR", "ABOSTATUS", "K_GRUND", "STATUS", "FAKT_ZR", "PERSON_NR_BV", "KZ_STORNO", "AUFTRAGS_NR", "SPREIS", "RA_FAKT", "W_AKT_ID", "W_UAKT_ID", "PREIS_KAT_NO", "NO_ENDE_DAT", "NO_ENDE_JAHR", "NO_ENDE_HNR", "BEST_DATUM", "K_DATUM", "VERSAND_SOLL_VBEG", "VERSAND_SOLL_VEND", "VERSAND_SOLL_NO") AS
  select                a.adr_gr, a.adr_nr, a.adr_nr_bv, a.inaus,
                      a.person_nr, a.e_mandant,
