  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TMP_BUNDLE_PREISE" ("L_AUSG_NR", "PRICETYPE", "PRICEAMOUNT", "ID1", "TAXRATECODE1", "TAXRATEPERCENT1", "TAXABLEAMOUNT1", "TAXAMOUNT1", "ID2", "TAXRATECODE2", "TAXRATEPERCENT2", "TAXABLEAMOUNT2", "TAXAMOUNT2") AS
  select
a.l_ausg_nr, pl.preiskat, mp.preis,
(case when b1.isbn is not null
     then b1.isbn
     else b1.band_nr
     end),
m1.steuer_code, st1.steuersatz, round((mp.preis * mk1.erloesanteil/100),2), round((st1.steuersatz/100 * (mp.preis * mk1.erloesanteil/100)),2),
(case when b2.isbn is not null
     then b2.isbn
     else b2.band_nr
     end),
m2.steuer_code, st2.steuersatz, round((mp.preis * mk2.erloesanteil/100),2), round((st2.steuersatz/100 * (mp.preis * mk2.erloesanteil/100)),2)
from buausgab a,  buplist pl, bumpreis mp, stsatz st1, stsatz st2,
bumanaus m1, bumanaus m2, onixmandant om, bumankom mk, bumankom mk1, bumankom mk2, buausgab b1, buausgab b2
where a.bundle in ('E','F','G', 'H')
and a.l_ausg_nr = mk.l_ausg_nr
and mk.e_mandant = om.e_mandant
and m1.l_ausg_nr = (select min(u_ausg_nr) from bumankom b where b.l_ausg_nr = a.l_ausg_nr and b.e_mandant = om.e_mandant)
and m1.e_mandant = om.e_mandant
and mk1.l_ausg_nr = a.l_ausg_nr and mk1.e_mandant = om.e_mandant and mk1.u_ausg_nr = m1.l_ausg_nr
and mk2.l_ausg_nr = a.l_ausg_nr and mk2.e_mandant = om.e_mandant and mk2.u_ausg_nr = m2.l_ausg_nr
and m2.e_mandant = om.e_mandant
and m2.l_ausg_nr = (select max(u_ausg_nr) from bumankom b where b.l_ausg_nr = a.l_ausg_nr and b.e_mandant = om.e_mandant)
and b1.l_ausg_nr = m1.l_ausg_nr
and b2.l_ausg_nr = m2.l_ausg_nr
and pl.l_ausg_nr = a.l_ausg_nr and pl.e_mandant = om.e_mandant
and mp.list_nr = pl.list_nr
and st1.steuer_code = m1.steuer_code and st1.land_code = 'D' and
st1.datum_ab = (select max(datum_ab) from stsatz dm where dm.land_code='D' and dm.steuer_code=m1.steuer_code and dm.datum_ab<=sysdate)
and st2.steuer_code = m2.steuer_code and st2.land_code = 'D' and
st2.datum_ab = (select max(datum_ab) from stsatz dm where dm.land_code='D' and dm.steuer_code=m2.steuer_code and dm.datum_ab<=sysdate);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TMP_BUNDLES_VIEW" ("L_AUSG_NR", "U_AUSG_NR", "U_ID", "MENGE") AS
  select
a.l_ausg_nr, k.u_ausg_nr,
(case when b.isbn is not null
     then b.isbn
     else b.band_nr
     end),
k.menge
from buausgab a, bukombi k, buausgab b, bumankom c, onixmandant om
where
a.bundle in('E','F','G', 'H')
and a.l_ausg_nr = k.l_ausg_nr
and b.l_ausg_nr = k.u_ausg_nr
and c.l_ausg_nr = k.l_ausg_nr
and c.u_ausg_nr = k.u_ausg_nr
and c.e_mandant = om.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TNABOVIE" ("L_TITEL_NR", "AUTOR_NR", "L_AUSG_NR", "L_AUFL_NR", "AUFLAGE_NR", "HERKUNFT", "D_ANZ_TN", "ANZ_TERMIN", "D_ANZ_ABO") AS
  select a.l_titel_nr, a.autor_nr, b.l_ausg_nr, l.l_aufl_nr, l.auflage_nr, b.herkunft,
       (select sum(p.ber_menge-p.gut_menge+p.frei_menge) from buaufpos p
              where p.l_ausg_nr = b.l_ausg_nr and p.l_ausg_nr = l.l_ausg_nr and p.storno='F' and exists (select auflage_nr from buaufl a1
              where b.l_ausg_nr= a1.l_ausg_nr and p.l_ausg_nr= a1.l_ausg_nr and p.l_aufl_nr= a1.l_aufl_nr and auflage_nr>=200809)),
       (select count(*) from buaufl l1 where b.l_ausg_nr=l1.l_ausg_nr and auflage_nr>=200809),
       (select count(*) from konto k where a.adr_gr=k.adr_gr and a.adr_nr_aut=k.adr_nr and a.person_nr_aut=k.person_nr and verw_typ='A')
from  buautor a, buausgab b, bumanaus m, buaufl l
where b.l_titel_nr  = a.l_titel_nr and
      m.l_ausg_nr  = b.l_ausg_nr and
      l.l_ausg_nr  = b.l_ausg_nr
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TPWHVIEW" ("E_MANDANT", "AKT_ID", "UAKT_ID", "START_ID", "ADR_GR", "ADR_NR", "PERSON_NR", "LFD_NR", "DATUM", "KZ_ERLEDIGT", "KZ_WH") AS
  select
t.e_mandant, t.akt_id, t.uakt_id, t.start_id, t.adr_gr, t.adr_nr, t.person_nr, 0, t.datum, t.kz_erledigt, 'F'
from teilnemp t
union
select
w.e_mandant, w.akt_id, w.uakt_id, w.start_id, w.adr_gr, w.adr_nr, w.person_nr,w.lfd_nr, w.datum, w.kz_erledigt, 'T'
from werbehis w
where  w.start_id = 0
and w.in_out = 'I';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRAAVIEW" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "HAUPT_NAME", "NACHNAME", "VORNAME", "WOHNORT", "POSTORT", "W_AKT_ID", "W_UAKT_ID", "VERSART", "R_ART", "BESTELLG", "BEST_DATUM", "BER_MENGE", "B_GRUND", "BIND_DAT", "PREIS_KAT", "FAKT_ZR", "PREIS_KAT_NO", "FAKT_ZR_NO", "Z_BED", "K_GRUND", "K_DATUM", "KZ_GUTSCHEIN", "VBEG_DAT", "VBEG_JAHR", "VBEG_HEFT", "VEND_DAT", "VEND_JAHR", "VEND_HEFT", "ABOSTATUS", "ABO_DAUER", "NO_ENDE_DAT", "NO_ENDE_JAHR", "NO_ENDE_HNR", "SPREIS", "R_BEG_DAT", "R_BEG_HNR", "R_BEG_JAHR", "R_ENDE_DAT", "R_ENDE_HNR", "R_ENDE_JAHR", "DATUM_NEU", "B_ID_NEU", "KZ_STORNO", "STATUS", "VERANLASSER", "BEST_WEG", "TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "LFD_NR", "TR_SATZ_ID", "TR_POS_NR", "LFD_NR_AKTVORB") AS
  select distinct b.e_mandant, b.adr_gr, b.adr_nr, p.person_nr, b.obj_nr, b.ausg,
       b.abo_nr, a.haupt_name, p.nachname, p.vorname, a.wohnort, a.postort,
       b.w_akt_id, b.w_uakt_id, v.versart, b.r_art,
       b.bestellg, b.best_datum, b.ber_menge, b.b_grund, b.bind_dat,
       b.preis_kat, b.fakt_zr, b.preis_kat_no, b.fakt_zr_no, b.z_bed,
       b.k_grund, b.k_datum, b.kz_gutschein,
       b.vbeg_dat, b.vbeg_jahr, b.vbeg_heft,
       b.vend_dat, b.vend_jahr, b.vend_heft, b.abostatus, b.abo_dauer,
       b.no_ende_dat, b.no_ende_jahr, b.no_ende_hnr, b.spreis,
       b.r_beg_dat, b.r_beg_hnr, b.r_beg_jahr, b.r_ende_dat, b.r_ende_hnr, b.r_ende_jahr,
       b.datum_neu,b.b_id_neu,b.kz_storno,b.status,b.veranlasser,b.best_weg,
       t.transfer_id, t.kunde, t.bereich, t.verwend_typ, t.lfd_nr, t.tr_satz_id, t.tr_pos_nr, t.lfd_nr_aktvorb
from trabo t, abostamm b, person p, anschr a, abovers v
where  b.adr_gr    = a.adr_gr    and b.adr_nr    = a.adr_nr
   and b.adr_gr    = p.adr_gr    and b.adr_nr    = p.adr_nr
   and b.person_nr = p.person_nr
   and b.adr_gr    = v.adr_gr
   and b.adr_nr    = v.adr_nr    and b.person_nr = v.person_nr
   and b.e_mandant = v.e_mandant and b.obj_nr    = v.obj_nr
   and b.ausg      = v.ausg      and b.abo_nr    = v.abo_nr
   and b.e_mandant = t.e_mandant and b.adr_gr    = t.adr_gr
   and b.adr_nr    = t.adr_nr    and b.person_nr = t.person_nr
   and b.obj_nr    = t.obj_nr    and b.ausg      = t.ausg
   and b.abo_nr    = t.abo_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRABNVIE" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "ADR_NR_BV", "PERSON_NR_BV", "TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "DATUM_AEND", "ABOSTATUS") AS
  select t."E_MANDANT",t."ADR_GR",t."ADR_NR",t."PERSON_NR",t."OBJ_NR",t."AUSG",t."ABO_NR",t."ADR_NR_BV",t."PERSON_NR_BV",t."TRANSFER_ID",t."KUNDE",t."BEREICH",t."VERWEND_TYP",t."DATUM_AEND",t."ABOSTATUS" from trabview t where not exists(
select c.e_mandant,c.adr_gr,c.adr_nr,c.person_nr,c.abo_nr,c.obj_nr,c.ausg,max(c.zeitstempel) from c2wbest c
where c.adr_gr=t.adr_gr and c.adr_nr=t.adr_nr and c.person_nr=t.person_nr and c.obj_nr=t.obj_nr and c.ausg=t.ausg and c.abo_nr=t.abo_nr
and (c.abostatus = 'aktiv' and t.abostatus in ('bestellt','gekundigt','aktiv','unterbr.')
or   c.abostatus = 'loschen' and t.abostatus in ('inaktiv a','inaktiv b'))
group by c.e_mandant,c.adr_gr,c.adr_nr,c.person_nr,c.abo_nr,c.obj_nr,c.ausg)
and ((t.kunde='MTR' and t.obj_nr='EGH') or t.kunde <> 'MTR');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRABVIEW" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "ADR_NR_BV", "PERSON_NR_BV", "TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "DATUM_AEND", "ABOSTATUS") AS
  select distinct s.e_mandant,s.adr_gr,s.adr_nr,s.person_nr,s.obj_nr,s.ausg,s.abo_nr,s.adr_nr_bv,s.person_nr_bv,
t.transfer_id,t.kunde,t.bereich,t.verwend_typ,
case when (case when coalesce(s.datum_aend,s.datum_neu) > coalesce(pr.datum_aend,pr.datum_neu)
                then coalesce(s.datum_aend,s.datum_neu)
                else coalesce(pr.datum_aend,pr.datum_neu)
                end)
              > coalesce(pl.datum_aend,pl.datum_neu)
     then (case when coalesce(s.datum_aend,s.datum_neu) > coalesce(pr.datum_aend,pr.datum_neu)
                then coalesce(s.datum_aend,s.datum_neu)
                else coalesce(pr.datum_aend,pr.datum_neu)
                end)
     else coalesce(pl.datum_aend,pl.datum_neu)
     end,
s.abostatus
from trreview t, trabo ta, abostamm s, person pr, person pl
where s.adr_gr=t.adr_gr  and s.adr_nr_bv=t.adr_nr and s.person_nr_bv=t.person_nr
and   pr.adr_gr=s.adr_gr and pr.adr_nr=s.adr_nr_bv and pr.person_nr=s.person_nr_bv
and   pl.adr_gr=s.adr_gr and pl.adr_nr=s.adr_nr    and pl.person_nr=s.person_nr
and   ta.transfer_id=t.transfer_id and ta.kunde=t.kunde and ta.verwend_typ=t.verwend_typ and ta.bereich=t.bereich
and   ta.adr_gr=s.adr_gr and ta.adr_nr=s.adr_nr and ta.person_nr=s.person_nr and ta.obj_nr=s.obj_nr and ta.ausg=s.ausg and ta.abo_nr=s.abo_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRANSFVW" ("TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "TR_SATZ_ID", "TR_POS_NR", "VORGANG", "ADR_ROLLE", "ABW_TR_SATZ_ID", "TR_STATUS", "E_MANDANT", "ADR_GR", "ADR_NR_LE", "PERSON_NR_LE", "OBJ_NR", "AUSG", "ABO_NR", "AUFT_NR", "ADR_NR_RE", "PERSON_NR_RE", "EMAIL_1", "BENUTZER_WEB", "GUELTIG_AB", "GUELTIG_BIS", "BEITRAG_ID", "PORTAL_ID", "PORT_BER_ID") AS
  select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, a.tr_pos_nr,
	'VZ', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	k.adr_nr, k.person_nr, a.obj_nr, a.ausg, a.abo_nr, 0, a.adr_nr_re, a.person_nr_re,
	k.email_1, k.nachsend_firma_ges, a.vbeg_datum, a.vend_datum, '                              ', v.portal_id, v.port_ber_id
from TRABO a, AKTVORB v, PORTAL p, TRKOPF k
where 	k.transfer_id = a.transfer_id and
	k.kunde       = a.kunde and
        k.bereich     = a.bereich and
	k.verwend_typ = a.verwend_typ and
	k.tr_satz_id  = a.tr_satz_id and
        k.e_mandant   = v.e_mandant and
	a.akt_id      = v.akt_id and
        a.obj_nr      = v.obj_nr and
  	a.ausg        = v.ausg and
        p.e_mandant   = k.e_mandant and
        p.portal_id   = v.portal_id and
        p.kz_abo = 'T'
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, a.tr_pos_nr,
	'VZ', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	k.adr_nr, k.person_nr, a.obj_nr, a.ausg, a.abo_nr, 0, a.adr_nr_re, a.person_nr_re,
	k.email_1, k.nachsend_firma_ges, a.vbeg_datum, a.vend_datum, '                              ', v.portal_id, v.port_ber_id
from TRABO a, PORTZUOB v, PORTAL p, TRKOPF k
where 	k.transfer_id = a.transfer_id and
	k.kunde       = a.kunde and
        k.bereich     = a.bereich and
	k.verwend_typ = a.verwend_typ and
	k.tr_satz_id  = a.tr_satz_id and
        k.e_mandant   = v.e_mandant and
        a.obj_nr      = v.obj_nr and
  	a.ausg        = v.ausg and
        p.e_mandant   = k.e_mandant and
        p.kz_abo = 'T'
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, b.tr_pos_nr,
	'BU', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	k.adr_nr, k.person_nr, 'xxx', 'xxxxxxxxxxxx', 0, b.auft_nr, b.adr_nr_re, b.person_nr_re,
	k.email_1, k.nachsend_firma_ges, k.fakt_soll_dat, k.vers_soll_dat, b.beitrag_id,'          ', '            '
from TRBUPOS b, TRKOPF k
where 	k.transfer_id = b.transfer_id and
	k.kunde       = b.kunde and
        k.bereich     = b.bereich and
	k.verwend_typ = b.verwend_typ and
	k.tr_satz_id  = b.tr_satz_id
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, 0,
	'RE', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	k.adr_nr, k.person_nr, 'xxx', 'xxxxxxxxxxxx', 0, 0, k.adr_nr, k.person_nr,
	k.email_1, k.nachsend_firma_ges, k.zeit_neu, k.vers_soll_dat, '                              ','          ', '            '
from TRKOPF k
where not exists (select * from trabo a where	
        k.transfer_id = a.transfer_id and
	k.kunde       = a.kunde and
        k.bereich     = a.bereich and
	k.verwend_typ = a.verwend_typ and
	k.tr_satz_id  = a.tr_satz_id) and
      not exists (select * from trbupos b where	
        k.transfer_id = b.transfer_id and
	k.kunde       = b.kunde and
        k.bereich     = b.bereich and
	k.verwend_typ = b.verwend_typ and
	k.tr_satz_id  = b.tr_satz_id);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRANSUUIDVIEW" ("TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "TR_SATZ_ID", "TR_POS_NR", "LFD_NR", "VORGANG", "BEST_DATUM", "ADR_ROLLE", "ABW_TR_SATZ_ID", "TR_STATUS", "E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "A_TYP", "EMAIL_1", "EMAIL_2", "EMAIL_RECH", "FIRMA1", "FIRMA2", "FIRMA3", "FIRMA_GES", "VORNAME", "NACHNAME", "SPRACH_CODE", "ANREDE_CODE", "TITEL_CODE", "LAND_CODE", "STRASSE", "POSTFACH", "PLZ", "PLZ_POSTFACH", "NACHSEND_PLZ", "ORT", "NACHSEND_ORT", "UUID") AS
  select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, 0, k.lfd_nr,
	'ADR', k.best_datum, k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr, k.adr_nr, k.person_nr, k.a_typ,
	k.email_1, k.email_2, k.email_rech, k.firma1, k.firma2, k.firma3, k.firma_ges, k.vorname, k.nachname,
	k.sprach_code, k.anrede_code, k.titel_code,
	k.land_code, k.strasse, k.postfach, k.plz, k.plz_postfach, k.nachsend_plz, k.ort, k.nachsend_ort, z.uuid_adr
from TRKOPF k, TRKOPFZ z
where 	z.transfer_id = k.transfer_id and
	z.kunde       = k.kunde and
        z.bereich     = k.bereich and
	z.verwend_typ = k.verwend_typ and
	z.tr_satz_id  = k.tr_satz_id
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, 0, k.lfd_nr,
	'AUFT', k.best_datum, k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr, k.adr_nr, k.person_nr, k.a_typ,
	k.email_1, k.email_2, k.email_rech, k.firma1, k.firma2, k.firma3, k.firma_ges, k.vorname, k.nachname,
	k.sprach_code, k.anrede_code, k.titel_code,
	k.land_code, k.strasse, k.postfach, k.plz, k.plz_postfach, k.nachsend_plz, k.ort, k.nachsend_ort, z.uuid_auft
from TRKOPF k, TRKOPFZ z
where 	z.transfer_id = k.transfer_id and
	z.kunde       = k.kunde and
        z.bereich     = k.bereich and
	z.verwend_typ = k.verwend_typ and
	z.tr_satz_id  = k.tr_satz_id
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, a.tr_pos_nr, k.lfd_nr,
	'ABO', k.best_datum, k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr, k.adr_nr, k.person_nr, k.a_typ,
	k.email_1, k.email_2, k.email_rech, k.firma1, k.firma2, k.firma3, k.firma_ges, k.vorname, k.nachname,
	k.sprach_code, k.anrede_code, k.titel_code,
	k.land_code, k.strasse, k.postfach, k.plz, k.plz_postfach, k.nachsend_plz, k.ort, k.nachsend_ort, a.uuid_pos
from TRKOPF k, TRABO a
where 	a.transfer_id = k.transfer_id and
	a.kunde       = k.kunde and
        a.bereich     = k.bereich and
	a.verwend_typ = k.verwend_typ and
	a.tr_satz_id  = k.tr_satz_id
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, b.tr_pos_nr, k.lfd_nr,
	'BUCH', k.best_datum, k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr, k.adr_nr, k.person_nr, k.a_typ,
	k.email_1, k.email_2, k.email_rech, k.firma1, k.firma2, k.firma3, k.firma_ges, k.vorname, k.nachname,
	k.sprach_code, k.anrede_code, k.titel_code,
	k.land_code, k.strasse, k.postfach, k.plz, k.plz_postfach, k.nachsend_plz, k.ort, k.nachsend_ort, b.uuid_pos
from TRKOPF k, TRBUPOS b
where 	b.transfer_id = k.transfer_id and
	b.kunde       = k.kunde and
        b.bereich     = k.bereich and
	b.verwend_typ = k.verwend_typ and
	b.tr_satz_id  = k.tr_satz_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRBEVIEW" ("TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "TR_SATZ_ID", "TR_POS_NR", "VORGANG", "ADR_ROLLE", "ABW_TR_SATZ_ID", "TR_STATUS", "E_MANDANT", "ADR_GR", "ADR_NR_LE", "PERSON_NR_LE", "OBJ_NR", "AUSG", "ABO_NR", "AUFT_NR", "ADR_NR_RE", "PERSON_NR_RE", "STORNO", "STATUS") AS
  select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, a.tr_pos_nr,
	'VZ', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	 s.adr_nr, s.person_nr, s.obj_nr, s.ausg, s.abo_nr, 0, s.adr_nr_bv, s.person_nr_bv,
	'T', 'E'
from TRKOPF k, TRABO a, ABOSTAMM s
where 	k.transfer_id = a.transfer_id
and 	k.kunde       = a.kunde
and     k.bereich     = a.bereich
and 	k.verwend_typ = a.verwend_typ
and 	k.tr_satz_id  = a.tr_satz_id
and	a.e_mandant   = s.e_mandant
and 	a.adr_gr      = s.adr_gr
and 	a.adr_nr      = s.adr_nr
and 	a.person_nr   = s.person_nr
and 	a.obj_nr      = s.obj_nr
and 	a.ausg        = s.ausg
and 	a.abo_nr      = s.abo_nr
and not exists (select * from c2wproto c where c.key_cov_1 = k.transfer_id and c.key_cov_2 = k.kunde
and c.key_cov_3 = k.bereich and c.key_cov_4 = k.verwend_typ and c.key_cov_7 = k.tr_satz_id and c.export_typ = 'R_SSTAT')
union
select	k.transfer_id, k.kunde, k.bereich, k.verwend_typ, k.tr_satz_id, b.tr_pos_nr,
	'BU', k.adr_rolle, k.abw_tr_satz_id, k.tr_status, k.e_mandant, k.adr_gr,
	a.adr_nr_le, a.person_nr_le, 'xxx', 'xxxxxxxxxxxx', 0, a.auft_nr, a.adr_nr_re, a.person_nr_re,
	a.storno, a.status
from TRKOPF k, TRBUPOS b, buauftra a
where 	k.transfer_id = b.transfer_id
and 	k.kunde       = b.kunde
and     k.bereich     = b.bereich
and 	k.verwend_typ = b.verwend_typ
and 	k.tr_satz_id  = b.tr_satz_id
and 	b.auft_nr     = a.auft_nr
and not exists (select * from c2wproto c where c.key_cov_1 = k.transfer_id and c.key_cov_2 = k.kunde
and c.key_cov_3 = k.bereich and c.key_cov_4 = k.verwend_typ and c.key_cov_7 = k.tr_satz_id and c.export_typ = 'R_SSTAT');


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRBUVIEW" ("TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "TR_SATZ_ID", "TR_POS_NR", "LFD_NR", "TR_STATUS", "STATUS_RESERV", "AUFT_NR", "AUF_POS", "E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "BEST_ART", "LAGER_MANDANT", "LAGER_CODE", "BER_MENGE", "FREI_MENGE", "RESERVIERT_MENGE", "KZ_BEST_UNABH", "DATUM_NEU_BUAUFPOS", "STATUS_BUAUFPOS", "STORNO_BUAUFPOS") AS
  select
t.transfer_id, t.kunde, t.bereich, t.verwend_typ, t.tr_satz_id, t.tr_pos_nr, t.lfd_nr, t.tr_status, t.status_reserv,
b.auft_nr, b.auf_pos, b.e_mandant, b.l_ausg_nr, b.l_aufl_nr, b.best_art,b.lager_mandant, b.lager_code,
b.ber_menge, b.frei_menge, b.reserviert_menge, b.kz_best_unabh,
b.datum_neu, b.status, b.storno
from trbupos t, buaufpos b
where t.auft_nr = b.auft_nr
and t.auf_pos = b.auf_pos;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TROBSVIEW" ("TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "TR_SATZ_ID", "LFD_NR", "TR_POS_NR", "SEND_HIST_NR", "VORGANG", "TR_STATUS", "KZ_BEARBEITEN", "KZ_DISPO_ALT", "OBS_STATUS", "OBS_VERSION", "TR_SATZ_ID_EXT", "MODUS", "AGENTUR_KENNUNG", "FIRMA1_WA", "ADR_GR", "ADR_NR_WA", "E_MANDANT", "BEST_ZEICHEN", "BESTELL_NR", "BEST_DATUM", "TELEFON", "EMAIL_1", "FAX", "NAME_WT_EXT", "ADR_NR_WT_EXT", "ADR_NR_WT", "DISPO_TYP_EXT", "OBJEKT_NR_EXT", "OBJEKT_NAME_EXT", "OBJ_NR", "HNR", "JAHR", "KZ_TEILBEL", "TEILBEL_NAME_EXT", "AUSG", "ANZART_ID", "ANZART_ID_EXT", "FORMAT_ID", "ANSCHN_SATZ_SPIEGEL", "GEOMETRIE_CODE", "AUSRICHTUNG_EXT", "FMT_ANZAHL", "KZ_ANSCHNITT_EXT", "KZ_UEBER_BUND_EXT", "BREITE_MM", "HOEHE_MM", "SPALTEN_ANZAHL", "FARB_ID", "FARBE_EXT", "FARBE_BEZ_EXT", "PLATZIER_ID", "KZ_SI", "SI_KAT_1", "SI_KAT_2", "SI_ANZAHL_TSD", "SI_GEWICHT", "SI_ANZAHL_SEITEN", "KZ_KOMBI", "AUFT_VERWEND_TYP", "AUFT_NR", "DISPO_NR", "STO_AEND_NR_EXT", "AUFT_NR_EXT", "AUFT_DATUM_AB", "AUFT_DATUM_BIS", "AUFT_VOLUMEN", "AUFT_RABATT", "BENUTZER_ID", "PRODUKT_NAME_EXT", "PRODUKT_NR_EXT", "PRODUKT", "TEXT_NR", "SCHL_DISPO_ALT_NEU", "SCHL_DISPO_EXP_IMP", "TEXT_NR_DISPO", "TEXT_NR_MEMO", "KZ_ZUORD_MANU", "DATUM_NEU", "DATUM_AEND", "DATUM_SEND") AS
  select
	d.transfer_id, d.kunde, d.bereich, d.verwend_typ, d.tr_satz_id, d.lfd_nr, d.tr_pos_nr, e.send_hist_nr,
	i.vorgang, d.tr_status, i.kz_bearbeiten, e.kz_dispo_alt, e.obs_status, i.obs_version, i.tr_satz_id_ext, i.modus,
	i.agentur_kennung, k.firma1,  k.adr_gr, k.adr_nr, k.e_mandant,
	d.best_zeichen, d.bestell_nr, d.best_datum, k.telefon, k.email_1, k.fax,
	d.name_ext_wt, d.adr_nr_wt_ext, adr_nr_wt,
	e.dispo_typ_ext,
	d.objekt_nr_ext, e.objekt_name_ext, d.obj_nr, d.hnr, d.jahr, e.kz_teilbel, e.teilbel_name_ext, d.ausg,
	d.anzart_id, d.anzart_id_ext, d.format_id, e.anschn_satz_spiegel, e.geometrie_code, e.ausrichtung_ext, e.fmt_anzahl,
	e.kz_anschnitt_ext, e.kz_ueber_bund_ext, d.breite_mm, d.hoehe_mm, d.spalten_anzahl,
	d.farb_id, d.farbe_ext, e.farbe_bez_ext,
        d.platzier_ID,
	e.kz_si, e.si_kat_1, e.si_kat_2, e.si_anzahl_tsd, e.si_gewicht, e.si_anzahl_seiten,
	i.kz_kombi, i.auft_verwend_typ, d.auft_nr, d.dispo_nr, i.sto_aend_nr_ext, k.auft_nr_ext, i.auft_datum_ab, i.auft_datum_bis, i.auft_volumen, i.auft_rabatt,
	e.benutzer_id, e.produkt_name_ext, e.produkt_nr_ext, e.produkt,
	i.text_nr, e.schl_dispo_alt_neu, e.schl_dispo_exp_imp, e.text_nr_dispo, e.text_nr_memo,
	e.KZ_ZUORD_MANU, e.datum_neu, e.datum_aend, e.datum_send
from
	trdispo d left outer join trdisobs e on
	d.transfer_id = e.transfer_id and d.kunde = e.kunde and
	d.bereich = e.bereich and d.verwend_typ = e.verwend_typ and
	d.tr_satz_id = e.tr_satz_id and e.tr_pos_nr = d.tr_pos_nr
	left outer join trkopf k on
	d.transfer_id = k.transfer_id and d.kunde = k.kunde and
	d.bereich = k.bereich and d.verwend_typ = k.verwend_typ and
	d.tr_satz_id = k.tr_satz_id
	left outer join trkpfobs i on
	d.transfer_id = i.transfer_id and d.kunde = i.kunde and
	d.bereich = i.bereich and d.verwend_typ = i.verwend_typ and
	d.tr_satz_id = i.tr_satz_id
where d.transfer_id = 'OBS' and (e.kz_dispo_alt is null or e.kz_dispo_alt = 0);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRRENVIE" ("ADR_GR", "ADR_NR", "PERSON_NR", "TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "REFERENZ_TYP", "LFD_NR", "VORNAME", "NACHNAME", "NAME1", "NAME2", "NAME3", "ORT", "PLZ", "LAND_CODE", "STRASSE", "DATUM_AEND", "ADR_NR_EXT") AS
  select distinct t."ADR_GR",t."ADR_NR",t."PERSON_NR",t."TRANSFER_ID",t."KUNDE",t."BEREICH",t."VERWEND_TYP",t."REFERENZ_TYP",t."LFD_NR",t."VORNAME",t."NACHNAME",t."NAME1",t."NAME2",t."NAME3",t."ORT",t."PLZ",t."LAND_CODE",t."STRASSE",t."DATUM_AEND",t."ADR_NR_EXT" from trreview t where exists(
select * from c2wkunde c where
c.adr_gr=t.adr_gr and c.adr_nr=t.adr_nr and c.person_nr = t.person_nr
and c.zeitstempel = (select max(zeitstempel) from c2wkunde c2 where
c2.adr_gr=c.adr_gr and c2.adr_nr=c.adr_nr and c2.person_nr = c.person_nr)
and t.datum_aend+1>c.zeitstempel
) or not exists(
select * from c2wkunde c where
c.adr_gr=t.adr_gr and c.adr_nr=t.adr_nr and c.person_nr = t.person_nr
and c.zeitstempel = (select max(zeitstempel) from c2wkunde c2 where
c2.adr_gr=c.adr_gr and c2.adr_nr=c.adr_nr and c2.person_nr = c.person_nr)
);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."TRREVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "TRANSFER_ID", "KUNDE", "BEREICH", "VERWEND_TYP", "REFERENZ_TYP", "LFD_NR", "VORNAME", "NACHNAME", "NAME1", "NAME2", "NAME3", "ORT", "PLZ", "LAND_CODE", "STRASSE", "DATUM_AEND", "ADR_NR_EXT") AS
  select
a.adr_gr,to_number(a.adr_nr),to_number(p.person_nr),r.transfer_id,r.kunde,r.bereich,r.verwend_typ,r.referenz_typ,
r.lfd_nr,p.vorname,p.nachname,a.name1,a.name2,a.name3,a.haupt_ort,a.haupt_plz,a.land_code,
a.strasse,
case when coalesce(p.datum_aend,p.datum_neu)>coalesce(p0.datum_aend,p0.datum_neu)
     then coalesce(p.datum_aend,p.datum_neu)
     else coalesce(p0.datum_aend,p0.datum_neu)
     end
,r.key_ext_char_3
from anschr a, person p, person p0, transref r
where a.adr_gr=p.adr_gr and a.adr_nr=p.adr_nr
and r.referenz_typ='EXT_NR_ADR_NR' and r.lfd_nr=(
select max(r2.lfd_nr) from transref r2
where r2.transfer_id=r.transfer_id and r2.kunde=r.kunde and r2.bereich=r.bereich and r2.verwend_typ=r.verwend_typ
and r2.key_ext_char_3=r.key_ext_char_3
and r2.key_cov_char_3=r.key_cov_char_3 and r2.key_cov_char_4=r.key_cov_char_4 and r2.key_cov_char_5=r.key_cov_char_5
)
and r.key_cov_char_3=a.adr_gr and to_number(r.key_cov_char_4)=a.adr_nr and r.key_ext_char_2 in ('E','R')
and r.key_cov_char_3=p.adr_gr and to_number(r.key_cov_char_4)=p.adr_nr and to_number(r.key_cov_char_5)=p.person_nr
and p0.adr_gr=a.adr_gr and p0.adr_nr=a.adr_nr and p0.person_nr=0;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."UNIFACE_TABLES" ("TABLE_NAME", "TABLESPACE_NAME", "CLUSTER_NAME", "PCT_FREE", "PCT_USED", "INI_TRANS", "MAX_TRANS", "INITIAL_EXTENT", "NEXT_EXTENT", "MIN_EXTENTS", "MAX_EXTENTS", "PCT_INCREASE", "BACKED_UP") AS
  SELECT USER_TABLES.TABLE_NAME,
	USER_TABLES.TABLESPACE_NAME,
	USER_TABLES.CLUSTER_NAME,
	USER_TABLES.PCT_FREE,
	USER_TABLES.PCT_USED,
	USER_TABLES.INI_TRANS,
	USER_TABLES.MAX_TRANS,
	USER_TABLES.INITIAL_EXTENT,
	USER_TABLES.NEXT_EXTENT,
	USER_TABLES.MIN_EXTENTS,
	USER_TABLES.MAX_EXTENTS,
	USER_TABLES.PCT_INCREASE,
	USER_TABLES.BACKED_UP
FROM USER_TABLES
UNION
SELECT USER_VIEWS.VIEW_NAME,
	'VIEW',
	'',
	0,
	0,
	0,
	0,
	0,
	0,
	0,
	0,
	0,
	'F'
	FROM USER_VIEWS;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."UUIDVIEW" ("ADR_GR", "E_MANDANT", "VORGANG", "TRANSFER_ID", "ADR_NR_RE", "PERSON_NR_RE", "MODIFIED_ON", "UUID_AUFT", "UUID_POS", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "AUFT_NR", "AUF_POS", "STAORD_NR", "DISPO_NR") AS
  select u.adr_gr, u.e_mandant, u.vorgang, u.transfer_id, u.adr_nr, u.person_nr, u.modified_on,
	u.uuid_auft, u.uuid_pos, u.adr_nr, u.person_nr, u.obj_nr, u.ausg, u.abo_nr, u.auft_nr, u.auf_pos, u.staord_nr, u.dispo_nr
from uuidref u
where u.uuid_auft = u.uuid_pos
union
select u.adr_gr, u.e_mandant, u.vorgang, u.transfer_id, a.adr_nr_bv, a.person_nr_bv, u.modified_on,
	u.uuid_auft, u.uuid_pos, u.adr_nr, u.person_nr, u.obj_nr, u.ausg, u.abo_nr, u.auft_nr, u.auf_pos, u.staord_nr, u.dispo_nr
from uuidref u join abostamm a
on a.adr_gr = u.adr_gr and a.e_mandant = u.e_mandant and a.adr_nr = u.adr_nr and a.person_nr = u.person_nr and a.obj_nr = u.obj_nr and a.ausg = u.ausg and a.abo_nr = u.abo_nr
union
select u.adr_gr, u.e_mandant, u.vorgang, u.transfer_id, a.adr_nr_re, a.person_nr_re, u.modified_on,
	u.uuid_auft, u.uuid_pos, u.adr_nr, u.person_nr, u.obj_nr, u.ausg, u.abo_nr, u.auft_nr, u.auf_pos, u.staord_nr, u.dispo_nr
from uuidref u join buauftra a
on a.auft_nr = u.auft_nr
union
select u.adr_gr, u.e_mandant, u.vorgang, u.transfer_id, s.adr_nr_re, s.person_nr_re, u.modified_on,
	u.uuid_auft, u.uuid_pos, u.adr_nr, u.person_nr, u.obj_nr, u.ausg, u.abo_nr, u.auft_nr, u.auf_pos, u.staord_nr, u.dispo_nr
from uuidref u join bustaord s
on s.e_mandant = u.e_mandant and s.staord_nr = u.staord_nr
union
select u.adr_gr, u.e_mandant, u.vorgang, u.transfer_id, p.adr_nr_beleg, p.person_nr, u.modified_on,
	u.uuid_auft, u.uuid_pos, u.adr_nr, u.person_nr, u.obj_nr, u.ausg, u.abo_nr, u.auft_nr, u.auf_pos, u.staord_nr, u.dispo_nr
from uuidref u join dispo d
on d.adr_gr = u.adr_gr and d.adr_nr = u.adr_nr and d.auft_nr = u.auft_nr and d.auft_hist_nr = 0 and d.dispo_nr = u.dispo_nr and d.dispo_hist_nr = 0
join apostweg p
on p.adr_gr = u.adr_gr and p.adr_nr = u.adr_nr and p.auft_nr = u.auft_nr and p.auft_hist_nr = 0;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VACRMV_AUFTRAG" ("MODIFIED_ON", "BESTELL_NR_EXTERN", "MANDANT", "AUFTRAG_ID", "AUFTRAG_ID2", "LEISTUNGSEMPFAENGER_ID", "LEISTUNGSEMPFAENGER_NAME", "LEISTUNGSEMPFAENGER_ZH", "LEISTUNGSEMPFAENGER", "LEISTUNGSEMPFAENGER_PNR", "RECHNUNGSEMPFAENGER_ID", "RECHNUNGSEMPFAENGER_NAME", "RECHNUNGSEMPFAENGER_ZH", "RECHNUNGSEMPFAENGER", "RECHNUNGSEMPFAENGER_PNR", "BESTELLER_ID", "BESTELLER_NAME", "BESTELLER_ZH", "BESTELLER", "BESTELLER_PNR", "AUFTRAGSSTATUS", "POSITIONSSTATUS", "BESTELL_DATUM", "ARTIKEL_NR", "ARTIKEL_NAME", "ANZAHL_ARTIKEL_BERECHNET", "ANZAHL_ARTIKEL_FREI", "ANZAHL_ARTIKEL_RETOUR", "AKTIONS_ID", "AKTIONS_BEZEICHNUNG", "WAEHRUNG", "PREIS_LISTE", "PREIS_POSITION_GESAMT", "POSITIONSRABATTCODE", "POSITIONSRABATT", "PREIS_POSITION_ABZGL_RABATT", "AUFTRAGSRABATTCODE", "AUFTRAGSRABATT", "PREIS_NETTO", "PREIS_MWST", "PREIS_BRUTTO", "BRUTTO_NETTO", "ABRECHNUNGSART", "ZAHLUNGSCODE", "ZAHLUNGSART", "FAKTURA_NR", "NOTIZ", "CREATED_DATE", "CREATED_USER", "UPDATE_DATE", "UPDATE_USER") AS
  SELECT BAT.modified_on,	TREF.key_ext_char_3, BAV.E_MANDANT, BAV.AUFT_NR, ('va-' || BAV.AUFT_NR || '-' || BAV.AUF_POS),
	(
		CASE
		WHEN (PLE.a_typ = 'F') THEN
			('c-unt-' || PLE.adr_nr)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'M') THEN
			(
				'c-mit-' || PLE.adr_nr || '-' || PLE.person_nr
			)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'P') THEN
			('c-per-' || PLE.adr_nr)
		ELSE
			('c-err-' || PLE.adr_nr)
		END
		END
		END
	),
	TRIM (ALE.name1),
	(
		TRIM (PLE.nachname) || CASE
		WHEN (PLE.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (PLE.vorname)
	),
  PLE.adr_nr,
  PLE.person_nr,
	CASE
WHEN (PRE.adr_nr IS NULL) THEN
	(
		CASE
		WHEN (PLE.a_typ = 'F') THEN
			('c-unt-' || PLE.adr_nr)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'M') THEN
			(
				'c-mit-' || ple.adr_nr || '-' || ple.person_nr
			)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'P') THEN
			('c-per-' || ple.adr_nr)
		ELSE
			('c-err-' || PLE.adr_nr)
		END
		END
		END
	)
ELSE
	(
		CASE
		WHEN (pre.a_typ = 'F') THEN
			('c-unt-' || pre.adr_nr)
		ELSE
			CASE
		WHEN (pre.a_typ = 'M') THEN
			(
				'c-mit-' || pre.adr_nr || '-' || pre.person_nr
			)
		ELSE
			CASE
		WHEN (pre.a_typ = 'P') THEN
			('c-per-' || pre.adr_nr)
		ELSE
			('c-err-' || pre.adr_nr)
		END
		END
		END
	)
END,
 CASE
WHEN (pre.adr_nr IS NULL) THEN
	TRIM (Ale.name1)
ELSE
	TRIM (are.name1)
END,
 CASE
WHEN (pre.adr_nr IS NULL) THEN
	(
		TRIM (Ple.nachname) || CASE
		WHEN (Ple.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (Ple.vorname)
	)
ELSE
	(
		TRIM (pre.nachname) || CASE
		WHEN (Pre.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (pre.vorname)
	)
END,
CASE
WHEN (PRE.adr_nr IS NULL) THEN
  PLE.adr_nr
ELSE
  PRE.adr_nr
END,
CASE
WHEN (PRE.adr_nr IS NULL) THEN
  PLE.person_nr
ELSE
  PRE.person_nr
END,
CASE
WHEN (PBE.adr_nr IS NULL) THEN
	(
		CASE
		WHEN (PLE.a_typ = 'F') THEN
			('c-unt-' || PLE.adr_nr)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'M') THEN
			(
				'c-mit-' || ple.adr_nr || '-' || ple.person_nr
			)
		ELSE
			CASE
		WHEN (PLE.a_typ = 'P') THEN
			('c-per-' || ple.adr_nr)
		ELSE
			('c-err-' || PLE.adr_nr)
		END
		END
		END
	)
ELSE
	(
		CASE
		WHEN (pbe.a_typ = 'F') THEN
			('c-unt-' || pbe.adr_nr)
		ELSE
			CASE
		WHEN (pbe.a_typ = 'M') THEN
			(
				'c-mit-' || pbe.adr_nr || '-' || pbe.person_nr
			)
		ELSE
			CASE
		WHEN (pbe.a_typ = 'P') THEN
			('c-per-' || pbe.adr_nr)
		ELSE
			('c-err-' || pbe.adr_nr)
		END
		END
		END
	)
END,
CASE
WHEN (pbe.adr_nr IS NULL) THEN
	TRIM (Ale.name1)
ELSE
	TRIM (abe.name1)
END,
 CASE
WHEN (pbe.adr_nr IS NULL) THEN
	(
		TRIM (Ple.nachname) || CASE
		WHEN (Ple.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (Ple.vorname)
	)
ELSE
	(
		TRIM (pbe.nachname) || CASE
		WHEN (Pbe.vorname IS NULL) THEN
			''
		ELSE
			','
		END || TRIM (pbe.vorname)
	)
END,
CASE
WHEN (PBE.adr_nr IS NULL) THEN
  PLE.adr_nr
ELSE
  PBE.adr_nr
END,
CASE
WHEN (PBE.adr_nr IS NULL) THEN
  PLE.person_nr
ELSE
  PBE.person_nr
END,
BAV.STATUS,
BAV.POS_STATUS,
BAV.BEST_DATUM,
BAV.artikel_nr,
CASE WHEN (bga.l_titel_nr = 0) THEN COALESCE(bus.artikel_bez,bga.ausg_text) ELSE but.titel1 END,
BAV.BER_MENGE,
BAV.FREI_MENGE,
BAV.RETOUR_MENGE,
BAV.AKT_ID,
WA.b_aktid,
BAT.WAEHRUNG,
BAP.EINZEL_PREIS,
BAP.GES_PREIS,
BAP.BU_RA,
BAP.RAB_PROZ,
BAP.POS_BETRAG,
BAT.BU_RA,
BAT.RAB_PROZ,
BAV.RE_NETTO,
BAV.RE_MWST,
BAV.RE_BRUTTO,
BAP.brut_net,
BAT.R_ART,
ZB.Z_BED,
ZB.BESCHREIBUNG,
BAV.RECH_NR,
BAT.AUFTRAG_TEXT,
BAT.DATUM_NEU,
BAT.B_ID_NEU,
BAT.DATUM_AEND,
BAT.B_ID_AEND
FROM
	BUAAVIEW BAV
JOIN BUAUFTRA bat ON (BAT.AUFT_NR = BAV.AUFT_NR AND BAT.HERKUNFT = 'VA')
JOIN BUAUFPOS bap ON (BAV.AUFT_NR = BAP.AUFT_NR AND BAV.AUF_POS=BAP.AUF_POS)
JOIN ZAHLBED zb ON (
	BAT.Z_BED = ZB.Z_BED
	AND BAT.E_MANDANT = ZB.E_MANDANT
)
JOIN BUAUSGAB bga ON (bga.L_AUSG_NR = bav.L_AUSG_NR)
LEFT JOIN BUTITEL but ON (but.L_TITEL_NR = bga.l_titel_nr)
LEFT JOIN BUAUSSPR bus ON (bus.L_AUSG_NR = bav.L_AUSG_NR and bus.SPRACH_CODE = 'D')
LEFT JOIN mhaktion wa ON (wa.e_mandant = BAV.e_mandant and wa.akt_id = BAV.akt_id)
LEFT JOIN person PLE ON (
	PLE.adr_gr = BAT.adr_gr
	AND PLE.adr_nr = BAT.ADR_NR_le
	AND PLE.person_nr = BAT.person_nr_le
)
LEFT JOIN person PRE ON (
	PRE.adr_gr = BAT.adr_gr
	AND PRE.adr_nr = BAT.ADR_NR_re
	AND PRE.person_nr = BAT.person_nr_re
)
LEFT JOIN person PBE ON (
	PBE.adr_gr = BAT.adr_gr
	AND PBE.adr_nr = BAT.ADR_NR_best
	AND PBE.person_nr = BAT.person_nr_best
)
LEFT JOIN anschr ALE ON (
	ALE.adr_gr = BAT.adr_gr
	AND ALE.adr_nr = BAT.adr_nr_le
)
LEFT JOIN anschr ARE ON (
	ARE.adr_gr = BAT.adr_gr
	AND ARE.adr_nr = BAT.adr_nr_re
)
LEFT JOIN anschr ABE ON (
	ABE.adr_gr = BAT.adr_gr
	AND ABE.adr_nr = BAT.adr_nr_best
)
LEFT JOIN transref TREF ON (
  TREF.transfer_id = 'COVCRM_' || BAT.e_mandant
  AND TREF.kunde = 'FAL'
  AND TREF.bereich = 'BUABO'
  AND TREF.verwend_typ = 'WSVIMP'
  AND TREF.referenz_typ = 'EXT_NR_AUFT_NR'
  AND TREF.key_cov_char_1 is null
	AND TREF.key_cov_char_4 = BAT.auft_nr
)
WHERE (bav.rech_typ like 'R%' and (bav.rech_typ != 'RS' or bav.r_art != 'P' or bav.p_status_lief != 'F') and (bav.rech_typ != 'RO' or bav.r_art != 'P')
    OR bav.rech_typ like 'G%'
    OR (bav.rech_typ like 'L%' and bav.rech_ref is null)
    OR bav.rech_nr is null
    );


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VACRMV_TITEL" ("MODIFIED_ON", "TITEL_ID", "E_MANDANT", "ARTIKEL_NR", "ISBN", "EAN", "ARTIKEL_BEZ", "AUFLAGEN_NR", "AUFLAGEN_BEZ", "MENGE") AS
  select b.modified_on, 'V-' || m.e_mandant || '-' || b.l_ausg_nr || '-' || l.l_aufl_nr, m.e_mandant, m.artikel_nr, b.isbn, b.ean, case when (b.l_titel_nr = 0) then coalesce(s.artikel_bez,b.ausg_text) else t.titel1 end, 0, l.aufl_text,
(select sum(g.ges_menge) - sum(g.anz_reserv) from bulagges g where g.e_mandant = m.e_mandant and g.l_ausg_nr = l.l_ausg_nr and g.l_aufl_nr = l.l_aufl_nr) -
coalesce((select sum(i.min_best) from bulagmin i where i.e_mandant = m.e_mandant and i.l_ausg_nr = l.l_ausg_nr and i.l_aufl_nr = l.l_aufl_nr),0)
from	BUAUSGAB b
	left join BUAUSSPR s on	(s.l_ausg_nr = b.l_ausg_nr and s.sprach_code = 'D')
	left join BUTITEL t on (t.l_titel_nr = b.l_titel_nr)
	join BUMANAUS m on (m.l_ausg_nr = b.l_ausg_nr)
	join BUAUFL l on (l.l_ausg_nr = b.l_ausg_nr and l.l_aufl_nr = 0)
where	b.herkunft = 'VA' and b.kz_aufl_best = 'F'
union
select b.modified_on, 'V-' || m.e_mandant || '-' || b.l_ausg_nr || '-' || l.l_aufl_nr, m.e_mandant, m.artikel_nr, b.isbn, b.ean, case when (b.l_titel_nr = 0) then coalesce(s.artikel_bez,b.ausg_text) else t.titel1 end, l.auflage_nr, l.aufl_text,
(select sum(g.ges_menge) - sum(g.anz_reserv) from bulagges g where g.e_mandant = m.e_mandant and g.l_ausg_nr = l.l_ausg_nr and g.l_aufl_nr = l.l_aufl_nr) -
coalesce((select sum(i.min_best) from bulagmin i where i.e_mandant = m.e_mandant and i.l_ausg_nr = l.l_ausg_nr and i.l_aufl_nr = l.l_aufl_nr),0)
from	BUAUSGAB b
	left join BUAUSSPR s on	(s.l_ausg_nr = b.l_ausg_nr and s.sprach_code = 'D')
	left join BUTITEL t on (t.l_titel_nr = b.l_titel_nr)
	join BUMANAUS m on (m.l_ausg_nr = b.l_ausg_nr)
	join BUAUFL l on (l.l_ausg_nr = b.l_ausg_nr and l.l_aufl_nr > 0)
where	b.herkunft = 'VA' and b.kz_aufl_best = 'T';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VASELVIE" ("L_TITEL_NR", "AUTOR_NR", "L_AUSG_NR", "TITEL_SUCH", "TITEL1", "ORG_SPR_CODE", "RANK_ID", "ADR_GR", "ADR_NR_AUT", "PERSON_NR_AUT", "ZUSATZ", "AUTOR_TYP", "KZ_HPAUT", "E_MANDANT", "PROD_TYP", "AUSG_TEXT", "LAND_CODE", "BU_LA_ID", "BEGINN_ID", "QM_ID", "QAUS", "Q_CODE", "Q_AUSP_CODE", "A_TYP", "SUM_PUNKTE", "D_ANZ_TN", "D_ANZ_ABOS", "D_ANZ_ABOS_2", "L_AUFL_NR", "AUFLAGE_NR", "HERKUNFT", "ANZ_TERMIN", "AUFL_HOEHE", "KZ_LOESCHEN", "ANZ_TN") AS
  select a.l_titel_nr, a.autor_nr, b.l_ausg_nr, t.titel_such, t.titel1, t.org_spr_code, t.rank_id, a.adr_gr, a.adr_nr_aut, a.person_nr_aut,
       a.zusatz, a.autor_typ, a.kz_hpaut, m.e_mandant, b.prod_typ,
       to_number(regexp_replace(b.ausg_text,'[^[:digit:]]')),
       b.land_code, b.bu_la_id, k.beginn_id, q.qm_id, q.qaus,
       w.q_code, w.q_ausp_code, w.a_typ, sum(p.punkte),
       (case when o.d_anz_tn is Null then 0 else o.d_anz_tn end)/(case when o.anz_termin=0 then 1 else o.anz_termin end),
       o.d_anz_abo/(case when o.anz_termin=0 then 1 else o.anz_termin end), o.d_anz_abo, l.l_aufl_nr, l.auflage_nr, b.herkunft,
       (case when o.anz_termin=0 then 1 else o.anz_termin end), l.aufl_hoehe, b.kz_loeschen, (case when o.d_anz_tn is Null then 0 else o.d_anz_tn end)
from  buautor a, butitel t, buausgab b, bumanaus m, koausbeg k, buartqa q, qwerte w, konto p, buaufl l, tnabovie o
where t.l_titel_nr = a.l_titel_nr and
      b.l_titel_nr  = a.l_titel_nr and
      m.l_ausg_nr  = b.l_ausg_nr and
      l.l_ausg_nr  = b.l_ausg_nr and
      k.l_ausg_nr (+) = b.l_ausg_nr and
      q.l_ausg_nr (+) = b.l_ausg_nr and
      w.adr_gr (+) = a.adr_gr and
      w.adr_nr (+) = a.adr_nr_aut and
      w.person_nr (+) = a.person_nr_aut and
      p.adr_gr (+) = a.adr_gr and
      p.adr_nr (+) = a.adr_nr_aut and
      p.person_nr (+) = a.person_nr_aut and
      l.l_ausg_nr  = o.l_ausg_nr and
      l.l_aufl_nr  = o.l_aufl_nr and
      a.l_titel_nr  = o.l_titel_nr and
      a.autor_nr  = o.autor_nr
group by a.l_titel_nr, a.autor_nr, b.l_ausg_nr, t.titel_such, t.titel1, t.org_spr_code, t.rank_id, a.adr_gr, a.adr_nr_aut, a.person_nr_aut,
       a.zusatz, a.autor_typ, a.kz_hpaut, m.e_mandant, b.prod_typ, b.ausg_text, b.land_code, b.bu_la_id, k.beginn_id, q.qm_id, q.qaus,
       w.q_code, w.q_ausp_code, w.a_typ,
       (case when o.d_anz_tn is Null then 0 else o.d_anz_tn end)/(case when o.anz_termin=0 then 1 else o.anz_termin end),
       o.d_anz_abo/(case when o.anz_termin=0 then 1 else o.anz_termin end), o.d_anz_abo, l.l_aufl_nr, l.auflage_nr, b.herkunft,
       (case when o.anz_termin=0 then 1 else o.anz_termin end), l.aufl_hoehe, b.kz_loeschen, (case when o.d_anz_tn is Null then 0 else o.d_anz_tn end)
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VERGEVIE" ("VERTRETER_ID", "LAND_CODE", "ADR_NR", "PERSON_NR_LE", "REG_ID", "REG_CODE", "VERTRETER_KGS_VON", "ABO_KGS", "VERTRETER_KGS_BIS", "GEBIET") AS
  select v.vertreter_id, an.land_code, a.adr_nr, v.person_nr_le, typ.reg_id, typ.reg_code, r.kgs_von, a.kgs, r.kgs_bis,
		  (case when (((select min(a1.kgs_von) from regkgs a1 where a1.reg_code='GS' and a1.land_code='D')) <= r.kgs_von and
					  ((select max(a2.kgs_bis) from regkgs a2 where a2.reg_code='GS' and a2.land_code='D')) >= r.kgs_bis) then 'GS' else 'GN' end)
	 from vzveprov v, ainfo a, anschr an, vztyptmp typ, regkgs r
	   where v.kz_abo_bringer = 'T'
	   and v.adr_gr = a.adr_gr and v.adr_nr_le = a.adr_nr
	   and a.adr_gr = an.adr_gr and a.adr_nr = an.adr_nr
	   and v.vertreter_id = typ.vertreter_id
	   and v.vertreter_typ = typ.vertreter_typ
	   and an.land_code = r.land_code
	   and typ.reg_id = r.reg_id
	   and typ.reg_code = r.reg_code
	   and r.kgs_von <= a.kgs
	   and r.kgs_bis >= a.kgs
	  ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VERKUVIE" ("E_MANDANT", "LFD_NR", "AKT_ID", "ADR_NR", "PERSON_NR", "A_TYP", "Q_CODE", "Q_AUSP_CODE", "HERKUNFT", "GUELTIG_AB", "UPOS_NR", "PROV_GRP", "L_AUSG_NR", "VERTRETER_ID") AS
  SELECT a.e_mandant, a.lfd_nr, a.akt_id, a.adr_nr, a.person_nr, a.a_typ, a.q_code, a.q_ausp_code, a.herkunft, a.gueltig_ab,
       b.upos_nr, b.prov_grp, b.l_ausg_nr, b.vertreter_id
FROM   vzverkon a, vzveruko b
WHERE  a.lfd_nr   = b.lfd_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VERPVIEW" ("E_MANDANT", "OBJ_NR", "AUSG", "ABRUNR", "NUMMER", "BUND_NR", "ZAEHLER", "PZD", "ETI1", "ETI2", "ETI3", "ETI4", "ETI5", "ETI6", "ETI7", "ETI8", "ETI9", "ETI10", "JAHR", "HNR", "ADR_GR", "ADR_NR", "PERSON_NR", "ABO_NR", "VERSEINH", "L_MENGE", "PV_KZ", "VERSART", "PREIS_KAT", "VERB_CODE", "UVERB_CODE", "EXTERNE_NR", "KZ_FREMD", "PLZ", "ADR_NR_9", "ORT", "AUFTCODE", "REG_CODE", "RECH_NR", "STRASSE", "HAUSNR", "HAUSNR_ZUS", "OBJ_NAME", "AUSG_NAME", "NAME1", "NAME2", "NAME3", "ANREDE", "TITEL", "VORNAME", "NACHNAME", "LANDNAME", "POSTFACH") AS
  select p.e_mandant,p.obj_nr,p.ausg,p.abrunr,p.nummer,p.bund_nr,p.zaehler,v.pzd,
       v.eti1,v.eti2,v.eti3,v.eti4, v.eti5,v.eti6,v.eti7,v.eti8,v.eti9,v.eti10,
       v.jahr,v.hnr,v.adr_gr,v.adr_nr,v.person_nr,
       v.abo_nr,v.verseinh,v.l_menge,v.pv_kz,v.versart,v.preis_kat,v.verb_code,
       v.uverb_code,'','0', v.plz, v.adr_nr, v.ort, v.auftcode,r.reg_code,v.rech_nr,
       v.strasse,v.hausnr,v.hausnr_zus,v.obj_name,v.ausg_name,v.name1,v.name2,v.name3,
       v.anrede,v.titel,v.vorname,v.nachname,v.landname,v.postfach
  from popsort p, versausg v,  anschreg r
 where p.e_mandant  = v.e_mandant and
       p.obj_nr     = v.u_obj_nr and
       p.ausg       = v.u_ausg and
       p.abrunr     = v.abrunr and
       p.nummer     = v.lfd_nr and
       v.adr_gr = r.adr_gr(+) and
       v.adr_nr = r.adr_nr(+) and
       r.reg_id(+) = 'NI';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VERTVIEW" ("VERTRETER_ID", "OBJ_NR", "AUSG") AS
  SELECT DISTINCT vertreter_id,obj_nr,ausg
FROM vertbuch;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VERWEND3" ("ADR_GR", "ADR_NR", "PERSON_NR", "ADR_NR_BV", "OBJ_NR", "AUSG", "ABO_NR", "E_MANDANT", "HAUPT_NAME", "STRASSE", "PLZ_WOHN", "WOHNORT", "LAND_CODE", "POSTFACH", "PLZ_POST", "POSTORT") AS
  SELECT a.adr_gr, a.adr_nr, a.person_nr, a.adr_nr_bv,
       a.obj_nr, a.ausg, a.abo_nr, a.e_mandant,
       b.haupt_name, b.strasse, b.plz_wohn, b.wohnort,
       b.land_code, b.postfach, b.plz_post, b.postort
FROM   abostamm a, anschr b
WHERE  b.adr_gr  = a.adr_gr
AND    b.adr_nr  = a.adr_nr_bv;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VHD_FASUVIEW" ("E_MANDANT", "L_AUSG_NR", "L_AUFL_NR", "JAHR_MONAT", "AUFTRAG_TYP", "WAEHRUNG", "SUM_BERECHNET", "SUM_FREI", "SUM_REMITTEND", "SUM_BRUTTO_BETR", "SUM_PARTIE") AS
  select e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung,
          sum(sum_berechnet), sum(sum_frei), sum(sum_remittend), sum(sum_brutto_betr),
          sum(sum_partie)
from   bufaksum
where preis_kat != 'EKP'
group by e_mandant, l_ausg_nr, l_aufl_nr, jahr_monat, auftrag_typ, waehrung
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VHD_UMRECHNUNG_SFR" ("KURS_SFR") AS
  select to_number(kurs)
from waehkurs a
  where a.waehrung = 'SFR' and a.ziel_waehr = 'EUR'
  and a.stichtag =
     (select max(b.stichtag) from waehkurs b
      where a.waehrung = b.waehrung
      and a.ziel_waehr = b.ziel_waehr
      and b.stichtag <= sysdate);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VIEWQSTE" ("ADR_GR", "ADR_NR", "PERSON_NR", "A_TYP", "Q_CODE", "Q_AUSP_CODE", "QSTEUER_ID", "LFD_NR", "Q_AUSP_PRIO") AS
