       a.name1, a.name2, p.vorname, p.nachname, b.adr_nr_bv, b.person_nr, p.a_typ, p.anrede_code,
       p.titel_code,  b.e_mandant, b.obj_nr, b.ausg, b.abostatus, b.ber_menge, b.preis_kat,
       b.dat_fakt_von, b.dat_fakt_bis, b.r_beg_dat, b.r_ende_dat, b.r_beg_hnr,b.r_ende_hnr,
       b.r_beg_jahr, b.r_ende_jahr, b.r_art, v.versart, b.fakt_zr, a.name3
  from abostamm b, person p, anschr a, abovers v
 where b.adr_gr = a.adr_gr and b.adr_nr_bv = a.adr_nr
   and b.adr_gr = p.adr_gr and a.adr_nr = p.adr_nr
   and b.person_nr_bv = p.person_nr
   and b.adr_nr_bv <> b.adr_nr
   and b.adr_gr = v.adr_gr and b.adr_nr = v.adr_nr and b.person_nr = v.person_nr
