  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VLS1VIEW" ("ADR_GR", "ADR_NR", "ABO_NR", "LAND_CODE", "SPRACH_CODE", "L_MENGE", "HAUPT_PLZ", "HAUPT_ORT", "HAUPT_NAME", "NAME1", "VORNAME", "NACHNAME", "S_ADNR", "PERSON_NR", "A_TYP", "ANREDE_CODE", "TITEL_CODE", "E_MANDANT", "OBJ_NR", "AUSG", "ABOSTATUS", "BER_MENGE", "PREIS_KAT", "NAME2", "NAME3") AS
