  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VLS3VIEW" ("ADR_GR", "ADR_NR", "ABO_NR", "LAND_CODE", "SPRACH_CODE", "L_MENGE", "HAUPT_PLZ", "HAUPT_ORT", "HAUPT_NAME", "NAME1", "NAME2", "VORNAME", "NACHNAME", "S_ADNR", "PERSON_NR", "A_TYP", "ANREDE_CODE", "TITEL_CODE", "E_MANDANT", "OBJ_NR", "AUSG", "ABOSTATUS", "BER_MENGE", "PREIS_KAT", "DAT_FAKT_VON", "DAT_FAKT_BIS", "R_BEG_DAT", "R_ENDE_DAT", "R_BEG_HNR", "R_ENDE_HNR", "R_BEG_JAHR", "R_ENDE_JAHR", "R_ART", "VERSART", "FAKT_ZR", "NAME3") AS
