       v.l_menge, a.haupt_plz,  a.haupt_ort, a.haupt_name
       ,a.name1, a.name2, p.vorname, p.nachname, v.s_adnr,
       b.person_nr, p.a_typ, p.anrede_code,
       p.titel_code,  b.e_mandant, b.obj_nr, b.ausg, b.abostatus,
       b.ber_menge, b.preis_kat, b.dat_fakt_von, b.dat_fakt_bis,
       b.r_beg_dat, b.r_ende_dat, b.r_beg_hnr, b.r_ende_hnr,
       b.r_beg_jahr, b.r_ende_jahr, b.r_art, v.versart, b.fakt_zr, a.name3
  from abovers v, abostamm b, person p, anschr a
 where v.s_adnr is not null and b.adr_gr = v.adr_gr and b.adr_nr = v.adr_nr
   and b.person_nr = v.person_nr and b.e_mandant = v.e_mandant
   and b.obj_nr = v.obj_nr and b.ausg = v.ausg and b.abo_nr = v.abo_nr
   and a.adr_gr = b.adr_gr and a.adr_nr = b.adr_nr
