  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VOE_ONIXPRODUCT" ("RECORDIDENTIFIER", "RECORDREFERENCE", "NOTIFICATIONTYPE", "PUBLISHERORDERID", "PRODUCTISBN13", "PRODUCTEAN", "BARCODE", "PRODUCTFORM", "PRODUCTFORMDETAIL", "DISTINCTIVETITLE", "SUBTITLE", "ORIGINALTITLE", "ORIGINALSUBTITLE", "CONTRIBUTORSTATEMENT", "NOCONTRIBUTOR", "EDITIONNUMBER", "NOEDITION", "LANGUAGEOFTEXT", "ORIGINALLANGUAGE", "NUMBEROFPAGES", "PUBLISHERCODE", "PUBLISHERNAME", "PUBLISHERWEBSITE", "PUBLISHINGSTATUS", "PUBLICATIONDATEYEAR", "PUBLICATIONDATEMONTH", "PUBLICATIONDATEDAY", "COPYRIGHTYEAR", "PRODUCTHEIGHT", "PRODUCTWIDTH", "PRODUCTTHICKNESS", "PRODUCTWEIGHT", "REPLACESISBN", "REPLACEDBYISBN", "PRODUCTAVAILABILITY", "EXPECTEDSHIPDATEYEAR", "EXPECTEDSHIPDATEMONTH", "EXPECTEDSHIPDATEDAY", "ONSALEDATE", "UNPRICEDITEMTYPE") AS
  select
a.l_ausg_nr, a.ean, '03', trim(m.artikel_nr), a.ean, a.ean, trim(q1.qaus),
trim(h.einbandart), trim(h.einbandart),trim(t.titel1), trim(t.titel_unter), trim(t.orig_titel), trim(t.orig_u_titel),
trim(k.ContributorStatement),
k.NoContributor,
b0.auflage_nr, 1,
trim(t.sprach_code), trim(t.org_spr_code), trim(h.umfang),
decode(a.verlags_id, null, null, (decode(trim(bv.verkehrs_nr), null, '05/'||trim(bv.kenn_nr),
'04/'||trim(substr(bv.verkehrs_nr,1,5))))), decode(a.verlags_id, null, null,trim(bv.verlag_lang)),
decode(a.verlags_id, null, null,trim(bv.website)), trim(b0.meld_nr),
b0.ist_jahr, b0.ist_monat, b0.ist_tag,
null, decode(round((a.hoehe * 10), 0),0,null,round((a.hoehe * 10), 0)), decode(round((a.breite *
10),0),0,null,round((a.breite * 10),0)), decode(round((a.dicke * 10),0),0,null,round((a.dicke * 10),0)),
decode(a.gewicht,0,null,a.gewicht), a2.ean, a3.ean,
trim(b0.meld_nr), b0.soll_jahr, b0.soll_monat, b0.soll_tag,
null, o.UnpricedItemType
from
buausgab a, buausgab a2, buausgab a3, bumanaus m, bumanaus m2,
butitel t, buoxaufl b0,  bugruppe g,
buartqa q1,
onixohnepreis o, onixkeinautor k, buherste h, onixmandant om, buverlag bv
where
a.l_titel_nr = t.l_titel_nr and
a.l_ausg_nr = m.l_ausg_nr and
a2.l_ausg_nr (+) = m2.l_ausg_nr and
a3.l_ausg_nr (+) = m.l_ausg_nr_neu and
b0.l_ausg_nr  = a.l_ausg_nr and
g.l_titel_nr (+) = a.l_titel_nr and
q1.l_ausg_nr (+) = a.l_ausg_nr and
q1.prod_typ (+) = a.prod_typ and
q1.qm_id (+) = 'BARCODE' and
a.kombityp in ('E','B', 'V', 'M', 'Z', 'S') and
a.ean is not null and
a.isbn is not null and
m2.e_mandant (+) = m.e_mandant and
m2.l_ausg_nr_neu (+) = m.l_ausg_nr and
a.kz_aufl_best = 'F' and
a.kz_eigen = 'T' and
o.l_ausg_nr (+) = a.l_ausg_nr and
k.l_ausg_nr = a.l_ausg_nr and
h.l_ausg_nr (+) = a.l_ausg_nr and
m.e_mandant = om.e_mandant and
bv.verlags_id (+) = a.verlags_id ;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VORGVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "ADR_NR_RECH", "PERSON_NR_RECH", "ADR_NR_LIEF", "PERSON_NR_LIEF", "BEREICH", "VORG_TYP", "VORGANG", "MANDANT", "REF_NR", "TYP", "STATUS", "KZ_STORNO", "OBJ_NR", "AUSG", "WAEHRUNG", "NETTO_BETRAG", "MENGE", "RECH_ART", "BESTELL_DATUM", "LAUFZEIT_VON", "LAUFZEIT_BIS", "TEXT", "HNR_NUM", "HNR_NUM_BIS", "DATUM_NEU", "B_ID_NEU", "DATUM_AEND", "B_ID_AEND", "ATTR_1", "ATTR_2", "ATTR_3", "ATTR_4", "ATTR_5") AS
  select s.adr_gr, s.adr_nr, s.person_nr,
	s.adr_nr_bv, s.person_nr_bv, 0, 0,
	'VZ', 'ABO  ', 'ABO  ',
	s.e_mandant, s.abo_nr, ' ', s.abostatus, s.kz_storno,
	s.obj_nr, s.ausg, s.waehrung, f.l_rbetrag, s.ber_menge,
	s.r_art, s.best_datum, s.vbeg_dat, s.vend_dat,
	s.best_nr||'          ',
        1000*s.vbeg_jahr, 1000*s.vend_jahr,
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend,
	s.preis_kat, '', s.vbeg_heft||';'||s.preis_kat_no, s.w_akt_id||'        ', s.w_uakt_id
from ABOSTAMM s, ABOFAKT f
where	s.adr_gr    = f.adr_gr(+)
and	s.adr_nr    = f.adr_nr(+)
and 	s.person_nr = f.person_nr(+)
and	s.e_mandant = f.e_mandant(+)
and 	s.obj_nr    = f.obj_nr(+)
and 	s.ausg      = f.ausg(+)
and 	s.abo_nr    = f.abo_nr(+)
union
select s.adr_gr, s.adr_nr_bv, s.person_nr_bv,
	s.adr_nr_bv, s.person_nr_bv, s.adr_nr, s.person_nr,
	'VZ', 'ABO  ', 'ABORE',
	s.e_mandant, s.abo_nr, ' ', s.abostatus, s.kz_storno,
	s.obj_nr, s.ausg, s.waehrung, f.l_rbetrag, s.ber_menge,
	s.r_art, s.best_datum, s.vbeg_dat, s.vend_dat,
	s.best_nr||'          ',
        1000*s.vbeg_jahr, 1000*s.vend_jahr,
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend,
	s.preis_kat, '', s.vbeg_heft||';'||s.preis_kat_no, s.w_akt_id, s.w_uakt_id
from ABOSTAMM s, ABOFAKT f
where   s.adr_nr    <> s.adr_nr_bv
and	s.adr_gr    = f.adr_gr(+)
and	s.adr_nr    = f.adr_nr(+)
and 	s.person_nr = f.person_nr(+)
and	s.e_mandant = f.e_mandant(+)
and 	s.obj_nr    = f.obj_nr(+)
and 	s.ausg      = f.ausg(+)
and 	s.abo_nr    = f.abo_nr(+)
union
select w.adr_gr, w.w_adr_nr, w.w_person_nr,
	w.adr_nr, w.person_nr, 0, w.pos_nr,
	'VZ', 'ABO  ', 'ABOWP',
	w.e_mandant, w.abo_nr, ' ', s.abostatus, s.kz_storno,
	w.obj_nr, w.ausg, s.waehrung, w.EINZEL_PREIS, s.ber_menge,
	s.r_art, s.best_datum, s.vbeg_dat, s.vend_dat,
	s.best_nr||'          ',
--OFF-AD/11.5.23 1000*s.vbeg_jahr, 1000*s.vend_jahr, --dafur Artikel-PK:
        w.l_ausg_nr, w.l_aufl_nr,
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend,
	w.preiskat, '', s.vbeg_heft||';'||s.preis_kat_no, s.w_akt_id, s.w_uakt_id
from WERBEPRA w, ABOSTAMM s
where w.adr_gr    = s.adr_gr
and   w.adr_nr    = s.adr_nr
and   w.person_nr = s.person_nr
and   w.e_mandant = s.e_mandant
and   w.obj_nr    = s.obj_nr
and   w.ausg      = s.ausg
and   w.abo_nr    = s.abo_nr
union
select wb.adr_gr, wb.w_adr_nr, wb.w_person_nr,
	wb.adr_nr, wb.person_nr, 0, wb.pos_nr+100,   -- +100 zur Untersch.werbeprA/AD/24.11.22
	'VZ', 'ABO  ', 'ABOWP',
	wb.e_mandant, wb.abo_nr, ' ', s.abostatus, s.kz_storno,
	wb.obj_nr, wb.ausg, s.waehrung, 0, s.ber_menge,
	s.r_art, s.best_datum, s.vbeg_dat, s.vend_dat,
	s.best_nr||'          ',
        1000*s.vbeg_jahr, 1000*s.vend_jahr,
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend,
	wb.p_preiskat, '', wb.a_obj_nr||';'||substr(wb.a_ausg,1,8), wb.a_akt_id, wb.a_lfd_nr
from WERBEPRB wb, ABOSTAMM s
where wb.adr_gr    = s.adr_gr
and   wb.adr_nr    = s.adr_nr
and   wb.person_nr = s.person_nr
and   wb.e_mandant = s.e_mandant
and   wb.obj_nr    = s.obj_nr
and   wb.ausg      = s.ausg
and   wb.abo_nr    = s.abo_nr
union
select f.adr_gr, f.adr_nr, f.person_nr,
	f.adr_nr_obj, f.person_nr_obj, f.auftrags_nr, 0,
	'VZ', 'ABO  ', 'MANRE',
	f.e_mandant, f.man_nr, ' ', 'Z           ', ' ',
	f.obj_nr, f.ausg, f.waehrung, f.e_betrag, f.l_menge,
	f.r_art, f.ffakt_dat, f.buchdat_von, f.buchdat_bis,
	f.best_nr||'          ',
        1000*f.jahr, 1000*f.jahr_bis,
	f.datum_neu, f.b_id_neu, f.datum_aend, f.b_id_aend,
	f.preis_kat, '', f.hnr, f.w_akt_id, f.w_uakt_id
from FAKTMAN f
where buch_art in ('S','N')
union
select f.adr_gr, f.adr_nr, f.person_nr,
	f.adr_nr_obj, f.person_nr_obj, f.auftrags_nr, 0,
	'VZ', 'ABO  ', 'MANGS',
	f.e_mandant, f.man_nr, ' ', 'Z           ', ' ',
	f.obj_nr, f.ausg, f.waehrung, f.e_betrag, f.l_menge,
	f.r_art, f.ffakt_dat, f.buchdat_von, f.buchdat_bis,
	f.best_nr||'          ',
        1000*f.jahr, 1000*f.jahr_bis,
	f.datum_neu, f.b_id_neu, f.datum_aend, f.b_id_aend,
	f.preis_kat, '', f.hnr, f.w_akt_id, f.w_uakt_id
from FAKTMAN f
where buch_art in ('H','R')
union
select a.adr_gr, a.adr_nr_best, a.person_nr_best,
	a.adr_nr_re, a.person_nr_re, a.adr_nr_le, a.person_nr_le,
	'BU', 'BUCH ', 'BUCH ',
	a.e_mandant, a.auft_nr, a.auftrag_typ, a.status||'           ', a.storno,
	'   ', '            ', a.waehrung, a.betrag_ne, 0,
	a.r_art, a.best_datum, a.vers_soll_dat, a.vers_soll_dat,
        a.best_text,
	a.auftrag_verw, 0,
        a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	'', a.best_weg, a.versart, a.akt_id, a.uakt_id
from BUAUFTRA a
where a.herkunft is null
union
select a.adr_gr, a.adr_nr_re, a.person_nr_re,
	a.adr_nr_re, a.person_nr_re, a.adr_nr_le, a.person_nr_le,
	'BU', 'BUCH ', 'BUCHR',
	a.e_mandant, a.auft_nr, a.auftrag_typ, a.status||'           ', a.storno,
	'   ', '            ', a.waehrung, a.betrag_ne, 0,
	a.r_art, a.best_datum, a.vers_soll_dat, a.vers_soll_dat,
        a.best_text,
	a.auftrag_verw, 0,
        a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	'', a.best_weg, a.versart, a.akt_id, a.uakt_id
from BUAUFTRA a
where (a.adr_nr_best <> a.adr_nr_re
or a.adr_nr_best is null)
and a.herkunft is null
union
