from BUREZENS a
where  (a.auft_nr is null or a.auft_nr = 9999999999)
union
select a.adr_gr, a.adr_nr, a.person_nr,
	a.adr_nr, a.person_nr, a.adr_nr, a.person_nr,
	'BU', 'BUCH ', 'BUVOF',
	a.e_mandant, a.lfd_nr_vor, 'V', a.akt_id, 'F',
