union
select a.adr_gr, a.adr_nr, 0,
	0, 0, a.adr_nr_wa, 0,
	'FA', 'FLIES', 'FLIES',
	a.e_mandant, a.auft_nr, a.verwend_typ, '            ', a.kz_storno,
	a.obj_nr, a.ausg||'          ', a.waehrung, 0, 0,
	a.zahlungsart||' ', a.bdatum, a.auftrag_vom, a.auftrag_bis,
