        a.heft_ab_num, a.heft_bis_num,
	a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	a.abrech_id, '', '', '', 0
from AUFTRAG a
where	a.auft_hist_nr = 0
and 	a.verwend_typ  = 'G'
union
select  a.adr_gr, a.adr_nr_wa, 0,
	0, 0, a.adr_nr, 0,
	'EA', 'ANZ  ', 'ANZWA',
	a.e_mandant, a.auft_nr, a.verwend_typ, '            ', a.kz_storno,
	a.obj_nr, a.ausg||'          ', a.waehrung, 0, 0,
	a.zahlungsart||' ', a.bdatum, a.auftrag_vom, a.auftrag_bis,
	a.abschl_text||'          ',
        1000*a.jahr_ab + a.hnr_ab, 1000*a.jahr_bis + a.hnr_bis,
        a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	a.abrech_id, '', '', '', 0
from AUFTRAG a
where	a.auft_hist_nr = 0
and 	a.verwend_typ  != 'G'
and	a.adr_nr_wa > 0
union
select  a.adr_gr, p.adr_nr_beleg, 0,
	p.adr_nr_beleg, 0, a.adr_nr, 0,
	'EA', 'ANZ  ', 'ANZRE',
	a.e_mandant, a.auft_nr, a.verwend_typ, '            ', a.kz_storno,
	a.obj_nr, a.ausg||'          ', a.waehrung, 0, 0,
	a.zahlungsart||' ', a.bdatum, a.auftrag_vom, a.auftrag_bis,
	a.abschl_text||'          ',
        1000*a.jahr_ab + a.hnr_ab, 1000*a.jahr_bis + a.hnr_bis,
	a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	a.abrech_id, '', '', '', 0
from AUFTRAG a, APOSTWEG p
where	a.auft_hist_nr = 0
and     a.adr_gr           = p.adr_gr
