and	a.auft_hist_nr     = p.auft_hist_nr
and	p.auft_hist_nr     = 0
and 	p.belegart_id      = 'R'
and 	p.adr_nr_beleg     <> a.adr_nr
and 	p.adr_nr_beleg     <> a.adr_nr_wa
and 	a.adr_nr_wa        > 0
union
select  a.adr_gr, p.adr_nr_beleg, 0,
