	'EA', 'ANZ  ', 'ANZRE',
	a.e_mandant, a.auft_nr, a.verwend_typ, '            ', a.kz_storno,
	a.obj_nr, a.ausg||'          ', a.waehrung, 0, 0,
	a.zahlungsart||' ', a.bdatum, a.auftrag_vom, a.auftrag_bis,
	a.abschl_text||'          ',
        1000*a.jahr_ab + a.hnr_ab, 1000*a.jahr_bis + a.hnr_bis,
	a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	a.abrech_id, '', '', '', 0
from AUFTRAG a, APOSTWEG p
where	a.auft_hist_nr = 0
and     a.adr_gr           = p.adr_gr
and	a.adr_nr           = p.adr_nr
and	a.auft_nr          = p.auft_nr
and	a.auft_hist_nr     = p.auft_hist_nr
and	p.auft_hist_nr     = 0
and 	p.belegart_id      = 'R'
and 	p.adr_nr_beleg     <> a.adr_nr
and 	a.adr_nr_wa        is null
union
select  d.adr_gr, d.adr_nr, 0,
	0, 0, 0, 0,
	'DI', 'DISPO', 'DISPO',
	d.e_mandant, (d.auft_nr*1000+d.dispo_nr)*(-1), ' ', p.status_dispopos||'           ', ' ',
	p.obj_nr, p.ausg||'          ', '   ', d.netto_betrag, d.anz_anzeigen,
	d.zahlungsart||' ', d.bdatum, d.datum_neu, d.rech_datum,
	d.binfo||'                              ',
	p.hnr_num, d.heft_num,
	d.datum_neu, d.b_id_neu, d.datum_aend, d.b_id_aend,
	d.abrech_id, '', d.anzart_id,  d.obj_nr,
	d.volumen_mm*100 + d.volumen_fa
from ABSVIEW p, DISPO d
where	d.auft_hist_nr = 0
and	d.dispo_hist_nr = 0
and     d.adr_gr           = p.adr_gr
and	d.adr_nr           = p.adr_nr
and	d.auft_nr          = p.auft_nr
and	d.auft_hist_nr     = p.auft_hist_nr
and	d.dispo_nr         = p.dispo_nr
and	d.dispo_hist_nr    = p.dispo_hist_nr
union
select  d.adr_gr, d.adr_nr, 0,
	0, 0, 0, 0,
	'KA', 'KADIS', 'KADIS',
	'  ', d.dispo_nr*(-1), ' ', '            ', ' ',
	d.obj_nr, d.ausg||'          ', '   ', d.anzeigen_preis, 1,
	'  ', d.datum_neu, d.datum_neu, d.datum_neu,
              cast(substr(d.motiv,1,60) as char(60)),
	d.hnr_num, d.hnr_num,
	d.datum_neu, d.b_id_neu, d.datum_aend, d.b_id_aend,
	d.farb_id, '', d.anzart_id,
	d.format_id, d.anz_si*100+d.anz_seiten
from KADISPO d
union
select  d.adr_gr, d.adr_nr, 0,
	0, 0, 0, 0,
	'RD', 'REDKT', 'REDKT',
	d.e_mandant, d.lfd_nr*(-1), ' ', '            ', ' ',
	d.obj_nr, d.ausg||'          ', '   ', 0, 1,
	'  ', d.datum_neu, d.datum_neu, d.datum_neu,
	d.stichwort1,
	d.hnr_num, d.hnr_num,
	d.datum_neu, d.b_id_neu, d.datum_aend, d.b_id_aend,
	'', '', d.art, d.seite, 0
from RDKTVER d
union
select  t.adr_gr, t.adr_nr, t.person_nr,
	0, 0, 0, 0,
	'RD', 'ZRBET', 'AUTOR',
	r.e_mandant, r.beitrag_nr*(-1), ' ', '            ', ' ',
	h.obj_nr, h.ausg, '   ', 0, 1,
	'  ', r.datum_neu, r.datum_neu, r.datum_neu,
	t.beteil_typ||'                                                      ',
