	'EA', 'ANZ  ', 'SORE ',
	s.e_mandant, s.lfd_nr, ' ', s.rech_art||'         ', ' ',
	s.obj_nr, s.ausg||'          ', s.waehrung, s.wa_netto_betrag, 0,
	s.zahlungsart||' ', s.fakt_datum, s.bdatum, s.rech_datum,
	s.betreff||'          ',
	1000*s.jahr + s.hnr, 1000*s.jahr + s.hnr,
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend,
	'', '', '', '', rech_nr
from SORECHN s
union
select  s.adr_gr, s.abw_rech_empf, 0,
	s.rech_empf, 0, 0, 0,
	'EA', 'ANZ  ', 'SORE ',
	s.e_mandant, s.lfd_nr, ' ', s.rech_art||'         ', ' ',
	s.obj_nr, s.ausg||'          ', s.waehrung, s.wa_netto_betrag, 0,
	s.zahlungsart||' ', s.fakt_datum, s.bdatum, s.rech_datum,
	s.betreff||'          ',
	1000*s.jahr + s.hnr, 1000*s.jahr + s.hnr,
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend,
	'', '', '', '', rech_nr
from SORECHN s
where s.abw_rech_empf > 0
union
select  t.adr_gr, t.adr_nr, t.person_nr,
	d.lfd_nr, t.lfd_nr, d.adr_nr, d.person_nr,
	'RD', 'REDKT', 'REDZB',
	d.e_mandant, d.beitrag_nr*(-1), ' ', '            ', ' ',
	d.obj_nr, d.ausg||'          ', '   ', 0, 1,
	'  ', d.datum_neu, d.datum_neu, d.datum_neu,
	d.stichwort1,
	d.hnr_num, d.hnr_num,
	d.datum_neu, d.b_id_neu, d.datum_aend, d.b_id_aend,
	'', '', d.art, d.seite, 0
from ZRBETEIL t, RDKTVER d
where t.beitrag_nr = d.beitrag_nr
and t.beteil_typ = 'BELEG';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VORPVIEW" ("ADR_GR", "ADR_NR", "PERSON_NR", "ADR_NR_RECH", "PERSON_NR_RECH", "ADR_NR_LIEF", "PERSON_NR_LIEF", "BEREICH", "VORG_TYP", "VORGANG", "MANDANT", "REF_NR_1", "REF_NR_2", "TYP", "STATUS", "KZ_STORNO", "OBJ_NR", "AUSG", "ARTIKEL_NR", "WAEHRUNG", "NETTO_BETRAG", "MENGE", "FREI_MENGE", "RECH_ART", "BESTELL_DATUM", "LAUFZEIT_VON", "LAUFZEIT_BIS", "TEXT", "HNR_NUM", "DATUM_NEU", "B_ID_NEU", "DATUM_AEND", "B_ID_AEND", "ATTR_1", "ATTR_2", "ATTR_3", "ATTR_4", "ATTR_5") AS
  select s.adr_gr, s.adr_nr, s.person_nr,
	s.adr_nr_bv, s.person_nr_bv, 0, 0,
	'VZ', 'ABO  ', 'ABO  ',
	s.e_mandant, s.abo_nr, s.abo_nr, ' ', s.abostatus, s.kz_storno,
	s.obj_nr, s.ausg, '                    ', s.waehrung, f.l_rbetrag, s.ber_menge, 0,
	s.r_art, s.best_datum, s.vbeg_dat, s.vend_dat, s.best_nr||'          ',
      100000*s.vbeg_jahr + to_number(s.vbeg_heft),
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend,
	s.preis_kat, ' ', '   ', s.w_akt_id, s.w_uakt_id
from ABOSTAMM s, ABOFAKT f
where	s.adr_gr    = f.adr_gr(+)
and	s.adr_nr    = f.adr_nr(+)
and 	s.person_nr = f.person_nr(+)
and	s.e_mandant = f.e_mandant(+)
and 	s.obj_nr    = f.obj_nr(+)
and 	s.ausg      = f.ausg(+)
and 	s.abo_nr    = f.abo_nr(+)

union

select a.adr_gr, a.adr_nr_best, a.person_nr_best,
	a.adr_nr_re, a.person_nr_re, a.adr_nr_le, a.person_nr_le,
	'BU', 'BUCH ', 'BUCH ',
	a.e_mandant, a.auft_nr, 1000*a.auft_nr + p.auf_pos, a.auftrag_typ, a.status||'        ', a.storno,
	'   ', '            ', m.artikel_nr, a.waehrung, a.betrag_ne, p.ber_menge, p.frei_menge,
	a.r_art, a.best_datum, p.vers_ist_dat, to_date('01.01.2099'), a.best_text,
	0, a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	p.preiskat, a.best_weg, a.versart, a.akt_id, a.uakt_id
from BUAUFTRA a, BUAUFPOS p, BUMANAUS m
where a.auft_nr   = p.auft_nr(+)
and	m.e_mandant = p.e_mandant
and 	m.l_ausg_nr = p.l_ausg_nr

union

select a.adr_gr, a.adr_nr, 0,
	p.adr_nr, 0, a.adr_nr_wa, 0,
	'EA', 'ANZ  ', 'ANZ  ',
	a.e_mandant, a.auft_nr, 10000*a.auft_nr + d.dispo_nr, a.verwend_typ, d.status||'        ', a.kz_storno,
	a.obj_nr, a.ausg||'          ', '                    ', a.waehrung, d.netto_betrag, d.anz_anzeigen, 0,
	a.zahlungsart||' ', to_date('01.01.2099'), a.auftrag_vom, a.auftrag_bis,
	a.abschl_text||'          ',
      1000*a.jahr_ab + a.hnr_ab, a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	a.abrech_id||'  ', ' ', '   ', '        ', 0
from AUFTRAG a, DISPO d, APOSTWEG p
where	a.auft_hist_nr = 0
and 	a.verwend_typ  != 'G'
and   a.adr_gr           = d.adr_gr(+)
and	a.adr_nr           = d.adr_nr(+)
and	a.auft_nr          = d.auft_nr(+)
and	a.auft_hist_nr     = d.auft_hist_nr(+)
and	d.auft_hist_nr(+)  = 0
and	d.dispo_hist_nr(+) = 0
and	d.status(+)        != 'S'
and	d.status(+)        != 'L'
and   a.adr_gr           = p.adr_gr
and	a.adr_nr           = p.adr_nr
and	a.auft_nr          = p.auft_nr
and	a.auft_hist_nr     = p.auft_hist_nr
and	p.auft_hist_nr     = 0
and 	p.belegart_id      = 'R'

union

select a.adr_gr, a.adr_nr, 0,
	p.adr_nr, 0, a.adr_nr_wa, 0,
	'FA', 'FLIES', 'FLIES',
	a.e_mandant, a.auft_nr, 10000*a.auft_nr + d.dispo_nr, a.verwend_typ, d.status||'        ', a.kz_storno,
	a.obj_nr, a.ausg||'          ', '                    ', a.waehrung, d.netto_betrag, d.anz_anzeigen, 0,
	a.zahlungsart||' ', to_date('01.01.2099'), a.auftrag_vom, a.auftrag_bis,
	a.abschl_text||'          ',
	1000*a.jahr_ab + a.hnr_ab, a.datum_neu, a.b_id_neu, a.datum_aend, a.b_id_aend,
	a.abrech_id||'  ', ' ', '   ', '        ', 0
from AUFTRAG a, DISPO d, APOSTWEG p
where	a.auft_hist_nr = 0
and 	a.verwend_typ  = 'G'
and   a.adr_gr           = d.adr_gr(+)
and	a.adr_nr           = d.adr_nr(+)
and	a.auft_nr          = d.auft_nr(+)
and	a.auft_hist_nr     = d.auft_hist_nr(+)
and	d.auft_hist_nr(+)  = 0
and	d.dispo_hist_nr(+) = 0
and	d.status(+)        != 'S'
and	d.status(+)        != 'L'
and   a.adr_gr           = p.adr_gr
and	a.adr_nr           = p.adr_nr
and	a.auft_nr          = p.auft_nr
and	a.auft_hist_nr     = p.auft_hist_nr
and	p.auft_hist_nr     = 0
and 	p.belegart_id      = 'R';


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VPAAVIEW" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "HAUPT_NAME", "NACHNAME", "VORNAME", "WOHNORT", "POSTORT", "PREIS_KAT", "FAKT_ZR", "FAKT_ZR_NO", "VBEG_DAT", "VBEG_JAHR", "VBEG_HEFT", "VEND_DAT", "VEND_JAHR", "VEND_HEFT", "ABOSTATUS", "ABO_DAUER", "VERSART", "R_ART", "R_BEG_DAT", "R_BEG_HNR", "R_BEG_JAHR", "R_ENDE_DAT", "R_ENDE_HNR", "R_ENDE_JAHR", "L_RNR", "DATUM_NEU", "B_ID_NEU", "KZ_STORNO", "STATUS", "W_AKT_ID", "W_UAKT_ID", "BEST_DATUM", "PREIS_KAT_NO", "VERANLASSER", "BEST_WEG", "BESTELLG", "BER_MENGE", "K_GRUND", "K_DATUM", "L_RDAT", "L_RBETRAG", "F_ENDE_DAT_E", "ADR_NR_BV", "PERSON_NR_BV", "BEST_NR", "AUFTRAGS_NR", "PLZ_WOHN", "PLZ_POST", "LAND_CODE", "LFD_NR_AKTVORB", "KZ_R_DRUCK", "IP_ADR", "NOTIZ") AS
  select b.e_mandant, b.adr_gr, b.adr_nr, p.person_nr, b.obj_nr, b.ausg,
       b.abo_nr, a.haupt_name, p.nachname, p.vorname, a.wohnort, a.postort,
       b.preis_kat, b.fakt_zr, b.fakt_zr_no, b.vbeg_dat, b.vbeg_jahr, b.vbeg_heft,
       b.vend_dat, b.vend_jahr, b.vend_heft, b.abostatus, b.abo_dauer,
       v.versart, b.r_art, b.r_beg_dat, b.r_beg_hnr, b.r_beg_jahr,
       b.r_ende_dat, b.r_ende_hnr, b.r_ende_jahr, f.l_rnr,
       b.datum_neu,b.b_id_neu,b.kz_storno,b.status,b.w_akt_id,b.w_uakt_id,b.best_datum, b.PREIS_KAT_NO,b.VERANLASSER,b.BEST_WEG,b.BESTELLG,b.BER_MENGE,b.K_GRUND,b.K_DATUM,f.L_RDAT,f.L_RBETRAG,f.F_ENDE_DAT_E, b.ADR_NR_BV,b.PERSON_NR_BV, b.BEST_NR, b.auftrags_nr, a.PLZ_WOHN, a.PLZ_POST, a.LAND_CODE, b.LFD_NR_AKTVORB, b.KZ_R_DRUCK, b.IP_ADR, n.NOTIZ
from abostamm b LEFT OUTER JOIN abofakt f ON
      b.adr_gr    = f.adr_gr    and b.adr_nr    = f.adr_nr and
      b.person_nr = f.person_nr and b.e_mandant = f.e_mandant and
      b.obj_nr    = f.obj_nr    and b.ausg      = f.ausg and
      b.abo_nr    = f.abo_nr
      LEFT OUTER JOIN abonotiz n ON
      b.adr_gr    = n.adr_gr    and b.adr_nr    = n.adr_nr and
      b.person_nr = n.person_nr and b.e_mandant = n.e_mandant and
      b.obj_nr    = n.obj_nr    and b.ausg      = n.ausg and
      b.abo_nr    = n.abo_nr,
     person p, anschr a, abovers v
where b.adr_gr     = a.adr_gr    and b.adr_nr    = a.adr_nr
   and b.adr_gr    = p.adr_gr    and b.adr_nr    = p.adr_nr
   and b.person_nr = p.person_nr
   and b.adr_gr    = v.adr_gr
   and b.adr_nr    = v.adr_nr    and b.person_nr = v.person_nr
   and b.e_mandant = v.e_mandant and b.obj_nr    = v.obj_nr
   and b.ausg      = v.ausg      and b.abo_nr    = v.abo_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VZCRMV_ABO" ("MODIFIED_ON", "BESTELL_NR_EXTERN", "MANDANT", "AUFTRAG_ID", "LEISTUNGSEMPFAENGER_ID", "LEISTUNGSEMPFAENGER_NAME", "LEISTUNGSEMPFAENGER_ZH", "LEISTUNGSEMPFAENGER", "LEISTUNGSEMPFAENGER_PNR", "RECHNUNGSEMPFAENGER_ID", "RECHNUNGSEMPFAENGER_NAME", "RECHNUNGSEMPFAENGER_ZH", "RECHNUNGSEMPFAENGER", "RECHNUNGSEMPFAENGER_PNR", "BESTELL_DATUM", "OBJEKT", "TEILBELEGUNG", "HEFT_NR", "JAHR", "LAUFZEIT_START", "ANZAHL_ARTIKEL", "AKTIONS_ID", "AKTIONS_BEZEICHNUNG", "PREIS_KAT", "PREIS_KAT_BEZEICHNUNG", "PREIS_KAT_TEMP", "PREIS_KAT_TEMP_BEZEICHNUNG", "PREIS_NETTO", "PREIS_MWST", "PREIS_BRUTTO", "ABO_STATUS", "LIEFERUNG_START_HEFT_NR", "LIEFERUNG_START_JAHR", "LIEFERUNG_START_DATUM", "LIEFERUNG_ENDE_HEFT_NR", "LIEFERUNG_ENDE_JAHR", "LIEFERUNG_ENDE_DATUM", "LIEF_TEMP_ENDE_HEFT_NR", "LIEF_TEMP_ENDE_JAHR", "LIEF_TEMP_ENDE_DATUM", "KUENDIGUNG_GRUND", "KUENDIGUNG_BEZEICHNUNG", "KUENDIGUNG_DATUM", "FAKTURIERT_BIS_HEFT", "FAKTURIERT_BIS_JAHR", "FAKTURIERT_BIS_DATUM", "WAEHRUNG", "RECHNUNGSART", "RECHNUNGSART_BEZEICHNUNG", "ZAHLUNGSBEDINGUNG", "ZAHLUNGSBEDINGUNG_BEZEICHNUNG", "BESTELLGRUND", "BESTELLGRUND_BEZEICHNUNG", "BESTELLWEG", "VERSANDART", "VERSANDART_BEZEICHNUNG", "VERANLASSER", "NOTIZ", "CREATED_DATE", "CREATED_USER", "UPDATE_DATE", "UPDATE_USER") AS
  SELECT
  ast.modified_on, TREF.key_ext_char_3, ast.e_mandant,
	('abo-' || AST.ADR_GR || '-' || AST.ADR_NR || '-' || AST.PERSON_NR || '-' || AST.ABO_NR),
	(CASE
		WHEN (P.a_typ = 'F') THEN
			('c-unt-' || AST.adr_nr)
		ELSE
			CASE
		WHEN (P.a_typ = 'M') THEN
			(
				'c-mit-' || ast.adr_nr || '-' || ast.person_nr
			)
		ELSE
			CASE
		WHEN (P.a_typ = 'P') THEN
			('c-per-' || ast.adr_nr)
		ELSE
			('c-err-' || ast.adr_nr)
		END
		END
		END
	),
	TRIM (A.name1),
	(
		TRIM (P.nachname) ||
			CASE WHEN (P .vorname IS NULL) THEN
				''
			ELSE
				','
			END
		 || TRIM (P .vorname)
	),
ast.adr_nr,
ast.person_nr,
CASE
WHEN (ast.adr_nr_bv IS NULL) THEN
	(
		CASE
		WHEN (P.a_typ = 'F') THEN
			('c-unt-' || AST.adr_nr)
		ELSE
			CASE
		WHEN (P.a_typ = 'M') THEN
			(
				'c-mit-' || ast.adr_nr || '-' || ast.person_nr
			)
		ELSE
			CASE
		WHEN (P.a_typ = 'P') THEN
			('c-per-' || ast.adr_nr)
		ELSE
			('c-err-' || ast.adr_nr)
		END
		END
		END
	)
ELSE
	(
		CASE
		WHEN (pbv.a_typ = 'F') THEN
			('c-unt-' || AST.adr_nr_bv)
		ELSE
			CASE
		WHEN (pbv.a_typ = 'M') THEN
			(
				'c-mit-' || ast.adr_nr_bv || '-' || ast.person_nr_bv
			)
		ELSE
			CASE
		WHEN (pbv.a_typ = 'P') THEN
			('c-per-' || ast.adr_nr_bv)
		ELSE
			('c-err-' || ast.adr_nr_bv)
		END
		END
		END
	)
END,
CASE
WHEN (ast.adr_nr_bv IS NULL) THEN
	TRIM (A.name1)
ELSE
	TRIM (abv.name1)
END,
CASE
WHEN (ast.adr_nr_bv IS NULL) THEN
	(
		TRIM (P.nachname) ||
			CASE WHEN (P.vorname IS NULL) THEN
				''
			ELSE
				','
			END
		 || TRIM (P.vorname)
	)
ELSE
	(
		TRIM (pbv.nachname) ||
			CASE WHEN (PBV.vorname IS NULL) THEN
				''
			ELSE
				','
			END
		 || TRIM (pbv.vorname)
	)
END,
CASE
WHEN (ast.adr_nr_bv IS NULL) THEN
	ast.adr_nr
ELSE
	ast.adr_nr_bv
END,
CASE
WHEN (ast.adr_nr_bv IS NULL) THEN
	ast.person_nr
ELSE
	ast.person_nr_bv
END,
ast.BEST_DATUM,
ast.obj_nr,
ast.ausg,
AST.VBEG_HEFT,
ast.VBEG_JAHR,
AST.VBEG_DAT,
ast.ber_menge,
ast.W_AKT_ID,
wa.Beschreibung,
ast.preis_kat,
pk.bezeichnung,
ast.preis_kat_no,
pkt.bezeichnung,
fakt.NETTO,
(fakt.brutto - fakt.netto),
fakt.brutto,
AST.abostatus,
AST.VBEG_HEFT,
ast.VBEG_JAHR,
AST.VBEG_DAT,
ast.VEND_HEFT,
AST.vend_jahr,
ast.vend_dat,
ast.no_ende_hnr,
ast.no_ende_jahr,
ast.no_ende_dat,
ast.K_GRUND,
kue.beschreibung,
ast.K_DATUM,
aft.f_ende_hnr,
aft.f_ende_jahr,
aft.f_ende_dat_e,
ast.waehrung,
ast.r_art,
ra.beschreibung,
ast.z_bed,
zb.beschreibung,
ast.b_grund,
bg.beschreibung,
CASE
    WHEN ast.best_weg='B' THEN 'Brief/Karte'
    WHEN ast.best_weg='E' THEN 'E-Mail'
    WHEN ast.best_weg='F' THEN 'Fax'
    WHEN ast.best_weg='M' THEN 'Messe'
    WHEN ast.best_weg='T' THEN 'Telefon'
    WHEN ast.best_weg='U' THEN 'unbekannt'
    WHEN ast.best_weg='V' THEN 'Evalanche'
    WHEN ast.best_weg='W' THEN 'Webshop'
    ELSE ast.best_weg
END,
av.versart,
vb.bezeichnung,
ast.veranlasser,
an.notiz,
ast.datum_neu,
ast.b_id_neu,
ast.datum_aend,
ast.B_id_aend
FROM
	ABOSTAMM ast
  JOIN ABOFAKT aft on (
  aft.adr_gr = ast.adr_gr
  and aft.adr_nr = ast.adr_nr
  and aft.person_nr = ast.person_nr
  and aft.e_mandant = ast.e_mandant
  and aft.obj_nr = ast.obj_nr
  and aft.ausg = ast.ausg and aft.abo_nr = ast.abo_nr
)
LEFT JOIN person P ON (
	P.adr_gr = ast.adr_gr
	AND P.adr_nr = ast.adr_nr
	AND P.person_nr = ast.person_nr
)
LEFT JOIN anschr A ON (
	A.adr_gr = ast.adr_gr
	AND A.adr_nr = ast.adr_nr
)
LEFT JOIN person pbv ON (
	pbv.adr_gr = ast.adr_gr
	AND pbv.adr_nr = ast.adr_nr_bv
	AND pbv.person_nr = ast.person_nr_bv
)
LEFT JOIN anschr abv ON (
	abv.adr_gr = ast.adr_gr
	AND abv.adr_nr = ast.adr_nr_bv
)
LEFT JOIN aktvorb wa on (
  wa.e_mandant = ast.e_mandant
	and wa.akt_id = ast.w_akt_id
  and wa.obj_nr = ast.obj_nr
  and wa.ausg = ast.ausg
)
LEFT JOIN (
	SELECT faktupos.e_mandant, faktupos.ADR_GR, ADR_NR_OBJ, PNR_OBJ, ABO_NR, obj_nr, ausg,
  SUM(case when (buch_art = 'H') then GESPREIS_BR*(-1) else gespreis_br end) as BRUTTO,
  SUM(case when (buch_art = 'H') then GESPREIS_NET*(-1) else gespreis_net end) as NETTO
  from FAKTUPOS, faktpos
 where faktupos.e_mandant = faktpos.e_mandant
   and faktupos.rech_nr = faktpos.rech_nr
   and faktupos.re_dat = faktpos.re_dat
   and faktupos.abruf_nr = faktpos.abruf_nr
   and faktupos.kopie_nr = faktpos.kopie_nr
   and faktupos.posnr = faktpos.posnr
   GROUP BY faktupos.e_mandant, faktupos.ADR_GR, ADR_NR_OBJ, PNR_OBJ, ABO_NR, obj_nr,ausg) fakt ON
(fakt.e_mandant = ast.e_mandant and fakt.adr_gr=ast.adr_gr and fakt.adr_nr_obj = ast.adr_nr and fakt.pnr_obj = ast.person_nr and fakt.abo_nr = ast.abo_nr
 and fakt.obj_nr = ast.obj_nr and fakt.ausg = ast.ausg)
LEFT JOIN kuendig kue ON (
  kue.k_grund = ast.k_grund
)
LEFT JOIN preiskat pk ON (
  pk.preis_kat = ast.preis_kat
)
LEFT JOIN preiskat pkt ON (
  pkt.preis_kat = ast.preis_kat_no
)
LEFT JOIN rechart ra ON (
  ra.r_art = ast.r_art
)
LEFT JOIN zahlbed zb ON (
  zb.e_mandant = ast.e_mandant
  and zb.z_bed = ast.z_bed
)
LEFT JOIN bestell bg ON (
  bg.bestellg = ast.b_grund
)
LEFT JOIN abovers av ON (
  av.adr_gr = ast.adr_gr
  and av.adr_nr = ast.adr_nr
  and av.person_nr = ast.person_nr
  and av.e_mandant = ast.e_mandant
  and av.obj_nr = ast.obj_nr
  and av.ausg = ast.ausg and av.abo_nr = ast.abo_nr and rownum = 1
)
LEFT JOIN vartbez vb ON (
  vb.versart = av.versart
  and vb.sprach_code = 'D'
)
LEFT JOIN transref TREF ON (
  TREF.transfer_id = 'COVCRM_' || ast.e_mandant
  AND TREF.kunde = 'FAL'
  AND TREF.bereich = 'BUABO'
  AND TREF.verwend_typ = 'WSVIMP'
  AND TREF.referenz_typ = 'EXT_NR_AUFT_NR'
  AND TREF.key_cov_char_1 = ast.e_mandant || ast.adr_gr
	AND TREF.key_cov_char_2 = ast.obj_nr
	AND TREF.key_cov_char_3 = ast.ausg
	AND TREF.key_cov_char_4 = ast.abo_nr
	AND trim(TREF.key_cov_char_5) = ast.adr_nr || '/' || ast.person_nr
)
LEFT JOIN abonotiz an ON (
  an.adr_gr = ast.adr_gr
  and an.adr_nr = ast.adr_nr
  and an.person_nr = ast.person_nr
  and an.e_mandant = ast.e_mandant
  and an.obj_nr = ast.obj_nr
  and an.ausg = ast.ausg and an.abo_nr = ast.abo_nr and rownum = 1
) order by an.lfd_nr desc;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VZCRMV_AKTVORB" ("MODIFIED_ON", "AKTVORB_ID", "E_MANDANT", "AKT_ID", "OBJ_NR", "AUSG", "LFD_NR", "UAKT_ID", "BESCHREIBUNG", "PREIS_KAT", "PREIS_KAT_TEMP", "GUELTIG_AB", "GUELTIG_BIS", "PRAEM_ARTIKEL_NR", "PRAEM_AUFLAGE_NR", "PRAEM_BESCHREIBUNG") AS
  select av.modified_on, 'A-' || av.e_mandant || '-' || trim(av.akt_id) || '-' || trim(av.obj_nr) || '-' || trim(av.ausg) || '-' || av.lfd_nr, av.e_mandant, av.akt_id, av.obj_nr, av.ausg, av.lfd_nr, av.uakt_id, case when (ma.b_aktid is null) then av.beschreibung else ma.b_aktid end,
av.preis_kat, av.preis_kat_no, av.gueltig_ab, av.gueltig_bis,
bm.artikel_nr, bl.auflage_nr, case when (ba.l_titel_nr = 0) then coalesce(bs.artikel_bez,ba.ausg_text) else bt.titel1 end
from AKTVORB av
left join MHAKTION ma on
ma.e_mandant = av.e_mandant and ma.akt_id = av.akt_id
left join (AKTVORBA ab join BUMANAUS bm on
bm.e_mandant = ab.e_mandant and bm.l_ausg_nr = ab.l_ausg_nr
join BUAUFL bl on
bl.l_ausg_nr = ab.l_ausg_nr and bl.l_aufl_nr = ab.l_aufl_nr
join BUAUSGAB ba on
ba.l_ausg_nr = ab.l_ausg_nr
left join BUTITEL BT ON
bt.l_titel_nr = ba.l_titel_nr
left join BUAUSSPR bs on
bs.l_ausg_nr = ab.l_ausg_nr and bs.sprach_code = 'D')
on ab.e_mandant = av.e_mandant and ab.akt_id = av.akt_id and ab.obj_nr = av.obj_nr and ab.ausg = av.ausg and ab.lfd_nr = av.lfd_nr
where (av.gueltig_ab <= sysdate or av.gueltig_ab is null) and (av.gueltig_bis >= sysdate or av.gueltig_bis is null);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VZMAKOST" ("E_MANDANT", "KOSTEN_ID", "BEZ", "SOLL_REGEL", "IST_REGEL", "EINZEL_PREIS", "VERW_ID", "OBJ_NR", "GRP_ID", "VERW_ID_STAT", "KZ_NICHT_CPO", "KZ_ERLOES") AS
  select	 k.e_mandant, k.kosten_id, k.bez, k.soll_regel, k.ist_regel,
	k.einzel_preis, k.verw_id, k.obj_nr, k.grp_id, k.verw_id_stat,
	k.kz_nicht_cpo, s.kz_erloes
from makosten k, mastatgr s
where k.e_mandant    = s.e_mandant
and   k.verw_id_stat = s.verw_id_stat;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VZPRVIEW" ("E_MANDANT", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "ABO_NR", "POS_NR", "L_AUSG_NR", "L_AUFL_NR", "PREIS_KAT_PRA", "EINZEL_PREIS", "W_ADR_NR", "W_PERSON_NR", "R_BETRAG", "KZ_SPERREN", "ADR_NR_BV", "PERSON_NR_BV", "ABOSTATUS", "KZ_STORNO", "WAEHRUNG", "W_AKT_ID", "W_UAKT_ID", "PREIS_KAT", "PREIS_KAT_NO", "R_ART", "BER_MENGE", "BEST_DATUM", "BEST_NR", "VBEG_DAT", "VBEG_HEFT", "VBEG_JAHR", "VEND_DAT", "VEND_HEFT", "VEND_JAHR", "R_BEG_DAT", "R_BEG_HNR", "R_BEG_JAHR", "NO_ENDE_DAT", "NO_ENDE_HNR", "NO_ENDE_JAHR", "DATUM_NEU", "B_ID_NEU", "DATUM_AEND", "B_ID_AEND", "ABOART", "STATUS", "BU_BER_MENGE", "FREI_MENGE", "GELIEF_MENGE", "FAKT_MENGE", "AUF_POS", "AUFT_NR", "KZ_SCHNUPPERABO") AS
  select a.e_mandant, a.adr_gr, a.adr_nr, a.person_nr,
      a.obj_nr, a.ausg, a.abo_nr, a.pos_nr,
      a.l_ausg_nr, a.l_aufl_nr,
      a.preiskat, a.einzel_preis,
	a.w_adr_nr, a.w_person_nr, w.r_betrag, w.kz_sperren,
      s.adr_nr_bv, s.person_nr_bv,
	s.abostatus, s.kz_storno, s.waehrung,
      s.w_akt_id, s.w_uakt_id, s.preis_kat, s.preis_kat_no,
	s.r_art, s.ber_menge, s.best_datum, s.best_nr,
      s.vbeg_dat, s.vbeg_heft, s.vbeg_jahr,
      s.vend_dat, s.vend_heft, s.vend_jahr,
	s.r_beg_dat, s.r_beg_hnr, s.r_beg_jahr,
      s.no_ende_dat, s.no_ende_hnr, s.no_ende_jahr,
	s.datum_neu, s.b_id_neu, s.datum_aend, s.b_id_aend, s.aboart,
      b.status, b.ber_menge, b.frei_menge, b.gelief_menge, b.fakt_menge, b.auf_pos,
      f.auft_nr, a.kz_schnupperabo
from WERBEPRA a, WERBEPR w, ABOSTAMM s, BUAUFTRA f, BUAUFPOS b
where a.adr_gr    = w.adr_gr
and   a.adr_nr    = w.adr_nr
and   a.person_nr = w.person_nr
and   a.e_mandant = w.e_mandant
and   a.obj_nr    = w.obj_nr
and   a.ausg      = w.ausg
and   a.abo_nr    = w.abo_nr
and   a.adr_gr    = s.adr_gr
and   a.adr_nr    = s.adr_nr
and   a.person_nr = s.person_nr
and   a.e_mandant = s.e_mandant
and   a.obj_nr    = s.obj_nr
and   a.ausg      = s.ausg
and   a.abo_nr    = s.abo_nr
and   s.w_akt_id is not null
and   f.adr_gr    = a.adr_gr
and   f.adr_nr_re = a.w_adr_nr
and   f.person_nr_re = a.w_person_nr
and   f.e_mandant = a.e_mandant
and   f.akt_id    = s.w_akt_id
and   f.uakt_id   = s.w_uakt_id
and   b.auft_nr   = f.auft_nr
and   b.obj_nr    = a.obj_nr
and   b.ausg      = a.ausg
and   b.abo_nr    = a.abo_nr
and   b.l_ausg_nr = a.l_ausg_nr
