  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VZTYPVIE" ("E_MANDANT", "VERTRETER_ID", "VERTRETER_TYP", "AKT_ID", "REG_ID", "REG_CODE", "KZ_STANDARD", "VERTRETER_ART", "EBENE", "ADR_GR", "ADR_NR", "PERSON_NR", "BENUTZER_ID", "BANK_SATZ_NR", "RUECKBELAST_PROZ", "VERTRAGSENDE", "ABRECH_RHYTHMUS", "RUECKLAGE_BETR", "RUECKLAGE_BEHALT_PROZ", "KZ_GEBIET_PRUEF") AS
