        b.vertreter_art, b.ebene,
		c.adr_gr, c.adr_nr, c.person_nr, c.benutzer_id, c.bank_satz_nr, c.rueckbelast_proz, c.vertragsende,
		c.abrech_rhythmus, c.ruecklage_betr, c.ruecklage_behalt_proz, c.kz_gebiet_pruef
FROM   	VZTYPTMP a, VZVERTYP b, VZVERTRE c
WHERE	a.vertreter_typ = b.vertreter_typ
and     a.vertreter_id  = c.vertreter_id
and     a.e_mandant     = c.e_mandant;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."VZUMSKND" ("E_MANDANT", "RECH_TYP", "RECH_NR", "DATUM", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "WAEHRUNG", "SUM_NETTO_BETR", "SUM_NETTO_GUTS") AS
  select	r.e_mandant, r.buch_art, r.rech_nr, r.re_dat, r.adr_gr, r.adr_nr_re, r.person_nr_re, f.obj_nr, r.waehrung, abs(f.betr_net_pos), 0
from  FAKSTAMM r, FAKTPOS f
where r.kopie_nr=0 and r.buch_art <> 'H' and
      r.e_mandant = f.e_mandant and
      r.rech_nr = f.rech_nr and r.re_dat=f.re_dat
union
select	r.e_mandant, r.buch_art, r.rech_nr, r.re_dat, r.adr_gr, r.adr_nr_re, r.person_nr_re, f.obj_nr, r.waehrung, 0, abs(f.betr_net_pos)
