       r.adr_gr = a.adr_gr and r.adr_nr = a.adr_nr and r.auft_nr = a.auft_nr and
       r.auft_hist_nr = a.auft_hist_nr and
       r.adr_gr = b.adr_gr and r.adr_nr = b.adr_nr and r.auft_nr = b.auft_nr and
       r.auft_hist_nr = b.auft_hist_nr and
       r.adr_gr = h.adr_gr and r.adr_nr = h.adr_nr;


