  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."WBZSTAMMVIEW" ("E_MANDANT", "OBJ_NR", "AUSG", "LFD_NR_OBJ", "PVKZ", "VDZ_NR_DIENSTL", "LFD_NR_PL_WBZ", "LFD_NR_WBZ", "GUELTIG_AB_HNR", "GUELTIG_AB_JAHR", "WBZ_ABG_PREIS", "LFD_NR_PL_WKZ", "WKZ_SCHLUESSEL", "GUELTIG_AB_HNR_NUM_WKZ", "HAFTUNG_ANZAHL", "LFD_NR_WKZ", "FOLGE_TYP_WKZ", "FOLGE_ANZAHL", "WKZ_BETRAG") AS
  select a.e_mandant, a.obj_nr,a.ausg,a.lfd_nr_obj,a.pv_kz,a.vdz_nr_dienstl,b.lfd_nr_pl,c.lfd_nr,c.gueltig_ab_hnr,c.gueltig_ab_jahr,c.wbz_abg_preis,
d.lfd_nr_pl,d.wkz_schluessel, d.gueltig_ab_hnr_num,d.haftung_anzahl,e.lfd_nr,e.folge_wkz_typ,e.folge_anzahl,e.wkz_betrag
 from mobjwbz a
 left outer join wbzplgrup b on
      a.e_mandant  = b.e_mandant   and
      a.obj_nr     = b.obj_nr      and
      a.ausg       = b.ausg        and
      a.lfd_nr_obj = b.lfd_nr_obj
 left outer join wbzplpreis c on
      b.e_mandant  = c.e_mandant   and
      b.obj_nr     = c.obj_nr      and
      b.ausg       = c.ausg        and
      b.lfd_nr_obj = c.lfd_nr_obj  and
      b.lfd_nr_pl  = c.lfd_nr_pl
 left outer join wkzplist d on
      a.e_mandant  = d.e_mandant   and
      a.obj_nr     = d.obj_nr      and
      a.ausg       = d.ausg        and
      a.lfd_nr_obj = d.lfd_nr_obj
 left outer join wkzpreis e on
      d.e_mandant  = e.e_mandant   and
      d.obj_nr     = e.obj_nr      and
      d.ausg       = e.ausg        and
      d.lfd_nr_obj = e.lfd_nr_obj  and
      d.lfd_nr_pl  = e.lfd_nr_pl;


