        wek.uakt_id, u.b_uaktid, u.wek_grp, uwg.bez, u.kz_ef, u.id_vuakt, wek.erst_akt_id, u2.b_uaktid, u.mass_code, m.b_mass, r.er_code,
        wek.modul, wek.in_out,
        wek.anz_adressen, wek.anz_adr_uakt, wek.anz_adr_eakt, wek.anz_adr_bearbeitet, wek.anz_adr_bearb_uakt, wek.anz_adr_bearb_eakt,
        wek.soll_ist, wek.betr_kost, wek.betr_kost_cpo, wek.betr_kost_ncpo, wek.betr_erl_ncpo,
        wek.betr_kost_cpo_sum, wek.anz_bestell_cpo, wek.cpo,
        bum.artikel_nr, bua.ausg_text, but.titel_such,
        mob.obj_nr, mob.objektname,
        wek2.betr_kost, wek3.betr_kost, wek4.betr_kost, wek5.betr_kost, wek6.betr_kost, wek7.betr_erl_ncpo,
        wek.anz_abo_voll, wek.anz_aboabs, wek.anz_no2voll, wek.anz_sano2voll, wek.anz_abo_frei,
        wek.anz_abo_sa, wek.anz_abo_sano, wek.anz_abo_sapo, wek.anz_abo_no, wek.anz_abo_po, wek.anz_abosto,
        wek.anz_probeheft, wek.anz_einzelheft, wek.anz_bestellung, wek.anz_sonst, wek.anz_interes, wek.erfolg_proz
from    WEKSTAT wek, MHAKTION h, MAKTION a, MHWDHGRP wdh,
        BUMANAUS bum, BUAUSGAB bua, BUTITEL but, MOBJTYP mob,
        MUAKTION u, MUAKTION u2, MAWEKGRP uwg, MASSNAHM m, RESPVORG r,
        WEKSTAT wek2, WEKSTAT wek3, WEKSTAT wek4, WEKSTAT wek5, WEKSTAT wek6, WEKSTAT wek7
where   wek.verwend_typ     = 'CPO'
and     h.e_mandant(+)      = wek.e_mandant
and     h.akt_id(+)         = wek.akt_id
and     a.akt_code(+)       = h.akt_code
and     wdh.e_mandant(+)    = h.e_mandant
and     wdh.wdh_grp(+)      = h.wdh_grp
and     u.e_mandant(+)      = wek.e_mandant
and     u.akt_id(+)         = wek.akt_id
and     u.uakt_id(+)        = wek.uakt_id
and     u2.e_mandant(+)     = wek.e_mandant
and     u2.akt_id(+)        = wek.akt_id
and     u2.uakt_id(+)       = wek.erst_akt_id
and     uwg.e_mandant(+)    = u.e_mandant
and     uwg.wek_grp(+)      = u.wek_grp
and     m.mass_code(+)      = u.mass_code
and     r.e_mandant(+)      = wek.e_mandant
and     r.akt_id(+)         = wek.akt_id
