  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."WERBEERLAUSW" ("ADR_NR", "PERSON_NR", "OK") AS
  select adr_nr,person_nr,mod(min(
case
  when obj_nr='BUH' and   bereich is null and kz_erlaub='F' then     11
  when obj_nr='BUH' and   bereich is null and kz_erlaub is null then 21
  when obj_nr='BUH' and   bereich is null and kz_erlaub='T' then     30
  when obj_nr is null and bereich ='B101' and kz_erlaub='F' then     41
  when obj_nr is null and bereich ='B101' and kz_erlaub is null then 51
  when obj_nr is null and bereich ='B101' and kz_erlaub='T' then     60
  when obj_nr is null and bereich is null and kz_erlaub='F' then     71
  when obj_nr is null and bereich is null and kz_erlaub is null then 81
  when obj_nr is null and bereich is null and kz_erlaub='T' then     90
  else 1
end ),2) as ok
from werbeerl
where adr_gr='BBS' and adr_nr in (218153, 218154, 218155)
group by adr_nr,person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."WSELVIEW" ("BENUTZER_ID", "SEL_ID", "ADR_GR", "PRIO_AUFG", "ANZ_ADR", "ANZ_EX", "W_AKT_ID", "W_UAKT_ID", "W_START_ID", "E_MANDANT", "OBJ_NR", "AUSG", "KZ_ERLEDIGT", "JAHR", "HNR", "ADR_NR", "PERSON_NR", "VERWEIS_NR", "A_TYP") AS
  select
      v.BENUTZER_ID, v.SEL_ID, v.ADR_GR, PRIO_AUFG, ANZ_ADR, ANZ_EX,
      W_AKT_ID, W_UAKT_ID, W_START_ID, E_MANDANT, OBJ_NR, AUSG, KZ_ERLEDIGT,
      JAHR, HNR, ADR_NR, PERSON_NR, VERWEIS_NR, A_TYP
from WERBEVV v, SELPOOL s
where v.benutzer_id = s.benutzer_id
and   v.sel_id      = s.sel_id
and   v.adr_gr      = s.adr_gr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."WTDPVIEW" ("ADR_GR", "ADR_NR", "AUFT_NR", "DISPO_NR", "DISPOPOS_NR", "E_MANDANT", "OBJ_NR", "AUSG", "JAHR", "HNR", "MOTIV", "FARB_ID", "VOLUMEN_MM", "OBJEKTTYP") AS
  select d.adr_gr, d.adr_nr, d.auft_nr, d.dispo_nr, p.dispopos_nr,
       p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr,
       p.motiv, d.farb_id, d.volumen_mm,  t.objekttyp
from    dispo d, dispopos p, eobjtyp t
where  d.auft_hist_nr = 0 and d.dispo_hist_nr = 0 and
       (d.status='A' or d.status='F' or d.status='R') and
       d.adr_gr=p.adr_gr and d.adr_nr=p.adr_nr and
       d.auft_nr=p.auft_nr and d.auft_hist_nr=p.auft_hist_nr and
       d.dispo_nr=p.dispo_nr and d.dispo_hist_nr=p.dispo_hist_nr and
       d.e_mandant = t.e_mandant and d.obj_nr = t.obj_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."WTDVIEW" ("ADR_GR", "ADR_NR", "E_MANDANT", "OBJ_NR", "AUSG", "JAHR", "HNR", "VOLUMEN_FA", "VOLUMEN_MM", "VOLUMEN_ANZ", "ANZ_SI") AS
  select p.adr_gr, p.adr_nr,
       p.e_mandant, p.obj_nr, p.ausg, p.jahr, p.hnr,
       sum(d.volumen_fa/d.anz_schaltung),
       sum(d.volumen_mm/d.anz_schaltung), count(*), sum(d.anz_si)
from   dispopos p, dispo d
where  p.auft_hist_nr = 0 and p.dispo_hist_nr = 0 and
       (d.status='A' or d.status='F' or d.status='R') and
       p.adr_gr=d.adr_gr and p.adr_nr=d.adr_nr and
       p.auft_nr=d.auft_nr and p.auft_hist_nr=d.auft_hist_nr and
       p.dispo_nr=d.dispo_nr and p.dispo_hist_nr=d.dispo_hist_nr
group by p.adr_gr, p.adr_nr, p.e_mandant,
         p.obj_nr, p.ausg, p.jahr, p.hnr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."WTPRVIEW" ("ADR_GR", "ADR_NR", "PRODUKT", "KZ_LOESCH", "HERKUNFT_ID", "WB_ID", "HGRP_ID", "UGRP_ID", "BEZ", "VERWEND_TYP") AS
  select wt.adr_gr, wt.adr_nr, wt.produkt, wt.kz_loesch, wt.herkunft_id,
	 p.wb_id, p.hgrp_id, p.ugrp_id, p.bez, u.verwend_typ
from WTPROD wt, PRODUKT p, UGRUPPE u
where	wt.produkt   = p.produkt and
	p.wb_id      = u.wb_id and
	p.hgrp_id    = u.hgrp_id and
        p.ugrp_id    = u.ugrp_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."WVTPVIEW" ("E_MANDANT", "AKT_ID", "UAKT_ID", "START_ID", "ADR_GR", "ADR_NR", "PERSON_NR", "OBJ_NR", "AUSG", "JAHR", "HNR", "KZ_ERLEDIGT") AS
  select
t.e_mandant, t.akt_id, t.uakt_id, t.start_id, t.adr_gr, t.adr_nr, t.person_nr,
w.obj_nr, w.ausg, w.jahr, w.hnr, w.kz_erledigt
from teilnemp t
inner join  werbevv w on
   w.e_mandant = t.e_mandant and
   w.w_akt_id = t.akt_id and
   w.w_uakt_id = t.uakt_id and
   w.w_start_id = t.start_id;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."XXX" ("ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "JAHR", "HNR_VZ", "HNR_EA", "VERWEND_TYP") AS
  select p.adr_gr,p.adr_nr,p.person_nr,'0','0','0','0','0',0,'ADR'
from  person p
union
select '',0,0,m.e_mandant,m.obj_nr,m.ausg,'0','0',0,'OBJVZ'
from  mobstamm m
union
select '',0,0,k.e_mandant,k.obj_nr,k.ausg,k.jahr,k.hnr,0,'HEFTVZ'
from  kalender k
union
select '',0,0,e.e_mandant,e.obj_nr,e.ausg,e.jahr,'0',e.hnr,'HEFTEA'
from  kalendea e
;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ZRBEIVIE" ("ADR_GR", "ADR_NR", "HAUPT_NAME", "PERSON_NR", "NACHNAME", "VORNAME", "BETEIL_TYP", "BEITRAG_ID", "BEITRAG_ART", "BEITRAG_NR", "STATUS", "TITEL", "UNTERTITEL", "SUCH_SWORT", "E_MANDANT", "OBJ_NR", "AUSG", "HNR", "JAHR", "RUBRIK_ID", "RUBRIK_BEZ", "SEITE_VON", "SEITE_BIS", "DATUM_EVT") AS
  select b.adr_gr, b.adr_nr, a.haupt_name, b.person_nr, p.nachname, p.vorname,
       b.beteil_typ, z.beitrag_id, z.beitrag_art, z.beitrag_nr, z.status, z.titel, z.untertitel, s.such_swort,
       h.e_mandant, h.obj_nr, h.ausg, h.hnr, h.jahr, h.rubrik_id, h.rubrik_bez, h.seite_von, h.seite_bis, k.datum_evt
from anschr a, person p, zrbeitra z, zrbeteil b, zrheft h, kalendea k, zrstichw s
where b.beitrag_nr (+) = z.beitrag_nr and
           a.adr_gr (+)   = b.adr_gr  and
           a.adr_nr (+)  = b.adr_nr  and
           p.adr_gr  (+)  = b.adr_gr and
           p.adr_nr (+)   = b.adr_nr and
           p.person_nr (+) = b.person_nr and
           s.beitrag_nr (+) = z.beitrag_nr and
           h.beitrag_nr (+) = z.beitrag_nr and
           k.e_mandant (+) = h.e_mandant and
           k.obj_nr  (+) = h.obj_nr and
           k.ausg (+)  = h.ausg and
           k.hnr  (+) = h.hnr and
           k.jahr  (+) = h.jahr
union
select r.adr_gr, r.adr_nr, a.haupt_name, r.person_nr, p.nachname, p.vorname,
       'RDKTVE', z.beitrag_id, z.beitrag_art, z.beitrag_nr, z.status, z.titel, z.untertitel, s.such_swort,
       h.e_mandant, h.obj_nr, h.ausg, h.hnr, h.jahr, h.rubrik_id, h.rubrik_bez, h.seite_von, h.seite_bis, k.datum_evt
from anschr a, person p, zrbeitra z, rdktver r, zrheft h, kalendea k, zrstichw s
where r.beitrag_nr = z.beitrag_nr and
           a.adr_gr = r.adr_gr  and
           a.adr_nr = r.adr_nr  and
           p.adr_gr = r.adr_gr and
           p.adr_nr = r.adr_nr and
           p.person_nr = r.person_nr and
           s.beitrag_nr (+) = z.beitrag_nr and
           h.beitrag_nr (+) = z.beitrag_nr and
           k.e_mandant (+) = h.e_mandant and
           k.obj_nr  (+) = h.obj_nr and
           k.ausg (+)  = h.ausg and
           k.hnr  (+) = h.hnr and
           k.jahr  (+) = h.jahr
union
select b.adr_gr, b.adr_nr, a.haupt_name, b.person_nr, p.nachname, p.vorname,
       b.beteil_typ, z.beitrag_id, z.beitrag_art, z.beitrag_nr, z.status, z.titel, z.untertitel, s.such_swort,
       z.e_mandant, z.obj_nr, '            ', Null, '    ', '   ',
       '                                        ', '      ', '      ', Null
from anschr a, person p, zrbeitra z, zrbeteil b, zrstichw s
where b.beitrag_nr (+) = z.beitrag_nr and
           a.adr_gr (+)   = b.adr_gr  and
           a.adr_nr (+)  = b.adr_nr  and
           p.adr_gr  (+)  = b.adr_gr and
           p.adr_nr (+)   = b.adr_nr and
           p.person_nr (+) = b.person_nr and
           s.beitrag_nr (+) = z.beitrag_nr and
           not exists (select beitrag_nr from zrheft where z.beitrag_nr = zrheft.beitrag_nr);


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ZRBELVW" ("BEITRAG_NR", "E_MANDANT", "OBJ_NR", "AUSG", "JAHR", "HNR", "BETEIL_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "BETEIL_TYP", "ANZ_BELEGE") AS
