  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ZRHEFTVW" ("BEITRAG_NR", "E_MANDANT", "OBJ_NR", "AUSG", "JAHR", "HNR", "BETEIL_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "BETEIL_TYP", "HONART_ID", "ANTEIL_PROZ", "UMFANG", "ANZ_CM", "ANTEIL_PROZ_BILD", "VERWEND_TYP", "STEUER_CODE") AS
