  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ZRLESVIE" ("LESERBRIEF_NR", "ADR_GR", "ADR_NR", "PERSON_NR", "HAUPT_NAME", "NACHNAME", "VORNAME", "HONART_ID", "ZUSCHRIFT", "BEMERK", "EINGANGS_DAT", "VERS_DAT", "RUECK_DAT") AS
  select z.leserbrief_nr, z.adr_gr, z.adr_nr, z.person_nr,
	     a.haupt_name,
	     p.nachname, p.vorname,
	     z.honart_id, z.zuschrift, z.bemerk, z.eingangs_dat, z.vers_dat, z.rueck_dat	
  from zrlesbri z, anschr a, person p
  where  a.adr_gr   (+) = z.adr_gr and
  		 p.adr_gr   (+) = z.adr_gr and
		 a.adr_gr       = p.adr_gr and
  	     a.adr_nr   (+) = z.adr_nr and
		 p.adr_nr   (+) = z.adr_nr and
		 a.adr_nr       = p.adr_nr and
		 p.person_nr(+) = z.person_nr;


  CREATE OR REPLACE FORCE EDITIONABLE VIEW "XXX"."ZROBJVIE" ("LFD_NR", "AB_MENGE", "ADR_GR", "ADR_NR", "PERSON_NR", "E_MANDANT", "OBJ_NR", "AUSG", "JAHR", "HEFT", "HONART_ID", "VERWEND_TYP", "HON_BETRAG", "ABSCHLAG_2", "ABSCHLAG_3") AS
  select o.lfd_nr, s.ab_menge, o.adr_gr, o.adr_nr, o.person_nr,
       o.e_mandant, o.obj_nr, o.ausg, o.jahr, o.heft, o.honart_id,
       a.verwend_typ, s.hon_betrag, s.abschlag_2, s.abschlag_3
from zrobjaut o, zrobjsta s, honart a
where s.lfd_nr = o.lfd_nr and
      o.honart_id = a.honart_id;

